/**
 * Compliance Deadline Calendar Agent (P2-4) — Phase G8
 * Schedule: Monday 5:00 AM Asia/Manila (weekly).
 *
 * Rule-based: lists known recurring deadlines falling in the next 14 days.
 * Source: COMPLIANCE_DEADLINES lookup (lazy-seeded below if not present).
 * Adding a deadline = new lookup row, no code change (Rule #3).
 */
'use strict';

const mongoose = require('mongoose');
const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');

function tryModel(name) { try { return mongoose.model(name); } catch { return null; } }

// Baseline PH deadlines. Month offsets: 'every' = monthly; [1,4,7,10] = quarterly.
// Each deadline: { code, label, day_of_month, months (array) | 'every', description }.
// Entities add/remove via Control Center → Lookup Tables once the row category exists.
const BASELINE_DEADLINES = [
  { code: 'BIR_1601E', label: 'BIR 1601-E (monthly withholding)', day_of_month: 10, months: 'every', description: 'Expanded withholding tax return, filed monthly' },
  { code: 'BIR_2550M', label: 'BIR 2550-M (monthly VAT)', day_of_month: 20, months: 'every', description: 'Monthly VAT declaration' },
  { code: 'BIR_1701Q', label: 'BIR 1701-Q (quarterly income tax)', day_of_month: 15, months: [5, 8, 11], description: 'Quarterly income tax return' },
  { code: 'SSS_REMIT', label: 'SSS contribution remittance', day_of_month: 10, months: 'every', description: 'SSS employer remittance' },
  { code: 'PHIC_REMIT', label: 'PhilHealth remittance', day_of_month: 15, months: 'every', description: 'PhilHealth employer remittance' },
  { code: 'HDMF_REMIT', label: 'HDMF (Pag-IBIG) remittance', day_of_month: 15, months: 'every', description: 'Pag-IBIG employer remittance' },
];

async function loadDeadlines() {
  const Lookup = tryModel('Lookup');
  if (!Lookup) return BASELINE_DEADLINES;
  const rows = await Lookup.find({ category: 'COMPLIANCE_DEADLINES', is_active: { $ne: false } }).lean();
  if (!rows.length) return BASELINE_DEADLINES;
  return rows.map(r => ({
    code: r.code,
    label: r.label,
    day_of_month: r.metadata?.day_of_month || 10,
    months: r.metadata?.months || 'every',
    description: r.metadata?.description || '',
  }));
}

function upcomingFor(deadline, from = new Date(), windowDays = 14) {
  const out = [];
  for (let i = 0; i < windowDays + 1; i++) {
    const d = new Date(from.getFullYear(), from.getMonth(), from.getDate() + i);
    const m = d.getMonth() + 1;
    const dom = d.getDate();
    const monthsArr = deadline.months === 'every' ? null : deadline.months;
    if (dom === deadline.day_of_month && (!monthsArr || monthsArr.includes(m))) {
      out.push({ date: d, label: deadline.label, description: deadline.description });
    }
  }
  return out;
}

async function run() {
  try {
    const deadlines = await loadDeadlines();
    const now = new Date();
    const upcoming = deadlines.flatMap(d => upcomingFor(d, now, 14)).sort((a, b) => a.date - b.date);

    const lines = upcoming.length
      ? upcoming.map(u => `• ${u.date.toISOString().slice(0, 10)} — ${u.label}`)
      : ['No filings / remittances in the next 14 days.'];

    const body = lines.join('\n');

    const results = await notify({
      recipient_id: 'PRESIDENT',
      title: 'Compliance Deadline Calendar — Next 14 Days',
      body,
      category: 'compliance_alert',
      priority: upcoming.length > 0 ? 'important' : 'normal',
      channels: ['in_app', 'email'],
      agent: 'compliance_calendar',
    });

    return {
      status: 'success',
      summary: { alerts_generated: upcoming.length, messages_sent: countSuccessfulChannels(results, 'in_app'), key_findings: lines.slice(0, 6) },
      message_ids: getInAppMessageIds(results),
    };
  } catch (err) {
    console.error('[Compliance] Run failed:', err.message);
    return { status: 'error', summary: {}, message_ids: [], error_msg: err.message };
  }
}

module.exports = { run };

/**
 * Credit Risk Agent (#8)
 */

const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');

async function run() {
  console.log('[CreditRisk] Running...');

  const SalesLine = require('../erp/models/SalesLine');
  const Collection = require('../erp/models/Collection');
  const Hospital = require('../erp/models/Hospital');
  const Customer = require('../erp/models/Customer');

  const results = [];
  const significantChanges = [];

  function getRiskLevel(score) {
    if (score >= 80) return 'LOW';
    if (score >= 60) return 'MODERATE';
    if (score >= 40) return 'HIGH';
    if (score >= 20) return 'VERY_HIGH';
    return 'CRITICAL';
  }

  async function scoreEntity({ entityType, entityId, entityName, paymentTerms, creditLimit }) {
    try {
      const now = new Date();
      const twelveMonthsAgo = new Date(now.getFullYear() - 1, now.getMonth(), now.getDate());
      const idField = entityType === 'hospital' ? 'hospital_id' : 'customer_id';

      const sales = await SalesLine.find({
        [idField]: entityId,
        status: 'POSTED',
        csi_date: { $gte: twelveMonthsAgo },
      }).select('_id csi_date invoice_total').lean();
      if (!sales.length) return null;

      const collections = await Collection.find({
        [idField]: entityId,
        status: 'POSTED',
        cr_date: { $gte: twelveMonthsAgo },
      }).select('cr_date cr_amount settled_csis').lean();

      let totalDaysToPay = 0;
      let paidInvoiceCount = 0;
      let paidOnTimeCount = 0;
      const terms = paymentTerms || 30;

      for (const collection of collections) {
        for (const settled of collection.settled_csis || []) {
          const sale = sales.find((item) => String(item._id) === String(settled.sales_line_id));
          if (!sale) continue;
          const daysToPay = Math.floor((new Date(collection.cr_date) - new Date(sale.csi_date)) / (1000 * 60 * 60 * 24));
          totalDaysToPay += Math.max(0, daysToPay);
          paidInvoiceCount += 1;
          if (daysToPay <= terms) paidOnTimeCount += 1;
        }
      }

      let speedScore = 50;
      if (paidInvoiceCount > 0) {
        const avgDays = totalDaysToPay / paidInvoiceCount;
        if (avgDays <= 0) speedScore = 100;
        else if (avgDays <= terms) speedScore = 100 - (avgDays / terms) * 30;
        else if (avgDays <= terms * 2) speedScore = 70 - ((avgDays - terms) / terms) * 40;
        else if (avgDays <= terms * 3) speedScore = 30 - ((avgDays - terms * 2) / terms) * 30;
        else speedScore = 0;
        speedScore = Math.max(0, Math.min(100, speedScore));
      }

      let consistencyScore = 50;
      if (paidInvoiceCount > 0) consistencyScore = (paidOnTimeCount / paidInvoiceCount) * 100;

      let utilizationScore = 80;
      if (creditLimit && creditLimit > 0) {
        const totalSales = sales.reduce((sum, sale) => sum + (sale.invoice_total || 0), 0);
        const totalCollected = collections.reduce((sum, collection) => sum + (collection.cr_amount || 0), 0);
        const currentAR = Math.max(0, totalSales - totalCollected);
        const utilization = currentAR / creditLimit;

        if (utilization <= 0.5) utilizationScore = 100;
        else if (utilization <= 0.75) utilizationScore = 80;
        else if (utilization <= 0.9) utilizationScore = 60;
        else if (utilization <= 1.0) utilizationScore = 40;
        else if (utilization <= 1.2) utilizationScore = 20;
        else utilizationScore = 0;
      }

      const oldestSale = sales.reduce((oldest, sale) => (!oldest || new Date(sale.csi_date) < new Date(oldest.csi_date) ? sale : oldest), null);
      let relationshipScore = 50;
      if (oldestSale) {
        const monthsActive = Math.floor((now - new Date(oldestSale.csi_date)) / (1000 * 60 * 60 * 24 * 30));
        if (monthsActive >= 24) relationshipScore = 100;
        else if (monthsActive >= 12) relationshipScore = 80;
        else if (monthsActive >= 6) relationshipScore = 60;
        else if (monthsActive >= 3) relationshipScore = 40;
        else relationshipScore = 20;
      }

      const incidentScore = 80;
      const score = Math.round(
        speedScore * 0.35 +
        consistencyScore * 0.25 +
        utilizationScore * 0.2 +
        relationshipScore * 0.1 +
        incidentScore * 0.1
      );

      return {
        entityType,
        entityId,
        entityName,
        score,
        riskLevel: getRiskLevel(score),
        breakdown: {
          speedScore: Math.round(speedScore),
          consistencyScore: Math.round(consistencyScore),
          utilizationScore: Math.round(utilizationScore),
          relationshipScore,
          incidentScore,
        },
      };
    } catch (err) {
      console.error(`[CreditRisk] Error scoring ${entityType} ${entityName}:`, err.message);
      return null;
    }
  }

  try {
    const hospitals = await Hospital.find({ status: 'ACTIVE' })
      .select('_id hospital_name payment_terms credit_limit credit_limit_action credit_risk_score')
      .lean();

    for (const hospital of hospitals) {
      const result = await scoreEntity({
        entityType: 'hospital',
        entityId: hospital._id,
        entityName: hospital.hospital_name,
        paymentTerms: hospital.payment_terms,
        creditLimit: hospital.credit_limit,
      });
      if (!result) continue;

      results.push(result);

      try {
        const updateFields = {
          credit_risk_score: result.score,
          credit_risk_level: result.riskLevel,
          credit_risk_updated: new Date(),
        };
        if (result.score < 40) updateFields.credit_limit_action = 'BLOCK';
        else if (result.score >= 60 && hospital.credit_limit_action === 'BLOCK') updateFields.credit_limit_action = 'WARN';
        await Hospital.findByIdAndUpdate(hospital._id, { $set: updateFields });
      } catch (err) {
        console.warn(`[CreditRisk] Could not update Hospital ${hospital.hospital_name}:`, err.message);
      }

      if (hospital.credit_risk_score !== undefined) {
        const delta = Math.abs(result.score - hospital.credit_risk_score);
        if (delta > 10) {
          significantChanges.push({
            name: hospital.hospital_name,
            type: 'Hospital',
            oldScore: hospital.credit_risk_score,
            newScore: result.score,
            riskLevel: result.riskLevel,
            delta,
          });
        }
      }
    }
  } catch (err) {
    console.error('[CreditRisk] Hospital scoring failed:', err.message);
  }

  try {
    const customers = await Customer.find({ status: 'ACTIVE' })
      .select('_id customer_name payment_terms credit_limit credit_limit_action credit_risk_score')
      .lean();

    for (const customer of customers) {
      const result = await scoreEntity({
        entityType: 'customer',
        entityId: customer._id,
        entityName: customer.customer_name,
        paymentTerms: customer.payment_terms,
        creditLimit: customer.credit_limit,
      });
      if (!result) continue;

      results.push(result);

      try {
        const updateFields = {
          credit_risk_score: result.score,
          credit_risk_level: result.riskLevel,
          credit_risk_updated: new Date(),
        };
        if (result.score < 40) updateFields.credit_limit_action = 'BLOCK';
        else if (result.score >= 60 && customer.credit_limit_action === 'BLOCK') updateFields.credit_limit_action = 'WARN';
        await Customer.findByIdAndUpdate(customer._id, { $set: updateFields });
      } catch (err) {
        console.warn(`[CreditRisk] Could not update Customer ${customer.customer_name}:`, err.message);
      }

      if (customer.credit_risk_score !== undefined) {
        const delta = Math.abs(result.score - customer.credit_risk_score);
        if (delta > 10) {
          significantChanges.push({
            name: customer.customer_name,
            type: 'Customer',
            oldScore: customer.credit_risk_score,
            newScore: result.score,
            riskLevel: result.riskLevel,
            delta,
          });
        }
      }
    }
  } catch (err) {
    console.error('[CreditRisk] Customer scoring failed:', err.message);
  }

  const notificationResults = [];
  if (results.length > 0) {
    const critical = results.filter((result) => result.score < 40);
    const high = results.filter((result) => result.score >= 40 && result.score < 60);

    let body = `Credit Risk Assessment - ${new Date().toLocaleDateString()}\n\n`;
    body += `Scored: ${results.length} accounts\n`;
    body += `Critical/Very High risk: ${critical.length}\n`;
    body += `High risk: ${high.length}\n\n`;

    if (critical.length > 0) {
      body += '=== CRITICAL / VERY HIGH RISK (auto-blocked) ===\n';
      for (const result of critical) {
        body += `  - ${result.entityName} (${result.entityType}): score ${result.score} - ${result.riskLevel}\n`;
        body += `    Speed: ${result.breakdown.speedScore}, Consistency: ${result.breakdown.consistencyScore}, Utilization: ${result.breakdown.utilizationScore}\n`;
      }
      body += '\n';
    }

    if (high.length > 0) {
      body += '=== HIGH RISK ===\n';
      for (const result of high) {
        body += `  - ${result.entityName} (${result.entityType}): score ${result.score} - ${result.riskLevel}\n`;
      }
      body += '\n';
    }

    if (significantChanges.length > 0) {
      body += '=== SIGNIFICANT SCORE CHANGES (>10 pts) ===\n';
      for (const change of significantChanges) {
        const direction = change.newScore > change.oldScore ? 'IMPROVED' : 'DECLINED';
        body += `  - ${change.name} (${change.type}): ${change.oldScore} -> ${change.newScore} (${direction}, delta: ${change.delta})\n`;
      }
      body += '\n';
    }

    notificationResults.push(
      ...(await notify({
        recipient_id: 'PRESIDENT',
        title: `Credit Risk Report: ${critical.length} critical, ${high.length} high risk`,
        body,
        category: 'system',
        priority: critical.length > 0 ? 'high' : 'important',
        channels: ['in_app', 'email'],
        agent: 'credit_risk',
      }))
    );
  }

  console.log(`[CreditRisk] Complete. Scored ${results.length} accounts, ${significantChanges.length} significant changes.`);

  const riskyCount = results.filter((result) => result.score < 60).length;
  return {
    status: 'success',
    summary: {
      bdms_processed: results.length,
      alerts_generated: riskyCount,
      messages_sent: countSuccessfulChannels(notificationResults, 'in_app'),
      key_findings: results.length
        ? results.slice(0, 5).map((result) => `${result.entityName}: ${result.score} (${result.riskLevel})`)
        : ['No accounts had enough activity for credit-risk scoring.'],
    },
    message_ids: getInAppMessageIds(notificationResults),
  };
}

module.exports = { run };

/**
 * dailyBriefingAgent — Phase G7.9
 *
 * Reuses the President's Copilot infrastructure to compose a morning briefing.
 * Zero new Claude prompt-engineering — the prompt lives in the lookup row
 * AI_COWORK_FEATURES/PRESIDENT_DAILY_BRIEFING.metadata.user_template (admin
 * editable, Mustache placeholders).
 *
 * Flow:
 *   1) For each entity that has both PRESIDENT_COPILOT and PRESIDENT_DAILY_BRIEFING
 *      enabled, find the entity's president user.
 *   2) Render the user_template with {{date}} + {{entity_name}} placeholders.
 *   3) Call copilotService.runChat as that president user. The chat loop will
 *      automatically use COPILOT_TOOLS (LIST_PENDING_APPROVALS, SUMMARIZE_MODULE,
 *      COMPARE_ENTITIES, ...) to gather facts.
 *   4) Post the assistant reply to MessageInbox (category: 'briefing').
 *
 * Spend: counts toward the same AI_SPEND_CAPS as interactive Copilot calls.
 *
 * Entry point matches agentExecutor's contract: exports `run({ ... })` →
 *   { status, summary, message_ids?, error_msg? }
 */
'use strict';

const Lookup = require('../erp/models/Lookup');
const User = require('../models/User');
const MessageInbox = require('../models/MessageInbox');
const { runChat } = require('../erp/services/copilotService');
const { logInfo, logWarn } = require('../utils/logger');

const FEATURE_CODE = 'PRESIDENT_DAILY_BRIEFING';

function renderTemplate(template, vars = {}) {
  if (!template) return '';
  return String(template).replace(/\{\{\s*([\w.]+)\s*\}\}/g, (_, key) => {
    const v = vars[key];
    return v == null ? '' : String(v);
  });
}

async function getEnabledEntities() {
  // We need entity_ids where BOTH PRESIDENT_COPILOT and PRESIDENT_DAILY_BRIEFING are active
  const copilotRows = await Lookup.find({
    category: 'AI_COWORK_FEATURES', code: 'PRESIDENT_COPILOT', is_active: true,
  }).select('entity_id').lean();
  const briefingRows = await Lookup.find({
    category: 'AI_COWORK_FEATURES', code: FEATURE_CODE, is_active: true,
  }).select('entity_id metadata').lean();

  const copilotEntityIds = new Set(copilotRows.map((r) => String(r.entity_id)));
  return briefingRows.filter((r) => copilotEntityIds.has(String(r.entity_id)));
}

async function findPresidentUserForEntity(entityId) {
  // Prefer a user with role=president whose entity_id (or entity_ids) includes this one
  const user = await User.findOne({
    role: { $in: ['president', 'ceo'] },
    $or: [
      { entity_id: entityId },
      { entity_ids: entityId },
    ],
  }).select('_id name full_name role entity_id entity_ids').lean();
  return user || null;
}

async function postBriefingMessage({ entityId, recipient, title, body }) {
  // Phase G9.R2 — entity_id + folder so the briefing surfaces in the
  // recipient's "AI Agents" folder of the unified inbox (Phase G9.A).
  return MessageInbox.create({
    senderName: 'Daily Briefing',
    senderRole: 'system',
    senderUserId: null,
    title,
    body,
    category: 'briefing',
    priority: 'normal',
    recipientRole: recipient.role,
    recipientUserId: recipient._id,
    entity_id: entityId || recipient.entity_id || null,
    folder: 'AI_AGENT_REPORTS',
  });
}

async function runForEntity(briefingRow) {
  const entityId = briefingRow.entity_id;
  const md = briefingRow.metadata || {};
  const president = await findPresidentUserForEntity(entityId);
  if (!president) return { ok: false, reason: 'no_president_user', entityId };

  const Entity = require('../erp/models/Entity');
  const entity = await Entity.findById(entityId).select('name short_name').lean();
  const entityName = entity?.name || entity?.short_name || String(entityId);
  const today = new Date().toISOString().slice(0, 10);

  const userPrompt = renderTemplate(md.user_template || 'Generate the {{date}} morning briefing for {{entity_name}}.', {
    date: today,
    entity_name: entityName,
  });

  const chatUser = {
    _id: president._id,
    name: president.full_name || president.name,
    full_name: president.full_name || president.name,
    role: president.role,
    entity_id: entityId,
    entity_ids: president.entity_ids || [entityId],
  };

  let result;
  try {
    result = await runChat({
      entityId,
      user: chatUser,
      entityIds: chatUser.entity_ids,
      messages: [{ role: 'user', content: userPrompt }],
      mode: 'normal',
    });
  } catch (e) {
    return { ok: false, reason: e.message, entityId };
  }

  const body = result?.reply || '(no reply)';
  const message = await postBriefingMessage({
    entityId,
    recipient: president,
    title: `☀️ Daily Briefing — ${today}`,
    body,
  });

  return { ok: true, entityId, recipient: president._id, messageId: message._id, cost: result?.usage?.cost_usd };
}

async function run() {
  const startTs = Date.now();
  let success = 0, failed = 0;
  const messageIds = [];
  const findings = [];

  let rows;
  try {
    rows = await getEnabledEntities();
  } catch (e) {
    logWarn('daily_briefing_lookup_query_failed', { error: e.message });
    return {
      status: 'error', summary: { entities: 0 }, message_ids: [],
      error_msg: `Lookup query failed: ${e.message}`,
    };
  }

  if (!rows.length) {
    return {
      status: 'success',
      summary: { bdms_processed: 0, alerts_generated: 0, messages_sent: 0, key_findings: ['No entities have PRESIDENT_DAILY_BRIEFING enabled.'] },
    };
  }

  for (const row of rows) {
    const r = await runForEntity(row);
    if (r.ok) {
      success++;
      messageIds.push(r.messageId);
      findings.push(`✓ ${String(r.entityId).slice(-6)} → message ${String(r.messageId).slice(-6)} ($${(r.cost || 0).toFixed(4)})`);
    } else {
      failed++;
      findings.push(`✗ ${String(r.entityId).slice(-6)} → ${r.reason}`);
    }
  }

  logInfo('daily_briefing_run_completed', {
    success, failed, totalMs: Date.now() - startTs,
  });

  return {
    status: failed === 0 ? 'success' : (success > 0 ? 'partial' : 'error'),
    summary: {
      bdms_processed: success + failed,
      alerts_generated: success,
      messages_sent: success,
      key_findings: findings.slice(0, 10),
    },
    message_ids: messageIds,
  };
}

module.exports = { run };

/**
 * Document Expiry Agent (#10)
 */

const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');

async function run() {
  console.log('[DocumentExpiry] Running...');

  const alerts = [];
  const now = new Date();

  try {
    const CsiBooklet = require('../erp/models/CsiBooklet');

    const lowBooklets = await CsiBooklet.find({
      status: 'ACTIVE',
      remaining_count: { $lt: 20, $gt: 0 },
    }).lean();

    for (const booklet of lowBooklets) {
      alerts.push({
        type: 'CSI_BOOKLET_LOW',
        severity: 'warning',
        detail: `CSI Booklet "${booklet.booklet_code}" almost full - ${booklet.remaining_count} numbers remaining (series ${booklet.series_start}-${booklet.series_end})`,
      });
    }

    const exhaustedBooklets = await CsiBooklet.find({
      status: 'ACTIVE',
      remaining_count: { $lte: 0 },
    }).lean();

    for (const booklet of exhaustedBooklets) {
      alerts.push({
        type: 'CSI_BOOKLET_EXHAUSTED',
        severity: 'critical',
        detail: `CSI Booklet "${booklet.booklet_code}" is exhausted - 0 numbers remaining. Needs replacement.`,
      });
    }
  } catch (err) {
    if (err.code !== 'MODULE_NOT_FOUND') {
      console.error('[DocumentExpiry] CSI Booklet check failed:', err.message);
    }
  }

  try {
    const InventoryLedger = require('../erp/models/InventoryLedger');
    const ninetyDaysFromNow = new Date(now);
    ninetyDaysFromNow.setDate(ninetyDaysFromNow.getDate() + 90);

    const expiringBatches = await InventoryLedger.aggregate([
      { $match: { expiry_date: { $lte: ninetyDaysFromNow, $gte: now } } },
      {
        $group: {
          _id: { product_id: '$product_id', batch_lot_no: '$batch_lot_no' },
          total_in: { $sum: '$qty_in' },
          total_out: { $sum: '$qty_out' },
          expiry_date: { $first: '$expiry_date' },
          bdm_ids: { $addToSet: '$bdm_id' },
        },
      },
      { $addFields: { current_stock: { $subtract: ['$total_in', '$total_out'] } } },
      { $match: { current_stock: { $gt: 0 } } },
      {
        $lookup: {
          from: 'erp_product_master',
          localField: '_id.product_id',
          foreignField: '_id',
          as: 'product',
        },
      },
      { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } },
      { $sort: { expiry_date: 1 } },
      { $limit: 100 },
    ]);

    for (const batch of expiringBatches) {
      const productName = batch.product ? `${batch.product.brand_name} ${batch.product.dosage_strength || ''}`.trim() : String(batch._id.product_id);
      const daysToExpiry = Math.floor((new Date(batch.expiry_date) - now) / (1000 * 60 * 60 * 24));

      alerts.push({
        type: 'PRODUCT_EXPIRY',
        severity: daysToExpiry <= 30 ? 'critical' : 'warning',
        detail: `${productName} batch ${batch._id.batch_lot_no} - expires in ${daysToExpiry} days (${new Date(batch.expiry_date).toLocaleDateString()}), stock: ${batch.current_stock} units`,
        bdm_ids: batch.bdm_ids,
      });
    }

    const expiredWithStock = await InventoryLedger.aggregate([
      { $match: { expiry_date: { $lt: now } } },
      {
        $group: {
          _id: { product_id: '$product_id', batch_lot_no: '$batch_lot_no' },
          total_in: { $sum: '$qty_in' },
          total_out: { $sum: '$qty_out' },
          expiry_date: { $first: '$expiry_date' },
          bdm_ids: { $addToSet: '$bdm_id' },
        },
      },
      { $addFields: { current_stock: { $subtract: ['$total_in', '$total_out'] } } },
      { $match: { current_stock: { $gt: 0 } } },
      {
        $lookup: {
          from: 'erp_product_master',
          localField: '_id.product_id',
          foreignField: '_id',
          as: 'product',
        },
      },
      { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } },
      { $limit: 50 },
    ]);

    for (const batch of expiredWithStock) {
      const productName = batch.product ? `${batch.product.brand_name} ${batch.product.dosage_strength || ''}`.trim() : String(batch._id.product_id);
      const daysExpired = Math.floor((now - new Date(batch.expiry_date)) / (1000 * 60 * 60 * 24));

      alerts.push({
        type: 'PRODUCT_EXPIRED',
        severity: 'critical',
        detail: `EXPIRED: ${productName} batch ${batch._id.batch_lot_no} - expired ${daysExpired} days ago, ${batch.current_stock} units still in stock. Requires disposal/return.`,
        bdm_ids: batch.bdm_ids,
      });
    }
  } catch (err) {
    console.error('[DocumentExpiry] Product expiry check failed:', err.message);
  }

  try {
    const ConsignmentTracker = require('../erp/models/ConsignmentTracker');
    const sixtyDaysFromNow = new Date(now);
    sixtyDaysFromNow.setDate(sixtyDaysFromNow.getDate() + 60);

    const activeConsignments = await ConsignmentTracker.find({
      status: 'ACTIVE',
      batch_lot_no: { $exists: true, $ne: null },
    }).select('product_id batch_lot_no hospital_name dr_ref qty_remaining bdm_id').lean();

    if (activeConsignments.length > 0) {
      const orConditions = activeConsignments.slice(0, 100).map((consignment) => ({
        product_id: consignment.product_id,
        batch_lot_no: consignment.batch_lot_no,
      }));

      if (orConditions.length > 0) {
        const InventoryLedger = require('../erp/models/InventoryLedger');
        const batchExpiries = await InventoryLedger.aggregate([
          { $match: { $or: orConditions } },
          {
            $group: {
              _id: { product_id: '$product_id', batch_lot_no: '$batch_lot_no' },
              expiry_date: { $first: '$expiry_date' },
            },
          },
          { $match: { expiry_date: { $lte: sixtyDaysFromNow, $gte: now } } },
        ]);

        const expiryMap = new Map();
        for (const batch of batchExpiries) {
          expiryMap.set(`${batch._id.product_id}_${batch._id.batch_lot_no}`, batch.expiry_date);
        }

        for (const consignment of activeConsignments) {
          const expiryDate = expiryMap.get(`${consignment.product_id}_${consignment.batch_lot_no}`);
          if (!expiryDate || consignment.qty_remaining <= 0) continue;
          const daysToExpiry = Math.floor((new Date(expiryDate) - now) / (1000 * 60 * 60 * 24));
          alerts.push({
            type: 'CONSIGNMENT_EXPIRY',
            severity: daysToExpiry <= 30 ? 'critical' : 'warning',
            detail: `Consignment at ${consignment.hospital_name || 'Unknown'} (DR# ${consignment.dr_ref}): batch ${consignment.batch_lot_no} expires in ${daysToExpiry} days, ${consignment.qty_remaining} units remaining`,
            bdm_ids: consignment.bdm_id ? [consignment.bdm_id] : [],
          });
        }
      }
    }
  } catch (err) {
    console.error('[DocumentExpiry] Consignment expiry check failed:', err.message);
  }

  const notificationResults = [];
  if (alerts.length > 0) {
    const critical = alerts.filter((alert) => alert.severity === 'critical');
    const warnings = alerts.filter((alert) => alert.severity === 'warning');

    let body = `Document & Expiry Report - ${now.toLocaleDateString()}\n\n`;
    body += `Total alerts: ${alerts.length} (${critical.length} critical, ${warnings.length} warnings)\n\n`;

    const grouped = {};
    for (const alert of alerts) {
      if (!grouped[alert.type]) grouped[alert.type] = [];
      grouped[alert.type].push(alert);
    }

    for (const [type, items] of Object.entries(grouped)) {
      body += `=== ${type} (${items.length}) ===\n`;
      for (const item of items) {
        body += `  [${item.severity.toUpperCase()}] ${item.detail}\n`;
      }
      body += '\n';
    }

    notificationResults.push(
      ...(await notify({
        recipient_id: 'PRESIDENT',
        title: `Expiry Alerts: ${critical.length} critical, ${alerts.length} total`,
        body,
        category: 'system',
        priority: critical.length > 0 ? 'high' : 'important',
        channels: ['in_app', 'email'],
        agent: 'document_expiry',
      }))
    );

    const bdmAlerts = {};
    for (const alert of alerts) {
      for (const bdmId of alert.bdm_ids || []) {
        const key = String(bdmId);
        if (!bdmAlerts[key]) bdmAlerts[key] = [];
        bdmAlerts[key].push(alert.detail);
      }
    }

    for (const [bdmId, details] of Object.entries(bdmAlerts)) {
      notificationResults.push(
        ...(await notify({
          recipient_id: bdmId,
          title: `Product Expiry Alert: ${details.length} item(s)`,
          body: `The following products in your inventory are approaching or past expiry:\n\n${details.map((detail) => `- ${detail}`).join('\n')}`,
          category: 'system',
          priority: 'important',
          channels: ['in_app'],
          agent: 'document_expiry',
        }))
      );
    }
  }

  console.log(`[DocumentExpiry] Complete. Found ${alerts.length} alerts.`);

  const uniqueBdmIds = new Set(
    alerts.flatMap((alert) => (alert.bdm_ids || []).map((bdmId) => String(bdmId)))
  );

  return {
    status: 'success',
    summary: {
      bdms_processed: uniqueBdmIds.size,
      alerts_generated: alerts.length,
      messages_sent: countSuccessfulChannels(notificationResults, 'in_app'),
      key_findings: alerts.length ? alerts.slice(0, 5).map((alert) => alert.detail) : ['No document or expiry alerts detected.'],
    },
    message_ids: getInAppMessageIds(notificationResults),
  };
}

module.exports = { run };

/**
 * Expansion Readiness Agent (P2-8) — Phase G8
 * Schedule: 1st of month 10:00 AM Asia/Manila (monthly).
 *
 * Rule-based entity performance ranking + BDM graduation flags.
 *   - Per-entity: sales / collections / active-BDM count (60-day window)
 *   - BDMs exceeding threshold for 3 consecutive months → flagged for graduation
 *     (threshold + window come from EXPANSION_READINESS_CONFIG lookup)
 */
'use strict';

const mongoose = require('mongoose');
const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');

function peso(n) { return `₱${(Number(n) || 0).toLocaleString('en-PH', { maximumFractionDigits: 0 })}`; }
function tryModel(name) { try { return mongoose.model(name); } catch { return null; } }

async function loadConfig() {
  try {
    const Lookup = require('../erp/models/Lookup');
    const row = await Lookup.findOne({ category: 'EXPANSION_READINESS_CONFIG', code: 'DEFAULT', is_active: { $ne: false } }).lean();
    const m = row?.metadata || {};
    return {
      bdm_graduation_monthly_sales_min: Number(m.bdm_graduation_monthly_sales_min) || 500000,
      bdm_graduation_months_required: Number(m.bdm_graduation_months_required) || 3,
    };
  } catch {
    return { bdm_graduation_monthly_sales_min: 500000, bdm_graduation_months_required: 3 };
  }
}

async function entityRanking() {
  const SalesLine = tryModel('SalesLine');
  if (!SalesLine) return [];
  const since = new Date(Date.now() - 60 * 24 * 3600 * 1000);
  return SalesLine.aggregate([
    { $match: { csi_date: { $gte: since }, status: 'POSTED' } },
    { $group: { _id: '$entity_id', total: { $sum: { $ifNull: ['$invoice_total', 0] } }, count: { $sum: 1 } } },
    { $sort: { total: -1 } },
    { $limit: 10 },
  ]);
}

async function bdmGraduationFlags(cfg) {
  const SalesLine = tryModel('SalesLine');
  if (!SalesLine) return [];
  const months = cfg.bdm_graduation_months_required;
  const since = new Date();
  since.setMonth(since.getMonth() - months);
  since.setDate(1);
  since.setHours(0, 0, 0, 0);

  const agg = await SalesLine.aggregate([
    { $match: { csi_date: { $gte: since }, status: 'POSTED', bdm_id: { $ne: null } } },
    {
      $group: {
        _id: {
          bdm: '$bdm_id',
          ym: { $dateToString: { format: '%Y-%m', date: '$csi_date' } },
        },
        total: { $sum: { $ifNull: ['$invoice_total', 0] } },
      },
    },
    {
      $group: {
        _id: '$_id.bdm',
        months_over: {
          $sum: { $cond: [{ $gte: ['$total', cfg.bdm_graduation_monthly_sales_min] }, 1, 0] },
        },
        months_tracked: { $sum: 1 },
        trailing_total: { $sum: '$total' },
      },
    },
    { $match: { months_over: { $gte: months } } },
    { $sort: { trailing_total: -1 } },
    { $limit: 10 },
  ]);
  return agg;
}

async function run() {
  try {
    const cfg = await loadConfig();
    const [entities, graduates] = await Promise.all([entityRanking(), bdmGraduationFlags(cfg)]);

    const lines = [];
    lines.push('Entity performance (60-day POSTED sales):');
    entities.slice(0, 5).forEach((e, i) => lines.push(`  ${i + 1}. entity ${String(e._id)} — ${peso(e.total)} · ${e.count} CSI(s)`));

    lines.push('');
    lines.push(`BDM graduation flags (≥₱${cfg.bdm_graduation_monthly_sales_min.toLocaleString('en-PH')}/mo for ${cfg.bdm_graduation_months_required} months):`);
    if (graduates.length === 0) lines.push('  — None this cycle.');
    graduates.slice(0, 5).forEach(g => lines.push(`  bdm ${String(g._id)} — ${peso(g.trailing_total)} trailing, ${g.months_over}/${g.months_tracked} months over threshold`));

    const body = lines.join('\n');
    const results = await notify({
      recipient_id: 'PRESIDENT',
      title: `Expansion Readiness — ${graduates.length} BDM graduation flag(s)`,
      body,
      category: 'briefing',
      priority: graduates.length > 0 ? 'important' : 'normal',
      channels: ['in_app', 'email'],
      agent: 'expansion_readiness',
    });

    return {
      status: 'success',
      summary: { alerts_generated: graduates.length, messages_sent: countSuccessfulChannels(results, 'in_app'), key_findings: lines.slice(0, 8) },
      message_ids: getInAppMessageIds(results),
    };
  } catch (err) {
    console.error('[Expansion] Run failed:', err.message);
    return { status: 'error', summary: {}, message_ids: [], error_msg: err.message };
  }
}

module.exports = { run };

/**
 * Expense Anomaly Agent (#3)
 * Runs daily at 6 AM
 *
 * Detects:
 * 1. Duplicate OR numbers across expense entries
 * 2. Over-budget BDMs (current cycle > 130% of 3-month average)
 * 3. Large single expenses > P5,000 without president override
 * 4. ORE lines with non-cash payment (ORE should be cash-only)
 */

const { notify } = require('./notificationService');
const { ROLES } = require('../constants/roles');

async function run() {
  console.log('[ExpenseAnomaly] Running...');
  try {
    const ExpenseEntry = require('../erp/models/ExpenseEntry');
    const User = require('../models/User');

    const anomalies = [];

    // ─── 1. Duplicate OR numbers ───────────────────────────────────
    try {
      const dupes = await ExpenseEntry.aggregate([
        { $unwind: '$lines' },
        { $match: { 'lines.or_number': { $exists: true, $ne: null, $ne: '' } } },
        {
          $group: {
            _id: '$lines.or_number',
            count: { $sum: 1 },
            entry_ids: { $addToSet: '$_id' },
            bdm_ids: { $addToSet: '$bdm_id' }
          }
        },
        { $match: { count: { $gt: 1 } } },
        { $limit: 50 }
      ]);

      for (const d of dupes) {
        anomalies.push({
          type: 'DUPLICATE_OR',
          detail: `OR# ${d._id} appears in ${d.count} expense lines across ${d.entry_ids.length} entries`,
          or_number: d._id,
          entry_ids: d.entry_ids
        });
      }
    } catch (err) {
      console.error('[ExpenseAnomaly] Duplicate OR check failed:', err.message);
    }

    // ─── 2. Over-budget BDMs (current cycle vs 3-month avg) ───────
    try {
      const now = new Date();
      const currentPeriod = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;

      // Determine current cycle: C1 if day <= 15, C2 otherwise
      const currentCycle = now.getDate() <= 15 ? 'C1' : 'C2';

      // Get all active BDMs
      const bdms = await User.find({ role: ROLES.CONTRACTOR, isActive: true }).select('_id name').lean();

      // Build 3-month lookback periods
      const lookbackPeriods = [];
      for (let i = 1; i <= 3; i++) {
        const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
        lookbackPeriods.push(`${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`);
      }

      for (const bdm of bdms) {
        try {
          // Current cycle total
          const currentResult = await ExpenseEntry.aggregate([
            { $match: { bdm_id: bdm._id, period: currentPeriod, cycle: currentCycle } },
            { $group: { _id: null, total: { $sum: '$total_amount' } } }
          ]);
          const currentTotal = currentResult[0]?.total || 0;
          if (currentTotal === 0) continue;

          // 3-month average (same cycle)
          const avgResult = await ExpenseEntry.aggregate([
            { $match: { bdm_id: bdm._id, period: { $in: lookbackPeriods }, cycle: currentCycle } },
            { $group: { _id: null, total: { $sum: '$total_amount' }, count: { $sum: 1 } } }
          ]);
          const avgTotal = avgResult[0]?.total || 0;
          const avgCount = avgResult[0]?.count || 0;
          if (avgCount === 0) continue;

          const monthlyAvg = avgTotal / Math.min(avgCount, 3);
          const ratio = currentTotal / monthlyAvg;

          if (ratio > 1.3) {
            anomalies.push({
              type: 'OVER_BUDGET',
              detail: `${bdm.name} current ${currentCycle} expenses: P${currentTotal.toFixed(2)} (${(ratio * 100).toFixed(0)}% of 3-month avg P${monthlyAvg.toFixed(2)})`,
              bdm_name: bdm.name,
              current: currentTotal,
              average: monthlyAvg,
              ratio
            });
          }
        } catch (err) {
          // Skip individual BDM errors
        }
      }
    } catch (err) {
      console.error('[ExpenseAnomaly] Over-budget check failed:', err.message);
    }

    // ─── 3. Large single expenses > P5,000 without president override ──
    try {
      const largeExpenses = await ExpenseEntry.aggregate([
        { $match: { recorded_on_behalf_of: { $exists: false } } },
        { $unwind: '$lines' },
        { $match: { 'lines.amount': { $gt: 5000 } } },
        {
          $lookup: {
            from: 'users',
            localField: 'bdm_id',
            foreignField: '_id',
            as: 'bdm'
          }
        },
        { $unwind: { path: '$bdm', preserveNullAndEmptyArrays: true } },
        {
          $project: {
            bdm_name: '$bdm.name',
            amount: '$lines.amount',
            category: '$lines.expense_category',
            establishment: '$lines.establishment',
            expense_date: '$lines.expense_date',
            period: 1
          }
        },
        { $sort: { 'lines.amount': -1 } },
        { $limit: 20 }
      ]);

      for (const exp of largeExpenses) {
        anomalies.push({
          type: 'LARGE_EXPENSE',
          detail: `${exp.bdm_name || 'Unknown BDM'}: P${exp.amount.toFixed(2)} at ${exp.establishment || 'N/A'} (${exp.category || 'uncategorized'}) on ${exp.expense_date ? new Date(exp.expense_date).toLocaleDateString() : 'N/A'}`,
          amount: exp.amount
        });
      }
    } catch (err) {
      console.error('[ExpenseAnomaly] Large expense check failed:', err.message);
    }

    // ─── 4. ORE with non-cash payment ─────────────────────────────
    try {
      const oreCashViolations = await ExpenseEntry.aggregate([
        { $unwind: '$lines' },
        {
          $match: {
            'lines.expense_type': 'ORE',
            'lines.payment_mode': { $exists: true, $ne: 'CASH' }
          }
        },
        {
          $lookup: {
            from: 'users',
            localField: 'bdm_id',
            foreignField: '_id',
            as: 'bdm'
          }
        },
        { $unwind: { path: '$bdm', preserveNullAndEmptyArrays: true } },
        {
          $project: {
            bdm_name: '$bdm.name',
            payment_mode: '$lines.payment_mode',
            amount: '$lines.amount',
            or_number: '$lines.or_number',
            expense_date: '$lines.expense_date'
          }
        },
        { $limit: 30 }
      ]);

      for (const v of oreCashViolations) {
        anomalies.push({
          type: 'ORE_NON_CASH',
          detail: `${v.bdm_name || 'Unknown BDM'}: ORE paid via ${v.payment_mode} (P${(v.amount || 0).toFixed(2)}, OR# ${v.or_number || 'N/A'}). ORE must be CASH only.`,
          payment_mode: v.payment_mode
        });
      }
    } catch (err) {
      console.error('[ExpenseAnomaly] ORE cash check failed:', err.message);
    }

    // ─── Send summary to PRESIDENT ─────────────────────────────────
    if (anomalies.length > 0) {
      const grouped = {};
      for (const a of anomalies) {
        if (!grouped[a.type]) grouped[a.type] = [];
        grouped[a.type].push(a.detail);
      }

      let body = `Expense Anomaly Report — ${new Date().toLocaleDateString()}\n\n`;
      body += `Total anomalies found: ${anomalies.length}\n\n`;

      for (const [type, details] of Object.entries(grouped)) {
        body += `=== ${type} (${details.length}) ===\n`;
        for (const d of details) {
          body += `  - ${d}\n`;
        }
        body += '\n';
      }

      await notify({
        recipient_id: 'PRESIDENT',
        title: `Expense Anomalies Detected (${anomalies.length})`,
        body,
        category: 'system',
        priority: 'important',
        channels: ['in_app', 'email'],
        agent: 'expense_anomaly'
      });
    }

    console.log(`[ExpenseAnomaly] Complete. Found ${anomalies.length} anomalies.`);
  } catch (err) {
    console.error('[ExpenseAnomaly] Error:', err.message);
  }
}

module.exports = { run };

/**
 * FP&A Rolling Forecast Agent (P2-2) — Phase G8
 * Schedule: Monday 6:00 AM Asia/Manila (weekly).
 *
 * Rule-based: compares MTD and QTD sales / collections against quarter pace,
 * highlights top variance drivers by BDM or entity, and flags if the trailing
 * run-rate projects to miss quarter target.
 *
 * AI toggle (FPA_FORECAST_AI_MODE): appends a Claude-generated scenario
 * projection when mode === 'ai' and budget allows.
 */
'use strict';

const mongoose = require('mongoose');
const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');

function peso(n) { return `₱${(Number(n) || 0).toLocaleString('en-PH', { maximumFractionDigits: 0 })}`; }
function pct(n) { return `${((Number(n) || 0) * 100).toFixed(1)}%`; }
function tryModel(name) { try { return mongoose.model(name); } catch { return null; } }

async function getAiMode() {
  try {
    const Lookup = require('../erp/models/Lookup');
    const row = await Lookup.findOne({ category: 'FPA_FORECAST_AI_MODE', code: 'DEFAULT', is_active: { $ne: false } }).lean();
    return row?.metadata?.value === 'ai' ? 'ai' : 'rule';
  } catch { return 'rule'; }
}

function quarterRange(now = new Date()) {
  const q = Math.floor(now.getMonth() / 3);
  const start = new Date(now.getFullYear(), q * 3, 1);
  const end = new Date(now.getFullYear(), q * 3 + 3, 1);
  const daysElapsed = Math.max(1, Math.round((now - start) / (24 * 3600 * 1000)));
  const totalDays = Math.round((end - start) / (24 * 3600 * 1000));
  return { start, end, now, daysElapsed, totalDays, pct: daysElapsed / totalDays };
}

async function sumQtd(Model, dateField, amountField, qr) {
  if (!Model) return 0;
  const agg = await Model.aggregate([
    { $match: { [dateField]: { $gte: qr.start, $lt: qr.end } } },
    { $group: { _id: null, total: { $sum: { $ifNull: [`$${amountField}`, 0] } } } },
  ]);
  return agg[0]?.total || 0;
}

async function run() {
  try {
    const qr = quarterRange();
    const SalesLine = tryModel('SalesLine');
    const Collection = tryModel('Collection');
    const [salesQtd, collQtd] = await Promise.all([
      sumQtd(SalesLine, 'csi_date', 'invoice_total', qr),
      sumQtd(Collection, 'cr_date', 'cr_amount', qr),
    ]);

    // Simple run-rate projection — scale QTD linearly to end of quarter.
    const projectedSales = qr.pct > 0 ? Math.round(salesQtd / qr.pct) : 0;
    const projectedColl = qr.pct > 0 ? Math.round(collQtd / qr.pct) : 0;
    const collectionRatio = salesQtd > 0 ? collQtd / salesQtd : 0;

    const lines = [
      `Quarter pacing: day ${qr.daysElapsed} of ${qr.totalDays} (${pct(qr.pct)}).`,
      `Sales QTD: ${peso(salesQtd)} → projected quarter-end: ${peso(projectedSales)}.`,
      `Collections QTD: ${peso(collQtd)} → projected quarter-end: ${peso(projectedColl)}.`,
      `Collection-to-sales ratio QTD: ${pct(collectionRatio)}.`,
    ];
    if (collectionRatio < 0.7 && salesQtd > 0) {
      lines.push('⚠ Collection discipline below 70% QTD — review aging buckets.');
    }

    let body = lines.join('\n');

    const aiMode = await getAiMode();
    if (aiMode === 'ai' && process.env.ANTHROPIC_API_KEY) {
      try {
        const { enforceSpendCap } = require('../erp/services/spendCapService');
        await enforceSpendCap(null, 'FPA_FORECAST_AGENT');
        const { askClaude } = require('./claudeClient');
        const r = await askClaude({
          system: 'You are an FP&A analyst. Read the quarter pacing + run-rate and write 2-3 sentences flagging variance drivers and one scenario adjustment. No boilerplate.',
          prompt: `FP&A pacing:\n${body}`,
          maxTokens: 250,
          agent: 'fpa_forecast',
        });
        if (r?.text) body += `\n\n— Scenario Commentary —\n${r.text.trim()}`;
      } catch (e) {
        if (e?.reason !== 'SPEND_CAP_EXCEEDED') console.warn('[FPA] AI append failed:', e.message);
      }
    }

    const results = await notify({
      recipient_id: 'PRESIDENT',
      title: 'FP&A Rolling Forecast — Weekly',
      body,
      category: 'briefing',
      priority: 'normal',
      channels: ['in_app', 'email'],
      agent: 'fpa_forecast',
    });

    return {
      status: 'success',
      summary: { alerts_generated: 1, messages_sent: countSuccessfulChannels(results, 'in_app'), key_findings: lines.slice(0, 4) },
      message_ids: getInAppMessageIds(results),
    };
  } catch (err) {
    console.error('[FPA] Run failed:', err.message);
    return { status: 'error', summary: {}, message_ids: [], error_msg: err.message };
  }
}

module.exports = { run };

/**
 * Inventory Reorder Agent (#6)
 */

const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');

async function run() {
  console.log('[InventoryReorder] Running...');

  const InventoryLedger = require('../erp/models/InventoryLedger');
  const ConsignmentTracker = require('../erp/models/ConsignmentTracker');

  const REORDER_LEVEL = 20;
  const alerts = [];

  try {
    const stockLevels = await InventoryLedger.aggregate([
      {
        $group: {
          _id: { product_id: '$product_id', warehouse_id: '$warehouse_id' },
          total_in: { $sum: '$qty_in' },
          total_out: { $sum: '$qty_out' },
          bdm_id: { $first: '$bdm_id' },
        },
      },
      {
        $addFields: {
          current_stock: { $subtract: ['$total_in', '$total_out'] },
        },
      },
      { $match: { current_stock: { $lte: REORDER_LEVEL } } },
      {
        $lookup: {
          from: 'erp_product_master',
          localField: '_id.product_id',
          foreignField: '_id',
          as: 'product',
        },
      },
      { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } },
      {
        $lookup: {
          from: 'erp_warehouses',
          localField: '_id.warehouse_id',
          foreignField: '_id',
          as: 'warehouse',
        },
      },
      { $unwind: { path: '$warehouse', preserveNullAndEmptyArrays: true } },
      { $sort: { current_stock: 1 } },
      { $limit: 100 },
    ]);

    for (const item of stockLevels) {
      const productName = item.product ? `${item.product.brand_name} ${item.product.dosage_strength || ''}`.trim() : String(item._id.product_id);
      const warehouseName = item.warehouse?.warehouse_name || 'Unknown warehouse';
      const stock = item.current_stock;

      if (stock <= 0) {
        alerts.push({
          type: 'STOCKOUT',
          severity: 'critical',
          detail: `STOCKOUT: ${productName} at ${warehouseName} - stock: ${stock}`,
          bdm_id: item.bdm_id,
        });
      } else {
        alerts.push({
          type: 'LOW_STOCK',
          severity: 'warning',
          detail: `LOW STOCK: ${productName} at ${warehouseName} - stock: ${stock} (reorder at ${REORDER_LEVEL})`,
          bdm_id: item.bdm_id,
        });
      }
    }
  } catch (err) {
    console.error('[InventoryReorder] Stock level check failed:', err.message);
  }

  try {
    const sixtyDaysAgo = new Date();
    sixtyDaysAgo.setDate(sixtyDaysAgo.getDate() - 60);

    const slowConsignments = await ConsignmentTracker.aggregate([
      {
        $match: {
          status: 'ACTIVE',
          created_at: { $lt: sixtyDaysAgo },
        },
      },
      {
        $addFields: {
          conversion_ratio: {
            $cond: [{ $gt: ['$qty_delivered', 0] }, { $divide: ['$qty_consumed', '$qty_delivered'] }, 0],
          },
        },
      },
      { $match: { conversion_ratio: { $lt: 0.5 } } },
      {
        $lookup: {
          from: 'erp_product_master',
          localField: 'product_id',
          foreignField: '_id',
          as: 'product',
        },
      },
      { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } },
      { $sort: { created_at: 1 } },
      { $limit: 50 },
    ]);

    for (const consignment of slowConsignments) {
      const productName = consignment.product ? `${consignment.product.brand_name} ${consignment.product.dosage_strength || ''}`.trim() : String(consignment.product_id);
      const daysOpen = Math.floor((Date.now() - new Date(consignment.created_at).getTime()) / (1000 * 60 * 60 * 24));
      const pct = ((consignment.qty_consumed / consignment.qty_delivered) * 100).toFixed(0);

      alerts.push({
        type: 'SLOW_CONVERSION',
        severity: 'warning',
        detail: `SLOW CONVERSION: ${productName} at ${consignment.hospital_name || 'Unknown hospital'} - DR# ${consignment.dr_ref}, ${daysOpen} days open, ${pct}% consumed (${consignment.qty_consumed}/${consignment.qty_delivered})`,
        bdm_id: consignment.bdm_id,
      });
    }
  } catch (err) {
    console.error('[InventoryReorder] Slow conversion check failed:', err.message);
  }

  try {
    const OfficeSupply = require('../erp/models/OfficeSupply');
    const lowSupplies = await OfficeSupply.find({
      is_active: true,
      $expr: { $lte: ['$qty_on_hand', '$reorder_level'] },
    }).lean();

    for (const supply of lowSupplies) {
      alerts.push({
        type: 'OFFICE_SUPPLY_REORDER',
        severity: 'info',
        detail: `OFFICE SUPPLY: ${supply.item_name} (${supply.item_code || 'no code'}) - on hand: ${supply.qty_on_hand}, reorder level: ${supply.reorder_level}`,
      });
    }
  } catch (err) {
    console.error('[InventoryReorder] Office supply check failed:', err.message);
  }

  const notificationResults = [];
  if (alerts.length > 0) {
    const critical = alerts.filter((alert) => alert.severity === 'critical');
    const warnings = alerts.filter((alert) => alert.severity === 'warning');
    const info = alerts.filter((alert) => alert.severity === 'info');

    let body = `Inventory Reorder Report - ${new Date().toLocaleDateString()}\n\n`;
    body += `Total alerts: ${alerts.length} (${critical.length} critical, ${warnings.length} warnings, ${info.length} info)\n\n`;

    if (critical.length > 0) {
      body += '=== CRITICAL - STOCKOUTS ===\n';
      for (const alert of critical) body += `  - ${alert.detail}\n`;
      body += '\n';
    }
    if (warnings.length > 0) {
      body += '=== WARNINGS ===\n';
      for (const alert of warnings) body += `  - ${alert.detail}\n`;
      body += '\n';
    }
    if (info.length > 0) {
      body += '=== INFO - OFFICE SUPPLIES ===\n';
      for (const alert of info) body += `  - ${alert.detail}\n`;
      body += '\n';
    }

    notificationResults.push(
      ...(await notify({
        recipient_id: 'PRESIDENT',
        title: `Inventory Alerts (${critical.length} critical, ${alerts.length} total)`,
        body,
        category: 'system',
        priority: critical.length > 0 ? 'high' : 'important',
        channels: ['in_app', 'email'],
        agent: 'inventory_reorder',
      }))
    );

    const bdmAlerts = {};
    for (const alert of alerts) {
      if (!alert.bdm_id) continue;
      const key = String(alert.bdm_id);
      if (!bdmAlerts[key]) bdmAlerts[key] = [];
      bdmAlerts[key].push(alert.detail);
    }

    for (const [bdmId, details] of Object.entries(bdmAlerts)) {
      notificationResults.push(
        ...(await notify({
          recipient_id: bdmId,
          title: `Inventory Alert: ${details.length} item(s) need attention`,
          body: `Inventory alerts for your warehouse:\n\n${details.map((detail) => `- ${detail}`).join('\n')}`,
          category: 'system',
          priority: 'important',
          channels: ['in_app'],
          agent: 'inventory_reorder',
        }))
      );
    }
  }

  console.log(`[InventoryReorder] Complete. Found ${alerts.length} alerts.`);

  const uniqueBdmIds = new Set(alerts.map((alert) => alert.bdm_id?.toString()).filter(Boolean));
  return {
    status: 'success',
    summary: {
      bdms_processed: uniqueBdmIds.size,
      alerts_generated: alerts.length,
      messages_sent: countSuccessfulChannels(notificationResults, 'in_app'),
      key_findings: alerts.length ? alerts.slice(0, 5).map((alert) => alert.detail) : ['No inventory reorder alerts detected.'],
    },
    message_ids: getInAppMessageIds(notificationResults),
  };
}

module.exports = { run };

/**
 * KPI Variance Agent (#V) — Phase SG-Q2 Week 3
 *
 * Reads the latest YTD KpiSnapshot for every active BDM and surfaces KPIs
 * that deviate from target by more than the per-KPI threshold. Sends a
 * variance email to the BDM, their reports_to chain, and president.
 *
 * Type: FREE (rule-based — no AI cost).
 * Schedule: Monthly day 2 at 6:00 AM Manila — fires the day AFTER kpiSnapshotAgent
 *   so it reads the freshly-computed snapshots. Manual Run Now via Agent Console.
 *
 * Lookup-driven thresholds (`KPI_VARIANCE_THRESHOLDS` category, per-entity):
 *   metadata.warning_pct   — deviation % that triggers a 'warning' alert
 *   metadata.critical_pct  — deviation % that triggers a 'critical' alert
 *   code = KPI_CODE the threshold applies to (e.g. 'PCT_HOSP_ACCREDITED')
 *   When no row exists for a given KPI, falls back to GLOBAL defaults:
 *     warning at 20% deviation, critical at 40%.
 *
 * Subscriber posture: zero hardcoded thresholds. Admins re-tune per entity
 * via Control Center → Lookup Tables → KPI_VARIANCE_THRESHOLDS without a
 * code deploy. New KPIs added to the plan inherit the GLOBAL defaults until
 * an entity-specific row is added.
 */

const Entity = require('../erp/models/Entity');
const SalesGoalPlan = require('../erp/models/SalesGoalPlan');
const KpiSnapshot = require('../erp/models/KpiSnapshot');
const SalesGoalTarget = require('../erp/models/SalesGoalTarget');
const PeopleMaster = require('../erp/models/PeopleMaster');
const Lookup = require('../erp/models/Lookup');
const VarianceAlert = require('../erp/models/VarianceAlert');
const { notifyKpiVariance } = require('../erp/services/erpNotificationService');

const DEFAULT_WARNING_PCT = 20;
const DEFAULT_CRITICAL_PCT = 40;

// SG-5 #27 — Cooldown window for re-firing the same (plan, bdm, kpi, severity)
// breach. Lookup-driven via VARIANCE_ALERT_COOLDOWN_DAYS; this is the last-
// resort fallback used only if the Lookup read fails or is missing.
const DEFAULT_COOLDOWN_DAYS = 7;

/**
 * Read VARIANCE_ALERT_COOLDOWN_DAYS for the entity. A single GLOBAL row is the
 * typical shape, but admins can add per-severity rows (code = 'WARNING' or
 * 'CRITICAL') to differentiate cooldowns.
 */
async function loadCooldown(entityId) {
  try {
    const rows = await Lookup.find({
      entity_id: entityId,
      category: 'VARIANCE_ALERT_COOLDOWN_DAYS',
      is_active: true,
    }).lean();
    if (!rows.length) return { global: DEFAULT_COOLDOWN_DAYS, warning: null, critical: null };
    const out = { global: DEFAULT_COOLDOWN_DAYS, warning: null, critical: null };
    for (const r of rows) {
      const d = Number(r.metadata?.days ?? r.metadata?.value);
      const days = Number.isFinite(d) && d >= 0 ? d : DEFAULT_COOLDOWN_DAYS;
      const code = String(r.code).toUpperCase();
      if (code === 'GLOBAL') out.global = days;
      else if (code === 'WARNING') out.warning = days;
      else if (code === 'CRITICAL') out.critical = days;
    }
    return out;
  } catch (err) {
    console.warn('[kpiVarianceAgent] cooldown lookup failed, using default:', err.message);
    return { global: DEFAULT_COOLDOWN_DAYS, warning: null, critical: null };
  }
}

function cooldownFor(severity, cooldown) {
  if (severity === 'warning' && cooldown.warning !== null) return cooldown.warning;
  if (severity === 'critical' && cooldown.critical !== null) return cooldown.critical;
  return cooldown.global;
}

/**
 * Load KPI_VARIANCE_THRESHOLDS for the entity, indexed by KPI code (uppercase).
 * GLOBAL row (code='GLOBAL') becomes the fallback for any KPI without an
 * explicit threshold.
 */
async function loadThresholds(entityId) {
  let rows = await Lookup.find({
    entity_id: entityId,
    category: 'KPI_VARIANCE_THRESHOLDS',
    is_active: true,
  }).lean();

  // Safety net: seed the GLOBAL row if no thresholds exist yet for this entity.
  // The primary seed happens on plan activation (salesGoalService.
  // ensureKpiVarianceGlobalThreshold); this catches historical entities whose
  // plans were activated before the seeder was deployed. Non-fatal — the
  // hardcoded DEFAULT_* constants keep the agent functional either way.
  if (rows.length === 0 && entityId) {
    try {
      const salesGoalService = require('../erp/services/salesGoalService');
      const seedResult = await salesGoalService.ensureKpiVarianceGlobalThreshold(entityId);
      if (seedResult.seeded) {
        rows = await Lookup.find({
          entity_id: entityId,
          category: 'KPI_VARIANCE_THRESHOLDS',
          is_active: true,
        }).lean();
      }
    } catch (err) {
      console.warn('[kpiVarianceAgent] GLOBAL self-seed skipped:', err.message);
    }
  }

  const map = new Map();
  let global = { warning_pct: DEFAULT_WARNING_PCT, critical_pct: DEFAULT_CRITICAL_PCT };

  for (const r of rows) {
    const w = Number(r.metadata?.warning_pct);
    const c = Number(r.metadata?.critical_pct);
    const t = {
      warning_pct: Number.isFinite(w) && w > 0 ? w : DEFAULT_WARNING_PCT,
      critical_pct: Number.isFinite(c) && c > 0 ? c : DEFAULT_CRITICAL_PCT,
    };
    if (String(r.code).toUpperCase() === 'GLOBAL') {
      global = t;
    } else {
      map.set(String(r.code).toUpperCase(), t);
    }
  }

  return { map, global };
}

/**
 * Compute the deviation % between actual and target. Direction-aware:
 *   - higher_better (default): deviation = (target - actual) / target * 100, only
 *     positive deviations (under-performance) count.
 *   - lower_better: deviation = (actual - target) / target * 100, only positive
 *     deviations (over-shoot, i.e. higher = worse) count.
 *
 * Plan KPI definitions are not stored on the snapshot (only kpi_code + value),
 * so we infer direction from a small lookup of "lower_better" KPIs that the
 * salesGoalService computes inversely. Anything not in this list is treated as
 * higher_better. This keeps the agent self-contained and avoids re-loading
 * the full plan + driver tree per BDM.
 */
const LOWER_BETTER_KPIS = new Set([
  'LOST_SALES_INCIDENTS',
  'EXPIRY_RETURNS',
]);

function computeDeviationPct(kpiCode, actual, target) {
  const t = Number(target) || 0;
  const a = Number(actual) || 0;
  if (t === 0) return 0;
  if (LOWER_BETTER_KPIS.has(String(kpiCode).toUpperCase())) {
    // higher = worse; alert when actual exceeds target
    return Math.max(((a - t) / t) * 100, 0);
  }
  // higher = better; alert when actual falls short of target
  return Math.max(((t - a) / t) * 100, 0);
}

function classifySeverity(deviationPct, threshold) {
  if (deviationPct >= threshold.critical_pct) return 'critical';
  if (deviationPct >= threshold.warning_pct) return 'warning';
  return null;
}

/**
 * Run entry point — standard agent signature called by agentExecutor.
 * Receives `{ triggerSource, runId, entity_id?, period? }`.
 */
async function run(args = {}) {
  const startTime = Date.now();
  const entityFilter = { status: 'ACTIVE' };
  if (args.entity_id) entityFilter._id = args.entity_id;

  const entities = await Entity.find(entityFilter).select('_id entity_name short_name').lean();
  if (entities.length === 0) {
    return {
      status: 'success',
      summary: { bdms_processed: 0, alerts_generated: 0, messages_sent: 0, key_findings: ['No active entities'] },
      execution_ms: Date.now() - startTime,
    };
  }

  let bdmsProcessed = 0;
  let bdmsFlagged = 0;
  let alertsGenerated = 0;
  let alertsSuppressed = 0;
  let alertsPersisted = 0;
  let messagesSent = 0;
  const errors = [];
  const findings = [];

  for (const entity of entities) {
    try {
      const thresholds = await loadThresholds(entity._id);
      const cooldown = await loadCooldown(entity._id);

      // ACTIVE plans for this entity
      const plans = await SalesGoalPlan.find({
        entity_id: entity._id,
        status: 'ACTIVE',
      }).select('_id fiscal_year plan_name reference').lean();

      if (plans.length === 0) continue;

      for (const plan of plans) {
        // Pull every YTD snapshot for the plan
        const snapshots = await KpiSnapshot.find({
          plan_id: plan._id,
          period_type: 'YTD',
          period: String(plan.fiscal_year),
        }).lean();

        for (const snap of snapshots) {
          if (!snap.bdm_id) continue;
          bdmsProcessed++;

          // Filter to active BDMs (skip deactivated PeopleMaster)
          const target = await SalesGoalTarget.findOne({
            plan_id: plan._id,
            bdm_id: snap.bdm_id,
            status: 'ACTIVE',
          }).select('person_id').lean();
          if (target?.person_id) {
            const person = await PeopleMaster.findById(target.person_id).select('is_active full_name bdm_code').lean();
            if (person && !person.is_active) continue;
          }

          // Walk every driver KPI; flag deviations. Cooldown dedup (SG-5 #27)
          // filters out breaches that already fired within the window so
          // persistent low-performers don't spam the inbox every run.
          const alerts = [];
          const suppressedCodes = [];
          for (const driver of (snap.driver_kpis || [])) {
            for (const kpi of (driver.kpis || [])) {
              const upperCode = String(kpi.kpi_code).toUpperCase();
              const t = thresholds.map.get(upperCode) || thresholds.global;
              const deviation = computeDeviationPct(kpi.kpi_code, kpi.actual_value, kpi.target_value);
              const severity = classifySeverity(deviation, t);
              if (!severity) continue;

              const cdDays = cooldownFor(severity, cooldown);
              const suppress = cdDays > 0 ? await VarianceAlert.findOne({
                entity_id: entity._id,
                plan_id: plan._id,
                bdm_id: snap.bdm_id,
                kpi_code: upperCode,
                severity,
                fired_at: { $gte: new Date(Date.now() - cdDays * 24 * 60 * 60 * 1000) },
              }).select('_id').lean() : null;

              if (suppress) {
                suppressedCodes.push(upperCode);
                alertsSuppressed++;
                continue;
              }

              alerts.push({
                kpi_code: upperCode,
                kpi_label: kpi.kpi_label || kpi.kpi_code,
                actual: kpi.actual_value,
                target: kpi.target_value,
                deviation_pct: deviation,
                threshold_pct: severity === 'critical' ? t.critical_pct : t.warning_pct,
                severity,
              });
            }
          }

          if (alerts.length === 0) {
            if (suppressedCodes.length > 0) {
              // Keep a trace on findings for visibility even when no email fires.
              findings.push(`Cooldown suppressed ${suppressedCodes.length} alert(s) for ${snap.bdm_id}`);
            }
            continue;
          }
          bdmsFlagged++;
          alertsGenerated += alerts.length;

          // Persist each alert BEFORE dispatch so cooldown works for the next
          // run even if the notification path fails.
          try {
            const toPersist = alerts.map(a => ({
              entity_id: entity._id,
              plan_id: plan._id,
              bdm_id: snap.bdm_id,
              person_id: target?.person_id || snap.person_id || null,
              fiscal_year: plan.fiscal_year,
              period: snap.period,
              kpi_code: a.kpi_code,
              kpi_label: a.kpi_label,
              severity: a.severity,
              actual_value: Number(a.actual) || 0,
              target_value: Number(a.target) || 0,
              deviation_pct: Math.round((Number(a.deviation_pct) || 0) * 100) / 100,
              threshold_pct: Math.round((Number(a.threshold_pct) || 0) * 100) / 100,
              status: 'OPEN',
              fired_at: new Date(),
            }));
            await VarianceAlert.insertMany(toPersist, { ordered: false });
            alertsPersisted += toPersist.length;
          } catch (persistErr) {
            // Duplicate key collisions can occur if two agent runs race; safe
            // to log and move on (cooldown check above already prevents most
            // of this).
            console.warn('[kpiVarianceAgent] persist alerts failed:', persistErr.message);
          }

          // Resolve a readable name for the BDM (PeopleMaster preferred, else snap.person_id)
          let bdmLabel = 'BDM';
          try {
            const personId = target?.person_id || snap.person_id;
            if (personId) {
              const person = await PeopleMaster.findById(personId).select('full_name bdm_code').lean();
              if (person) bdmLabel = `${person.full_name}${person.bdm_code ? ` (${person.bdm_code})` : ''}`;
            }
          } catch { /* fall back to 'BDM' */ }

          // Fire-and-forget notification (the service already swallows its own errors).
          // We await here so the agent counts dispatches accurately.
          await notifyKpiVariance({
            entityId: entity._id,
            bdmId: snap.bdm_id,
            bdmLabel,
            fiscalYear: plan.fiscal_year,
            period: snap.period,
            alerts,
          });
          messagesSent++;
        }
      }

      findings.push(`${entity.short_name || entity.entity_name}: ${bdmsFlagged} BDMs flagged, ${alertsGenerated} alerts`);
    } catch (err) {
      console.error(`[kpiVarianceAgent] Entity ${entity._id} failed:`, err.message);
      errors.push(`${entity.short_name || entity.entity_name}: ${err.message}`);
    }
  }

  const summary = {
    bdms_processed: bdmsProcessed,
    alerts_generated: alertsGenerated,
    alerts_suppressed: alertsSuppressed,
    alerts_persisted: alertsPersisted,
    messages_sent: messagesSent,
    key_findings: [
      `BDMs flagged: ${bdmsFlagged} of ${bdmsProcessed}`,
      `Total alerts: ${alertsGenerated} (persisted ${alertsPersisted}; cooldown-suppressed ${alertsSuppressed})`,
      `Notifications dispatched: ${messagesSent}`,
      ...findings.slice(0, 5),
      ...(errors.length > 0 ? [`Errors: ${errors.length} — ${errors.slice(0, 2).join(' | ')}`] : []),
    ],
  };

  return {
    status: errors.length > 0 && bdmsProcessed === 0 ? 'error' : (errors.length > 0 ? 'partial' : 'success'),
    summary,
    error_msg: errors.length > 0 ? errors.join(' | ') : null,
    message_ids: [],
    execution_ms: Date.now() - startTime,
  };
}

module.exports = { run };

/**
 * KPI Variance Digest Agent (#VD) — Phase SG-5 #27
 *
 * Rolls up all VarianceAlert rows fired since the last digest run into a single
 * weekly email per manager. Complements kpiVarianceAgent (#V) which fires an
 * immediate alert per breach; the digest smooths that out to one Monday-morning
 * summary per manager so they're not deluged across the week.
 *
 * Type: FREE (rule-based — no AI cost).
 * Schedule: Weekly Monday 07:00 Manila (one step after kpiVarianceAgent's
 * monthly day-2 run so both agents are authoritative on their respective
 * cadences). Manual Run Now via Agent Console.
 *
 * Subscription posture:
 *   - Per-entity (walks Entity.find({ status: 'ACTIVE' })).
 *   - Aggregates by `reports_to` chain (resolved via erpNotificationService
 *     helpers). Manager sees a digest of *their BDMs*, not a firehose.
 *   - Digest format + subject line are lookup-configurable via the
 *     KPI_VARIANCE_DIGEST_TEMPLATE category (not mandatory — sensible
 *     fallback baked in).
 *   - Idempotency: each VarianceAlert carries `digested_at`. A single digest
 *     window marks every alert it included so re-running the agent the same
 *     week does NOT re-email the same manager.
 */

const Entity = require('../erp/models/Entity');
const VarianceAlert = require('../erp/models/VarianceAlert');
const PeopleMaster = require('../erp/models/PeopleMaster');
const User = require('../models/User');
const Lookup = require('../erp/models/Lookup');
const { dispatchMultiChannel } = require('../erp/services/erpNotificationService');
const { kpiVarianceDigestTemplate } = require('../templates/erpEmails');

async function loadDigestWindowDays(entityId) {
  try {
    const row = await Lookup.findOne({
      entity_id: entityId,
      category: 'VARIANCE_ALERT_DIGEST_WINDOW_DAYS',
      code: 'GLOBAL',
      is_active: true,
    }).lean();
    const n = Number(row?.metadata?.days ?? row?.metadata?.value);
    if (Number.isFinite(n) && n > 0) return n;
  } catch (_) { /* fall through */ }
  return 7; // default one-week window — matches the Monday digest cadence
}

/**
 * Group alerts by (manager user_id). Managers resolved by walking
 * PeopleMaster.reports_to up from each BDM's person_id. BDMs without a
 * reports_to line up to president (presidents are already in the escalation
 * audience for the immediate agent — we don't re-notify them weekly here to
 * avoid inbox noise).
 */
async function groupByManager(alerts) {
  const personIds = [...new Set(alerts.map(a => a.person_id?.toString()).filter(Boolean))];
  const people = await PeopleMaster.find({ _id: { $in: personIds } }).select('_id full_name reports_to user_id').lean();
  const personIndex = new Map(people.map(p => [String(p._id), p]));

  const managerIds = [...new Set(people.map(p => p.reports_to?.toString()).filter(Boolean))];
  const managerPeople = await PeopleMaster.find({ _id: { $in: managerIds } }).select('_id full_name user_id').lean();
  const managerPeopleIndex = new Map(managerPeople.map(p => [String(p._id), p]));

  const managerUserIds = managerPeople.map(p => p.user_id).filter(Boolean);
  const managerUsers = await User.find({ _id: { $in: managerUserIds }, isActive: true }).select('_id name email phone role').lean();
  const managerUserIndex = new Map(managerUsers.map(u => [String(u._id), u]));

  const bucket = new Map(); // managerUserId -> { user, alerts, bdms: Set }
  for (const a of alerts) {
    const person = a.person_id ? personIndex.get(String(a.person_id)) : null;
    if (!person) continue;
    const manager = person.reports_to ? managerPeopleIndex.get(String(person.reports_to)) : null;
    if (!manager?.user_id) continue;
    const managerUser = managerUserIndex.get(String(manager.user_id));
    if (!managerUser) continue;
    const key = String(managerUser._id);
    if (!bucket.has(key)) bucket.set(key, { user: managerUser, alerts: [], bdmIds: new Set() });
    const rec = bucket.get(key);
    rec.alerts.push({ ...a, bdm_name: person.full_name || 'BDM' });
    rec.bdmIds.add(String(person._id));
  }
  return bucket;
}

async function run(args = {}) {
  const startTime = Date.now();
  const entityFilter = { status: 'ACTIVE' };
  if (args.entity_id) entityFilter._id = args.entity_id;

  const entities = await Entity.find(entityFilter).select('_id entity_name short_name').lean();
  if (!entities.length) {
    return {
      status: 'success',
      summary: { digests_sent: 0, alerts_included: 0, managers_covered: 0, key_findings: ['No active entities'] },
      execution_ms: Date.now() - startTime,
    };
  }

  let digestsSent = 0;
  let alertsIncluded = 0;
  let managersCovered = 0;
  const errors = [];
  const findings = [];

  for (const entity of entities) {
    try {
      const windowDays = await loadDigestWindowDays(entity._id);
      const since = new Date(Date.now() - windowDays * 24 * 60 * 60 * 1000);

      // Pull every alert fired in the window that hasn't been digested yet.
      const alerts = await VarianceAlert.find({
        entity_id: entity._id,
        fired_at: { $gte: since },
        $or: [{ digested_at: null }, { digested_at: { $exists: false } }],
      }).lean();

      if (!alerts.length) {
        findings.push(`${entity.short_name || entity.entity_name}: 0 undigested alerts`);
        continue;
      }

      const grouped = await groupByManager(alerts);
      if (grouped.size === 0) {
        findings.push(`${entity.short_name || entity.entity_name}: ${alerts.length} alerts, no managers resolved`);
        continue;
      }

      for (const [, rec] of grouped) {
        const recipient = rec.user;
        const digestAlerts = rec.alerts.map(a => ({
          bdm_name: a.bdm_name,
          kpi_label: a.kpi_label || a.kpi_code,
          kpi_code: a.kpi_code,
          severity: a.severity,
          actual: a.actual_value,
          target: a.target_value,
          deviation_pct: a.deviation_pct,
          period: a.period,
        }));

        await dispatchMultiChannel([recipient], {
          templateFn: kpiVarianceDigestTemplate,
          templateData: {
            managerName: recipient.name || 'Manager',
            entityName: entity.entity_name || entity.short_name || '',
            windowDays,
            alerts: digestAlerts,
            bdmCount: rec.bdmIds.size,
          },
          emailType: 'ERP_KPI_VARIANCE_DIGEST',
          category: 'kpiVariance',
          entityId: entity._id,
          inAppCategory: 'compliance_alert',
          inAppPriority: digestAlerts.some(a => a.severity === 'critical') ? 'high' : 'normal',
        });

        // Mark every included alert as digested so next week's run starts clean.
        const alertIds = rec.alerts.map(a => a._id);
        if (alertIds.length) {
          await VarianceAlert.updateMany(
            { _id: { $in: alertIds } },
            { $set: { digested_at: new Date() } }
          );
        }

        digestsSent++;
        alertsIncluded += digestAlerts.length;
        managersCovered++;
      }

      findings.push(`${entity.short_name || entity.entity_name}: ${grouped.size} manager(s), ${alerts.length} alert(s)`);
    } catch (err) {
      console.error(`[kpiVarianceDigestAgent] Entity ${entity._id} failed:`, err.message);
      errors.push(`${entity.short_name || entity.entity_name}: ${err.message}`);
    }
  }

  return {
    status: errors.length > 0 && digestsSent === 0 ? 'error' : (errors.length > 0 ? 'partial' : 'success'),
    summary: {
      digests_sent: digestsSent,
      alerts_included: alertsIncluded,
      managers_covered: managersCovered,
      key_findings: [
        `Digests sent: ${digestsSent}`,
        `Alerts included: ${alertsIncluded}`,
        `Managers covered: ${managersCovered}`,
        ...findings.slice(0, 4),
        ...(errors.length > 0 ? [`Errors: ${errors.length} — ${errors.slice(0, 2).join(' | ')}`] : []),
      ],
    },
    error_msg: errors.length > 0 ? errors.join(' | ') : null,
    message_ids: [],
    execution_ms: Date.now() - startTime,
  };
}

module.exports = { run };

/**
 * Org Intelligence Agent (#O)
 *
 * Weekly AI agent that analyzes partner scorecards across all entities
 * and produces actionable intelligence digest for the President.
 *
 * Schedule: Monday 5:30 AM (after daily scorecard refresh at 5:00 AM)
 * Type: Paid (uses Claude API)
 */
const Anthropic = require('@anthropic-ai/sdk');
const PartnerScorecard = require('../erp/models/PartnerScorecard');
const PeopleMaster = require('../erp/models/PeopleMaster');
const Entity = require('../erp/models/Entity');
const AgentRun = require('../erp/models/AgentRun');
const MessageInbox = require('../models/MessageInbox');
const User = require('../models/User');
const { ROLES } = require('../constants/roles');
const { getParentEntityIds } = require('../erp/utils/parentEntityResolver');

function currentPeriod() {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
}

function previousPeriod() {
  const now = new Date();
  const prev = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  return `${prev.getFullYear()}-${String(prev.getMonth() + 1).padStart(2, '0')}`;
}

async function run() {
  const startTime = Date.now();
  const period = currentPeriod();
  const prevPeriod = previousPeriod();

  try {
    // Get all entities
    const entities = await Entity.find({ status: 'ACTIVE' }).select('entity_name short_name entity_type').lean();

    // Get current and previous scorecards
    const current = await PartnerScorecard.find({ period })
      .populate('person_id', 'full_name person_type position bdm_code date_hired entity_id')
      .populate('entity_id', 'short_name')
      .sort({ score_overall: -1 })
      .lean();

    const previous = await PartnerScorecard.find({ period: prevPeriod })
      .select('person_id score_overall')
      .lean();
    const prevMap = new Map(previous.map(s => [s.person_id.toString(), s.score_overall]));

    if (current.length === 0) {
      console.log('[OrgIntelligence] No scorecards found — skipping.');
      return;
    }

    // Build data summary for Claude
    const partnerData = current.map((s, i) => {
      const prevScore = prevMap.get(s.person_id?._id?.toString()) || null;
      const delta = prevScore !== null ? s.score_overall - prevScore : null;
      return {
        rank: i + 1,
        name: s.person_id?.full_name || 'Unknown',
        type: s.person_id?.person_type || 'BDM',
        entity: s.entity_id?.short_name || '?',
        score_overall: s.score_overall,
        delta: delta !== null ? `${delta >= 0 ? '+' : ''}${delta}` : 'new',
        visits: `${s.visits_completed}/${s.visits_expected} (${s.visit_compliance_pct}%)`,
        sales: `₱${(s.sales_total || 0).toLocaleString()}`,
        collections: `₱${(s.collections_total || 0).toLocaleString()} (${s.collection_rate_pct}%)`,
        expense_ratio: `${s.expense_sales_ratio_pct}%`,
        engagement: s.avg_engagement_level,
        clients: `${s.total_clients_assigned} assigned, ${s.clients_at_risk} at risk`,
        graduation: `${s.graduation?.checklist_met || 0}/${s.graduation?.checklist_total || 7}`,
        graduation_ready: s.graduation?.ready || false,
        blocking_criteria: (s.graduation?.criteria || []).filter(c => !c.met).map(c => `${c.label}: ${c.actual} (need ${c.comparator === 'lte' ? '≤' : '≥'}${c.target})`),
        ai_insights: (s.ai_insights || []).map(i => `[${i.agent}] ${i.message}`),
      };
    });

    const entitySummary = entities.map(e => {
      const ePeople = current.filter(s => s.entity_id?._id?.toString() === e._id.toString());
      return {
        name: e.short_name || e.entity_name,
        type: e.entity_type,
        partners: ePeople.length,
        avg_score: ePeople.length > 0 ? Math.round(ePeople.reduce((s, p) => s + p.score_overall, 0) / ePeople.length) : 0,
      };
    });

    // Call Claude API
    const client = new Anthropic();
    const prompt = `You are the Org Intelligence Analyst for VIP Group (VIOS INTEGRATED PROJECTS INC.), a pharmaceutical company.

CONTEXT:
- VIP is a parent company that supplies subsidiaries.
- BDMs are partners/entrepreneurs-to-be who can graduate to own their own subsidiary.
- Graduation requires meeting 7 criteria (months active, clients, sales, collection rate, expense ratio, visit compliance, engagement).
- The President (Gregg) needs actionable, concise insights — not just numbers.

ENTITIES:
${JSON.stringify(entitySummary, null, 2)}

PARTNER SCORECARDS (${period}):
${JSON.stringify(partnerData, null, 2)}

Produce a weekly org intelligence digest. Use this exact format:

📊 ORG INTELLIGENCE — Week of [date]

GROUP HEALTH: [1 line summary with avg score and trend]

🏆 TOP PERFORMERS (top 3)
[rank. name — score (delta) — key strength]

⚠️ NEEDS ATTENTION
[partners with score <50 or declining >10 points — what's wrong]

🎓 GRADUATION PIPELINE
[partners closest to graduation — what criteria they still need — specific recommendation]

📈 TRENDS
[3 bullet points on org-wide patterns]

💡 RECOMMENDATIONS
[3 specific, actionable recommendations for the President]

Keep it concise, specific, and actionable. Use real names and numbers from the data.`;

    const response = await client.messages.create({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1000,
      messages: [{ role: 'user', content: prompt }],
    });

    const digest = response.content[0]?.text || 'Unable to generate digest.';

    // Send message to parent-entity presidents only. The org-intelligence
    // digest is a cross-entity analysis (VIP + all subsidiaries) intended
    // for company owners, not for subsidiary presidents who should only see
    // their own subsidiary's data.
    const parentEntityIds = await getParentEntityIds();
    const presidents = await User.find({
      role: ROLES.PRESIDENT,
      entity_id: { $in: parentEntityIds },
    }).select('_id entity_id entity_ids').lean();
    const messageIds = [];

    for (const pres of presidents) {
      const presEntityId = pres.entity_id
        || (Array.isArray(pres.entity_ids) && pres.entity_ids.length > 0 ? pres.entity_ids[0] : null);
      const msg = await MessageInbox.create({
        recipientUserId: pres._id,
        recipientRole: ROLES.PRESIDENT,
        title: `Org Intelligence — ${period}`,
        body: digest,
        category: 'ai_coaching',
        priority: 'normal',
        senderName: 'Org Intelligence Agent',
        senderRole: 'system',
        entity_id: presEntityId,
        folder: 'AI_AGENT_REPORTS',
      });
      messageIds.push(msg._id);
    }

    // Log agent run
    const topPerformers = partnerData.slice(0, 3).map(p => `${p.name}: ${p.score_overall}`);
    const nearGrad = partnerData.filter(p => p.graduation.startsWith('6/') || p.graduation.startsWith('7/')).map(p => p.name);

    await AgentRun.create({
      agent_key: 'org_intelligence',
      agent_label: 'Org Intelligence',
      status: 'success',
      summary: {
        bdms_processed: current.length,
        alerts_generated: partnerData.filter(p => p.score_overall < 50).length,
        messages_sent: messageIds.length,
        key_findings: [
          `Avg score: ${Math.round(current.reduce((s, c) => s + c.score_overall, 0) / current.length)}`,
          `Top: ${topPerformers.join(', ')}`,
          nearGrad.length > 0 ? `Near graduation: ${nearGrad.join(', ')}` : 'No partners near graduation yet',
        ],
      },
      message_ids: messageIds,
      execution_ms: Date.now() - startTime,
    });

    console.log(`[OrgIntelligence] Digest sent to ${messageIds.length} president(s). ${current.length} partners analyzed.`);
  } catch (err) {
    console.error('[OrgIntelligence] Error:', err.message);
    await AgentRun.create({
      agent_key: 'org_intelligence',
      agent_label: 'Org Intelligence',
      status: 'error',
      error_msg: err.message,
      execution_ms: Date.now() - startTime,
    });
  }
}

module.exports = { run };

/**
 * BDM Performance Coach Agent (#7) - AI-powered coaching feedback
 *
 * Runs weekly Monday 6:00 AM. Analyzes per BDM:
 *   - Visit frequency vs target (CRM visits)
 *   - Sales volume trends (ERP sales)
 *   - Expense patterns (ERP expenses)
 *   - Collection efficiency (ERP collections)
 *
 * Generates personalized coaching feedback per BDM.
 * Notifies: Each BDM (their own feedback) + PRESIDENT (summary)
 */
const { askClaude } = require('./claudeClient');
const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');
const { ROLES } = require('../constants/roles');

function formatPhpAmount(value) {
  return `PHP ${Number(value || 0).toLocaleString('en-PH')}`;
}

async function run() {
  console.log('[PerformanceCoach] Running...');

  const User = require('../models/User');
  const Visit = require('../models/Visit');
  const SalesLine = require('../erp/models/SalesLine');
  const ExpenseEntry = require('../erp/models/ExpenseEntry');
  const Collection = require('../erp/models/Collection');

  const bdms = await User.find({ role: ROLES.CONTRACTOR, isActive: true }).select('_id name entity_id').lean();
  if (!bdms.length) {
    console.log('[PerformanceCoach] No active BDMs.');
    return {
      status: 'success',
      summary: {
        bdms_processed: 0,
        alerts_generated: 0,
        messages_sent: 0,
        key_findings: ['No active BDMs found for coaching.'],
      },
      message_ids: [],
    };
  }

  const now = new Date();
  const weekAgo = new Date(now.getTime() - 7 * 86400000);
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
  const currentPeriod = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;

  const successfulBdms = [];
  const failures = [];
  const notificationResults = [];

  for (const bdm of bdms) {
    try {
      const weekVisits = await Visit.countDocuments({
        user: bdm._id,
        visitDate: { $gte: weekAgo },
      });

      const monthVisits = await Visit.countDocuments({
        user: bdm._id,
        visitDate: { $gte: monthStart },
      });

      const sales = await SalesLine.aggregate([
        { $match: { bdm_id: bdm._id, status: 'POSTED', csi_date: { $gte: monthStart } } },
        { $group: { _id: null, total: { $sum: '$invoice_total' }, count: { $sum: 1 } } },
      ]);
      const salesTotal = sales[0]?.total || 0;
      const salesCount = sales[0]?.count || 0;

      const expenses = await ExpenseEntry.aggregate([
        { $match: { bdm_id: bdm._id, status: 'POSTED', period: currentPeriod } },
        { $group: { _id: null, total: { $sum: '$total_amount' } } },
      ]);
      const expenseTotal = expenses[0]?.total || 0;

      const collections = await Collection.aggregate([
        { $match: { bdm_id: bdm._id, status: 'POSTED', cr_date: { $gte: monthStart } } },
        { $group: { _id: null, total: { $sum: '$cr_amount' }, count: { $sum: 1 } } },
      ]);
      const collectionTotal = collections[0]?.total || 0;
      const collectionCount = collections[0]?.count || 0;

      const summary = {
        id: bdm._id,
        name: bdm.name,
        weekVisits,
        monthVisits,
        salesTotal,
        salesCount,
        expenseTotal,
        collectionTotal,
        collectionCount,
      };

      const data = `BDM: ${summary.name}
Week visits: ${summary.weekVisits} | Month visits: ${summary.monthVisits}
Month sales: ${formatPhpAmount(summary.salesTotal)} (${summary.salesCount} invoices)
Month expenses: ${formatPhpAmount(summary.expenseTotal)}
Month collections: ${formatPhpAmount(summary.collectionTotal)} (${summary.collectionCount} receipts)
Expense/Sales ratio: ${summary.salesTotal > 0 ? ((summary.expenseTotal / summary.salesTotal) * 100).toFixed(1) : 'N/A'}%`;

      const { text } = await askClaude({
        system: `You are a sales performance coach for Philippine pharmaceutical BDMs (Business Development Managers). Give brief, constructive weekly feedback. Focus on:
- Visit consistency (target: 8-10 MDs/day, ~40-50/week)
- Sales vs expense efficiency
- Collection follow-up
Keep it encouraging and actionable. 3-4 bullet points max. Use Philippine business context.`,
        prompt: `Weekly performance for:\n${data}\n\nGive brief coaching feedback.`,
        maxTokens: 400,
        agent: 'performance_coach',
      });

      notificationResults.push(...(await notify({
        recipient_id: summary.id,
        title: 'Weekly Performance Coaching',
        body: text,
        category: 'ai_coaching',
        priority: 'normal',
        channels: ['in_app'],
        agent: 'performance_coach',
      })));

      successfulBdms.push(summary);
    } catch (err) {
      console.error('[PerformanceCoach] Error:', err.message);
      failures.push({ bdmId: bdm._id, name: bdm.name, error: err });
    }
  }

  if (!successfulBdms.length) {
    throw failures[0]?.error || new Error('No BDM coaching runs completed successfully');
  }

  const summaryLines = successfulBdms
    .map((bdm) => `${bdm.name}: ${bdm.weekVisits} visits, ${formatPhpAmount(bdm.salesTotal)} sales, ${formatPhpAmount(bdm.collectionTotal)} collected`)
    .join('\n');

  notificationResults.push(...(await notify({
    recipient_id: 'PRESIDENT',
    title: 'Weekly BDM Performance Summary',
    body: `BDM metrics for the week ending ${now.toLocaleDateString('en-PH')}:\n\n${summaryLines}`,
    category: 'ai_coaching',
    priority: 'normal',
    channels: ['in_app'],
    agent: 'performance_coach',
  })));

  const keyFindings = [...successfulBdms]
    .sort((a, b) => b.salesTotal - a.salesTotal)
    .slice(0, 3)
    .map((bdm) => `${bdm.name}: ${formatPhpAmount(bdm.salesTotal)} sales, ${bdm.weekVisits} visits`);

  if (failures.length) {
    keyFindings.push(`${failures.length} BDM coaching run(s) failed and were skipped.`);
  }

  console.log(`[PerformanceCoach] Coached ${successfulBdms.length} BDMs.`);

  return {
    status: failures.length ? 'partial' : 'success',
    summary: {
      bdms_processed: successfulBdms.length,
      alerts_generated: successfulBdms.length,
      messages_sent: countSuccessfulChannels(notificationResults, 'in_app'),
      key_findings: keyFindings,
    },
    message_ids: getInAppMessageIds(notificationResults),
  };
}

