/**
 * Proxy SLA Agent — Phase P1 (#PX) (April 23, 2026).
 *
 * Rule-based (FREE tier). Runs every 4 hours.
 *
 * 1. Finds CaptureSubmission with status='PENDING_PROXY' older than SLA threshold
 *    (default 24h, lookup-driven PROXY_SLA_THRESHOLDS) → alerts office lead.
 * 2. Finds status='AWAITING_BDM_REVIEW' older than auto-ack threshold
 *    (default 72h) → auto-acknowledges with warning.
 * 3. Computes metrics: avg turnaround, proxy throughput, BDM review rate.
 *
 * Idempotent: re-runs do not re-fire alerts (checks sla_alert_sent_at).
 */

// Lazy-loaded below in ensureDeps()
let Entity;

// Lazy-require to avoid circular dependency at module load
let CaptureSubmission;
let Lookup;
let User;
let dispatchMultiChannel;

function ensureDeps() {
  if (!CaptureSubmission) {
    CaptureSubmission = require('../erp/models/CaptureSubmission');
    Lookup = require('../erp/models/Lookup');
    Entity = require('../erp/models/Entity');
    User = require('../models/User');
    ({ dispatchMultiChannel } = require('../erp/services/erpNotificationService'));
  }
}

const DEFAULT_PENDING_SLA_HOURS = 24;
const DEFAULT_AUTO_ACK_HOURS = 72;

async function getSlaThresholds(entityId) {
  try {
    const row = await Lookup.findOne({
      entity_id: entityId,
      category: 'PROXY_SLA_THRESHOLDS',
      code: 'DEFAULT',
      is_active: true,
    }).lean();
    if (row && row.metadata) {
      return {
        pendingHours: Number(row.metadata.pending_alert_hours) || DEFAULT_PENDING_SLA_HOURS,
        autoAckHours: Number(row.metadata.auto_ack_hours) || DEFAULT_AUTO_ACK_HOURS,
      };
    }
  } catch (err) {
    console.warn('[proxySlaAgent] Failed to read PROXY_SLA_THRESHOLDS:', err.message);
  }
  return { pendingHours: DEFAULT_PENDING_SLA_HOURS, autoAckHours: DEFAULT_AUTO_ACK_HOURS };
}

async function run({ entityId } = {}) {
  ensureDeps();

  // Resolve entities to scan
  let entities;
  if (entityId) {
    const e = await Entity.findById(entityId).lean();
    entities = e ? [e] : [];
  } else {
    entities = await Entity.find({ is_active: true }).lean();
  }

  const results = [];

  for (const entity of entities) {
    const eid = entity._id;
    const { pendingHours, autoAckHours } = await getSlaThresholds(eid);
    const now = new Date();

    // ── 1. Alert on stale PENDING_PROXY ──
    const pendingCutoff = new Date(now.getTime() - pendingHours * 60 * 60 * 1000);
    const stalePending = await CaptureSubmission.find({
      entity_id: eid,
      status: 'PENDING_PROXY',
      created_at: { $lt: pendingCutoff },
      sla_alert_sent_at: { $exists: false },
    }).lean();

    if (stalePending.length > 0) {
      // Find office leads (admin/finance) for this entity
      const officeLeads = await User.find({
        $or: [
          { entity_id: eid, role: { $in: ['admin', 'finance'] }, isActive: true },
          { entity_ids: eid, role: { $in: ['admin', 'finance'] }, isActive: true },
        ],
      }).select('name email role').lean();

      if (officeLeads.length > 0) {
        await dispatchMultiChannel(officeLeads, {
          subject: `[SLA] ${stalePending.length} capture(s) pending > ${pendingHours}h`,
          text: `${stalePending.length} BDM capture submission(s) have been waiting for proxy processing longer than ${pendingHours} hours at ${entity.name || eid}. Please check the Proxy Queue.`,
          category: 'proxy_sla_alert',
          entityId: eid,
          priority: 'high',
        }).catch(err => console.error('[proxySlaAgent] alert dispatch failed:', err.message));
      }

      // Mark alert sent (idempotent)
      const staleIds = stalePending.map(s => s._id);
      await CaptureSubmission.updateMany(
        { _id: { $in: staleIds } },
        { $set: { sla_alert_sent_at: now } }
      );

      results.push({ entity: entity.name, action: 'sla_alert', count: stalePending.length });
    }

    // ── 2. Auto-acknowledge stale AWAITING_BDM_REVIEW ──
    const autoAckCutoff = new Date(now.getTime() - autoAckHours * 60 * 60 * 1000);
    const staleReview = await CaptureSubmission.find({
      entity_id: eid,
      status: 'AWAITING_BDM_REVIEW',
      proxy_completed_at: { $lt: autoAckCutoff },
    }).lean();

    if (staleReview.length > 0) {
      const staleReviewIds = staleReview.map(s => s._id);
      await CaptureSubmission.updateMany(
        { _id: { $in: staleReviewIds } },
        {
          $set: {
            status: 'AUTO_ACKNOWLEDGED',
            auto_ack_at: now,
            bdm_acknowledged_at: now,
          },
        }
      );

      // Notify BDMs that their reviews were auto-acknowledged
      const bdmIds = [...new Set(staleReview.map(s => String(s.bdm_id)))];
      const bdmUsers = await User.find({ _id: { $in: bdmIds } }).select('name email role').lean();
      if (bdmUsers.length > 0) {
        for (const bdm of bdmUsers) {
          const count = staleReview.filter(s => String(s.bdm_id) === String(bdm._id)).length;
          await dispatchMultiChannel([bdm], {
            subject: `${count} proxied entry/entries auto-acknowledged`,
            text: `${count} proxied entry/entries were auto-acknowledged after ${autoAckHours}h without your review. If any are incorrect, file a dispute from the Review Queue.`,
            category: 'proxy_auto_ack',
            entityId: eid,
            priority: 'normal',
          }).catch(err => console.error('[proxySlaAgent] auto-ack notify failed:', err.message));
        }
      }

      results.push({ entity: entity.name, action: 'auto_ack', count: staleReview.length });
    }
  }

  return {
    success: true,
    summary: results.length > 0 ? results : [{ action: 'no_action', message: 'All submissions within SLA' }],
  };
}

module.exports = { run };

/**
 * System Integrity Agent (#S)
 * Runs weekly Monday 5:00 AM (free, rule-based)
 *
 * Checks:
 * 1. Orphaned inventory records (product_id not in ProductMaster)
 * 2. COA mapping gaps (Settings references deactivated/missing accounts)
 * 3. Entities without warehouses
 * 4. People without access templates
 * 5. Transfer prices referencing deactivated products
 * 6. Sales referencing non-existent hospitals
 * 7. Missing required Settings fields
 */

const { notify } = require('./notificationService');
const { ROLE_SETS } = require('../constants/roles');

async function run() {
  const start = Date.now();
  console.log('[SystemIntegrity] Running...');

  try {
    const AgentRun = require('../erp/models/AgentRun');
    const findings = [];

    // ─── 1. Orphaned inventory (product_id not in ProductMaster) ───
    try {
      const InventoryLedger = require('../erp/models/InventoryLedger');
      const ProductMaster = require('../erp/models/ProductMaster');

      const inventoryProductIds = await InventoryLedger.distinct('product_id');
      const existingProductIds = new Set(
        (await ProductMaster.find({ _id: { $in: inventoryProductIds } }).select('_id').lean())
          .map(p => p._id.toString())
      );
      const orphaned = inventoryProductIds.filter(id => !existingProductIds.has(id.toString()));

      if (orphaned.length > 0) {
        findings.push({
          severity: 'warning',
          category: 'DATA_INTEGRITY',
          detail: `${orphaned.length} inventory record(s) reference non-existent products`
        });
      }
    } catch (err) {
      console.error('[SystemIntegrity] Orphaned inventory check failed:', err.message);
    }

    // ─── 2. Entities without warehouses ────────────────────────────
    try {
      const Entity = require('../erp/models/Entity');
      const Warehouse = require('../erp/models/Warehouse');

      const entities = await Entity.find({ status: 'ACTIVE' }).select('_id entity_name').lean();
      const entitiesWithWarehouses = new Set(
        (await Warehouse.distinct('entity_id')).map(id => id.toString())
      );

      const missing = entities.filter(e => !entitiesWithWarehouses.has(e._id.toString()));
      if (missing.length > 0) {
        findings.push({
          severity: 'critical',
          category: 'CONFIGURATION',
          detail: `${missing.length} active entity(s) have no warehouse: ${missing.map(e => e.entity_name).join(', ')}`
        });
      }
    } catch (err) {
      console.error('[SystemIntegrity] Entity/warehouse check failed:', err.message);
    }

    // ─── 3. People without access templates ────────────────────────
    try {
      const User = require('../../models/User');
      const usersWithoutAccess = await User.countDocuments({
        role: { $in: ROLE_SETS.ERP_FINANCE },
        erp_access: { $ne: true },
        isActive: { $ne: false }
      });

      if (usersWithoutAccess > 0) {
        findings.push({
          severity: 'warning',
          category: 'ACCESS',
          detail: `${usersWithoutAccess} active user(s) have no ERP access enabled`
        });
      }
    } catch (err) {
      console.error('[SystemIntegrity] Access check failed:', err.message);
    }

    // ─── 4. Transfer prices for deactivated products ───────────────
    try {
      const TransferPriceList = require('../erp/models/TransferPriceList');
      const ProductMaster = require('../erp/models/ProductMaster');

      const activePrices = await TransferPriceList.find({ is_active: true }).select('product_id').lean();
      if (activePrices.length > 0) {
        const priceProductIds = activePrices.map(p => p.product_id);
        const activeProducts = new Set(
          (await ProductMaster.find({ _id: { $in: priceProductIds }, is_active: true }).select('_id').lean())
            .map(p => p._id.toString())
        );
        const stale = activePrices.filter(p => !activeProducts.has(p.product_id.toString()));

        if (stale.length > 0) {
          findings.push({
            severity: 'warning',
            category: 'CONFIGURATION',
            detail: `${stale.length} active transfer price(s) reference deactivated/missing products`
          });
        }
      }
    } catch (err) {
      console.error('[SystemIntegrity] Transfer price check failed:', err.message);
    }

    // ─── 5. Sales referencing non-existent hospitals ───────────────
    try {
      const SalesLine = require('../erp/models/SalesLine');
      const Hospital = require('../erp/models/Hospital');

      const salesHospitalIds = await SalesLine.distinct('hospital_id', {
        status: { $in: ['DRAFT', 'VALID'] },
        hospital_id: { $exists: true, $ne: null }
      });

      if (salesHospitalIds.length > 0) {
        const existingHospitals = new Set(
          (await Hospital.find({ _id: { $in: salesHospitalIds } }).select('_id').lean())
            .map(h => h._id.toString())
        );
        const broken = salesHospitalIds.filter(id => !existingHospitals.has(id.toString()));

        if (broken.length > 0) {
          findings.push({
            severity: 'warning',
            category: 'DATA_INTEGRITY',
            detail: `${broken.length} draft/valid sales reference non-existent hospitals`
          });
        }
      }
    } catch (err) {
      console.error('[SystemIntegrity] Sales/hospital check failed:', err.message);
    }

    // ─── 6. Missing required Settings ──────────────────────────────
    try {
      const Settings = require('../erp/models/Settings');
      const settings = await Settings.getSettings();

      const requiredFields = ['VAT_RATE', 'CWT_RATE_WC158', 'NEAR_EXPIRY_DAYS', 'DEFAULT_PAYMENT_TERMS'];
      const missingSettings = requiredFields.filter(f => settings[f] == null);

      if (missingSettings.length > 0) {
        findings.push({
          severity: 'critical',
          category: 'CONFIGURATION',
          detail: `Missing required Settings: ${missingSettings.join(', ')}`
        });
      }
    } catch (err) {
      console.error('[SystemIntegrity] Settings check failed:', err.message);
    }

    // ─── 7. Products with zero prices ──────────────────────────────
    try {
      const ProductMaster = require('../erp/models/ProductMaster');
      const zeroPriceCount = await ProductMaster.countDocuments({
        is_active: true,
        $or: [
          { selling_price: { $lte: 0 } },
          { purchase_price: { $lte: 0 } }
        ]
      });

      if (zeroPriceCount > 0) {
        findings.push({
          severity: 'warning',
          category: 'DATA_QUALITY',
          detail: `${zeroPriceCount} active product(s) have zero or missing prices`
        });
      }
    } catch (err) {
      console.error('[SystemIntegrity] Zero price check failed:', err.message);
    }

    // ─── Send report ───────────────────────────────────────────────
    const critical = findings.filter(f => f.severity === 'critical');
    const warnings = findings.filter(f => f.severity === 'warning');

    if (findings.length > 0) {
      let body = `System Integrity Report — ${new Date().toLocaleDateString()}\n\n`;
      body += `${findings.length} issue(s) found (${critical.length} critical, ${warnings.length} warnings)\n\n`;

      const grouped = {};
      for (const f of findings) {
        if (!grouped[f.category]) grouped[f.category] = [];
        grouped[f.category].push(f);
      }

      for (const [cat, items] of Object.entries(grouped)) {
        body += `=== ${cat} ===\n`;
        for (const item of items) {
          body += `  [${item.severity.toUpperCase()}] ${item.detail}\n`;
        }
        body += '\n';
      }

      await notify({
        recipient_id: 'PRESIDENT',
        title: `System Integrity: ${critical.length} critical, ${findings.length} total`,
        body,
        category: 'system',
        priority: critical.length > 0 ? 'high' : 'important',
        channels: ['in_app', 'email'],
        agent: 'system_integrity'
      });
    }

    // Record run
    await AgentRun.create({
      agent_key: 'system_integrity',
      agent_label: 'System Integrity',
      status: findings.length > 0 ? (critical.length > 0 ? 'partial' : 'success') : 'success',
      summary: {
        alerts_generated: findings.length,
        key_findings: findings.slice(0, 5).map(f => f.detail)
      },
      execution_ms: Date.now() - start
    });

    console.log(`[SystemIntegrity] Complete. Found ${findings.length} issue(s) in ${Date.now() - start}ms.`);
  } catch (err) {
    console.error('[SystemIntegrity] Error:', err.message);
    try {
      const AgentRun = require('../erp/models/AgentRun');
      await AgentRun.create({ agent_key: 'system_integrity', agent_label: 'System Integrity', status: 'error', error_msg: err.message });
    } catch {}
  }
}

module.exports = { run };

/**
 * Task Overdue Agent (#TO) — Phase G9.R1
 *
 * Scans every active entity for OPEN / IN_PROGRESS / BLOCKED tasks whose
 * `due_date` has passed. For each overdue task it fires a `notifyTaskEvent`
 * with event='overdue', which lands in the assignee's TASKS folder of the
 * unified inbox (via dispatchMultiChannel — email + in-app + SMS opt-in,
 * NOTIFICATION_CHANNELS / NotificationPreference are honoured).
 *
 * Type: FREE (rule-based — no AI cost, no Anthropic key required).
 * Schedule: weekdays 06:15 Manila — fires after Treasury (05:30) and before
 *   Inventory Reorder (06:30) so the morning briefing window stays clean.
 *
 * Dedup / cooldown:
 *   The agent reads the per-entity `TASK_OVERDUE_COOLDOWN_DAYS` lookup
 *   (default GLOBAL row = 1 day) and skips tasks whose
 *   `last_overdue_notify_at` is newer than (now - cooldownDays * 24h).
 *   On a successful notify the field is stamped via `Task.updateOne`.
 *   Entities can change cooldown via Control Center → Lookup Tables;
 *   no code deploy required (Rule #3 lookup-driven).
 *
 * Subscriber posture: zero hardcoded thresholds. The cooldown lookup
 * lazy-seeds on first run when missing; in-memory `DEFAULT_COOLDOWN_DAYS`
 * is the last-resort fallback so a brand-new entity still gets a single
 * notification per overdue task per day.
 *
 * Returned summary follows the agentExecutor contract:
 *   { status, summary: { bdms_processed, alerts_generated, alerts_suppressed,
 *                       messages_sent, key_findings: [...] }, error_msg, message_ids,
 *     execution_ms }
 *   - bdms_processed = unique assignees scanned this run
 *   - alerts_generated = total overdue tasks found (incl. suppressed)
 *   - alerts_suppressed = skipped due to cooldown
 *   - messages_sent = notifyTaskEvent calls dispatched
 */

'use strict';

const Entity = require('../erp/models/Entity');
const Lookup = require('../erp/models/Lookup');
const Task = require('../erp/models/Task');
const { notifyTaskEvent } = require('../erp/services/erpNotificationService');

const DEFAULT_COOLDOWN_DAYS = 1;
const SAFETY_TASK_LIMIT_PER_ENTITY = 500; // hard cap to avoid runaway runs

/**
 * Read TASK_OVERDUE_COOLDOWN_DAYS for the entity. GLOBAL row applies to all
 * tasks. A 0 day value disables dedup (notify every run — useful only for
 * test environments). Negative numbers are clamped to the default.
 */
async function loadCooldownDays(entityId) {
  if (!entityId) return DEFAULT_COOLDOWN_DAYS;
  try {
    const row = await Lookup.findOne({
      entity_id: entityId,
      category: 'TASK_OVERDUE_COOLDOWN_DAYS',
      code: 'GLOBAL',
      is_active: true,
    }).select('metadata').lean();
    if (!row) {
      // Lazy-seed GLOBAL row so admin can edit it in Control Center next time.
      try {
        await Lookup.updateOne(
          { entity_id: entityId, category: 'TASK_OVERDUE_COOLDOWN_DAYS', code: 'GLOBAL' },
          {
            $setOnInsert: {
              label: 'Cooldown days between overdue notifications for the same task',
              sort_order: 0,
              is_active: true,
              metadata: { days: DEFAULT_COOLDOWN_DAYS, value: DEFAULT_COOLDOWN_DAYS },
            },
          },
          { upsert: true }
        );
      } catch (err) {
        // 11000 (duplicate) is fine — another concurrent run already seeded it.
        if (err.code !== 11000) {
          console.warn('[taskOverdueAgent] cooldown seed failed:', err.message);
        }
      }
      return DEFAULT_COOLDOWN_DAYS;
    }
    const raw = Number(row.metadata?.days ?? row.metadata?.value);
    if (!Number.isFinite(raw) || raw < 0) return DEFAULT_COOLDOWN_DAYS;
    return raw;
  } catch (err) {
    console.warn('[taskOverdueAgent] loadCooldownDays failed:', err.message);
    return DEFAULT_COOLDOWN_DAYS;
  }
}

/**
 * Build the actor name for the notification body. The notification reads
 * "X marked your task overdue" so a friendly system label keeps the inbox
 * row scannable.
 */
function actorName() {
  return 'Task Overdue Agent';
}

/**
 * Run entry point — standard agent signature called by agentExecutor.
 * Receives `{ triggerSource, runId, entity_id?, ignore_cooldown? }`.
 */
async function run(args = {}) {
  const startTime = Date.now();
  const entityFilter = { status: 'ACTIVE' };
  if (args.entity_id) entityFilter._id = args.entity_id;

  const entities = await Entity.find(entityFilter).select('_id entity_name short_name').lean();
  if (entities.length === 0) {
    return {
      status: 'success',
      summary: {
        bdms_processed: 0,
        alerts_generated: 0,
        alerts_suppressed: 0,
        messages_sent: 0,
        key_findings: ['No active entities'],
      },
      error_msg: null,
      message_ids: [],
      execution_ms: Date.now() - startTime,
    };
  }

  const ignoreCooldown = !!args.ignore_cooldown;
  const now = new Date();
  let bdmsProcessed = 0;
  let alertsGenerated = 0;
  let alertsSuppressed = 0;
  let messagesSent = 0;
  const errors = [];
  const findings = [];
  const seenAssignees = new Set();

  for (const entity of entities) {
    try {
      const cooldownDays = await loadCooldownDays(entity._id);
      const cooldownMs = Math.max(0, cooldownDays) * 24 * 60 * 60 * 1000;
      const cooldownSince = cooldownMs > 0 ? new Date(now.getTime() - cooldownMs) : null;

      // Pull every overdue task for this entity. Sort by oldest-due first so
      // the most stale items get notified first when SAFETY_TASK_LIMIT trips.
      const overdueTasks = await Task.find({
        entity_id: entity._id,
        status: { $in: ['OPEN', 'IN_PROGRESS', 'BLOCKED'] },
        due_date: { $ne: null, $lt: now },
        assignee_user_id: { $ne: null },
      })
        .sort({ due_date: 1 })
        .limit(SAFETY_TASK_LIMIT_PER_ENTITY)
        .select('_id title priority due_date assignee_user_id created_by last_overdue_notify_at')
        .lean();

      let entityFiredCount = 0;
      let entitySuppressedCount = 0;

      for (const task of overdueTasks) {
        alertsGenerated++;
        seenAssignees.add(String(task.assignee_user_id));

        // Cooldown gate (skipped when explicitly disabled via ignore_cooldown).
        if (cooldownSince && task.last_overdue_notify_at && task.last_overdue_notify_at > cooldownSince && !ignoreCooldown) {
          alertsSuppressed++;
          entitySuppressedCount++;
          continue;
        }

        // Stamp the dedup field BEFORE dispatching. If the notify fails the
        // field is still set — the next run will re-attempt after cooldown
        // expires. Better than firing twice: an extra missed alert is
        // recoverable; spam is not.
        try {
          await Task.updateOne(
            { _id: task._id },
            { $set: { last_overdue_notify_at: now } }
          );
        } catch (stampErr) {
          console.warn('[taskOverdueAgent] stamp failed:', stampErr.message);
          continue;
        }

        try {
          await notifyTaskEvent({
            entityId: entity._id,
            event: 'overdue',
            recipientUserId: task.assignee_user_id,
            actorName: actorName(),
            taskId: task._id,
            taskTitle: task.title,
            dueDate: task.due_date,
            priority: task.priority,
          });
          messagesSent++;
          entityFiredCount++;
        } catch (notifyErr) {
          // Notification failure is non-fatal but we surface in findings.
          console.warn('[taskOverdueAgent] notify failed:', notifyErr.message);
          errors.push(`task ${task._id}: ${notifyErr.message}`);
        }
      }

      findings.push(
        `${entity.short_name || entity.entity_name}: ${overdueTasks.length} overdue, ` +
        `${entityFiredCount} notified, ${entitySuppressedCount} suppressed (cooldown ${cooldownDays}d)`
      );
    } catch (err) {
      console.error(`[taskOverdueAgent] Entity ${entity._id} failed:`, err.message);
      errors.push(`${entity.short_name || entity.entity_name}: ${err.message}`);
    }
  }

  bdmsProcessed = seenAssignees.size;

  const summary = {
    bdms_processed: bdmsProcessed,
    alerts_generated: alertsGenerated,
    alerts_suppressed: alertsSuppressed,
    messages_sent: messagesSent,
    key_findings: [
      `Assignees with overdue tasks: ${bdmsProcessed}`,
      `Overdue tasks scanned: ${alertsGenerated} (notified ${messagesSent}; cooldown-suppressed ${alertsSuppressed})`,
      ...findings.slice(0, 5),
      ...(errors.length > 0 ? [`Errors: ${errors.length} — ${errors.slice(0, 2).join(' | ')}`] : []),
    ],
  };

  return {
    status: errors.length > 0 && messagesSent === 0 ? 'error' : (errors.length > 0 ? 'partial' : 'success'),
    summary,
    error_msg: errors.length > 0 ? errors.slice(0, 5).join(' | ') : null,
    message_ids: [],
    execution_ms: Date.now() - startTime,
  };
}

module.exports = { run };

/**
 * Treasury & Cash Flow Agent (P2-1) — Phase G8
 * Schedule: weekdays 5:30 AM Asia/Manila.
 *
 * Rule-based: sums current bank balances, upcoming 14-day PRF/CALF cash outflow,
 * expected 14-day collection inflow, and inter-entity imbalances. Posts a daily
 * brief to PRESIDENT inbox.
 *
 * AI toggle (TREASURY_AGENT_AI_MODE): when value === 'ai' AND ANTHROPIC_API_KEY
 * present AND AI_SPEND_CAPS allow, appends a Claude-generated narrative. Gated
 * via enforceSpendCap() — never bypasses the budget.
 */
'use strict';

const mongoose = require('mongoose');
const { notify, countSuccessfulChannels, getInAppMessageIds } = require('./notificationService');

function peso(n) { return `₱${(Number(n) || 0).toLocaleString('en-PH', { maximumFractionDigits: 0 })}`; }
function tryModel(name) { try { return mongoose.model(name); } catch { return null; } }

async function getAiMode() {
  try {
    const Lookup = require('../erp/models/Lookup');
    const row = await Lookup.findOne({ category: 'TREASURY_AGENT_AI_MODE', code: 'DEFAULT', is_active: { $ne: false } }).lean();
    return row?.metadata?.value === 'ai' ? 'ai' : 'rule';
  } catch { return 'rule'; }
}

async function sumBankBalances() {
  const BankAccount = tryModel('BankAccount');
  if (!BankAccount) return { total: 0, byBank: [] };
  const rows = await BankAccount.find({ is_active: { $ne: false } }).select('bank_name current_balance').lean();
  const total = rows.reduce((s, r) => s + (Number(r.current_balance) || 0), 0);
  const byBank = rows.slice(0, 5).map(r => ({ bank: r.bank_name, bal: Number(r.current_balance) || 0 }));
  return { total, byBank };
}

async function sumUpcomingOutflows() {
  const PrfCalf = tryModel('PrfCalf');
  if (!PrfCalf) return { total: 0, count: 0 };
  // PrfCalf has no dedicated due_date / prf_date — lifecycle is period-based
  // (YYYY-MM) and status-gated. "Upcoming outflow" = SUBMITTED or APPROVED
  // (not yet POSTED) docs for the current or previous period. Use `amount`
  // (the canonical payable field) not a non-existent total_amount.
  const now = new Date();
  const currentPeriod = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  const prevDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  const prevPeriod = `${prevDate.getFullYear()}-${String(prevDate.getMonth() + 1).padStart(2, '0')}`;
  const agg = await PrfCalf.aggregate([
    {
      $match: {
        status: { $in: ['SUBMITTED', 'APPROVED'] },
        period: { $in: [currentPeriod, prevPeriod] },
      },
    },
    { $group: { _id: null, total: { $sum: { $ifNull: ['$amount', 0] } }, count: { $sum: 1 } } },
  ]);
  return { total: agg[0]?.total || 0, count: agg[0]?.count || 0 };
}

async function sumExpectedInflows() {
  const Collection = tryModel('Collection');
  if (!Collection) return { total: 0, count: 0 };
  const now = new Date();
  const weekAgo = new Date(now.getTime() - 7 * 24 * 3600 * 1000);
  const agg = await Collection.aggregate([
    { $match: { status: 'POSTED', cr_date: { $gte: weekAgo } } },
    { $group: { _id: null, total: { $sum: { $ifNull: ['$cr_amount', 0] } }, count: { $sum: 1 } } },
  ]);
  return { total: agg[0]?.total || 0, count: agg[0]?.count || 0 };
}

async function buildBody() {
  const [bank, out, inn] = await Promise.all([sumBankBalances(), sumUpcomingOutflows(), sumExpectedInflows()]);
  const runway = bank.total > 0 && out.total > 0 ? Math.round((bank.total / (out.total / 14)) * 10) / 10 : null;

  const lines = [
    `Cash on hand: ${peso(bank.total)} across ${bank.byBank.length} bank account(s).`,
    bank.byBank.length ? `  Top balances: ${bank.byBank.map(b => `${b.bank} ${peso(b.bal)}`).join('; ')}` : '',
    `Next 14-day outflow (PRF/CALF due): ${peso(out.total)} across ${out.count} doc(s).`,
    `Trailing 7-day collection inflow: ${peso(inn.total)} across ${inn.count} CR(s).`,
    runway ? `Indicative cash runway vs upcoming outflow: ~${runway} day(s).` : '',
  ].filter(Boolean);

  return lines.join('\n');
}

async function run() {
  try {
    const aiMode = await getAiMode();
    let body = await buildBody();

    if (aiMode === 'ai' && process.env.ANTHROPIC_API_KEY) {
      try {
        const { enforceSpendCap } = require('../erp/services/spendCapService');
        await enforceSpendCap(null, 'TREASURY_AGENT');
        const { askClaude } = require('./claudeClient');
        const r = await askClaude({
          system: 'You are a treasury risk commentator. Read the numbers and add 2-3 crisp sentences highlighting concentration risk, timing mismatches, and recommended transfers. No disclaimers.',
          prompt: `Cash brief:\n${body}`,
          maxTokens: 250,
          agent: 'treasury',
        });
        if (r?.text) body += `\n\n— Narrative —\n${r.text.trim()}`;
      } catch (e) {
        if (e?.reason !== 'SPEND_CAP_EXCEEDED') console.warn('[Treasury] AI append failed:', e.message);
      }
    }

    const results = await notify({
      recipient_id: 'PRESIDENT',
      title: 'Treasury Brief — Cash Position',
      body,
      category: 'briefing',
      priority: 'normal',
      channels: ['in_app', 'email'],
      agent: 'treasury',
    });

    return {
      status: 'success',
      summary: {
        alerts_generated: 1,
        messages_sent: countSuccessfulChannels(results, 'in_app'),
        key_findings: body.split('\n').slice(0, 5),
      },
      message_ids: getInAppMessageIds(results),
    };
  } catch (err) {
    console.error('[Treasury] Run failed:', err.message);
    return { status: 'error', summary: {}, message_ids: [], error_msg: err.message };
  }
}

module.exports = { run };

/**
 * Message Inbox Controller — Phase G9.R4 Unified Operational Inbox
 *
 * Handles inbox messages stored in `messages` collection (DB: vip-pharmacy-crm).
 *
 * Endpoints:
 *   GET    /api/messages                      List w/ filters (folder, requires_action, thread_id, counts=1)
 *   GET    /api/messages/counts               Lightweight unread + action_required counts
 *   GET    /api/messages/sent                 Admin sent items
 *   GET    /api/messages/thread/:thread_id    Full thread (oldest first)
 *   POST   /api/messages                      Admin generic compose
 *   POST   /api/messages/notify               Admin → specific user (compliance alert)
 *   POST   /api/messages/compose              Two-way DM compose (any role w/ messaging.* sub-perm)
 *   POST   /api/messages/:id/reply            Reply to a message (threaded)
 *   POST   /api/messages/:id/action           Execute the row's action (approve/reject/resolve/acknowledge)
 *   PATCH  /api/messages/:id/read             Per-user read
 *   PATCH  /api/messages/:id/unread           Per-user unread
 *
 * Entity scoping (Rule #21):
 *   - Privileged users (president/ceo/admin/finance) can pass ?entity_id=
 *     to scope queries; absent = no entity filter (see everything visible).
 *   - Non-privileged users always filter by their req.user.entity_id.
 *   - Writes always stamp the resolved entity_id on the new row.
 *
 * Folder derivation: writes that don't pass an explicit folder fall back to
 * folderForCategory() so the row lands in the right tab even when callers are
 * legacy.
 */

const mongoose = require('mongoose');
const { catchAsync, NotFoundError } = require('../middleware/errorHandler');
const { ROLES, isAdminLike } = require('../constants/roles');
const MessageInbox = require('../models/MessageInbox');
const {
  folderForCategory,
  canDm,
  canBroadcast,
  getFoldersConfig,
  getActionsConfig,
} = require('../erp/utils/inboxLookups');

const getMessageModel = () => MessageInbox;

/* ------------------------------------------------------------------ */
/* Helpers                                                            */
/* ------------------------------------------------------------------ */

const PRIVILEGED_ROLES = new Set([
  ROLES.PRESIDENT, ROLES.CEO, ROLES.ADMIN, ROLES.FINANCE,
]);
const isPrivileged = (role) => PRIVILEGED_ROLES.has(role);

/**
 * Resolve the entity_id to scope the query/write by. Privileged users may
 * pass `?entity_id=` (or X-Entity-Id header for ERP routes); absent means
 * "no entity filter — see everything I'm entitled to" per Rule #21 — never
 * silently fall back to `req.user.entity_id` for privileged users.
 */
const resolveEntityScope = (req) => {
  const headerEntity = req.headers?.['x-entity-id'];
  const queryEntity = req.query?.entity_id;
  if (isPrivileged(req.user.role)) {
    const raw = (queryEntity || headerEntity || '').toString();
    if (raw && /^[a-f\d]{24}$/i.test(raw)) {
      return new mongoose.Types.ObjectId(raw);
    }
    return null; // privileged + no override = no entity filter
  }
  // Non-privileged: always pinned to user's primary entity_id
  return req.user.entity_id || (Array.isArray(req.user.entity_ids) && req.user.entity_ids.length > 0 ? req.user.entity_ids[0] : null);
};

/**
 * Build the audience filter for "messages I should see":
 *   - broadcast (recipientUserId null/missing) AND recipientRole === my role
 *   - targeted to me directly (recipientUserId === my _id)
 *
 * NOT to be confused with entity scoping — the entity filter is layered on
 * top of this when applicable.
 */
const buildAudienceFilter = (user) => ({
  $or: [
    {
      recipientRole: user.role,
      $or: [
        { recipientUserId: { $exists: false } },
        { recipientUserId: null },
      ],
    },
    { recipientUserId: user._id },
  ],
});

const toInboxDTO = (doc, userId) => {
  const obj = typeof doc.toObject === 'function' ? doc.toObject() : doc;
  const userIdStr = String(userId);
  const read = Array.isArray(obj.readBy)
    ? obj.readBy.some((id) => String(id) === userIdStr)
    : false;
  // Phase G9.R8 — per-recipient archive + acknowledgement DTO projection.
  const archived = Array.isArray(obj.archivedBy)
    ? obj.archivedBy.some((id) => String(id) === userIdStr)
    : false;
  const ackList = Array.isArray(obj.acknowledgedBy) ? obj.acknowledgedBy : [];
  const myAck = ackList.find((e) => String(e.user) === userIdStr);
  return {
    _id: String(obj._id),
    senderName: obj.senderName,
    senderRole: obj.senderRole,
    senderUserId: obj.senderUserId ? String(obj.senderUserId) : null,
    recipientRole: obj.recipientRole,
    recipientUserId: obj.recipientUserId ? String(obj.recipientUserId) : null,
    title: obj.title,
    body: obj.body,
    category: obj.category,
    priority: obj.priority,
    folder: obj.folder || folderForCategory(obj.category),
    entity_id: obj.entity_id ? String(obj.entity_id) : null,
    thread_id: obj.thread_id ? String(obj.thread_id) : null,
    parent_message_id: obj.parent_message_id ? String(obj.parent_message_id) : null,
    requires_action: !!obj.requires_action,
    action_type: obj.action_type || null,
    action_payload: obj.action_payload || null,
    action_completed_at: obj.action_completed_at || null,
    action_completed_by: obj.action_completed_by ? String(obj.action_completed_by) : null,
    // Per-recipient state — what THIS caller sees:
    archived,
    must_acknowledge: !!obj.must_acknowledge,
    acknowledged_by_me: !!myAck,
    acknowledged_at: myAck ? myAck.at : null,
    // Aggregate ack count (sender/admin uses this to decide if a read-receipts
    // modal is worth opening). Full per-user breakdown is in GET /:id/ack-status.
    acknowledged_count: ackList.length,
    createdAt: obj.createdAt,
    read,
  };
};

const isObjectId = (v) => typeof v === 'string' && /^[a-f\d]{24}$/i.test(v);

/* ------------------------------------------------------------------ */
/* GET /api/messages                                                  */
/* ------------------------------------------------------------------ */
const getInboxMessages = catchAsync(async (req, res) => {
  const Message = getMessageModel();

  const page = Math.max(1, parseInt(req.query.page, 10) || 1);
  const limit = Math.min(100, Math.max(1, parseInt(req.query.limit, 10) || 20));
  const skip = (page - 1) * limit;

  const folder = (req.query.folder || '').toString().toUpperCase();
  const category = req.query.category;
  const status = req.query.status;
  const requiresActionParam = req.query.requires_action;
  const threadId = req.query.thread_id;
  const search = (req.query.search || '').trim();
  const wantCounts = req.query.counts === '1' || req.query.counts === 'true';

  // Phase G9.R8 — archivedBy replaces the single isArchived bool. Default
  // view hides messages archived BY the current caller; sibling recipients
  // still see the message. Also hide retention-soft-deleted rows so soft-
  // deleted items drop out of the inbox immediately without waiting for the
  // grace-period hard purge.
  const filter = {
    archivedBy: { $ne: req.user._id },
    deletion_candidate: { $ne: true },
    ...buildAudienceFilter(req.user),
  };

  // Entity scoping (Rule #21)
  const entityScope = resolveEntityScope(req);
  if (entityScope) filter.entity_id = entityScope;

  // Folder filter — virtual folders are computed (ARCHIVE / SENT / INBOX /
  // ACTION_REQUIRED), real folders match folder field directly.
  if (folder && folder !== 'INBOX') {
    if (folder === 'ARCHIVE') {
      // Flip the archive filter: show only messages archived by me.
      filter.archivedBy = req.user._id;
    } else if (folder === 'SENT') {
      // SENT is a sender-side filter: drop audience filter AND the
      // per-recipient archive filter (sender's Sent list is their authoritative
      // outbox regardless of what recipients did with their copies).
      delete filter.$or;
      delete filter.archivedBy;
      filter.senderUserId = req.user._id;
    } else if (folder === 'ACTION_REQUIRED') {
      filter.requires_action = true;
      filter.action_completed_at = null;
    } else {
      filter.folder = folder;
    }
  }

  if (category && category !== 'all') {
    const cats = category.split(',').map((c) => c.trim()).filter(Boolean);
    filter.category = cats.length > 1 ? { $in: cats } : cats[0];
  }

  if (status === 'read') filter.readBy = req.user._id;
  else if (status === 'unread') filter.readBy = { $ne: req.user._id };

  if (requiresActionParam === '1' || requiresActionParam === 'true') {
    filter.requires_action = true;
    filter.action_completed_at = null;
  }

  if (threadId && isObjectId(threadId)) {
    filter.thread_id = new mongoose.Types.ObjectId(threadId);
  }

  if (search) {
    // search is overlaid on top of the audience filter — combine with $and
    // since both branches use $or
    const searchOr = [
      { title: { $regex: search, $options: 'i' } },
      { body: { $regex: search, $options: 'i' } },
      { senderName: { $regex: search, $options: 'i' } },
    ];
    if (filter.$or) {
      filter.$and = [{ $or: filter.$or }, { $or: searchOr }];
      delete filter.$or;
    } else {
      filter.$or = searchOr;
    }
  }

  const [docs, total] = await Promise.all([
    Message.find(filter).sort({ createdAt: -1 }).skip(skip).limit(limit),
    Message.countDocuments(filter),
  ]);

  const response = {
    success: true,
    data: docs.map((d) => toInboxDTO(d, req.user._id)),
    pagination: { page, limit, total, pages: Math.ceil(total / limit) || 1 },
  };

  if (wantCounts) {
    response.counts = await computeFolderCounts(req, entityScope);
  }

  res.status(200).json(response);
});

/* ------------------------------------------------------------------ */
/* GET /api/messages/counts                                           */
/* ------------------------------------------------------------------ */
// Single-scan $group aggregation: all 8 counts are derived from one pass
// over the base-filter working set using $sum + $cond. This replaces the
// previous 8-query fan-out (which did 8 separate collection scans) with
// exactly one IXSCAN over the { entity_id, folder, createdAt } index.
const ZERO_COUNTS = Object.freeze({
  inbox: 0,
  unread: 0,
  unacknowledged: 0,
  action_required: 0,
  approvals: 0,
  tasks: 0,
  ai_agent_reports: 0,
  announcements: 0,
  chat: 0,
});

const computeFolderCounts = async (req, entityScope) => {
  const Message = getMessageModel();
  const baseAud = buildAudienceFilter(req.user);
  // Phase G9.R8 — hide per-user archived rows + soft-deleted rows from counts
  // (so the folder badges reflect "what I'd actually see in my inbox").
  const baseFilter = {
    archivedBy: { $ne: req.user._id },
    deletion_candidate: { $ne: true },
    ...baseAud,
  };
  if (entityScope) baseFilter.entity_id = entityScope;

  // Defensive cast: `$in` in aggregation does strict type-match. If auth
  // middleware ever normalises req.user._id to a string, comparing it to
  // BSON ObjectIds in `$readBy` would miss every hit. Casting here keeps
  // the pipeline robust regardless of upstream type drift.
  const userId = mongoose.Types.ObjectId.isValid(req.user._id)
    ? new mongoose.Types.ObjectId(req.user._id)
    : req.user._id;
  const pipeline = [
    { $match: baseFilter },
    {
      $group: {
        _id: null,
        inbox: { $sum: 1 },
        unread: {
          $sum: {
            $cond: [
              { $not: [{ $in: [userId, { $ifNull: ['$readBy', []] }] }] },
              1,
              0,
            ],
          },
        },
        // Phase G9.R8 — Unacknowledged count.
        //   Counts messages where must_acknowledge=true AND the current user's
        //   id does NOT appear in acknowledgedBy.user. Uses a $filter over the
        //   (small) acknowledgedBy array — cheap even for large inboxes since
        //   the array rarely exceeds the role-members count.
        unacknowledged: {
          $sum: {
            $cond: [
              {
                $and: [
                  { $eq: ['$must_acknowledge', true] },
                  {
                    $eq: [
                      {
                        $size: {
                          $filter: {
                            input: { $ifNull: ['$acknowledgedBy', []] },
                            cond: { $eq: ['$$this.user', userId] },
                          },
                        },
                      },
                      0,
                    ],
                  },
                ],
              },
              1,
              0,
            ],
          },
        },
        action_required: {
          $sum: {
            $cond: [
              {
                $and: [
                  { $eq: ['$requires_action', true] },
                  { $eq: ['$action_completed_at', null] },
                ],
              },
              1,
              0,
            ],
          },
        },
        approvals:        { $sum: { $cond: [{ $eq: ['$folder', 'APPROVALS'] }, 1, 0] } },
        tasks:            { $sum: { $cond: [{ $eq: ['$folder', 'TASKS'] }, 1, 0] } },
        ai_agent_reports: { $sum: { $cond: [{ $eq: ['$folder', 'AI_AGENT_REPORTS'] }, 1, 0] } },
        announcements:    { $sum: { $cond: [{ $eq: ['$folder', 'ANNOUNCEMENTS'] }, 1, 0] } },
        chat:             { $sum: { $cond: [{ $eq: ['$folder', 'CHAT'] }, 1, 0] } },
      },
    },
  ];

  const rows = await Message.aggregate(pipeline);
  if (!rows.length) return { ...ZERO_COUNTS };

  const { _id, ...counts } = rows[0];
  return counts;
};

const getCounts = catchAsync(async (req, res) => {
  const entityScope = resolveEntityScope(req);
  const counts = await computeFolderCounts(req, entityScope);
  // Soft cache hint — clients poll every 30s; allow ~25s of caching to absorb spikes.
  res.set('Cache-Control', 'private, max-age=25');
  res.status(200).json({ success: true, data: counts });
});

/* ------------------------------------------------------------------ */
/* GET /api/messages/thread/:thread_id                                */
/* ------------------------------------------------------------------ */
const getThread = catchAsync(async (req, res) => {
  const Message = getMessageModel();
  const threadId = req.params.thread_id;
  if (!isObjectId(threadId)) {
    return res.status(400).json({ success: false, message: 'Invalid thread_id' });
  }

  // Phase G9.R8 — threads hide only the CALLER's archived rows + soft-deleted
  // rows. Other recipients' archives don't affect my view of the same thread.
  const filter = {
    thread_id: new mongoose.Types.ObjectId(threadId),
    archivedBy: { $ne: req.user._id },
    deletion_candidate: { $ne: true },
  };
  // Entity scoping for non-privileged callers
  const entityScope = resolveEntityScope(req);
  if (entityScope) filter.entity_id = entityScope;

  const docs = await Message.find(filter).sort({ createdAt: 1 }).limit(500);

  // Audience guard: caller must appear as recipient (broadcast-to-role or
  // direct) on at least one row, OR be the sender of at least one row, OR
  // be privileged.
  const visibleByAudience = isPrivileged(req.user.role) || docs.some((d) => {
    if (String(d.senderUserId) === String(req.user._id)) return true;
    if (String(d.recipientUserId) === String(req.user._id)) return true;
    if (!d.recipientUserId && d.recipientRole === req.user.role) return true;
    return false;
  });
  if (!visibleByAudience) {
    return res.status(403).json({ success: false, message: 'Thread not visible' });
  }

  res.status(200).json({
    success: true,
    data: docs.map((d) => toInboxDTO(d, req.user._id)),
    count: docs.length,
  });
});

/* ------------------------------------------------------------------ */
/* POST /api/messages (admin generic)                                 */
/* ------------------------------------------------------------------ */
const createInboxMessage = catchAsync(async (req, res) => {
  if (!isAdminLike(req.user.role)) {
    return res.status(403).json({ success: false, message: 'Only admins can create inbox messages.' });
  }
  const Message = getMessageModel();
  const {
    title, body, category, priority = 'normal',
    senderName, recipientRole, recipientUserId = null, folder = null,
  } = req.body;

  if (!title || !body || !category || !recipientRole) {
    return res.status(400).json({ success: false, message: 'title, body, category, recipientRole are required.' });
  }

  const entityScope = resolveEntityScope(req)
    || req.user.entity_id
    || (Array.isArray(req.user.entity_ids) && req.user.entity_ids.length > 0 ? req.user.entity_ids[0] : null);

  const doc = await Message.create({
    title,
    body,
    category,
    priority,
    senderName: senderName || req.user.name || 'Admin',
    senderRole: req.user.role || 'admin',
    senderUserId: req.user._id,
    recipientRole,
    recipientUserId,
    readBy: [],
    archivedBy: [],
    acknowledgedBy: [],
    entity_id: entityScope,
    folder: folder || folderForCategory(category),
  });

  res.status(201).json({ success: true, data: toInboxDTO(doc, req.user._id) });
});

