 */
const override = catchAsync(async (req, res) => {
  const { vendor_id, supplier_name, new_coa_code, new_category, save_as_default } = req.body;

  if (!new_coa_code) {
    return res.status(400).json({ success: false, message: 'new_coa_code is required' });
