// ─────────────────────────────────────────────────────────────────────────────
// SG-5 #26 — What-if / scenario modeling endpoint.
//
// POST /sales-goals/plans/:id/simulate
// Body: { target_revenue_override?, baseline_override?, driver_weight_overrides?,
//         tier_attainment_overrides? }
//
// Pure read + compute — no DB writes, no journal post, no approval gate. Any
// user with sales_goals VIEW can exercise the modeler; privileged roles see
// all BDMs in the output while contractors see only themselves (scope-filter
// applied post-compute so the math is always full-company).
// ─────────────────────────────────────────────────────────────────────────────
exports.simulatePlan = catchAsync(async (req, res) => {
  const plan = await SalesGoalPlan.findById(req.params.id).lean();
  if (!plan) return res.status(404).json({ success: false, message: 'Plan not found' });

  // Enforce entity scope — even president/admin are pinned to their current
  // req.entityId unless they switched context via the entity switcher.
  if (!req.isPresident && String(plan.entity_id) !== String(req.entityId)) {
    return res.status(403).json({ success: false, message: 'Plan is in a different entity' });
  }

  const overrides = req.body || {};
  const result = await salesGoalService.simulatePlanSnapshots(plan, overrides);

  // BDM scoping (Rule #21 alignment): contractors see only their own row.
  const canSeeAll = req.isPresident || req.isAdmin || req.isFinance;
  const rows = canSeeAll
    ? result.rows
    : result.rows.filter(r => String(r.bdm_id) === String(req.user._id));

  res.json({
    success: true,
    data: {
      plan: {
        _id: plan._id,
        plan_name: plan.plan_name,
        fiscal_year: plan.fiscal_year,
        reference: plan.reference || '',
        status: plan.status,
      },
      plan_overrides: result.plan_overrides,
      drivers: result.drivers,
      rows,
      summary: canSeeAll
        ? result.summary
        : {
          // BDM-scoped summary only reflects their own row.
          bdm_count: rows.length,
          current: {
            total_incentive_budget: rows.reduce((s, r) => s + r.tier_budget_current, 0),
            total_actual_revenue: rows.reduce((s, r) => s + r.sales_actual, 0),
            attainment_pct: rows[0]?.attainment_current || 0,
          },
          scenario: {
            total_incentive_budget: rows.reduce((s, r) => s + r.tier_budget_scenario, 0),
            total_actual_revenue: rows.reduce((s, r) => s + r.sales_actual, 0),
            attainment_pct: rows[0]?.attainment_scenario || 0,
          },
          diff: {
            total_incentive_budget: rows.reduce((s, r) => s + r.budget_delta, 0),
          },
        },
      config: result.config,
      tiers: result.tiers,
    },
  });
});

// ─────────────────────────────────────────────────────────────────────────────
// SG-5 #28 — Year-over-Year / Quarter-over-Quarter trending endpoint.
//
// GET /sales-goals/trending?fiscal_year=&bdm_id=&kpi_code=
//
// Joins the current fiscal year's YTD KpiSnapshot with prior fiscal year(s) by
// (bdm_id, kpi_code) so the dashboard can render a "2025 vs 2026" comparison.
// Plan-version-aware (SG-4 #21): snapshots are keyed by plan_id which in turn
// belongs to a specific IncentivePlan version, so YoY comparisons implicitly
// use each year's active version at the time the snapshot was written.
//
// Output structure:
//   {
//     fiscal_year_current: 2026,
//     fiscal_year_prior:   2025,
//     company: { revenue: {current, prior, delta_pct}, attainment: {...} },
//     per_bdm: [{ bdm_id, name, current_revenue, prior_revenue, delta_pct,
//                 current_attainment, prior_attainment, kpi_trends: [...] }],
//     per_kpi: [{ kpi_code, kpi_label, current_avg, prior_avg, delta_pct }],
//   }
// ─────────────────────────────────────────────────────────────────────────────
exports.getTrending = catchAsync(async (req, res) => {
  const fiscalYear = Number(req.query.fiscal_year) || new Date().getFullYear();
  const priorYear = fiscalYear - 1;
  const entityId = req.entityId;

  const canSeeAll = req.isPresident || req.isAdmin || req.isFinance;
  const bdmScope = canSeeAll && req.query.bdm_id
    ? req.query.bdm_id
    : (canSeeAll ? null : req.user._id);

  // Snapshots for both years — YTD only (annual roll-up is the comparable unit).
  const match = {
    entity_id: new mongoose.Types.ObjectId(entityId),
    period_type: 'YTD',
    fiscal_year: { $in: [fiscalYear, priorYear] },
  };
  if (bdmScope) match.bdm_id = new mongoose.Types.ObjectId(bdmScope);

  const snapshots = await KpiSnapshot.find(match)
    .populate('person_id', 'full_name bdm_code is_active')
    .lean();

  // Bucket by (bdm_id, fiscal_year)
  const byBdm = new Map();
  for (const s of snapshots) {
    if (s.person_id && s.person_id.is_active === false) continue;
    const bdmKey = String(s.bdm_id || '');
    if (!byBdm.has(bdmKey)) {
      byBdm.set(bdmKey, {
        bdm_id: s.bdm_id,
        name: s.person_id?.full_name || 'Unknown',
        bdm_code: s.person_id?.bdm_code || '',
        years: new Map(),
      });
    }
    byBdm.get(bdmKey).years.set(s.fiscal_year, s);
  }

  const filterKpiCode = req.query.kpi_code ? String(req.query.kpi_code).toUpperCase() : null;

  // Per-BDM rows
  const perBdm = [];
  let companyCurrent = 0;
  let companyPrior = 0;
  let companyCurrentAtt = 0;
  let companyPriorAtt = 0;
  let companyCurrentCount = 0;
  let companyPriorCount = 0;

  for (const { bdm_id, name, bdm_code, years } of byBdm.values()) {
    const cur = years.get(fiscalYear);
    const prior = years.get(priorYear);

    const curRev = Number(cur?.sales_actual) || 0;
    const priorRev = Number(prior?.sales_actual) || 0;
    const curAtt = Number(cur?.sales_attainment_pct) || 0;
    const priorAtt = Number(prior?.sales_attainment_pct) || 0;

    companyCurrent += curRev;
    companyPrior += priorRev;
    if (cur) { companyCurrentAtt += curAtt; companyCurrentCount++; }
    if (prior) { companyPriorAtt += priorAtt; companyPriorCount++; }

    // Per-KPI comparison — joined by kpi_code across both years
    const curKpiMap = new Map();
    for (const d of (cur?.driver_kpis || [])) {
      for (const k of (d.kpis || [])) {
        if (filterKpiCode && String(k.kpi_code).toUpperCase() !== filterKpiCode) continue;
        curKpiMap.set(String(k.kpi_code).toUpperCase(), k);
      }
    }
    const priorKpiMap = new Map();
    for (const d of (prior?.driver_kpis || [])) {
      for (const k of (d.kpis || [])) {
        if (filterKpiCode && String(k.kpi_code).toUpperCase() !== filterKpiCode) continue;
        priorKpiMap.set(String(k.kpi_code).toUpperCase(), k);
      }
    }
    const allKpiCodes = new Set([...curKpiMap.keys(), ...priorKpiMap.keys()]);
    const kpiTrends = [];
    for (const code of allKpiCodes) {
      const curK = curKpiMap.get(code);
      const priorK = priorKpiMap.get(code);
      kpiTrends.push({
        kpi_code: code,
        kpi_label: curK?.kpi_label || priorK?.kpi_label || code,
        current_value: Number(curK?.actual_value) || 0,
        prior_value: Number(priorK?.actual_value) || 0,
        current_attainment: Number(curK?.attainment_pct) || 0,
        prior_attainment: Number(priorK?.attainment_pct) || 0,
      });
    }

    perBdm.push({
      bdm_id,
      name,
      bdm_code,
      current_revenue: curRev,
      prior_revenue: priorRev,
      revenue_delta: curRev - priorRev,
      revenue_delta_pct: priorRev > 0 ? Math.round(((curRev - priorRev) / priorRev) * 1000) / 10 : 0,
      current_attainment: curAtt,
      prior_attainment: priorAtt,
      attainment_delta: curAtt - priorAtt,
      kpi_trends: kpiTrends,
    });
  }

  // Aggregate per-KPI across BDMs
  const perKpiMap = new Map();
  for (const row of perBdm) {
    for (const k of row.kpi_trends) {
      if (!perKpiMap.has(k.kpi_code)) {
        perKpiMap.set(k.kpi_code, {
          kpi_code: k.kpi_code,
          kpi_label: k.kpi_label,
          current_sum: 0, prior_sum: 0,
          current_count: 0, prior_count: 0,
        });
      }
      const agg = perKpiMap.get(k.kpi_code);
      if (k.current_value || k.current_attainment) { agg.current_sum += k.current_value; agg.current_count++; }
      if (k.prior_value || k.prior_attainment) { agg.prior_sum += k.prior_value; agg.prior_count++; }
    }
  }
  const perKpi = [...perKpiMap.values()].map(a => {
    const curAvg = a.current_count > 0 ? a.current_sum / a.current_count : 0;
    const priorAvg = a.prior_count > 0 ? a.prior_sum / a.prior_count : 0;
    return {
      kpi_code: a.kpi_code,
      kpi_label: a.kpi_label,
      current_avg: Math.round(curAvg * 100) / 100,
      prior_avg: Math.round(priorAvg * 100) / 100,
      delta_pct: priorAvg > 0 ? Math.round(((curAvg - priorAvg) / priorAvg) * 1000) / 10 : 0,
    };
  });

  res.json({
    success: true,
    data: {
      fiscal_year_current: fiscalYear,
      fiscal_year_prior: priorYear,
      company: {
        revenue: {
          current: companyCurrent,
          prior: companyPrior,
          delta_pct: companyPrior > 0 ? Math.round(((companyCurrent - companyPrior) / companyPrior) * 1000) / 10 : 0,
        },
        attainment: {
          current: companyCurrentCount > 0 ? Math.round((companyCurrentAtt / companyCurrentCount) * 10) / 10 : 0,
          prior: companyPriorCount > 0 ? Math.round((companyPriorAtt / companyPriorCount) * 10) / 10 : 0,
        },
        bdm_count_current: companyCurrentCount,
        bdm_count_prior: companyPriorCount,
      },
      per_bdm: perBdm,
      per_kpi: perKpi,
    },
  });
});

// ─────────────────────────────────────────────────────────────────────────────
// SG-5 #27 — Variance Alert Center endpoints.
// Implemented in backend/erp/controllers/varianceAlertController.js (sibling
// file) to keep controller sizes manageable. Exports re-declared there.
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// Phase SG-6 #31 — Mid-period target revision workflow.
//
// POST /sales-goal-targets/:id/revise — alternative to reopening the whole
// plan when only a single BDM/entity target needs adjustment mid-period.
// Writes an append-only TargetRevision sub-doc so historical snapshots stay
// tied to the value that was active when they were computed.
//
// Behavior:
//  - Requires `revision_reason` (non-empty).
//  - Gated via gateApproval(module: 'SALES_GOAL_PLAN', docType: 'TARGET_REVISION').
//  - Feature is opt-in per entity via MID_PERIOD_REVISION_ENABLED lookup
//    (default disabled — reopen-plan remains the canonical path unless admin
//    flips the lookup).
//  - Atomic under one transaction. Emits integration event `target.revised`.
// ─────────────────────────────────────────────────────────────────────────────
exports.reviseTarget = catchAsync(async (req, res) => {
  const target = await SalesGoalTarget.findById(req.params.id);
  if (!target) return res.status(404).json({ success: false, message: 'Target not found' });

  // Feature toggle via lookup — default is disabled for safety. Subscribers
  // opt in per-entity via Control Center → MID_PERIOD_REVISION_ENABLED.
  const toggleRow = await Lookup.findOne({
    entity_id: target.entity_id,
    category: 'MID_PERIOD_REVISION_ENABLED',
    is_active: true,
  }).lean();
  const enabled = toggleRow?.metadata?.value === true || toggleRow?.metadata?.enabled === true;
  if (!enabled) {
    return res.status(403).json({
      success: false,
      message: 'Mid-period target revision is not enabled for this entity. Enable MID_PERIOD_REVISION_ENABLED in Control Center → Lookup Tables, or reopen the plan instead.',
    });
  }

  const plan = await SalesGoalPlan.findById(target.plan_id).lean();
  if (!plan) return res.status(404).json({ success: false, message: 'Linked plan not found' });
  if (plan.status !== 'ACTIVE') {
    return res.status(400).json({ success: false, message: `Plan status is ${plan.status}. Revisions apply only to ACTIVE plans.` });
  }

  // Period-lock check against the plan's fiscal year for SALES_GOAL module.
  // Mirrors periodLockCheckByPlan middleware (the :id on this route is the
  // target, not the plan — so we run the same check here where we have the
  // plan in hand).
  try {
    const PeriodLock = require('../models/PeriodLock');
    const lock = await PeriodLock.findOne({
      entity_id: plan.entity_id,
      module: 'SALES_GOAL',
      year: plan.fiscal_year,
      is_locked: true,
    }).select('month').lean();
    if (lock) {
      const monthName = new Date(plan.fiscal_year, lock.month - 1).toLocaleString('en', { month: 'long' });
      return res.status(403).json({
        success: false,
        message: `Period ${monthName} ${plan.fiscal_year} is locked for SALES_GOAL. Unlock the period in Control Center → Period Locks before revising.`,
      });
    }
  } catch (err) {
    // PeriodLock model resolution failure — defense in depth, don't block
    // the revise entirely, let the authority gate still run.
    console.warn('[reviseTarget] period-lock check skipped:', err.message);
  }

  const reason = String(req.body.revision_reason || '').trim();
  if (!reason) {
    return res.status(400).json({ success: false, message: 'revision_reason is required' });
  }

  // Parse new values. Missing fields = "keep current value".
  const newSalesTarget = req.body.sales_target != null ? Number(req.body.sales_target) : target.sales_target;
  const newCollectionTarget = req.body.collection_target != null
    ? Number(req.body.collection_target)
    : Math.round(newSalesTarget * (Number(plan.collection_target_pct) || 0));

  if (Number.isNaN(newSalesTarget) || newSalesTarget < 0) {
    return res.status(400).json({ success: false, message: 'sales_target must be a non-negative number' });
  }
  if (Number.isNaN(newCollectionTarget) || newCollectionTarget < 0) {
    return res.status(400).json({ success: false, message: 'collection_target must be a non-negative number' });
  }
  const noChange = newSalesTarget === target.sales_target && newCollectionTarget === target.collection_target;
  if (noChange) {
    return res.status(400).json({ success: false, message: 'No change — sales_target and collection_target are the same as current' });
  }

  // Default-Roles Gate (Phase G4). The amount is the delta (signed) so the
  // authority matrix can threshold on magnitude of adjustment.
  const gated = await gateApproval({
    entityId: plan.entity_id,
    module: 'SALES_GOAL_PLAN',
    docType: 'TARGET_REVISION',
    docId: target._id,
    docRef: `${plan.reference || plan.plan_name} · ${target.target_label || target.target_type}`,
    amount: Math.abs(newSalesTarget - target.sales_target),
    description: `Mid-period target revision — ${target.target_label || target.target_type}: ₱${target.sales_target.toLocaleString()} → ₱${newSalesTarget.toLocaleString()}`,
    requesterId: req.user._id,
    requesterName: req.user.name || req.user.email,
  }, res);
  if (gated) return;

  const priorSales = target.sales_target;
  const priorCollection = target.collection_target;

  const session = await mongoose.startSession();
  try {
    await session.withTransaction(async () => {
      target.target_revisions.push({
        revised_at: new Date(),
        revised_by: req.user._id,
        revision_reason: reason,
        prior_sales_target: priorSales,
        prior_collection_target: priorCollection,
        source: 'MANUAL',
      });
      target.sales_target = newSalesTarget;
      target.collection_target = newCollectionTarget;
      await target.save({ session });

      await ErpAuditLog.logChange([{
        entity_id: plan.entity_id,
        log_type: 'STATUS_CHANGE',
        target_ref: target._id.toString(),
        target_model: 'SalesGoalTarget',
        field_changed: 'sales_target',
        old_value: String(priorSales),
        new_value: String(newSalesTarget),
        changed_by: req.user._id,
        note: `[SG-6 #31] Mid-period revision — ${target.target_label || target.target_type}. Reason: ${reason}`,
      }], { session });
    });
  } finally {
    session.endSession();
  }

  // Emit integration event (non-blocking). Payroll/HR subscribers can react.
  try {
    const integrationHooks = require('../services/integrationHooks');
    integrationHooks.emit(integrationHooks.INTEGRATION_EVENTS.TARGET_REVISED, {
      entity_id: plan.entity_id,
      actor_id: req.user._id,
      ref: String(target._id),
      data: {
        plan_id: String(plan._id),
        plan_ref: plan.reference,
        target_type: target.target_type,
        target_label: target.target_label,
        prior_sales_target: priorSales,
        new_sales_target: newSalesTarget,
        prior_collection_target: priorCollection,
        new_collection_target: newCollectionTarget,
        reason,
      },
    });
  } catch (err) {
    console.warn('[reviseTarget] integrationHooks.emit skipped:', err.message);
  }

  res.json({
    success: true,
    data: target,
    message: `Target revised: ₱${priorSales.toLocaleString()} → ₱${newSalesTarget.toLocaleString()}. Historical snapshots preserved; future snapshots will use the new value.`,
  });
});

// ─────────────────────────────────────────────────────────────────────────────
// Phase SG-6 #29 — SOX Control Matrix endpoint.
//
// GET /sales-goals/sox-control-matrix — read-only endpoint that materializes
// a control matrix for every Sales Goal state change + segregation-of-duties
// findings. Lives in the sibling controller `soxControlMatrixController.js`
// to keep this file manageable; route delegates there.
// ─────────────────────────────────────────────────────────────────────────────

const PartnerScorecard = require('../models/PartnerScorecard');
const PeopleMaster = require('../models/PeopleMaster');
const ErpSettings = require('../models/Settings');
const AgentRun = require('../models/AgentRun');
const SalesLine = require('../models/SalesLine');
const Collection = require('../models/Collection');
const ExpenseEntry = require('../models/ExpenseEntry');
const Visit = require('../../models/Visit');
const Doctor = require('../../models/Doctor');
const Entity = require('../models/Entity');
const { catchAsync } = require('../../middleware/errorHandler');

/**
 * Scorecard Controller — Phase 24B
 * Aggregates CRM + ERP data into monthly partner scorecards.
 */

// ═══ Helpers ═══

function currentPeriod() {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
}

function monthStartEnd(period) {
  const [y, m] = period.split('-').map(Number);
  const start = new Date(y, m - 1, 1);
  const end = new Date(y, m, 0, 23, 59, 59, 999);
  return { start, end };
}



// ═══ Compute all scorecards ═══

exports.compute = catchAsync(async (req, res) => {
  const period = req.query.period || currentPeriod();
  const { start, end } = monthStartEnd(period);

  // Get entities — president computes all, others compute their own
  let entityIds;
  if (req.isPresident) {
    const entities = await Entity.find({ status: 'ACTIVE' }).select('_id').lean();
    entityIds = entities.map(e => e._id);
  } else {
    entityIds = [req.entityId];
  }

  // Get graduation criteria from settings
  const settings = await ErpSettings.getSettings();
  const gradCriteria = settings.GRADUATION_CRITERIA || [];
  const weights = settings.SCORECARD_WEIGHTS || { visits: 25, sales: 25, collections: 20, efficiency: 15, engagement: 15 };

  // Get all active partners across entities
  const partners = await PeopleMaster.find({
    entity_id: { $in: entityIds },
    person_type: { $in: ['BDM', 'ECOMMERCE_BDM', 'CONSULTANT'] },
    is_active: true,
  }).lean();

  // Compute org-wide averages for normalization
  const allSales = await SalesLine.aggregate([
    { $match: { entity_id: { $in: entityIds }, status: 'POSTED', csi_date: { $gte: start, $lte: end } } },
    { $group: { _id: null, total: { $sum: '$invoice_total' }, count: { $sum: 1 } } },
  ]);
  const orgAvgSales = partners.length > 0 ? (allSales[0]?.total || 0) / partners.length : 1;

  const results = [];

  for (const partner of partners) {
    const userId = partner.user_id;
    if (!userId) continue; // skip partners without CRM user link

    // ── Visits (CRM) ──
    const visitAgg = await Visit.aggregate([
      { $match: { user: userId, visitDate: { $gte: start, $lte: end } } },
      { $group: { _id: null, count: { $sum: 1 }, uniqueDoctors: { $addToSet: '$doctor' } } },
    ]);
    const visitsCompleted = visitAgg[0]?.count || 0;
    const uniqueClients = visitAgg[0]?.uniqueDoctors?.length || 0;

    // Expected visits = sum of assigned doctors' frequencies
    const doctors = await Doctor.find({ assignedTo: userId, isActive: true })
      .select('visitFrequency levelOfEngagement')
      .lean();
    const visitsExpected = doctors.reduce((sum, d) => sum + (d.visitFrequency || 2), 0);
    const visitCompliancePct = visitsExpected > 0 ? Math.min(100, Math.round((visitsCompleted / visitsExpected) * 100)) : 0;
    const avgEngagement = doctors.length > 0
      ? Math.round((doctors.reduce((s, d) => s + (d.levelOfEngagement || 1), 0) / doctors.length) * 10) / 10
      : 0;

    // ── Sales (ERP) ──
    const salesAgg = await SalesLine.aggregate([
      { $match: { entity_id: partner.entity_id, bdm_id: userId, status: 'POSTED', csi_date: { $gte: start, $lte: end } } },
      { $group: { _id: null, total: { $sum: '$invoice_total' }, count: { $sum: 1 } } },
    ]);
    const salesTotal = salesAgg[0]?.total || 0;
    const salesCount = salesAgg[0]?.count || 0;
    const avgInvoice = salesCount > 0 ? Math.round(salesTotal / salesCount) : 0;

    // ── Collections (ERP) ──
    const collAgg = await Collection.aggregate([
      { $match: { entity_id: partner.entity_id, bdm_id: userId, status: 'POSTED', cr_date: { $gte: start, $lte: end } } },
      { $group: { _id: null, total: { $sum: '$cr_amount' }, count: { $sum: 1 } } },
    ]);
    const collTotal = collAgg[0]?.total || 0;
    const collCount = collAgg[0]?.count || 0;
    const collRatePct = salesTotal > 0 ? Math.min(100, Math.round((collTotal / salesTotal) * 100)) : 0;

    // ── Expenses (ERP) ──
    const expAgg = await ExpenseEntry.aggregate([
      { $match: { entity_id: partner.entity_id, bdm_id: userId, status: { $in: ['POSTED', 'VALID'] }, period } },
      { $group: { _id: null, total: { $sum: '$total_amount' } } },
    ]);
    const expTotal = expAgg[0]?.total || 0;
    const expRatio = salesTotal > 0 ? Math.round((expTotal / salesTotal) * 100) : 0;

    // ── Clients at risk (doctors with low engagement or no recent visit) ──
    const thirtyDaysAgo = new Date(end.getTime() - 30 * 24 * 60 * 60 * 1000);
    const recentVisitDoctors = await Visit.distinct('doctor', {
      user: userId,
      visitDate: { $gte: thirtyDaysAgo },
    });
    const clientsAtRisk = Math.max(0, doctors.length - recentVisitDoctors.length);

    // ── Composite Scores (0-100) ──
    const scoreVisits = visitCompliancePct;
    const scoreSales = orgAvgSales > 0 ? Math.min(100, Math.round((salesTotal / orgAvgSales) * 50)) : 0;
    const scoreColl = collRatePct;
    const scoreEff = Math.max(0, Math.round(100 - expRatio * 2)); // 50% ratio = 0 score
    const scoreEng = Math.round((avgEngagement / 5) * 100);

    const scoreOverall = Math.round(
      (scoreVisits * weights.visits +
       scoreSales * weights.sales +
       scoreColl * weights.collections +
       scoreEff * weights.efficiency +
       scoreEng * weights.engagement) / 100
    );

    // ── Graduation criteria ──
    const monthsActive = partner.date_hired
      ? Math.floor((end - new Date(partner.date_hired)) / (30.44 * 24 * 60 * 60 * 1000))
      : 0;

    const criteriaActuals = {
      min_months_active: monthsActive,
      min_clients: doctors.length,
      min_monthly_sales: salesTotal,
      min_collection_rate: collRatePct,
      max_expense_ratio: expRatio,
      min_compliance: visitCompliancePct,
      min_engagement: avgEngagement,
    };

    const gradResults = gradCriteria.map(c => {
      const actual = criteriaActuals[c.key] ?? 0;
      const met = c.comparator === 'lte' ? actual <= c.target : actual >= c.target;
      return { key: c.key, label: c.label, target: c.target, actual: Math.round(actual * 100) / 100, comparator: c.comparator, met };
    });

    const checklistMet = gradResults.filter(c => c.met).length;
    const checklistTotal = gradResults.length || 7;

    // ── AI Insights (latest from each agent) ──
    const agentKeys = ['performance_coach', 'visit_compliance', 'engagement_decay'];
    const insights = [];
    for (const agentKey of agentKeys) {
      const run = await AgentRun.findOne({ agent_key: agentKey, status: 'success' })
        .sort({ run_date: -1 })
        .select('agent_label summary.key_findings run_date')
        .lean();
      if (run && run.summary?.key_findings?.length > 0) {
        // Find findings mentioning this partner
        const partnerName = partner.full_name?.split(' ')[0]; // first name match
        const relevant = run.summary.key_findings.find(f =>
          f.toLowerCase().includes(partnerName?.toLowerCase() || '___')
        );
        if (relevant) {
          insights.push({
            agent: agentKey,
            message: relevant,
            severity: relevant.toLowerCase().includes('critical') || relevant.toLowerCase().includes('low') ? 'warning' : 'info',
            run_date: run.run_date,
          });
        }
      }
    }

    // ── Upsert ──
    const scorecard = await PartnerScorecard.findOneAndUpdate(
      { entity_id: partner.entity_id, person_id: partner._id, period },
      {
        $set: {
          user_id: userId,
          track: 'PARTNER',
          visits_completed: visitsCompleted,
          visits_expected: visitsExpected,
          visit_compliance_pct: visitCompliancePct,
          unique_clients_visited: uniqueClients,
          sales_total: salesTotal,
          sales_count: salesCount,
          avg_invoice_value: avgInvoice,
          collections_total: collTotal,
          collections_count: collCount,
          collection_rate_pct: collRatePct,
          expenses_total: expTotal,
          expense_sales_ratio_pct: expRatio,
          total_clients_assigned: doctors.length,
          clients_at_risk: clientsAtRisk,
          avg_engagement_level: avgEngagement,
          score_visits: scoreVisits,
          score_sales: scoreSales,
          score_collections: scoreColl,
          score_efficiency: scoreEff,
          score_engagement: scoreEng,
          score_overall: scoreOverall,
          graduation: {
            criteria: gradResults,
            checklist_met: checklistMet,
            checklist_total: checklistTotal,
            readiness_pct: Math.round((checklistMet / checklistTotal) * 100),
            ready: checklistMet === checklistTotal,
          },
          ai_insights: insights,
          computed_at: new Date(),
        },
      },
      { upsert: true, new: true }
    );

    results.push({
      person: partner.full_name,
      score_overall: scoreOverall,
      graduation: `${checklistMet}/${checklistTotal}`,
    });
  }

  res.json({
    success: true,
    message: `Computed ${results.length} scorecards for ${period}`,
    data: { period, computed: results.length, scorecards: results },
  });
});

// ═══ List scorecards ═══

exports.list = catchAsync(async (req, res) => {
  const period = req.query.period || currentPeriod();
  const filter = { period };

  if (req.isPresident) {
    // President sees all entities
    if (req.query.entity_id) filter.entity_id = req.query.entity_id;
  } else {
    filter.entity_id = req.entityId;
  }

  const scorecards = await PartnerScorecard.find(filter)
    .populate('person_id', 'full_name person_type position department bdm_code entity_id')
    .populate('entity_id', 'entity_name short_name entity_type')
    .sort({ score_overall: -1 })
    .lean();

  res.json({ success: true, data: scorecards });
});

// ═══ Rankings ═══

exports.rankings = catchAsync(async (req, res) => {
  const period = req.query.period || currentPeriod();
  const filter = { period };
  if (!req.isPresident) filter.entity_id = req.entityId;

  const scorecards = await PartnerScorecard.find(filter)
    .populate('person_id', 'full_name person_type position bdm_code')
    .populate('entity_id', 'short_name')
    .sort({ score_overall: -1 })
    .lean();

  const ranked = scorecards.map((s, i) => ({
    rank: i + 1,
    name: s.person_id?.full_name,
    type: s.person_id?.person_type,
    entity: s.entity_id?.short_name,
    score_overall: s.score_overall,
    score_visits: s.score_visits,
    score_sales: s.score_sales,
    score_collections: s.score_collections,
    graduation_pct: s.graduation?.readiness_pct || 0,
    graduation_ready: s.graduation?.ready || false,
  }));

  res.json({ success: true, data: ranked });
});

// ═══ Group summary (cross-entity) ═══

exports.groupSummary = catchAsync(async (req, res) => {
  const period = req.query.period || currentPeriod();

  const pipeline = [
    { $match: { period } },
    { $lookup: { from: 'entities', localField: 'entity_id', foreignField: '_id', as: 'entity' } },
    { $unwind: { path: '$entity', preserveNullAndEmptyArrays: true } },
    { $group: {
      _id: '$entity_id',
      entity_name: { $first: '$entity.short_name' },
      entity_type: { $first: '$entity.entity_type' },
      count: { $sum: 1 },
      avg_score: { $avg: '$score_overall' },
      near_graduation: { $sum: { $cond: [{ $gte: ['$graduation.readiness_pct', 85] }, 1, 0] } },
      at_risk: { $sum: { $cond: [{ $lt: ['$score_overall', 40] }, 1, 0] } },
      total_sales: { $sum: '$sales_total' },
      total_collections: { $sum: '$collections_total' },
    }},
    { $sort: { entity_type: 1, entity_name: 1 } },
  ];

  const summary = await PartnerScorecard.aggregate(pipeline);

  // Org-wide totals
  const totals = summary.reduce((acc, s) => ({
    total_partners: acc.total_partners + s.count,
    avg_score: 0, // computed below
    near_graduation: acc.near_graduation + s.near_graduation,
    at_risk: acc.at_risk + s.at_risk,
  }), { total_partners: 0, avg_score: 0, near_graduation: 0, at_risk: 0 });

  if (totals.total_partners > 0) {
    totals.avg_score = Math.round(summary.reduce((s, e) => s + e.avg_score * e.count, 0) / totals.total_partners);
  }

  res.json({ success: true, data: { period, entities: summary, totals } });
});

// ═══ Single partner scorecard + history ═══

exports.getByPerson = catchAsync(async (req, res) => {
  const { personId } = req.params;
  const period = req.query.period || currentPeriod();

  const current = await PartnerScorecard.findOne({ person_id: personId, period })
    .populate('person_id', 'full_name person_type position department bdm_code date_hired')
    .populate('entity_id', 'entity_name short_name')
    .lean();

  // Last 6 months history
  const history = await PartnerScorecard.find({ person_id: personId })
    .sort({ period: -1 })
    .limit(6)
    .select('period score_overall score_visits score_sales score_collections score_efficiency score_engagement graduation.readiness_pct')
    .lean();

  res.json({ success: true, data: { current, history } });
});

/**
 * SOX Control Matrix controller — Phase SG-6 #29
 *
 * Materializes a live, subscription-ready control matrix for every Sales
 * Goal state change:
 *   - Enumerates each controlled operation (plan.activate, plan.close,
 *     plan.reopen, bulk_targets, compute_snapshot, target_revise, payout.*,
 *     dispute.*).
 *   - For each op, reads the live authorization posture from:
 *       · MODULE_DEFAULT_ROLES lookup (Default-Roles Gate — Phase G4)
 *       · ERP_SUB_PERMISSIONS lookup (sub-permission requirement)
 *       · APPROVAL_MODULE + APPROVAL_CATEGORY lookup (authority matrix tier)
 *   - Scans the last N days (configurable via SOX_MATRIX_CONFIG) of
 *     ErpAuditLog for actual activity per op — who performed it, how often.
 *   - Cross-checks for segregation-of-duties violations: any user who both
 *     CREATED and POSTED the same document type (plan, payout, dispute) in
 *     the window gets flagged.
 *   - Also surfaces integrationHooks.describeRegistry() so subscribers see
 *     which events are wired and how many listeners each has.
 *
 * GET /sales-goals/sox-control-matrix?window_days=90 — returns JSON.
 * GET /sales-goals/sox-control-matrix/print?window_days=90 — returns HTML
 *     suitable for browser "Save as PDF" (reuses pdfRenderer if opted-in).
