    <thead><tr>
      <th>Control</th><th>Description</th><th>Allowed Roles (live)</th>
      <th>Approval Category</th><th>Sub-Permission</th>
      <th>Activity</th><th>Actors (window)</th><th>Event Emitted</th>
    </tr></thead>
