/**
 * Backfill Deduction Schedule ApprovalRequests — Phase G4.2
 *
 * Context (2026-04-21): before Phase G4.2, `deductionScheduleService.approveSchedule`
 * flipped `DeductionSchedule.status` → ACTIVE but never wrote an ApprovalRequest.
 * Result: the Approval Hub's History tab showed PERDIEM_OVERRIDE / SALES / EXPENSES
 * but no DEDUCTION_SCHEDULE rows, even though deductions WERE being approved.
 *
 * Phase G4.2 wires gateApproval into createSchedule (PENDING row on submit) and
 * closeApprovalRequest into approve/reject/withdraw (decision mirrored on the row).
 * This script backfills ApprovalRequest rows for schedules that decided BEFORE
 * the wiring landed, so Approval History is complete retroactively.
 *
 * Rules (idempotent — skip if an ApprovalRequest for the schedule already exists):
 *   status PENDING_APPROVAL  → ApprovalRequest status PENDING  (appears in All Pending)
 *   status ACTIVE            → ApprovalRequest status APPROVED (appears in History)
 *   status COMPLETED         → ApprovalRequest status APPROVED (was ACTIVE, auto-completed)
 *   status REJECTED          → ApprovalRequest status REJECTED
 *   status CANCELLED
 *     - approved_by set      → ApprovalRequest status APPROVED (ACTIVE then cancelled; approval did happen)
 *     - approved_by not set  → ApprovalRequest status CANCELLED (withdrawn from PENDING)
 *
 * Usage (from backend/):
 *   node erp/scripts/backfillDeductionScheduleApprovals.js           # dry-run
 *   node erp/scripts/backfillDeductionScheduleApprovals.js --apply   # writes
 */
require('dotenv').config();
const mongoose = require('mongoose');

const APPLY = process.argv.includes('--apply');

function buildDescription(schedule) {
  const parts = [schedule.deduction_label];
  if (schedule.term_months > 1) {
    parts.push(`₱${schedule.installment_amount}/mo × ${schedule.term_months}`);
  }
  parts.push(schedule.target_cycle || 'C2');
  return parts.join(' · ');
}

async function main() {
  await mongoose.connect(process.env.MONGO_URI);
  console.log(`Connected. Mode: ${APPLY ? 'APPLY' : 'DRY-RUN'}`);

  const DeductionSchedule = require('../models/DeductionSchedule');
  const ApprovalRequest = require('../models/ApprovalRequest');

  const schedules = await DeductionSchedule.find({}).lean();
  console.log(`Scanning ${schedules.length} deduction schedules…`);

  const counts = { pending: 0, approved: 0, rejected: 0, cancelled: 0, skipped_existing: 0, skipped_other: 0 };

  for (const schedule of schedules) {
    // Skip if any ApprovalRequest exists for this doc (idempotent)
    const existing = await ApprovalRequest.findOne({
      doc_id: schedule._id,
      module: 'DEDUCTION_SCHEDULE',
    }).lean();
    if (existing) { counts.skipped_existing++; continue; }

    let decisionStatus, decidedBy, decidedAt, decisionReason;
    switch (schedule.status) {
      case 'PENDING_APPROVAL':
        decisionStatus = 'PENDING';
        break;
      case 'ACTIVE':
      case 'COMPLETED':
        decisionStatus = 'APPROVED';
        decidedBy = schedule.approved_by;
        decidedAt = schedule.approved_at;
        break;
      case 'REJECTED':
        decisionStatus = 'REJECTED';
        decidedBy = schedule.approved_by || schedule.created_by;
        decidedAt = schedule.approved_at || schedule.updated_at || schedule.createdAt;
        decisionReason = schedule.reject_reason || 'Rejected (pre-Phase G4.2, reason unrecorded)';
        break;
      case 'CANCELLED':
        if (schedule.approved_by) {
          // Was ACTIVE first → approval did happen. Reflect that in History.
          decisionStatus = 'APPROVED';
          decidedBy = schedule.approved_by;
          decidedAt = schedule.approved_at;
        } else {
          decisionStatus = 'CANCELLED';
          decidedBy = schedule.created_by;
          decidedAt = schedule.updated_at || schedule.createdAt;
          decisionReason = 'Withdrawn (pre-Phase G4.2)';
        }
        break;
      default:
        counts.skipped_other++;
        continue;
    }

    const description = buildDescription(schedule);
    const docType = schedule.term_months === 1 ? 'ONE_TIME' : 'INSTALLMENT';

    const payload = {
      entity_id: schedule.entity_id,
      rule_id: null,
      module: 'DEDUCTION_SCHEDULE',
      doc_type: docType,
      doc_id: schedule._id,
      doc_ref: schedule.schedule_code,
      amount: schedule.total_amount,
      description,
      metadata: { gate: 'DEFAULT_ROLES', backfilled: true },
      level: 0,
      requested_by: schedule.created_by || schedule.bdm_id,
      status: decisionStatus,
      history: [{
        status: 'PENDING',
        by: schedule.created_by || schedule.bdm_id,
        reason: 'Backfilled from DeductionSchedule (pre-Phase G4.2)',
        at: schedule.createdAt || schedule.created_at,
      }],
    };

    if (decisionStatus !== 'PENDING') {
      payload.decided_by = decidedBy;
      payload.decided_at = decidedAt;
      payload.decision_reason = decisionReason || `${decisionStatus.toLowerCase()} (backfill)`;
      payload.history.push({
        status: decisionStatus,
        by: decidedBy,
        reason: payload.decision_reason,
        at: decidedAt,
      });
    }

    console.log(`  [${decisionStatus}] ${schedule.schedule_code} (${schedule.status}) — ${description}`);
    if (APPLY) await ApprovalRequest.create(payload);

    if (decisionStatus === 'PENDING') counts.pending++;
    else if (decisionStatus === 'APPROVED') counts.approved++;
    else if (decisionStatus === 'REJECTED') counts.rejected++;
    else if (decisionStatus === 'CANCELLED') counts.cancelled++;
  }

  console.log('');
  console.log('Summary:');
  console.log(`  pending created:   ${counts.pending}`);
  console.log(`  approved created:  ${counts.approved}`);
  console.log(`  rejected created:  ${counts.rejected}`);
  console.log(`  cancelled created: ${counts.cancelled}`);
  console.log(`  skipped (had AR):  ${counts.skipped_existing}`);
  console.log(`  skipped (other):   ${counts.skipped_other}`);
  if (!APPLY) console.log('\nDRY-RUN — rerun with --apply to persist.');

  await mongoose.disconnect();
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});

/**
 * Migration Script: Canonicalize SalesLine.doc_ref values on CSI rows
 *
 * Aggressively normalizes every existing CSI SalesLine.doc_ref to digits-only
 * with leading zeros stripped. After this runs:
 *
 *   "4852"         → "4852"
 *   "004852"       → "4852"
 *   "CSI 004852"   → "4852"
 *   "INV 004852"   → "4852"
 *   "#004852"      → "4852"
 *
 * Matches the pre('save') normalization hook on the SalesLine schema — without
 * this backfill, legacy rows would bypass the duplicate-detection rule that
 * now assumes canonical storage.
 *
 * SCOPE: sale_type='CSI' only. CASH_RECEIPT and SERVICE_INVOICE rows have
 * auto-generated doc_refs ("RCT-ILO040326-001") where every character is
 * load-bearing for uniqueness — normalizing them would corrupt the sequence.
 *
 * SAFETY: within each CSI's duplicate-detection scope (entity + source +
 * hospital/customer), if canonicalizing this row would create a collision
 * with another already-canonical row, the row is SKIPPED and logged for
 * manual review. Never silently merges two historical rows.
 *
 * IDEMPOTENT: re-running after the backfill is a no-op because every row is
 * already in canonical form.
 *
 * Usage: node backend/erp/scripts/backfillDocRefNormalization.js
 */
require('dotenv').config();
const mongoose = require('mongoose');
const db = require('../../config/db');
const { normalizeDocRef } = require('../utils/normalize');

async function migrate() {
  await db();

  const SalesLine = require('../models/SalesLine');

  // Candidate filter: CSI rows whose stored doc_ref is NOT already canonical.
  // A canonical CSI doc_ref is pure-digits with no leading zeros (except "0"
  // itself). So we match anything that contains a non-digit character OR
  // starts with 0 followed by any character.
  const candidates = await SalesLine.find({
    sale_type: 'CSI',
    doc_ref: { $exists: true, $ne: '' },
    $or: [
      { doc_ref: /\D/ },        // contains non-digit (e.g. "CSI 004852")
      { doc_ref: /^0+\d/ }      // leading zeros followed by digit (e.g. "004852")
    ]
  })
    .select('_id doc_ref entity_id sale_type source hospital_id customer_id status')
    .lean();

  let changed = 0;
  let skipped = 0;
  const collisions = [];

  for (const row of candidates) {
    const canonical = normalizeDocRef(row.doc_ref, row.sale_type);
    if (!canonical || canonical === row.doc_ref) {
      skipped++;
      continue;
    }

    // Collision check within the same duplicate-detection scope (entity +
    // sale_type + source + hospital/customer). If an already-canonical row
    // exists there, do NOT overwrite — flag for human review.
    const collisionFilter = {
      _id: { $ne: row._id },
      entity_id: row.entity_id,
      sale_type: row.sale_type,
      source: row.source,
      doc_ref: canonical
    };
    if (row.hospital_id) collisionFilter.hospital_id = row.hospital_id;
    if (row.customer_id) collisionFilter.customer_id = row.customer_id;
    const conflict = await SalesLine.findOne(collisionFilter)
      .select('_id status doc_ref')
      .lean();

    if (conflict) {
      collisions.push({
        row_id: row._id.toString(),
        stored: row.doc_ref,
        canonical,
        conflicts_with: conflict._id.toString(),
        conflict_status: conflict.status
      });
      skipped++;
      continue;
    }

    // Use save() so the pre('save') hook fires — single normalization path.
    const doc = await SalesLine.findById(row._id);
    if (!doc) { skipped++; continue; }
    doc.doc_ref = canonical;
    await doc.save();
    changed++;
  }

  console.log(`Scanned ${candidates.length} candidate CSI rows.`);
  console.log(`Canonicalized: ${changed}`);
  console.log(`Skipped (already canonical or unchanged): ${skipped}`);
  if (collisions.length) {
    console.warn(`\nWARNING: ${collisions.length} row(s) skipped due to collision within their dup-scope.`);
    console.warn('Review each one and decide: keep both, mark one as deletion-requested, or merge manually.');
    for (const c of collisions) console.warn(' ', JSON.stringify(c));
  }

  await mongoose.disconnect();
}

migrate().catch((err) => {
  console.error('Backfill failed:', err);
  process.exit(1);
});

/**
 * Backfill User.entity_ids_static + rebuild User.entity_ids — Phase FRA-A (April 22, 2026).
 *
 * Context: before Phase FRA-A, `FunctionalRoleAssignment` rows were cosmetic
 * because `User.entity_ids` (what `tenantFilter` reads to set `req.entityId`)
 * was never updated from the FRA flow. Admin would assign Juan to MG and CO.
 * via Control Center → People & Access → Role Assignments, the UI would show
 * ACTIVE, but Juan's entity picker never offered MG and CO., and proxy-target
 * checks threw "target not assigned to the current entity."
 *
 * This script:
 *   1. For each User with a linked PeopleMaster (PeopleMaster.user_id set):
 *      - If `entity_ids_static` is empty/unset → seed = current `entity_ids`
 *        (captures every admin-direct assignment made pre-FRA-A).
 *      - Compute `union = uniq(entity_ids_static ∪ activeFraEntityIds)`.
 *      - If `entity_ids` differs from union → log drift, apply on --apply.
 *   2. Idempotent: re-running after an apply produces zero drift.
 *
 * Usage (from backend/):
 *   node erp/scripts/backfillEntityIdsFromFra.js             # dry-run, report only
 *   node erp/scripts/backfillEntityIdsFromFra.js --apply     # writes changes
 *   node erp/scripts/backfillEntityIdsFromFra.js --user <id> # scope to one user
 *
 * Also used by CI / health check as a drift detector (dry-run + exit 1 if
 * drift > 0 — wire into check-system-health.js if desired).
 */
require('dotenv').config();
const mongoose = require('mongoose');

const APPLY = process.argv.includes('--apply');
const userArgIdx = process.argv.indexOf('--user');
const USER_FILTER = userArgIdx >= 0 ? process.argv[userArgIdx + 1] : null;

const PAD = (s, n) => String(s || '').padEnd(n);

function formatIdList(ids) {
  if (!ids || !ids.length) return '[]';
  return `[${ids.map((id) => String(id).slice(-6)).join(', ')}]`;
}

async function main() {
  const MONGO_URI = process.env.MONGO_URI;
  if (!MONGO_URI) {
    console.error('❌ MONGO_URI not set in .env');
    process.exit(1);
  }

  console.log('═'.repeat(72));
  console.log(`FRA-A Backfill — ${APPLY ? 'APPLY MODE (writes)' : 'DRY RUN (reports only)'}`);
  if (USER_FILTER) console.log(`Scoped to user: ${USER_FILTER}`);
  console.log('═'.repeat(72));

  await mongoose.connect(MONGO_URI, { serverSelectionTimeoutMS: 10_000 });
  console.log('✓ Mongo connected\n');

  const User = require('../../models/User');
  const PeopleMaster = require('../models/PeopleMaster');
  const FunctionalRoleAssignment = require('../models/FunctionalRoleAssignment');

  // Find every User that is linkable via at least one PeopleMaster. Users
  // without any PeopleMaster (CRM-only users, orphaned admin accounts) are
  // untouched — entity_ids_static stays empty.
  const userFilter = USER_FILTER ? { _id: USER_FILTER } : {};
  const allUsers = await User.find(userFilter)
    .select('_id name email role entity_id entity_ids entity_ids_static')
    .lean();

  console.log(`Scanning ${allUsers.length} users...\n`);

  const stats = {
    scanned: 0,
    seededStatic: 0,
    rebuiltEntityIds: 0,
    added: 0,
    removed: 0,
    noop: 0,
    skippedNoPeople: 0,
  };

  const drifts = [];

  for (const u of allUsers) {
    stats.scanned += 1;

    const people = await PeopleMaster.find({ user_id: u._id }).select('_id').lean();
    if (!people.length) {
      stats.skippedNoPeople += 1;
      continue;
    }
    const personIds = people.map((p) => p._id);

    const activeFras = await FunctionalRoleAssignment.find({
      person_id: { $in: personIds },
      is_active: true,
      status: 'ACTIVE',
    })
      .select('entity_id')
      .lean();
    const fraIds = activeFras.map((f) => f.entity_id).filter(Boolean);

    // Static seed: on first backfill, entity_ids_static is empty/unset →
    // snapshot the current entity_ids as the admin-direct baseline. On
    // subsequent runs, we respect whatever static already holds.
    const existingStatic = u.entity_ids_static || [];
    let staticIds = existingStatic;
    let didSeedStatic = false;
    if (!existingStatic.length) {
      staticIds = u.entity_ids || [];
      didSeedStatic = true;
    }

    // Union
    const seen = new Set();
    const merged = [];
    for (const id of [...staticIds, ...fraIds]) {
      const k = String(id);
      if (!seen.has(k)) {
        seen.add(k);
        merged.push(id);
      }
    }

    const prevKeys = new Set((u.entity_ids || []).map((id) => String(id)));
    const nextKeys = new Set(merged.map((id) => String(id)));
    const addedKeys = [...nextKeys].filter((k) => !prevKeys.has(k));
    const removedKeys = [...prevKeys].filter((k) => !nextKeys.has(k));

    const needsWrite = didSeedStatic || addedKeys.length || removedKeys.length;

    if (!needsWrite) {
      stats.noop += 1;
      continue;
    }

    if (didSeedStatic) stats.seededStatic += 1;
    if (addedKeys.length || removedKeys.length) {
      stats.rebuiltEntityIds += 1;
      stats.added += addedKeys.length;
      stats.removed += removedKeys.length;
    }

    drifts.push({
      userId: String(u._id),
      name: u.name,
      role: u.role,
      prevEntityIds: (u.entity_ids || []).map(String),
      newEntityIds: merged.map(String),
      staticSeeded: didSeedStatic,
      staticIds: staticIds.map(String),
      fraIds: fraIds.map(String),
      added: addedKeys,
      removed: removedKeys,
    });

    if (APPLY) {
      const update = {};
      if (didSeedStatic) update.entity_ids_static = staticIds;
      if (addedKeys.length || removedKeys.length) update.entity_ids = merged;
      await User.updateOne({ _id: u._id }, { $set: update });
    }
  }

  console.log(`${PAD('Role', 12)}${PAD('Name', 28)}${PAD('Static', 10)}${PAD('FRA', 10)}${PAD('Added', 8)}${PAD('Removed', 8)}`);
  console.log('─'.repeat(76));
  for (const d of drifts) {
    console.log(
      `${PAD(d.role, 12)}${PAD(d.name.slice(0, 26), 28)}${PAD(d.staticIds.length, 10)}${PAD(d.fraIds.length, 10)}${PAD(d.added.length, 8)}${PAD(d.removed.length, 8)}`
    );
    if (d.staticSeeded) {
      console.log(`    static seed (first backfill) = ${formatIdList(d.staticIds)}`);
    }
    if (d.added.length) console.log(`    + added   ${formatIdList(d.added)}`);
    if (d.removed.length) console.log(`    - removed ${formatIdList(d.removed)}`);
  }

  console.log('\n' + '═'.repeat(72));
  console.log('Summary');
  console.log('─'.repeat(72));
  console.log(`  Users scanned:         ${stats.scanned}`);
  console.log(`  Skipped (no people):   ${stats.skippedNoPeople}`);
  console.log(`  No drift:              ${stats.noop}`);
  console.log(`  Static seeded:         ${stats.seededStatic}`);
  console.log(`  entity_ids rebuilt:    ${stats.rebuiltEntityIds}`);
  console.log(`    entities added:      ${stats.added}`);
  console.log(`    entities removed:    ${stats.removed}`);
  console.log('═'.repeat(72));

  if (!APPLY && drifts.length > 0) {
    console.log('\n⚠ Dry run — no writes. Re-run with --apply to persist.');
  } else if (APPLY) {
    console.log('\n✓ Apply mode complete — writes persisted.');
  } else {
    console.log('\n✓ No drift detected — entity_ids already in sync with FRA rows.');
  }

  await mongoose.disconnect();
  // Exit 1 on unresolved drift in dry-run mode → usable as a CI drift gate.
  process.exit(!APPLY && drifts.length > 0 ? 1 : 0);
}

main().catch((err) => {
  console.error('❌ Backfill failed:', err);
  process.exit(2);
});

#!/usr/bin/env node
/**
 * backfillGrnUndertakings.js — Phase 32 (Apr 2026)
 *
 * For every APPROVED GRN that has no `undertaking_id`, create a historical
 * ACKNOWLEDGED Undertaking whose line_items mirror the GRN. Lines are marked
 * `scan_confirmed: false` (we can't retroactively claim the BDM scanned the
 * packaging), and a note is set on the Undertaking documenting the backfill.
 *
 * Strategy:
 *   1. Find every approved GrnEntry without `undertaking_id` and without a
 *      `deletion_event_id` (active, non-reversed GRN).
 *   2. For each, build a line_items array from the GRN's line_items, copying
 *      product_id, expected_qty, received_qty, batch_lot_no, expiry_date,
 *      purchase_uom/selling_uom/conversion_factor. scan_confirmed: false.
 *   3. Create the Undertaking in status ACKNOWLEDGED, acknowledged_by = GRN's
 *      reviewed_by or bdm_id (fallback), acknowledged_at = GRN's approved_at
 *      or created_at.
 *   4. Back-link GRN: set `undertaking_id` on the GRN.
 *   5. Log audit entry per created row.
 *
 * Idempotent: running twice finds no GRNs without undertaking_id on the
 * second pass. Does NOT touch InventoryLedger — that was written by the
 * original GRN approval.
 *
 * Usage:
 *   node backend/erp/scripts/backfillGrnUndertakings.js --dry-run
 *   node backend/erp/scripts/backfillGrnUndertakings.js            (apply)
 *   node backend/erp/scripts/backfillGrnUndertakings.js --entity=<id>  (scope)
 */

const path = require('path');
require('dotenv').config({ path: path.resolve(__dirname, '../../../.env') });
const mongoose = require('mongoose');

const args = new Set(process.argv.slice(2));
const DRY_RUN = args.has('--dry-run');
const entityArg = [...args].find(a => a.startsWith('--entity='));
const ENTITY_ID = entityArg ? entityArg.split('=')[1] : null;

async function main() {
  const uri = process.env.MONGO_URI;
  if (!uri) {
    console.error('[backfill] MONGO_URI missing from env');
    process.exit(1);
  }
  await mongoose.connect(uri);
  console.log(`[backfill] connected (dryRun=${DRY_RUN}${ENTITY_ID ? `, entity=${ENTITY_ID}` : ''})`);

  const GrnEntry = require('../models/GrnEntry');
  const Undertaking = require('../models/Undertaking');
  const ErpAuditLog = require('../models/ErpAuditLog');

  const filter = {
    status: 'APPROVED',
    deletion_event_id: { $exists: false },
    undertaking_id: { $exists: false },
  };
  if (ENTITY_ID) filter.entity_id = new mongoose.Types.ObjectId(ENTITY_ID);

  const grns = await GrnEntry.find(filter).lean();
  console.log(`[backfill] found ${grns.length} approved GRN(s) needing Undertaking backfill`);

  let created = 0;
  let skipped = 0;

  for (const grn of grns) {
    // Safety — if any Undertaking already points here, skip. Covers
    // partial-run recovery where undertaking_id failed to persist.
    const existing = await Undertaking.findOne({
      linked_grn_id: grn._id,
      deletion_event_id: { $exists: false }
    }).lean();
    if (existing) {
      skipped++;
      continue;
    }

    const lineItems = (grn.line_items || []).map(li => ({
      product_id: li.product_id,
      item_key: li.item_key,
      po_line_index: li.po_line_index,
      expected_qty: li.qty || 0,
      received_qty: li.qty || 0,
      batch_lot_no: li.batch_lot_no || '',
      expiry_date: li.expiry_date || null,
      purchase_uom: li.purchase_uom,
      selling_uom: li.selling_uom,
      conversion_factor: li.conversion_factor || 1,
      qty_selling_units: (li.qty || 0) * (li.conversion_factor || 1),
      scan_confirmed: false,
      variance_flag: null,
    }));

    const docPayload = {
      entity_id: grn.entity_id,
      bdm_id: grn.bdm_id,
      warehouse_id: grn.warehouse_id,
      linked_grn_id: grn._id,
      receipt_date: grn.grn_date || grn.created_at,
      line_items: lineItems,
      notes: 'Historical backfill — no scan confirmation available (created by backfillGrnUndertakings.js).',
      status: 'ACKNOWLEDGED',
      acknowledged_by: grn.reviewed_by || grn.bdm_id,
      acknowledged_at: grn.approved_at || grn.reviewed_at || grn.created_at,
      event_id: grn.event_id || undefined,
      created_by: grn.bdm_id,
      created_at: grn.created_at || new Date(),
    };

    if (DRY_RUN) {
      console.log(`[backfill] would create Undertaking for GRN ${grn._id} (${grn.po_number || '—'}, ${lineItems.length} lines)`);
      created++;
      continue;
    }

    try {
      const ut = await Undertaking.create(docPayload);
      await GrnEntry.updateOne({ _id: grn._id }, { $set: { undertaking_id: ut._id } });
      await ErpAuditLog.logChange({
        entity_id: grn.entity_id,
        bdm_id: grn.bdm_id,
        log_type: 'BACKFILL',
        target_ref: ut._id.toString(),
        target_model: 'Undertaking',
        field_changed: 'status',
        new_value: 'ACKNOWLEDGED',
        changed_by: grn.reviewed_by || grn.bdm_id,
        note: `Historical Undertaking backfilled for GRN ${grn._id} (${grn.po_number || 'standalone'}) — no scan confirmation.`
      }).catch(() => {});
      created++;
      if (created % 20 === 0) console.log(`[backfill] created ${created} so far…`);
    } catch (err) {
      skipped++;
      console.warn(`[backfill] FAILED GRN ${grn._id}: ${err.message}`);
    }
  }

  console.log(`[backfill] done — created: ${created}, skipped: ${skipped}${DRY_RUN ? ' (dry-run)' : ''}`);
  await mongoose.disconnect();
}

main().catch(err => {
  console.error('[backfill] fatal:', err);
  process.exit(1);
});

/**
