/**
 * Suspect ADJUSTMENT Forensics — read-only
 *
 * Finds ALL ADJUSTMENT entries across ALL warehouses that match the
 * "accidental zero-out" fingerprint:
 *   - no event_id (not linked to a GRN / CSI / Transfer / etc.)
 *   - blank/null override_reason
 *
 * Groups them by (user, minute-bucket of recorded_at) so you can see
 * batch operations as clusters. Legitimate adjustments typically have
 * EITHER an event_id OR a reason — suspect ones have neither.
 *
 * Usage (from backend/):
 *   node erp/scripts/findSuspectAdjustments.js
 */
require('dotenv').config();
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const InventoryLedger = require('../models/InventoryLedger');
const ProductMaster = require('../models/ProductMaster');
const Warehouse = require('../models/Warehouse');
const User = require('../../models/User');

const pad = (s, n) => String(s ?? '').padEnd(n).slice(0, n);
const padNum = (n, w = 8) => String(n ?? 0).padStart(w);

async function run() {
  await connectDB();

  // Suspect fingerprint: ADJUSTMENT with no event_id AND blank/null override_reason
  const suspects = await InventoryLedger.find({
    transaction_type: 'ADJUSTMENT',
    $and: [
      { $or: [{ event_id: { $exists: false } }, { event_id: null }] },
      { $or: [{ override_reason: { $exists: false } }, { override_reason: null }, { override_reason: '' }] },
    ],
  }).sort({ recorded_at: 1 }).lean();

  // Also find legitimate adjustments for comparison (has event_id OR has reason)
  const legit = await InventoryLedger.find({
    transaction_type: 'ADJUSTMENT',
    $or: [
      { event_id: { $ne: null, $exists: true } },
      { override_reason: { $regex: /\S/ } },
    ],
  }).lean();

  const warehouses = await Warehouse.find({}).lean();
  const whMap = new Map(warehouses.map(w => [w._id.toString(), w]));

  const userIds = [...new Set([...suspects, ...legit].map(r => r.recorded_by?.toString()).filter(Boolean))];
  const users = await User.find({ _id: { $in: userIds } }).select('_id name email').lean();
  const uMap = new Map(users.map(u => [u._id.toString(), u]));

  const productIds = [...new Set([...suspects, ...legit].map(r => r.product_id?.toString()).filter(Boolean))];
  const products = await ProductMaster.find({ _id: { $in: productIds } }).select('_id brand_name dosage_strength').lean();
  const pMap = new Map(products.map(p => [p._id.toString(), p]));

  // ============ SUSPECT CLUSTERS ============
  console.log('\n======================================================================');
  console.log(`  SUSPECT ADJUSTMENTS (no event_id, no reason): ${suspects.length}`);
  console.log('======================================================================');
  if (!suspects.length) {
    console.log('None found. All ADJUSTMENTs have either an event_id or an override_reason.\n');
  } else {
    // Group by user + minute bucket
    const clusters = new Map();
    for (const r of suspects) {
      const minute = r.recorded_at?.toISOString().slice(0, 16); // "YYYY-MM-DDTHH:MM"
      const key = `${r.recorded_by}|${minute}`;
      if (!clusters.has(key)) clusters.set(key, []);
      clusters.get(key).push(r);
    }

    console.log(`\nGrouped into ${clusters.size} cluster(s):\n`);

    let clusterIdx = 0;
    for (const [key, rows] of clusters) {
      clusterIdx++;
      const first = rows[0];
      const u = uMap.get(first.recorded_by?.toString());
      const totalQtyOut = rows.reduce((s, r) => s + (r.qty_out || 0), 0);
      const totalQtyIn = rows.reduce((s, r) => s + (r.qty_in || 0), 0);
      const whSet = new Set(rows.map(r => whMap.get(r.warehouse_id?.toString())?.warehouse_code || '?'));

      console.log(`--- Cluster ${clusterIdx} ---`);
      console.log(`  When:       ${first.recorded_at?.toISOString()}`);
      console.log(`  Who:        ${u?.name || '?'} <${u?.email || '?'}>`);
      console.log(`  Warehouses: ${[...whSet].join(', ')}`);
      console.log(`  Rows:       ${rows.length}`);
      console.log(`  Total qty_in:  ${totalQtyIn}`);
      console.log(`  Total qty_out: ${totalQtyOut}`);
      console.log(`  Net impact:    ${totalQtyIn - totalQtyOut} (negative = stock depleted)`);
      console.log('');
      console.log(`  ${pad('WAREHOUSE', 10)}${pad('PRODUCT', 28)}${pad('BATCH', 14)}${padNum('QTY_IN', 8)}${padNum('QTY_OUT', 8)}`);
      for (const r of rows) {
        const w = whMap.get(r.warehouse_id?.toString());
        const p = pMap.get(r.product_id?.toString());
        const pLabel = p ? `${p.brand_name || '?'}${p.dosage_strength ? ' ' + p.dosage_strength : ''}` : '(unknown)';
        console.log(`  ${pad(w?.warehouse_code || '?', 10)}${pad(pLabel, 28)}${pad(r.batch_lot_no || '?', 14)}${padNum(r.qty_in, 8)}${padNum(r.qty_out, 8)}`);
      }
      console.log('');
    }
  }

  // ============ LEGIT ADJUSTMENTS (for contrast) ============
  console.log('======================================================================');
  console.log(`  LEGITIMATE ADJUSTMENTS (has event_id or reason): ${legit.length}`);
  console.log('======================================================================');
  if (!legit.length) {
    console.log('None. Every ADJUSTMENT in the ledger is suspect.\n');
  } else {
    console.log(`\n  ${pad('WAREHOUSE', 10)}${pad('DATE', 22)}${pad('USER', 22)}${padNum('QTY_IN', 8)}${padNum('QTY_OUT', 8)}  REASON/EVENT`);
    for (const r of legit.slice(0, 20)) {
      const w = whMap.get(r.warehouse_id?.toString());
      const u = uMap.get(r.recorded_by?.toString());
      const tag = r.event_id ? `event=${r.event_id}` : (r.override_reason || '');
      console.log(`  ${pad(w?.warehouse_code || '?', 10)}${pad(r.recorded_at?.toISOString() || '?', 22)}${pad(u?.name || '?', 22)}${padNum(r.qty_in, 8)}${padNum(r.qty_out, 8)}  ${tag}`);
    }
    if (legit.length > 20) console.log(`  ... and ${legit.length - 20} more`);
  }

  console.log('\n======================================================================');
  console.log('  INTERPRETATION');
  console.log('======================================================================');
  console.log('A "suspect cluster" is a batch of ADJUSTMENTs by one user in one minute');
  console.log('with no linked event and no reason. That\'s the fingerprint of a UI');
  console.log('button that bulk-wiped stock without asking for confirmation.');
  console.log('');
  console.log('Legitimate adjustments normally have EITHER an event_id (linked to a');
  console.log('GRN / CSI / transfer) or an override_reason (user typed why). Suspect');
  console.log('ones have neither — and are candidates for reversal.');

  await mongoose.disconnect();
}

run().catch(err => { console.error(err); process.exit(1); });

/**
 * Import Product Cleanup from SMART_ITEM_REVIEW CSV
 *
 * Actions:
 *   USE_NORMALIZED — update brand_name, generic_name, dosage_strength, unit_code
 *   DELETE_DUPLICATE — deactivate (is_active = false)
 *   KEEP_AS_IS — no change
 *
 * Usage: node backend/erp/scripts/importProductClean.js
 */
require('dotenv').config();
const fs = require('fs');
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const { normalizeUnit } = require('../utils/normalize');

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    if (line[i] === '"') { inQuotes = !inQuotes; continue; }
    if (line[i] === ',' && !inQuotes) { result.push(current.trim()); current = ''; continue; }
    current += line[i];
  }
  result.push(current.trim());
  return result;
}

function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

async function run() {
  await connectDB();
  const ProductMaster = require('../models/ProductMaster');

  const csvPath = 'C:/Users/LENOVO/Downloads/VIP Accounting - SMART_ITEM_REVIEW.csv';
  const csv = fs.readFileSync(csvPath, 'utf8');
  const lines = csv.split('\n').filter(l => l.trim());
  const headers = parseCSVLine(lines[0]);

  const idx = {};
  headers.forEach((h, i) => { idx[h] = i; });

  console.log('=== Product Cleanup Import ===');
  console.log(`Rows: ${lines.length - 1}`);
  console.log(`Headers: ${headers.join(', ')}\n`);

  let updated = 0, deleted = 0, kept = 0, notFound = 0, skipped = 0;

  for (let i = 1; i < lines.length; i++) {
    const cols = parseCSVLine(lines[i]);
    const action = cols[idx.Action] || '';
    const approved = cols[idx.AdminApproved] || '';
    const itemKey = cols[idx.ItemKey] || '';
    const normBrand = cols[idx.NormBrand] || '';
    const normGeneric = cols[idx.NormGeneric] || '';
    const normDosage = cols[idx.NormDosage] || '';
    const normSoldPer = cols[idx.NormSoldPer] || '';
    const rawBrand = cols[idx.RawBrandName] || '';

    // Skip unapproved
    if (approved !== 'TRUE') { skipped++; continue; }
    if (!itemKey && !rawBrand) { skipped++; continue; }

    // Find product by item_key first
    let product = await ProductMaster.findOne({ item_key: itemKey });

    // Fallback: match by brand name
    if (!product && rawBrand) {
      product = await ProductMaster.findOne({
        brand_name: new RegExp('^' + escapeRegex(rawBrand) + '$', 'i')
      });
    }

    if (!product) {
      notFound++;
      if (action !== 'DELETE_DUPLICATE') {
        console.log(`  [NOT FOUND] ${itemKey} — ${rawBrand}`);
      }
      continue;
    }

    if (action === 'USE_NORMALIZED') {
      const changes = [];
      if (normBrand && normBrand !== product.brand_name) {
        changes.push(`brand: ${product.brand_name} → ${normBrand}`);
        product.brand_name = normBrand;
      }
      if (normGeneric && normGeneric !== product.generic_name) {
        changes.push(`generic: ${product.generic_name} → ${normGeneric}`);
        product.generic_name = normGeneric;
      }
      if (normDosage && normDosage !== product.dosage_strength) {
        changes.push(`dosage: ${product.dosage_strength} → ${normDosage}`);
        product.dosage_strength = normDosage;
      }
      if (normSoldPer) {
        const normalizedUnit = normalizeUnit(normSoldPer);
        if (normalizedUnit && normalizedUnit !== product.unit_code) {
          changes.push(`unit: ${product.unit_code} → ${normalizedUnit}`);
          product.unit_code = normalizedUnit;
        }
      }

      if (changes.length) {
        await product.save();
        updated++;
        console.log(`  [UPDATED] ${product.brand_name} — ${changes.join(', ')}`);
      } else {
        kept++;
      }
    } else if (action === 'DELETE_DUPLICATE') {
      product.is_active = false;
      await product.save();
      deleted++;
      console.log(`  [DEACTIVATED] ${product.brand_name} (${itemKey})`);
    } else {
      kept++;
    }
  }

  console.log('\n=== Results ===');
  console.log(`  Updated: ${updated}`);
  console.log(`  Deactivated: ${deleted}`);
  console.log(`  Kept as-is: ${kept}`);
  console.log(`  Not found: ${notFound}`);
  console.log(`  Skipped (unapproved): ${skipped}`);

  await mongoose.disconnect();
}

run().catch(err => { console.error(err); process.exit(1); });

/**
 * Stock On Hand Import Script — Phase 17
 *
 * Imports opening stock balances from CSV into InventoryLedger as OPENING_BALANCE entries.
 * Expects CSV with WarehouseCode column (added by user during cleanup).
 *
 * Usage: node backend/erp/scripts/importStockOnHand.js <path-to-csv>
 *
 * CSV columns expected:
 *   SnapshotAt, BDM, Territory, WarehouseCode, ItemKey, GenericName, BrandName,
 *   DosageStrength, BatchLotNo, ExpiryDate, SoldPer, StockOnHand, MinimalStock,
 *   PurchasePrice, SellingPrice, InventoryValue, IsActive, NearExpiryFlag, StockStatus, Remarks
 *
 * If WarehouseCode column missing, falls back to BDM name mapping.
 */
require('dotenv').config();
const fs = require('fs');
const path = require('path');
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const InventoryLedger = require('../models/InventoryLedger');
const ProductMaster = require('../models/ProductMaster');
const Warehouse = require('../models/Warehouse');
const Entity = require('../models/Entity');
const User = require('../../models/User');
const { cleanName } = require('../utils/nameClean');
const { buildBdmToWarehouseMap } = require('../services/stockSeedService');

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    if (line[i] === '"') { inQuotes = !inQuotes; }
    else if (line[i] === ',' && !inQuotes) { result.push(current.trim()); current = ''; }
    else { current += line[i]; }
  }
  result.push(current.trim());
  return result;
}

function parseDate(dateStr) {
  if (!dateStr || dateStr === '0' || dateStr.includes('00/00')) return null;
  // Clean bad dates like "08/30;/2026"
  const cleaned = dateStr.replace(/;/g, '');
  const parsed = new Date(cleaned);
  if (isNaN(parsed.getTime())) return null;
  // Reject dates before 2020 (bad data)
  if (parsed.getFullYear() < 2020) return null;
  return parsed;
}

async function run() {
  const csvPath = process.argv[2];
  if (!csvPath) {
    console.error('Usage: node importStockOnHand.js <path-to-csv>');
    process.exit(1);
  }

  const fullPath = path.resolve(csvPath);
  if (!fs.existsSync(fullPath)) {
    console.error(`File not found: ${fullPath}`);
    process.exit(1);
  }

  await connectDB();
  console.log('=== Stock On Hand Import ===\n');

  // Parse CSV
  const content = fs.readFileSync(fullPath, 'utf-8');
  const lines = content.split('\n').filter(l => l.trim());
  const headers = parseCSVLine(lines[0]);
  const rows = lines.slice(1).map(l => {
    const vals = parseCSVLine(l);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = vals[i] || ''; });
    return obj;
  });

  console.log(`Parsed ${rows.length} rows from CSV`);
  console.log(`Columns: ${headers.join(', ')}\n`);

  const hasWarehouseCode = headers.includes('WarehouseCode') || headers.includes('Warehouse Code');
  if (!hasWarehouseCode) {
    console.log('WARNING: No WarehouseCode column — using BDM name fallback mapping\n');
  }

  // Resolve warehouses
  const warehouses = await Warehouse.find({}).lean();
  const whByCode = new Map(warehouses.map(w => [w.warehouse_code, w]));

  // Build BDM→warehouse fallback from DB (no hardcoded mapping)
  const BDM_TO_WAREHOUSE = await buildBdmToWarehouseMap();
  console.log(`BDM→Warehouse mapping (from DB): ${Object.keys(BDM_TO_WAREHOUSE).length} entries`);

  // Resolve entities
  const entities = await Entity.find({}).lean();
  const entityById = new Map(entities.map(e => [e._id.toString(), e]));

  // Stats
  let imported = 0, skipped = 0, productUpdated = 0, errors = 0;
  const perWarehouse = {};

  for (let i = 0; i < rows.length; i++) {
    const row = rows[i];
    const stockQty = parseInt(row.StockOnHand) || 0;

    // Skip zero-stock inactive items
    if (stockQty <= 0 && row.IsActive === 'FALSE') {
      skipped++;
      continue;
    }

    // Resolve warehouse
    const whCode = hasWarehouseCode ? (row.WarehouseCode || row['Warehouse Code'])?.toUpperCase() : BDM_TO_WAREHOUSE[row.BDM];
    if (!whCode) {
      console.log(`  Row ${i + 2}: No warehouse mapping for BDM "${row.BDM}" — SKIPPED`);
      errors++;
      continue;
    }

    const warehouse = whByCode.get(whCode);
    if (!warehouse) {
      console.log(`  Row ${i + 2}: Warehouse "${whCode}" not found — SKIPPED`);
      errors++;
      continue;
    }

    const entityId = warehouse.entity_id;
    const managerId = warehouse.manager_id;

    // Parse batch/expiry
    const batchLotNo = row.BatchLotNo || 'OPENING';
    const expiryDate = parseDate(row.ExpiryDate);

    // Match against cleaned ProductMaster — DO NOT auto-create duplicates
    const itemKey = row.ItemKey || `${row.BrandName}|${row.DosageStrength}`;
    const csvBrandClean = cleanName(row.BrandName || '');
    const csvDosage = (row.DosageStrength || '').trim();

    // Strategy 1: exact item_key match within entity
    let product = await ProductMaster.findOne({ entity_id: entityId, item_key: itemKey }).lean();

    // Strategy 2: brand_name_clean + dosage_strength within entity
    if (!product && csvBrandClean) {
      product = await ProductMaster.findOne({
        entity_id: entityId,
        brand_name_clean: csvBrandClean,
        dosage_strength: csvDosage || { $in: [null, ''] },
      }).lean();
    }

    // Strategy 3: brand_name_clean + dosage_strength across ALL entities (shared products)
    if (!product && csvBrandClean) {
      product = await ProductMaster.findOne({
        brand_name_clean: csvBrandClean,
        dosage_strength: csvDosage || { $in: [null, ''] },
      }).lean();
    }

    if (!product) {
      console.log(`  Row ${i + 2}: NO MATCH for "${row.BrandName} ${row.DosageStrength}" (clean: "${csvBrandClean}") — SKIPPED (review manually)`);
      errors++;
      continue;
    }

    // Update prices if currently zero and CSV has values
    const updates = {};
    if (!product.purchase_price && parseFloat(row.PurchasePrice)) updates.purchase_price = parseFloat(row.PurchasePrice);
    if (!product.selling_price && parseFloat(row.SellingPrice)) updates.selling_price = parseFloat(row.SellingPrice);
    if (!product.reorder_min_qty && parseInt(row.MinimalStock)) updates.reorder_min_qty = parseInt(row.MinimalStock);
    if (Object.keys(updates).length) {
      await ProductMaster.updateOne({ _id: product._id }, { $set: updates });
      productUpdated++;
    }

    // Skip zero-stock
    if (stockQty <= 0) {
      skipped++;
      continue;
    }

    // Dedup check: skip if OPENING_BALANCE already exists for this combo
    const existingLedger = await InventoryLedger.findOne({
      entity_id: entityId,
      warehouse_id: warehouse._id,
      product_id: product._id,
      batch_lot_no: batchLotNo,
      transaction_type: 'OPENING_BALANCE',
    }).lean();
    if (existingLedger) {
      skipped++;
      continue;
    }

    // Create OPENING_BALANCE InventoryLedger entry
    await InventoryLedger.create({
      entity_id: entityId,
      bdm_id: managerId,
      warehouse_id: warehouse._id,
      product_id: product._id,
      batch_lot_no: batchLotNo,
      expiry_date: expiryDate || new Date('2030-12-31'),
      transaction_type: 'OPENING_BALANCE',
      qty_in: stockQty,
      qty_out: 0,
      recorded_by: managerId,
    });

    imported++;
    perWarehouse[whCode] = (perWarehouse[whCode] || 0) + 1;
  }

  console.log('\n=== Import Complete ===');
  console.log(`Imported: ${imported} ledger entries`);
  console.log(`Skipped: ${skipped} (zero stock / inactive / dedup)`);
  console.log(`Unmatched (review manually): ${errors}`);
  console.log(`Products price-updated: ${productUpdated}`);
  console.log('\nPer warehouse:');
  for (const [code, count] of Object.entries(perWarehouse).sort((a, b) => b[1] - a[1])) {
    console.log(`  ${code}: ${count} entries`);
  }

  await mongoose.disconnect();
}

run().catch(err => { console.error('Import failed:', err); process.exit(1); });

/**
 * TransactionEvent Inspector — read-only
 *
 * Given an event_id, prints:
 *   - The TransactionEvent document (all fields)
 *   - All InventoryLedger rows linked to that event (any warehouse)
 *   - Any linked StockReassignment / InterCompanyTransfer doc
 *   - Any linked Sales / GRN / DR doc, if ref fields are populated
 *
 * Usage (from backend/):
 *   node erp/scripts/inspectTransactionEvent.js <event_id>
 *
 * READ-ONLY. Safe on prod.
 */
require('dotenv').config();
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const InventoryLedger = require('../models/InventoryLedger');
const TransactionEvent = require('../models/TransactionEvent');
const Warehouse = require('../models/Warehouse');
const ProductMaster = require('../models/ProductMaster');
const User = require('../../models/User');

const eventIdArg = process.argv[2];
if (!eventIdArg) {
  console.error('Usage: node erp/scripts/inspectTransactionEvent.js <event_id>');
  process.exit(1);
}

const pad = (s, n) => String(s ?? '').padEnd(n).slice(0, n);
const padNum = (n, w = 8) => String(n ?? 0).padStart(w);

async function run() {
  await connectDB();

  const eventId = new mongoose.Types.ObjectId(eventIdArg);

  // ============ The event document ============
  console.log('\n======================================================================');
  console.log(`  TRANSACTION EVENT: ${eventIdArg}`);
  console.log('======================================================================');
  const event = await TransactionEvent.findById(eventId).lean();
  if (!event) {
    console.log('No TransactionEvent document with that _id.');
    console.log('(Rows may still link to it — orphaned event reference.)');
  } else {
    console.log(JSON.stringify(event, null, 2));
  }

  // ============ All ledger rows linked to this event ============
  console.log('\n======================================================================');
  console.log('  LEDGER ROWS LINKED TO THIS EVENT');
  console.log('======================================================================');
  const rows = await InventoryLedger.find({ event_id: eventId }).sort({ recorded_at: 1 }).lean();

  if (!rows.length) {
    console.log('No ledger rows linked. Event has no inventory impact.');
  } else {
    const whs = await Warehouse.find({ _id: { $in: [...new Set(rows.map(r => r.warehouse_id?.toString()).filter(Boolean))] } }).lean();
    const pids = await ProductMaster.find({ _id: { $in: [...new Set(rows.map(r => r.product_id?.toString()).filter(Boolean))] } }).select('brand_name dosage_strength').lean();
    const uids = await User.find({ _id: { $in: [...new Set(rows.map(r => r.recorded_by?.toString()).filter(Boolean))] } }).select('name email').lean();
    const whMap = new Map(whs.map(w => [w._id.toString(), w]));
    const pMap = new Map(pids.map(p => [p._id.toString(), p]));
    const uMap = new Map(uids.map(u => [u._id.toString(), u]));

    console.log(`\n${rows.length} row(s):\n`);
    console.log(`${pad('WAREHOUSE', 10)}${pad('TYPE', 16)}${pad('PRODUCT', 28)}${pad('BATCH', 14)}${padNum('QTY_IN', 8)}${padNum('QTY_OUT', 8)}  USER`);
    console.log('-'.repeat(100));

    let totalIn = 0, totalOut = 0;
    const netByWh = new Map();
    for (const r of rows) {
      const w = whMap.get(r.warehouse_id?.toString());
      const p = pMap.get(r.product_id?.toString());
      const u = uMap.get(r.recorded_by?.toString());
      const pLabel = p ? `${p.brand_name || '?'}${p.dosage_strength ? ' ' + p.dosage_strength : ''}` : '(unknown)';
      console.log(
        pad(w?.warehouse_code || '?', 10) +
        pad(r.transaction_type || '?', 16) +
        pad(pLabel, 28) +
        pad(r.batch_lot_no || '?', 14) +
        padNum(r.qty_in, 8) +
        padNum(r.qty_out, 8) +
        '  ' + (u?.name || '?')
      );
      totalIn += (r.qty_in || 0);
      totalOut += (r.qty_out || 0);
      const whCode = w?.warehouse_code || '?';
      const prev = netByWh.get(whCode) || { in: 0, out: 0 };
      prev.in += (r.qty_in || 0);
      prev.out += (r.qty_out || 0);
      netByWh.set(whCode, prev);
    }

    console.log('-'.repeat(100));
    console.log(`Totals: qty_in=${totalIn}, qty_out=${totalOut}, net=${totalIn - totalOut}`);
    console.log('\nNet per warehouse:');
    for (const [whCode, net] of netByWh) {
      const netQty = net.in - net.out;
      const arrow = netQty > 0 ? '← received' : netQty < 0 ? '→ sent out' : '= neutral';
      console.log(`  ${pad(whCode, 12)} in=${padNum(net.in)}  out=${padNum(net.out)}  net=${padNum(netQty)}  ${arrow}`);
    }

    // Interpretation
    console.log('\nInterpretation:');
    const hasPositive = [...netByWh.values()].some(v => v.in > v.out);
    const hasNegative = [...netByWh.values()].some(v => v.out > v.in);
    if (hasPositive && hasNegative) {
      console.log('  PATTERN: stock MOVED between warehouses (transfer/reassignment).');
      console.log('  Sources LOST stock; destinations GAINED it. Reversing the source');
      console.log('  side (e.g. restoring ILO-MAIN) WITHOUT reversing the destination');
      console.log('  side would DOUBLE the total stock. Do not restore.');
    } else if (hasNegative && !hasPositive) {
      console.log('  PATTERN: pure stock REMOVAL (shrinkage, expiry, write-off, sale).');
      console.log('  No destination received it.');
    } else if (hasPositive && !hasNegative) {
      console.log('  PATTERN: pure stock ADDITION (opening, receipt, correction).');
    }
  }

  await mongoose.disconnect();
}

run().catch(err => { console.error(err); process.exit(1); });

#!/usr/bin/env node
/**
 * migrateCalfOneAckFlow.js — Phase G4.5h (Apr 2026)
 *
 * One-time transition script for the CALF↔Expense one-acknowledge cascade.
 * Before G4.5h, an ACCESS-bearing Expense was submitted separately from its
 * CALF; both had their own ApprovalRequest row and the Expense was held in
 * SUBMITTED until CALF was approved. After G4.5h, the Expense posts purely
 * via the CALF cascade — a standalone EXPENSE_ENTRY ApprovalRequest is no
 * longer valid and the SUBMITTED limbo state is a leftover to be cleared.
 *
 * Strategy (per stuck Expense):
 *   - Find Expense docs in SUBMITTED that have any line with calf_required
 *     and calf_id set.
 *   - Group by CALF status:
 *       * CALF is POSTED → cascade should already have fired. Log for manual
 *         review (post the Expense via postSinglePrfCalf re-run, or hand-post).
 *         Do NOT auto-cascade here — the CALF event is in the past and the
 *         JE would be backdated; defer to an operator.
 *       * CALF is anything else (DRAFT / VALID / ERROR) → revert Expense to
 *         DRAFT and delete its EXPENSE_ENTRY ApprovalRequest row. The CALF
 *         submit (upcoming) will drive approval from then on.
 *   - Idempotent. Dry-run is the default.
 *
 * Usage:
 *   node backend/erp/scripts/migrateCalfOneAckFlow.js                  (dry-run)
 *   node backend/erp/scripts/migrateCalfOneAckFlow.js --apply          (execute)
 *   node backend/erp/scripts/migrateCalfOneAckFlow.js --entity=<id>    (scope)
 */

const path = require('path');
require('dotenv').config({ path: path.join(__dirname, '../../.env') });
const mongoose = require('mongoose');

const args = new Set(process.argv.slice(2));
const APPLY = args.has('--apply');
const entityArg = [...args].find(a => a.startsWith('--entity='));
const ENTITY_ID = entityArg ? entityArg.split('=')[1] : null;

async function main() {
  const uri = process.env.MONGO_URI;
  if (!uri) {
    console.error('[migrate] MONGO_URI missing from env');
    process.exit(1);
  }
  await mongoose.connect(uri);
  console.log(`[migrate] connected (apply=${APPLY}${ENTITY_ID ? `, entity=${ENTITY_ID}` : ''})`);

  const ExpenseEntry = require('../models/ExpenseEntry');
  const PrfCalf = require('../models/PrfCalf');
  const ApprovalRequest = require('../models/ApprovalRequest');
  const ErpAuditLog = require('../models/ErpAuditLog');

  const filter = { status: 'SUBMITTED' };
  if (ENTITY_ID) filter.entity_id = new mongoose.Types.ObjectId(ENTITY_ID);

  const expenses = await ExpenseEntry.find(filter).lean();
  console.log(`[migrate] found ${expenses.length} SUBMITTED expense(s) in scope`);

  const stuck = [];
  for (const e of expenses) {
    const calfLine = (e.lines || []).find(l => l.calf_required && l.calf_id);
    if (!calfLine) continue;
    const calf = await PrfCalf.findById(calfLine.calf_id).select('status calf_number').lean();
    stuck.push({ expense: e, calf, calfLine });
  }
  console.log(`[migrate] ${stuck.length} of these are stuck by an unposted (or posted-but-orphaned) CALF`);

  const posted = stuck.filter(s => s.calf?.status === 'POSTED');
  const unposted = stuck.filter(s => !s.calf || s.calf.status !== 'POSTED');

  console.log(`  - CALF already POSTED (manual review): ${posted.length}`);
  console.log(`  - CALF not POSTED (revert to DRAFT):    ${unposted.length}`);

  // List what we'd do
  for (const row of posted) {
    console.log(`  [POSTED-CALF] expense ${row.expense._id} (EXP-${row.expense.period}-${row.expense.cycle}) — CALF ${row.calf.calf_number || row.calf._id} POSTED. Hand-post the expense or re-run postSinglePrfCalf.`);
  }
  for (const row of unposted) {
    console.log(`  [REVERT]      expense ${row.expense._id} (EXP-${row.expense.period}-${row.expense.cycle}) — CALF ${row.calf?._id || 'MISSING'} status=${row.calf?.status || 'NOT_FOUND'} → revert Expense to DRAFT, drop EXPENSE_ENTRY ApprovalRequest.`);
  }

  if (!APPLY) {
    console.log('\n[migrate] dry-run — re-run with --apply to commit.');
    await mongoose.disconnect();
    return;
  }

  // Apply: only the "CALF not POSTED" branch — the posted-CALF branch is
  // manual-review because blindly back-posting stale docs would backdate JEs.
  let reverted = 0;
  let requestsDeleted = 0;
  for (const row of unposted) {
    const exp = await ExpenseEntry.findById(row.expense._id);
    if (!exp || exp.status !== 'SUBMITTED') continue;
    exp.status = 'DRAFT';
    exp.validation_errors = [];
    await exp.save();
    reverted++;

    const del = await ApprovalRequest.deleteMany({
      module: 'EXPENSES',
      doc_type: 'EXPENSE_ENTRY',
      doc_id: exp._id,
      status: { $in: ['PENDING', 'IN_REVIEW'] },
    });
    requestsDeleted += del.deletedCount || 0;

    await ErpAuditLog.logChange({
      entity_id: exp.entity_id,
      bdm_id: exp.bdm_id,
      log_type: 'MIGRATE',
      target_ref: exp._id.toString(),
      target_model: 'ExpenseEntry',
      changed_by: null,
      note: 'Phase G4.5h migration: reverted SUBMITTED→DRAFT (CALF now owns approval).'
    }).catch(err => console.error('[migrate] audit write failed (non-critical):', err.message));
  }

  console.log(`\n[migrate] reverted ${reverted} expense(s) to DRAFT; deleted ${requestsDeleted} stale EXPENSE_ENTRY ApprovalRequest row(s).`);
  console.log(`[migrate] ${posted.length} POSTED-CALF expense(s) still need manual review.`);
  await mongoose.disconnect();
}

main().catch(err => {
  console.error('[migrate] FATAL', err);
  process.exit(1);
});

#!/usr/bin/env node
/**
 * Phase 4A — Entity Data Migration
 *
 * Consolidates data from the fake "VIP Pharmacy Inc." entity into the real entities:
 *   - VIOS INTEGRATED PROJECTS (VIP) INC. (parent) — 8 VIP BDMs + Cristina + TEST
 *   - MG AND CO. INC. (subsidiary) — Jake Montero
 *
 * Also:
 *   - Makes Hospital model globally shared (removes entity_id requirement)
 *   - Merges duplicate hospitals
 *   - Deletes the fake entity after verification
 *
 * Safe to run multiple times (idempotent).
 *
 * Usage: cd backend && node erp/scripts/migrateEntityData.js
 */

const mongoose = require('mongoose');
const path = require('path');
require('dotenv').config({ path: path.join(__dirname, '../../.env') });

// Models
const Entity = require('../models/Entity');
const User = require('../../models/User');
const ProductMaster = require('../models/ProductMaster');
const InventoryLedger = require('../models/InventoryLedger');
const SalesLine = require('../models/SalesLine');
const TransactionEvent = require('../models/TransactionEvent');
const GrnEntry = require('../models/GrnEntry');
const ConsignmentTracker = require('../models/ConsignmentTracker');
const Hospital = require('../models/Hospital');
const ErpAuditLog = require('../models/ErpAuditLog');

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) {
  console.error('MONGO_URI not set');
  process.exit(1);
}

// Known MG AND CO. BDM — case-insensitive match
const MG_BDM_NAMES = ['jake montero'];

/**
 * Determine whether a user is an MG BDM based on name matching
 */
function isMgBdm(user) {
  const name = (user.name || '').toLowerCase().trim();
  return MG_BDM_NAMES.some(mg => name.includes(mg));
}

async function run() {
  await mongoose.connect(MONGO_URI);
  console.log('Connected to MongoDB\n');

  // ─── Step 1: Find entities ───
  const vipEntity = await Entity.findOne({
    entity_name: { $regex: /VIOS INTEGRATED/i }
  });
  const mgEntity = await Entity.findOne({
    entity_name: { $regex: /MG AND CO/i }
  });

  if (!vipEntity) {
    console.error('VIP (VIOS INTEGRATED) entity not found. Run seedEntities.js first.');
    process.exit(1);
  }
  if (!mgEntity) {
    console.error('MG AND CO. entity not found. Run seedEntities.js first.');
    process.exit(1);
  }

  console.log(`VIP entity: ${vipEntity._id} — ${vipEntity.entity_name}`);
  console.log(`MG  entity: ${mgEntity._id} — ${mgEntity.entity_name}\n`);

  // ─── Step 2: Find all fake/wrong entity IDs ───
  // Any entity_id on Users/Products/Ledger that is NOT vipEntity or mgEntity
  const allEntities = await Entity.find().lean();
  const validIds = new Set([vipEntity._id.toString(), mgEntity._id.toString()]);
  const fakeEntities = allEntities.filter(e => !validIds.has(e._id.toString()));

  console.log(`Found ${fakeEntities.length} entities to clean up:`);
  for (const fe of fakeEntities) {
    console.log(`  - ${fe._id} "${fe.entity_name}" (${fe.entity_type})`);
  }
  const fakeIds = fakeEntities.map(e => e._id);

  // ─── Step 3: Identify and reassign users ───
  const allBdms = await User.find({
    role: { $in: ['employee'] },
    isActive: { $ne: false }
  }).select('name email entity_id role').lean();

  console.log(`\nFound ${allBdms.length} active BDMs:`);

  let vipCount = 0;
  let mgCount = 0;

  for (const bdm of allBdms) {
    const targetEntity = isMgBdm(bdm) ? mgEntity : vipEntity;
    const targetLabel = isMgBdm(bdm) ? 'MG' : 'VIP';
    const currentId = bdm.entity_id?.toString();
    const targetId = targetEntity._id.toString();

    if (currentId === targetId) {
      console.log(`  ✓ ${bdm.name} (${bdm.email}) — already ${targetLabel}`);
    } else {
      await User.updateOne(
        { _id: bdm._id },
        { $set: { entity_id: targetEntity._id } }
      );
      console.log(`  → ${bdm.name} (${bdm.email}) — moved to ${targetLabel}`);
    }
    if (isMgBdm(bdm)) mgCount++;
    else vipCount++;
  }

  // Also assign admin/president/finance users to VIP entity
  const adminUsers = await User.find({
    role: { $in: ['admin', 'president', 'ceo', 'finance'] }
  }).select('name email entity_id role').lean();

  for (const u of adminUsers) {
    if (u.entity_id?.toString() !== vipEntity._id.toString()) {
      await User.updateOne(
        { _id: u._id },
        { $set: { entity_id: vipEntity._id } }
      );
      console.log(`  → ${u.name} (${u.role}) — assigned to VIP`);
    }
  }

  console.log(`\nBDM assignment: ${vipCount} VIP, ${mgCount} MG\n`);

  // ─── Step 4: Migrate ProductMaster ───
  if (fakeIds.length > 0) {
    // Get all BDMs by entity for product assignment
    const mgBdms = allBdms.filter(isMgBdm);
    const mgBdmIds = mgBdms.map(b => b._id);

    // Find products that belong to fake entities
    const fakeProducts = await ProductMaster.find({
      entity_id: { $in: fakeIds }
    }).lean();

    console.log(`Products on fake entities: ${fakeProducts.length}`);

    // Check if these products were created for MG BDMs (via inventory)
    // MG products: those that have inventory ledger entries for MG BDMs
    const mgProductIds = new Set();
    if (mgBdmIds.length > 0) {
      const mgLedger = await InventoryLedger.distinct('product_id', {
        bdm_id: { $in: mgBdmIds }
      });
      for (const pid of mgLedger) mgProductIds.add(pid.toString());
    }

    let movedToVip = 0;
    let movedToMg = 0;
    let skippedDup = 0;

    for (const product of fakeProducts) {
      const targetEntity = mgProductIds.has(product._id.toString()) ? mgEntity : vipEntity;
      const targetLabel = mgProductIds.has(product._id.toString()) ? 'MG' : 'VIP';

      // Check for duplicate item_key in target entity
      const existing = await ProductMaster.findOne({
        entity_id: targetEntity._id,
        item_key: product.item_key
      });

      if (existing) {
        // Update references to point to existing product, then delete duplicate
        await InventoryLedger.updateMany(
          { product_id: product._id },
          { $set: { product_id: existing._id } }
        );
        await SalesLine.updateMany(
          { 'line_items.product_id': product._id },
          { $set: { 'line_items.$.product_id': existing._id } }
        );
        await ProductMaster.deleteOne({ _id: product._id });
        skippedDup++;
      } else {
        await ProductMaster.updateOne(
          { _id: product._id },
