  const hospitalCount = await Hospital.countDocuments();
  const hospWithEntity = await Hospital.countDocuments({ entity_id: { $exists: true, $ne: null } });
  console.log(`\nHospitals: ${hospitalCount} total, ${hospWithEntity} still with entity_id (should be 0)`);

  console.log('\n✅ Migration complete!');
  await mongoose.disconnect();
}

/**
 * Merge duplicate hospitals (same hospital_name_clean, different entity_id).
 * Keeps the first one found, merges tagged_bdms from others.
 */
async function mergeDuplicateHospitals() {
  const duplicates = await Hospital.aggregate([
    { $group: { _id: '$hospital_name_clean', count: { $sum: 1 }, ids: { $push: '$_id' } } },
    { $match: { count: { $gt: 1 } } }
  ]);

  for (const dup of duplicates) {
    const hospitals = await Hospital.find({ _id: { $in: dup.ids } }).sort({ createdAt: 1 });
    const keeper = hospitals[0];
    const toMerge = hospitals.slice(1);

    // Consolidate tagged_bdms
    const existingBdmIds = new Set(keeper.tagged_bdms.map(t => t.bdm_id.toString()));
    for (const h of toMerge) {
      for (const tag of h.tagged_bdms) {
        if (!existingBdmIds.has(tag.bdm_id.toString())) {
          keeper.tagged_bdms.push(tag);
          existingBdmIds.add(tag.bdm_id.toString());
        }
      }
    }
    await keeper.save();

    // Update references in other collections to point to keeper
    const mergeIds = toMerge.map(h => h._id);
    await SalesLine.updateMany(
      { hospital_id: { $in: mergeIds } },
      { $set: { hospital_id: keeper._id } }
    );
    await ConsignmentTracker.updateMany(
      { hospital_id: { $in: mergeIds } },
      { $set: { hospital_id: keeper._id } }
    );

    // Delete merged duplicates
    await Hospital.deleteMany({ _id: { $in: mergeIds } });
    console.log(`    Merged ${toMerge.length} duplicates of "${keeper.hospital_name}" → kept ${keeper._id}`);
  }
}

run().catch(err => {
  console.error('Migration failed:', err);
  process.exit(1);
});

/**
 * Migration: Set erp_access on existing users based on role
 *
 * - employee with entity_id → Field BDM template
 * - finance with entity_id  → Finance template
 * - admin / president / ceo  → skip (role override in middleware)
 * - users without entity_id  → skip (CRM-only)
 *
 * Idempotent: skips users where erp_access.enabled is already true.
 *
 * Usage: node backend/erp/scripts/migrateErpAccess.js
 */
const path = require('path');
require('dotenv').config({ path: path.join(__dirname, '../../.env') });
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const User = require('../../models/User');
const AccessTemplate = require('../models/AccessTemplate');

const ROLE_TEMPLATE_MAP = {
  employee: 'Field BDM',
  finance: 'Finance',
};

const migrate = async () => {
  await connectDB();
  console.log('═══ Migrate ERP Access ═══\n');

  // Build template lookup: entity_id -> template_name -> template doc
  const templates = await AccessTemplate.find({ is_system: true }).lean();
  const tplMap = {};
  for (const t of templates) {
    const eid = t.entity_id.toString();
    if (!tplMap[eid]) tplMap[eid] = {};
    tplMap[eid][t.template_name] = t;
  }

  // Get users who need migration
  const users = await User.find({
    entity_id: { $ne: null },
    role: { $in: ['employee', 'finance'] },
    $or: [
      { 'erp_access.enabled': { $ne: true } },
      { erp_access: { $exists: false } },
    ],
  }).select('_id name role entity_id erp_access');

  let migrated = 0;
  let skipped = 0;

  for (const user of users) {
    const templateName = ROLE_TEMPLATE_MAP[user.role];
    if (!templateName) { skipped++; continue; }

    const eid = user.entity_id.toString();
    const tpl = tplMap[eid]?.[templateName];
    if (!tpl) {
      console.log(`  ⚠ No "${templateName}" template for entity ${eid} — skipping ${user.name}`);
      skipped++;
      continue;
    }

    user.erp_access = {
      enabled: true,
      template_id: tpl._id,
      modules: { ...tpl.modules },
      can_approve: tpl.can_approve,
      updated_at: new Date(),
    };
    user.markModified('erp_access');
    await user.save();
    migrated++;
    console.log(`  ✓ ${user.name} (${user.role}) → ${templateName}`);
  }

  console.log(`\n  Migrated: ${migrated}, Skipped: ${skipped}`);
  console.log('\n═══ Done ═══');
  await mongoose.disconnect();
};

migrate().catch(err => {
  console.error('Migration error:', err);
  mongoose.disconnect();
  process.exit(1);
});

/**
 * Migrate Hospital Access: tagged_bdms → warehouse_ids
 * Also imports new hospitals for GSC (Gensan) territory.
 *
 * Logic:
 *   1. For each hospital with tagged_bdms, find which warehouse(s) those BDMs belong to
 *   2. Set warehouse_ids on the hospital based on the BDM→warehouse mapping
 *   3. Import new GSC hospitals that don't exist yet
 *   4. Assign GSC warehouse_id to all GSC hospitals
 *
 * Safe to run multiple times — idempotent.
 *
 * Usage: node backend/erp/scripts/migrateHospitalWarehouses.js
 */
const path = require('path');
require('dotenv').config({ path: path.resolve(__dirname, '../../.env') });
const mongoose = require('mongoose');
const connectDB = require('../../config/db');

// GSC hospitals (cleaned, deduped, typos fixed)
const GSC_HOSPITALS = [
  'Mindanao Medical Center',
  'Sarangani Bay Specialist',
  'Gensan Medical Center',
  'Nestor Dizon Hospital',
  'Labilla Hospital',
  'Doctors Hospital',
  'St Elizabeth Hospital',
  'Socsargen Hospital',
  'Diangas Medical Center',
  'Royeca Hospital',
  'Teoborsio Hospital',
  'Heramil Hospital',
  'Bontoyan Hospital',
  'Howard Havard Hospital',
  'Adventist Hospital',
  'Tupi Provincial Hospital',
  'Allah Valley Hospital',
  'Socomedics Hospital',
  'Sultan Kudarat Provincial Hospital',
  'Tacurong Doctors Hospital',
  'Sultan Kudarat Doctors Hospital',
  'Quijano Hospital',
  'St. Louis Hospital',
  'Notre Dame Hospital',
  'Cotabato Doctors',
  'Pingoy Hospital'
];

async function run() {
  await connectDB();
  const Hospital = require('../models/Hospital');
  const Warehouse = require('../models/Warehouse');
  const User = require('../../models/User');

  // ── Step 1: Build BDM → warehouse mapping ──
  console.log('\n=== Step 1: Building BDM → warehouse mapping ===');
  const warehouses = await Warehouse.find({ is_active: true }).select('_id warehouse_code warehouse_name manager_id assigned_users').lean();
  const bdmToWarehouse = new Map(); // bdmId → warehouseId

  for (const w of warehouses) {
    if (w.manager_id) {
      bdmToWarehouse.set(w.manager_id.toString(), w._id);
      console.log(`  ${w.warehouse_code}: manager → ${w.manager_id}`);
    }
    for (const uid of (w.assigned_users || [])) {
      bdmToWarehouse.set(uid.toString(), w._id);
      console.log(`  ${w.warehouse_code}: assigned → ${uid}`);
    }
  }
  console.log(`  Total BDM→warehouse mappings: ${bdmToWarehouse.size}`);

  // ── Step 2: Migrate existing hospitals (tagged_bdms → warehouse_ids) ──
  console.log('\n=== Step 2: Migrating tagged_bdms → warehouse_ids ===');
  const allHospitals = await Hospital.find({}).select('_id hospital_name tagged_bdms warehouse_ids');
  let migrated = 0;

  for (const h of allHospitals) {
    const existingWhIds = new Set((h.warehouse_ids || []).map(id => id.toString()));
    const newWhIds = new Set();

    for (const tag of (h.tagged_bdms || []).filter(t => t.is_active !== false)) {
      const whId = bdmToWarehouse.get(tag.bdm_id.toString());
      if (whId && !existingWhIds.has(whId.toString())) {
        newWhIds.add(whId.toString());
      }
    }

    if (newWhIds.size > 0) {
      const toAdd = [...newWhIds].map(id => new mongoose.Types.ObjectId(id));
      await Hospital.updateOne(
        { _id: h._id },
        { $addToSet: { warehouse_ids: { $each: toAdd } } }
      );
      const whCodes = toAdd.map(id => warehouses.find(w => w._id.toString() === id.toString())?.warehouse_code || '?');
      console.log(`  ${h.hospital_name}: +${newWhIds.size} warehouse(s) [${whCodes.join(', ')}]`);
      migrated++;
    }
  }
  console.log(`  Migrated: ${migrated} hospital(s)`);

  // ── Step 3: Import GSC hospitals ──
  console.log('\n=== Step 3: Importing GSC hospitals ===');
  const gscWarehouse = warehouses.find(w => w.warehouse_code === 'GSC');
  if (!gscWarehouse) {
    console.error('  GSC warehouse not found!');
    await mongoose.disconnect();
    return;
  }
  console.log(`  GSC warehouse: ${gscWarehouse.warehouse_name} (${gscWarehouse._id})`);

  let created = 0, alreadyExists = 0, gscTagged = 0;

  for (const name of GSC_HOSPITALS) {
    // Case-insensitive check for existing hospital
    const existing = await Hospital.findOne({
      hospital_name: { $regex: `^${name.replace(/[-/\\^$*+?.()|[\]{}]/g, '\\$&')}$`, $options: 'i' }
    });

    if (existing) {
      // Ensure GSC warehouse_id is set
      const hasGsc = (existing.warehouse_ids || []).some(id => id.toString() === gscWarehouse._id.toString());
      if (!hasGsc) {
        await Hospital.updateOne(
          { _id: existing._id },
          { $addToSet: { warehouse_ids: gscWarehouse._id } }
        );
        console.log(`  EXISTS + tagged GSC: ${existing.hospital_name}`);
        gscTagged++;
      } else {
        console.log(`  EXISTS (already GSC): ${existing.hospital_name}`);
      }
      alreadyExists++;
    } else {
      await Hospital.create({
        hospital_name: name,
        warehouse_ids: [gscWarehouse._id],
        status: 'ACTIVE',
        payment_terms: 30,
        vat_status: 'VATABLE',
        cwt_rate: 0.01
      });
      console.log(`  CREATED: ${name}`);
      created++;
    }
  }

  console.log(`\n  GSC summary: ${created} created, ${alreadyExists} existed, ${gscTagged} newly tagged to GSC`);

  // ── Step 4: Summary ──
  console.log('\n=== Final Summary ===');
  const finalCount = await Hospital.countDocuments({ status: 'ACTIVE' });
  const withWh = await Hospital.countDocuments({ status: 'ACTIVE', 'warehouse_ids.0': { $exists: true } });
  const withoutWh = finalCount - withWh;
  console.log(`  Active hospitals: ${finalCount}`);
  console.log(`  With warehouse assignment: ${withWh}`);
  console.log(`  Without warehouse assignment: ${withoutWh}`);

  if (withoutWh > 0) {
    const unassigned = await Hospital.find({ status: 'ACTIVE', $or: [{ warehouse_ids: { $exists: false } }, { warehouse_ids: { $size: 0 } }] }).select('hospital_name').lean();
    console.log('  Unassigned hospitals:');
    for (const h of unassigned) console.log(`    - ${h.hospital_name}`);
  }

  await mongoose.disconnect();
}

run().catch(err => {
  console.error('Error:', err);
  process.exit(1);
});

/**
 * Migration: Split SALES_SETTINGS.REQUIRE_CSI_PHOTO into two codes.
 *
 * Old (single code): REQUIRE_CSI_PHOTO — gated Validate for every CSI row
 * regardless of source. Default 1.
 *
 * New (two codes):
 *   - REQUIRE_CSI_PHOTO_OPENING_AR (default 1): gates Validate for OPENING_AR.
 *   - REQUIRE_CSI_PHOTO_SALES_LINE (default 0): reserved future Submit gate
 *     for live Sales; off by default because the signed CSI is a post-
 *     delivery artifact attached via PUT /sales/:id/received-csi.
 *
 * Per-entity: for each entity that has the old code, we copy its value into
 * REQUIRE_CSI_PHOTO_OPENING_AR (preserving whatever the subscriber already
 * tuned) and leave SALES_LINE at the off default. Then we deactivate the old
 * code (is_active=false) so Control Center stops surfacing it.
 *
 * Safe to re-run — skips entries that already exist at the new codes.
 *
 * Usage: node backend/erp/scripts/migrateSalesPhotoLookup.js
 */
require('dotenv').config();
const db = require('../../config/db');

async function migrate() {
  await db();
  const Lookup = require('../models/Lookup');

  const oldEntries = await Lookup.find({
    category: 'SALES_SETTINGS',
    code: 'REQUIRE_CSI_PHOTO',
  });

  console.log(`Found ${oldEntries.length} legacy REQUIRE_CSI_PHOTO rows`);

  let createdOpeningAr = 0;
  let createdSalesLine = 0;
  let deactivated = 0;

  for (const old of oldEntries) {
    const preservedValue = old.metadata?.value ?? 1;

    const existingOa = await Lookup.findOne({
      entity_id: old.entity_id,
      category: 'SALES_SETTINGS',
      code: 'REQUIRE_CSI_PHOTO_OPENING_AR',
    });
    if (!existingOa) {
      await Lookup.create({
        entity_id: old.entity_id,
        category: 'SALES_SETTINGS',
        code: 'REQUIRE_CSI_PHOTO_OPENING_AR',
        label: 'Require CSI Photo on Opening AR Validate',
        metadata: {
          value: preservedValue,
          description: 'Migrated from REQUIRE_CSI_PHOTO. Any proof accepted (csi_photo_url OR csi_received_photo_url).',
        },
        is_active: true,
      });
      createdOpeningAr++;
    }

    const existingSl = await Lookup.findOne({
      entity_id: old.entity_id,
      category: 'SALES_SETTINGS',
      code: 'REQUIRE_CSI_PHOTO_SALES_LINE',
    });
    if (!existingSl) {
      await Lookup.create({
        entity_id: old.entity_id,
        category: 'SALES_SETTINGS',
        code: 'REQUIRE_CSI_PHOTO_SALES_LINE',
        label: 'Require Received CSI Photo on Live Sales Submit (reserved)',
        metadata: {
          value: 0,
          description: 'Reserved Submit gate. Default 0 — live Sales post at invoice issuance; signed CSI is attached post-delivery.',
        },
        is_active: true,
      });
      createdSalesLine++;
    }

    if (old.is_active !== false) {
      old.is_active = false;
      await old.save();
      deactivated++;
    }
  }

  console.log(`Created ${createdOpeningAr} REQUIRE_CSI_PHOTO_OPENING_AR entries`);
  console.log(`Created ${createdSalesLine} REQUIRE_CSI_PHOTO_SALES_LINE entries`);
  console.log(`Deactivated ${deactivated} legacy REQUIRE_CSI_PHOTO entries`);
  console.log('Migration complete');
  process.exit(0);
}

migrate().catch((err) => {
  console.error('Migration failed:', err);
  process.exit(1);
});

/**
 * Archive-Rename Reversed SMERs to Free Unique Keys
 *
 * Context (2026-04-21): the SmerEntry unique index `{entity_id, bdm_id, period,
 * cycle}` blocks a BDM from creating a fresh SMER for a period+cycle whose
 * prior SMER was reversed via Reversal Console (SAP Storno leaves the row with
 * `deletion_event_id` stamped). A partial-filter-on-`$exists: false` approach
 * was attempted first and abandoned — MongoDB rejects it with
 * "Expression not supported in partial index: $not".
 *
 * Instead we keep the plain unique index and archive-rename reversed rows:
 *   period: `${period}::REV::${_id}`
 * so the key frees for a new SMER while the reversed row keeps its _id, daily
 * entries, and deletion_event_id. `getSmerList` already hides reversed rows,
 * so the renamed period is invisible in normal UI flows.
 *
 * Going forward, `createSmer` performs this rename in-line when a new SMER
 * collides with a reversed dupe. This script handles the backlog — any
 * pre-existing reversed SMERs that still sit on the original period+cycle.
 *
 * Idempotent: a row whose period already contains "::REV::" is skipped.
 *
 * Usage (from backend/):
 *   node erp/scripts/migrateSmerUniqueIndex.js           # dry-run
 *   node erp/scripts/migrateSmerUniqueIndex.js --apply   # writes
 */
require('dotenv').config();
const mongoose = require('mongoose');

const APPLY = process.argv.includes('--apply');

async function main() {
  await mongoose.connect(process.env.MONGO_URI);
  console.log(`Connected. Mode: ${APPLY ? 'APPLY' : 'DRY-RUN'}`);

  const SmerEntry = require('../models/SmerEntry');
  const reversed = await SmerEntry.find({
    deletion_event_id: { $exists: true },
    period: { $not: /::REV::/ },
  }).select('_id entity_id bdm_id period cycle').lean();

  console.log(`Scanning ${reversed.length} reversed SMER(s) still holding their original period+cycle…`);

  let renamed = 0;
  for (const s of reversed) {
    const newPeriod = `${s.period}::REV::${s._id}`;
    console.log(`  ${s._id}: ${s.period} ${s.cycle}  →  ${newPeriod}`);
    if (APPLY) {
      await SmerEntry.updateOne({ _id: s._id }, { $set: { period: newPeriod } });
    }
    renamed++;
  }

  console.log('');
  console.log(`Summary: ${renamed} reversed SMER(s) archived.`);
  if (!APPLY) console.log('DRY-RUN — rerun with --apply to persist.');

  await mongoose.disconnect();
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});

/**
 * Migration Script: Backfill UOM fields on ProductMaster
 *
 * Sets selling_uom = unit_code, purchase_uom = unit_code, conversion_factor = 1
 * for all existing products where these fields are not yet set.
 *
 * Safe to run multiple times — only updates documents missing the fields.
 *
 * Usage: node backend/erp/scripts/migrateUomFields.js
 */
require('dotenv').config();
const mongoose = require('mongoose');
const db = require('../../config/db');

async function migrate() {
  await db();

  const ProductMaster = require('../models/ProductMaster');

  // Find products where selling_uom or purchase_uom is not set
  const products = await ProductMaster.find({
    $or: [
      { selling_uom: { $exists: false } },
      { selling_uom: null },
      { selling_uom: '' },
      { purchase_uom: { $exists: false } },
      { purchase_uom: null },
      { purchase_uom: '' }
    ]
  }).select('unit_code sold_per selling_uom purchase_uom conversion_factor');

  console.log(`Found ${products.length} products to update`);

  let updated = 0;
  for (const p of products) {
    const baseUnit = p.unit_code || 'PC';
    const changes = {};

    if (!p.selling_uom) changes.selling_uom = baseUnit;
    if (!p.purchase_uom) changes.purchase_uom = baseUnit;
    if (p.conversion_factor == null) changes.conversion_factor = 1;

    if (Object.keys(changes).length > 0) {
      await ProductMaster.updateOne({ _id: p._id }, { $set: changes });
      updated++;
    }
  }

  console.log(`Updated ${updated} products with UOM defaults`);
  console.log('Migration complete');
  await mongoose.disconnect();
}

migrate().catch(err => {
  console.error('Migration failed:', err);
  process.exit(1);
});

