/**
 * Refresh Product Master from cleaned CSV — Phase 17
 *
 * Reads the MASTER_ITEM_MASTER.csv, deduplicates by BrandName|DosageStrength,
 * upserts into ProductMaster, deactivates duplicates and stale records.
 *
 * Usage: node backend/erp/scripts/refreshProductMaster.js
 */
require('dotenv').config();
const fs = require('fs');
const path = require('path');
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const ProductMaster = require('../models/ProductMaster');
const Entity = require('../models/Entity');
const { cleanName } = require('../utils/nameClean');
const { normalizeUnit } = require('../utils/normalize');

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    if (line[i] === '"') { inQuotes = !inQuotes; }
    else if (line[i] === ',' && !inQuotes) { result.push(current.trim()); current = ''; }
    else { current += line[i]; }
  }
  result.push(current.trim());
  return result;
}

async function run() {
  const csvPath = process.argv[2] || path.resolve(__dirname, '../../../docs/MASTER ITEM MASTER - MASTER_ITEM_MASTER.csv');
  if (!fs.existsSync(csvPath)) {
    console.error('CSV not found:', csvPath);
    process.exit(1);
  }

  await connectDB();
  console.log('=== Product Master Refresh ===\n');

  // Parse CSV
  const content = fs.readFileSync(csvPath, 'utf-8');
  const lines = content.split('\n').filter(l => l.trim());
  const headers = parseCSVLine(lines[0]);
  const rows = lines.slice(1).map(l => {
    const vals = parseCSVLine(l);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = vals[i] || ''; });
    return obj;
  });

  console.log(`Parsed ${rows.length} rows from CSV`);

  // Find VIP entity (primary)
  const vipEntity = await Entity.findOne({ short_name: { $regex: /^VIP$/i } }).lean();
  if (!vipEntity) {
    console.error('VIP entity not found!');
    process.exit(1);
  }
  const entityId = vipEntity._id;
  console.log(`Entity: ${vipEntity.entity_name} (${entityId})\n`);

  // Deduplicate CSV by BrandName|DosageStrength (case-insensitive)
  // Same product from different BDMs = same product, keep the one with better prices
  const dedupMap = new Map();
  for (const row of rows) {
    const brand = (row.BrandName || '').trim();
    const dosage = (row.DosageStrength || '').trim();
    if (!brand) continue;

    // Case-insensitive key for dedup
    const key = `${brand.toUpperCase()}|${dosage.toLowerCase()}`;
    const isActive = (row.IsActive || 'TRUE').toUpperCase() !== 'FALSE';
    const sp = parseFloat((row.DefaultSellingPrice || '0').replace(/,/g, '')) || 0;

    if (!dedupMap.has(key)) {
      dedupMap.set(key, { row, isActive, sp });
    } else {
      const existing = dedupMap.get(key);
      // Prefer: active over inactive, then higher selling price (more likely the real product)
      if ((!existing.isActive && isActive) || (existing.sp === 0 && sp > 0)) {
        dedupMap.set(key, { row, isActive, sp });
      }
    }
  }

  console.log(`Unique products: ${dedupMap.size} (${rows.length - dedupMap.size} CSV duplicates merged)\n`);

  let updated = 0, created = 0, deactivated = 0, errors = 0;
  const processedCleanKeys = new Set();

  for (const [dedupKey, { row, isActive }] of dedupMap) {
    const brand = (row.BrandName || '').trim();
    const dosage = (row.DosageStrength || '').trim();
    const generic = (row.GenericName || '').trim();
    const soldPer = (row.SoldPer || '').trim();
    const pp = parseFloat((row.DefaultPurchasePrice || '0').replace(/,/g, '')) || 0;
    const sp = parseFloat((row.DefaultSellingPrice || '0').replace(/,/g, '')) || 0;
    const itemKey = `${brand}|${dosage}`;
    const brandClean = cleanName(brand);

    processedCleanKeys.add(`${brandClean}|${dosage.toLowerCase().replace(/\s+/g, '')}`);

    try {
      // Find ALL candidates that could be this product (case-insensitive dosage)
      const dosageRegex = dosage ? new RegExp(`^${dosage.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$`, 'i') : null;
      const candidates = await ProductMaster.find({
        entity_id: entityId,
        $or: [
          { item_key: itemKey },
          { brand_name_clean: brandClean, ...(dosageRegex ? { dosage_strength: dosageRegex } : { dosage_strength: { $in: [null, ''] } }) },
        ],
      }).lean();

      if (candidates.length > 0) {
        // Pick keeper (prefer active, then first)
        const keeper = candidates.find(c => c.is_active) || candidates[0];

        // Deactivate duplicates FIRST
        for (const dup of candidates) {
          if (dup._id.toString() !== keeper._id.toString()) {
            await ProductMaster.updateOne({ _id: dup._id }, { $set: { is_active: false } });
            deactivated++;
          }
        }

        // Update keeper
        const update = {
          brand_name: brand,
          brand_name_clean: brandClean,
          dosage_strength: dosage,
          item_key: itemKey,
          is_active: isActive,
        };
        if (generic) update.generic_name = generic;
        if (soldPer) { update.sold_per = soldPer; update.unit_code = normalizeUnit(soldPer); }
        if (pp > 0) update.purchase_price = pp;
        if (sp > 0) update.selling_price = sp;

        await ProductMaster.updateOne({ _id: keeper._id }, { $set: update });
        updated++;
      } else {
        // Create new
        await ProductMaster.create({
          entity_id: entityId,
          item_key: itemKey,
          brand_name: brand,
          brand_name_clean: brandClean,
          generic_name: generic || brand,
          dosage_strength: dosage,
          sold_per: soldPer || 'PC',
          unit_code: normalizeUnit(soldPer),
          purchase_price: pp,
          selling_price: sp,
          is_active: isActive,
        });
        created++;
        console.log(`  + ${brand} ${dosage}`);
      }
    } catch (err) {
      console.log(`  ERROR: ${brand} ${dosage} — ${err.message}`);
      errors++;
    }
  }

  // Deactivate stale products not in CSV
  let staleDeactivated = 0;
  const activeProducts = await ProductMaster.find({ entity_id: entityId, is_active: true }).lean();
  for (const prod of activeProducts) {
    const prodClean = `${cleanName(prod.brand_name)}|${(prod.dosage_strength || '').toLowerCase().replace(/\s+/g, '')}`;
    if (!processedCleanKeys.has(prodClean)) {
      await ProductMaster.updateOne({ _id: prod._id }, { $set: { is_active: false } });
      staleDeactivated++;
      console.log(`  STALE: ${prod.brand_name} ${prod.dosage_strength} — deactivated`);
    }
  }

  // Final counts
  const totalActive = await ProductMaster.countDocuments({ entity_id: entityId, is_active: true });
  const totalInactive = await ProductMaster.countDocuments({ entity_id: entityId, is_active: false });

  console.log('\n=== Refresh Complete ===');
  console.log(`Updated: ${updated}`);
  console.log(`Created: ${created}`);
  console.log(`Duplicates deactivated: ${deactivated}`);
  console.log(`Stale deactivated: ${staleDeactivated}`);
  console.log(`Errors: ${errors}`);
  console.log(`\nFinal: ${totalActive} active, ${totalInactive} inactive`);

  await mongoose.disconnect();
}

run().catch(err => { console.error('Refresh failed:', err); process.exit(1); });

/**
 * Migration: renumber legacy JournalEntry.je_number values.
 *
 * Legacy rollout stored a raw DocSequence number (e.g. "8"). Apr 2026 switched
 * to `JE-{ENTITY_CODE}{MMDDYY}-{NNN}` via `services/docNumbering.js#generateJeNumber`.
 * Existing JEs in the DB still show bare numbers in the detail panel.
 *
 * This script finds every JE whose `je_number` is purely numeric and rewrites
 * it using the new format, keyed by each JE's own `entity_id` + `je_date`.
 * Sequence numbers come from DocSequence, so the rewritten numbers interleave
 * safely with any already-correct same-day JEs.
 *
 * Also re-derives `source_doc_ref` for SALES JEs where the ref is a 24-char
 * hex ObjectId (legacy fallback from the old `journalFromSale`), by looking
 * up the linked SalesLine's `doc_ref` (CSI booklet#) or `invoice_number`.
 *
 * Safe to re-run — the numeric filter skips already-migrated JEs.
 *
 * Usage: node backend/erp/scripts/renumberLegacyJEs.js [--dry-run]
 */
require('dotenv').config();
const mongoose = require('mongoose');
const db = require('../../config/db');
const JournalEntry = require('../models/JournalEntry');
const SalesLine = require('../models/SalesLine');
const { generateJeNumber } = require('../services/docNumbering');

const DRY_RUN = process.argv.includes('--dry-run');
const OBJECT_ID_RE = /^[0-9a-f]{24}$/i;
const NUMERIC_RE = /^\d+$/;

async function migrate() {
  await db();

  const legacy = await JournalEntry.find({ je_number: { $regex: NUMERIC_RE } })
    .select('_id entity_id je_date je_number source_module source_doc_ref source_event_id')
    .sort({ je_date: 1, created_at: 1 })
    .lean();

  console.log(`Found ${legacy.length} JE(s) with legacy numeric je_number`);

  let renumbered = 0;
  let refFixed = 0;
  const failures = [];

  for (const je of legacy) {
    const updates = {};

    try {
      const newNumber = await generateJeNumber({ entityId: je.entity_id, date: je.je_date });
      updates.je_number = newNumber;
    } catch (err) {
      failures.push({ id: je._id.toString(), reason: `je_number: ${err.message}` });
      continue;
    }

    // Legacy sales fallback wrote ObjectId hex strings into source_doc_ref.
    // Resolve those to the SalesLine's human-readable doc_ref.
    if (je.source_module === 'SALES' && je.source_doc_ref && OBJECT_ID_RE.test(je.source_doc_ref)) {
      try {
        const sale = await SalesLine.findById(je.source_doc_ref)
          .select('doc_ref invoice_number sale_type')
          .lean();
        const resolved = sale?.doc_ref || sale?.invoice_number;
        if (resolved) {
          updates.source_doc_ref = resolved;
          updates.description = `${sale.sale_type === 'SERVICE_INVOICE' ? 'SI' : sale.sale_type === 'CASH_RECEIPT' ? 'CR' : 'CSI'} ${resolved}`;
          refFixed++;
        }
      } catch (err) {
        // non-fatal — renumbering still applies
        console.warn(`  ⚠ source_doc_ref resolve failed for JE ${je._id}: ${err.message}`);
      }
    }

    if (DRY_RUN) {
      console.log(`  [dry] ${je.je_number} → ${updates.je_number}${updates.source_doc_ref ? ` · doc_ref → ${updates.source_doc_ref}` : ''}`);
    } else {
      try {
        await JournalEntry.updateOne({ _id: je._id }, { $set: updates });
      } catch (err) {
        failures.push({ id: je._id.toString(), reason: err.message });
        continue;
      }
    }
    renumbered++;
  }

  console.log('');
  console.log(`${DRY_RUN ? '[dry-run] ' : ''}Renumbered: ${renumbered}/${legacy.length}`);
  console.log(`${DRY_RUN ? '[dry-run] ' : ''}source_doc_ref resolved: ${refFixed}`);
  if (failures.length) {
    console.log(`Failures: ${failures.length}`);
    failures.forEach(f => console.log(`  ✗ ${f.id}: ${f.reason}`));
  }

  await mongoose.disconnect();
}

migrate().catch(err => {
  console.error(err);
  process.exit(1);
});

/**
 * Repair Stuck Per Diem Overrides
 *
 * Context (2026-04-21): a latent bug in universalApprovalController.perdiem_override
 * silently no-op'd the SMER write-back when the parent SMER's status was not in
 * the lookup-driven editable set (typically ['DRAFT', 'ERROR']). The handler flipped
 * the ApprovalRequest to APPROVED but the daily entry stayed `override_status: 'PENDING'`,
 * so the contractor's UI kept showing "pending" forever.
 *
 * The handler has since been fixed and the SMER validate/submit path now blocks
 * submission while any override is PENDING. This script repairs pre-existing
 * stuck records.
 *
 * For every ApprovalRequest with:
 *   module: 'PERDIEM_OVERRIDE', status: 'APPROVED'
 * we look up the linked SmerEntry + daily entry. If the entry is still PENDING:
 *   - SMER in DRAFT/VALID/ERROR → re-apply the override (totals auto-recompute on save)
 *   - SMER in POSTED            → log a warning (ledger already journaled with
 *                                 pre-override amount; admin must reopen via
 *                                 Reversal Console, then resubmit)
 *
 * REJECTED requests follow the same pattern: clear entry.override_status from
 * PENDING to REJECTED, preserving the CRM-computed per diem.
 *
 * Idempotent — running twice is a no-op once entries are reconciled.
 *
 * Usage (from backend/):
 *   node erp/scripts/repairStuckPerdiemOverrides.js           # dry-run
 *   node erp/scripts/repairStuckPerdiemOverrides.js --apply   # writes
 */
require('dotenv').config();
const mongoose = require('mongoose');

const APPLY = process.argv.includes('--apply');

async function main() {
  await mongoose.connect(process.env.MONGO_URI);
  console.log(`Connected. Mode: ${APPLY ? 'APPLY' : 'DRY-RUN'}`);

  const ApprovalRequest = require('../models/ApprovalRequest');
  const SmerEntry = require('../models/SmerEntry');
  const Settings = require('../models/Settings');
  const PeopleMaster = require('../models/PeopleMaster');
  const CompProfile = require('../models/CompProfile');
  const ErpAuditLog = require('../models/ErpAuditLog');
  const { computePerdiemAmount, resolvePerdiemConfig } = require('../services/perdiemCalc');

  const decided = await ApprovalRequest.find({
    module: 'PERDIEM_OVERRIDE',
    status: { $in: ['APPROVED', 'REJECTED'] },
  }).lean();

  console.log(`Scanning ${decided.length} decided per-diem override requests…`);

  let repaired = 0;
  let alreadyOk = 0;
  let postedWarn = 0;
  let missing = 0;

  for (const req of decided) {
    if (!req.doc_id) { missing++; continue; }
    const smer = await SmerEntry.findById(req.doc_id);
    if (!smer) { missing++; console.warn(`  [missing] SMER ${req.doc_id} for request ${req._id}`); continue; }

    const entryId = req.metadata?.entry_id
      || req.description?.match(/Entry ID: (.+)$/)?.[1];
    const entry = entryId ? smer.daily_entries.id(entryId) : null;
    if (!entry) { missing++; console.warn(`  [missing] daily entry ${entryId} on SMER ${smer._id}`); continue; }

    // Already reconciled?
    if (req.status === 'APPROVED' && entry.override_status === 'APPROVED' && entry.perdiem_override === true) { alreadyOk++; continue; }
    if (req.status === 'REJECTED' && (entry.override_status === 'REJECTED' || !entry.override_status)) { alreadyOk++; continue; }

    if (req.status === 'APPROVED') {
      const tier = req.metadata?.override_tier
        || req.description?.match(/→ (FULL|HALF)/)?.[1];
      if (!tier) { missing++; console.warn(`  [missing tier] request ${req._id}`); continue; }

      if (smer.status === 'POSTED') {
        postedWarn++;
        console.warn(`  [POSTED] SMER ${smer._id} (${smer.period}-${smer.cycle}) day ${entry.day} — override approved but SMER already journaled. Admin must reopen via Reversal Console then resubmit.`);
        continue;
      }

      const settings = await Settings.getSettings();
      const person = await PeopleMaster.findOne({ user_id: smer.bdm_id, entity_id: smer.entity_id }).select('_id').lean();
      const compProfile = person
        ? await CompProfile.findOne({ person_id: person._id, entity_id: smer.entity_id, status: 'ACTIVE' }).sort({ effective_date: -1 }).lean()
        : null;
      // Phase G1.6 — resolve per-role config so repair amounts match what the
      // live approval flow produces. Degrade to undefined if lookup missing.
      let perdiemConfig;
      try {
        perdiemConfig = await resolvePerdiemConfig({ entityId: smer.entity_id, role: 'BDM' });
      } catch (_) {
        perdiemConfig = undefined;
      }
      const { amount } = computePerdiemAmount(tier === 'FULL' ? 999 : 3, smer.perdiem_rate, settings, compProfile, perdiemConfig);

      const oldTier = entry.perdiem_tier;
      const rsn = req.metadata?.override_reason || 'Approved override';
      entry.perdiem_override = true;
      entry.override_tier = tier;
      entry.override_reason = `${rsn} (Approval #${req._id}) [repair]`;
      entry.override_status = 'APPROVED';
      entry.overridden_by = req.decided_by || req.requested_by;
      entry.overridden_at = req.decided_at || new Date();
      entry.perdiem_tier = tier;
      entry.perdiem_amount = amount;

      console.log(`  [APPLY] SMER ${smer._id} day ${entry.day}: ${oldTier} → ${tier} (₱${amount})`);

      if (APPLY) {
        await smer.save();
        await ErpAuditLog.logChange({
          entity_id: smer.entity_id, bdm_id: smer.bdm_id,
          log_type: 'ITEM_CHANGE', target_ref: smer._id.toString(), target_model: 'SmerEntry',
          field_changed: `daily_entries.${entry.day}.perdiem_tier`,
          old_value: `${oldTier} (md_count: ${entry.md_count})`,
          new_value: `${tier} (approved override, repaired)`,
          changed_by: req.decided_by || req.requested_by,
          note: `Per diem override day ${entry.day}: ${oldTier} → ${tier} — repaired from stuck approval #${req._id}`,
        });
      }
      repaired++;
    } else {
      // REJECTED — clear pending state
      console.log(`  [REJECT] SMER ${smer._id} day ${entry.day}: clear PENDING → REJECTED`);
      entry.override_status = 'REJECTED';
      entry.requested_override_tier = undefined;
      if (APPLY) await smer.save();
      repaired++;
    }
  }

  console.log('');
  console.log(`Summary:`);
  console.log(`  repaired:      ${repaired}`);
  console.log(`  already-ok:    ${alreadyOk}`);
  console.log(`  posted-skip:   ${postedWarn}  (require manual reopen + resubmit)`);
  console.log(`  missing-data:  ${missing}`);
  if (!APPLY) console.log(`\nDRY-RUN — rerun with --apply to persist.`);

  await mongoose.disconnect();
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});

/**
 * Repost Missing JEs — Phase 35 backlog script
 *
 * Context (2026-04-21): the JournalEntry pre-save validator's "#15 Hardening"
 * check rejected any line that credited a DEBIT-normal account or debited a
 * CREDIT-normal account, even when the full JE was balanced and the intent
 * was a legitimate asset/liability reduction (e.g. SMER crediting AR-BDM to
 * draw down a BDM's advance). The rejection was swallowed by the surrounding
 * auto-journal try/catch in every controller, so POSTED documents silently
 * ended up without matching JournalEntry rows — the ledger drifted by the
 * undocumented amount every day since 2026-04-13.
 *
 * Phase 35 fix: added `is_contra` flag to JE line sub-schema + skip the direction
 * check on flagged lines + marked all reduction lines in every auto-journal
 * helper and controller. With the code fix in place, this script repairs the
 * backlog of POSTED documents that never got a JournalEntry companion row.
 *
 * Scoped sources (matches the blast-radius in the handoff):
 *   - SmerEntry                  (submitSmer / postSingleSmer)
 *   - CarLogbookCycle            (submitCarLogbookCycle / postSingleCarLogbook)
 *   - ExpenseEntry               (submitExpenses / postSingleExpense)
 *   - PrfCalf                    (submitPrfCalf / postSinglePrfCalf)
 *
 * For each POSTED doc with `deletion_event_id` absent and no JournalEntry
 * at `source_event_id === doc.event_id`, we rebuild the JE via the same
 * helpers the controllers use and post it. Re-invokes the auto-journal
 * builder; idempotent — if a JE already exists, skip.
 *
 * Period-lock aware: if the doc's period is closed, we skip by default with a
 * warning. Pass --force-closed-period to repost anyway (uses the normal post
 * path which still respects JE-level period lock; closed-period reposts will
 * fail loudly rather than silently, which is the correct behavior).
 *
 * Usage (run from backend/):
 *   node erp/scripts/repostMissingJEs.js                 # dry-run, since=2026-04-13
 *   node erp/scripts/repostMissingJEs.js --apply         # writes
 *   node erp/scripts/repostMissingJEs.js --since 2026-04-01
 *   node erp/scripts/repostMissingJEs.js --type SMER     # single doc type
 *   node erp/scripts/repostMissingJEs.js --force-closed-period
 */
require('dotenv').config();
const mongoose = require('mongoose');

const args = process.argv.slice(2);
const APPLY = args.includes('--apply');
const FORCE_CLOSED = args.includes('--force-closed-period');
const typeIdx = args.indexOf('--type');
const TYPE_FILTER = typeIdx >= 0 ? args[typeIdx + 1] : null; // SMER|CARLOGBOOK|EXPENSE|PRFCALF
const sinceIdx = args.indexOf('--since');
const SINCE = sinceIdx >= 0 ? new Date(args[sinceIdx + 1]) : new Date('2026-04-13T00:00:00Z');

async function main() {
  if (!process.env.MONGO_URI) {
    console.error('MONGO_URI not set. Run from backend/ with .env present.');
    process.exit(1);
  }
  await mongoose.connect(process.env.MONGO_URI);
  console.log(`Connected. Mode: ${APPLY ? 'APPLY' : 'DRY-RUN'}  since=${SINCE.toISOString().slice(0, 10)}  type=${TYPE_FILTER || 'ALL'}  force=${FORCE_CLOSED}`);

  // Register every model the validator / helpers may reach via mongoose.model(...)
  // Standalone scripts bypass server.js's implicit registration, so missing a
  // model here surfaces as "Schema hasn't been registered" during save.
  // JE pre-save hook looks up ChartOfAccounts; autoJournal helpers resolve
  // Settings + BankAccount + CreditCard + PaymentMode via resolveFundingCoa.
  require('../models/ChartOfAccounts');
  require('../models/Settings');
  require('../models/BankAccount');
  require('../models/CreditCard');
  require('../models/PaymentMode');
  require('../models/MonthlyArchive');
  const SmerEntry = require('../models/SmerEntry');
  const CarLogbookCycle = require('../models/CarLogbookCycle');
  const CarLogbookEntry = require('../models/CarLogbookEntry');
  const ExpenseEntry = require('../models/ExpenseEntry');
  const PrfCalf = require('../models/PrfCalf');
  const JournalEntry = require('../models/JournalEntry');
  const { getCoaMap, resolveFundingCoa, journalFromPrfCalf } = require('../services/autoJournal');
  const { createAndPostJournal } = require('../services/journalEngine');
  const { checkPeriodOpen } = require('../utils/periodLock');

  const summary = { smer: 0, smer_repaired: 0, logbook: 0, logbook_repaired: 0, expense: 0, expense_repaired: 0, prfcalf: 0, prfcalf_repaired: 0, period_locked: 0, failed: [] };

  async function hasExistingJe(event_id) {
    if (!event_id) return false;
    const je = await JournalEntry.findOne({ source_event_id: event_id }).select('_id').lean();
    return !!je;
  }

  async function guardPeriod(entityId, period, label) {
    try {
      await checkPeriodOpen(entityId, period);
      return true;
    } catch (err) {
      if (FORCE_CLOSED) {
        console.log(`  [${label}] period ${period} closed — forcing repost (--force-closed-period)`);
        return true;
      }
      summary.period_locked += 1;
      console.log(`  [${label}] SKIP — period ${period} closed. Use --force-closed-period to override.`);
      return false;
    }
  }

  // ─── 1) SMER ────────────────────────────────────────────────────
  if (!TYPE_FILTER || TYPE_FILTER === 'SMER') {
    const smers = await SmerEntry.find({
      status: 'POSTED',
      posted_at: { $gte: SINCE },
      deletion_event_id: { $exists: false },
    }).lean();
    summary.smer = smers.length;
    console.log(`\n── SMER candidates: ${smers.length}`);

    for (const smer of smers) {
      if (!smer.event_id) { console.log(`  SKIP SMER ${smer._id} — no event_id`); continue; }
      if (await hasExistingJe(smer.event_id)) continue;
      const label = `SMER ${smer.period}-${smer.cycle} (${smer._id})`;
      if (!(await guardPeriod(smer.entity_id, smer.period, label))) continue;

      try {
        const coaMap = await getCoaMap();
        const lines = [];
        const desc = `SMER ${smer.period}-${smer.cycle}`;
        if (smer.total_perdiem > 0) lines.push({ account_code: coaMap.PER_DIEM || '6100', account_name: 'Per Diem Expense', debit: smer.total_perdiem, credit: 0, description: desc });
        if (smer.total_transpo > 0) lines.push({ account_code: coaMap.TRANSPORT || '6150', account_name: 'Transport Expense', debit: smer.total_transpo, credit: 0, description: desc });
        if (smer.total_special_cases > 0) lines.push({ account_code: coaMap.SPECIAL_TRANSPORT || '6160', account_name: 'Special Transport Expense', debit: smer.total_special_cases, credit: 0, description: desc });
        if (smer.total_ore > 0) lines.push({ account_code: coaMap.OTHER_REIMBURSABLE || '6170', account_name: 'Other Reimbursable Expense', debit: smer.total_ore, credit: 0, description: desc });
        if (!lines.length || !smer.total_reimbursable) {
          console.log(`  [${label}] SKIP — no reimbursable amount to journal`);
          continue;
        }
        lines.push({ account_code: coaMap.AR_BDM || '1110', account_name: 'AR — BDM Advances', debit: 0, credit: smer.total_reimbursable, description: desc, is_contra: true });

        if (!APPLY) {
          console.log(`  [${label}] DRY-RUN would post ${lines.length} lines; total_reimbursable=${smer.total_reimbursable}`);
          summary.smer_repaired += 1;
          continue;
        }
        await createAndPostJournal(smer.entity_id, {
          je_date: smer.posted_at || new Date(),
          period: smer.period,
          description: `SMER: ${desc} (Phase 35 repost)`,
          source_module: 'EXPENSE',
          source_event_id: smer.event_id,
          source_doc_ref: `SMER-${smer.period}-${smer.cycle}`,
          lines,
          bir_flag: 'BOTH',
          vat_flag: 'N/A',
          bdm_id: smer.bdm_id,
          created_by: smer.posted_by || smer.bdm_id,
        });
        summary.smer_repaired += 1;
        console.log(`  [${label}] REPOSTED — ${smer.total_reimbursable}`);
      } catch (err) {
        summary.failed.push({ type: 'SMER', id: String(smer._id), error: err.message });
        console.error(`  [${label}] FAILED: ${err.message}`);
      }
    }
  }

  // ─── 2) CAR LOGBOOK (cycle wrapper, Phase 33) ────────────────────
  if (!TYPE_FILTER || TYPE_FILTER === 'CARLOGBOOK') {
    const cycles = await CarLogbookCycle.find({
      status: 'POSTED',
      posted_at: { $gte: SINCE },
      deletion_event_id: { $exists: false },
    }).lean();
    summary.logbook = cycles.length;
    console.log(`\n── CarLogbookCycle candidates: ${cycles.length}`);

    for (const cycle of cycles) {
      if (!cycle.event_id) continue;
      if (await hasExistingJe(cycle.event_id)) continue;
      const label = `CarLogbookCycle ${cycle.period}-${cycle.cycle} (${cycle._id})`;
      if (!(await guardPeriod(cycle.entity_id, cycle.period, label))) continue;

      try {
        const days = await CarLogbookEntry.find({
          entity_id: cycle.entity_id, bdm_id: cycle.bdm_id,
          period: cycle.period, cycle: cycle.cycle, status: 'POSTED',
        }).lean();
        const coaMap = await getCoaMap();
        let cashTotal = 0, fundedTotal = 0, fundedCoa = null;
        for (const d of days) {
          for (const fuel of (d.fuel_entries || [])) {
            if (!fuel.payment_mode || fuel.payment_mode === 'CASH') cashTotal += fuel.total_amount || 0;
            else {
              fundedTotal += fuel.total_amount || 0;
              if (!fundedCoa) fundedCoa = await resolveFundingCoa(fuel);
            }
          }
        }
        const totalFuel = cashTotal + fundedTotal;
        if (totalFuel <= 0) { console.log(`  [${label}] SKIP — no fuel amount`); continue; }
        const jeDesc = `Car Logbook ${cycle.period} ${cycle.cycle}`;
        const lines = [{ account_code: coaMap.FUEL_GAS || '6200', account_name: 'Fuel & Gas Expense', debit: totalFuel, credit: 0, description: jeDesc }];
        if (cashTotal > 0) lines.push({ account_code: coaMap.AR_BDM || '1110', account_name: 'AR — BDM Advances', debit: 0, credit: cashTotal, description: jeDesc, is_contra: true });
        if (fundedTotal > 0 && fundedCoa) {
          const isContra = /^[156]/.test(String(fundedCoa.coa_code || ''));
          lines.push({ account_code: fundedCoa.coa_code, account_name: fundedCoa.coa_name, debit: 0, credit: fundedTotal, description: jeDesc, is_contra: isContra });
        }
        if (!APPLY) { console.log(`  [${label}] DRY-RUN would post ${lines.length} lines; total_fuel=${totalFuel}`); summary.logbook_repaired += 1; continue; }
        await createAndPostJournal(cycle.entity_id, {
          je_date: new Date(),
          period: cycle.period,
          description: `${jeDesc} (Phase 35 repost)`,
          source_module: 'EXPENSE',
          source_event_id: cycle.event_id,
          source_doc_ref: `LOGBOOK-${cycle.period}-${cycle.cycle}`,
          lines,
          bir_flag: 'BOTH',
          vat_flag: 'N/A',
          bdm_id: cycle.bdm_id,
          created_by: cycle.posted_by || cycle.bdm_id,
        });
        summary.logbook_repaired += 1;
        console.log(`  [${label}] REPOSTED — fuel=${totalFuel}`);
      } catch (err) {
        summary.failed.push({ type: 'CARLOGBOOK', id: String(cycle._id), error: err.message });
        console.error(`  [${label}] FAILED: ${err.message}`);
      }
    }
  }

  // ─── 3) EXPENSE ENTRIES ─────────────────────────────────────────
  if (!TYPE_FILTER || TYPE_FILTER === 'EXPENSE') {
    const expenses = await ExpenseEntry.find({
      status: 'POSTED',
      posted_at: { $gte: SINCE },
      deletion_event_id: { $exists: false },
    });
    summary.expense = expenses.length;
    console.log(`\n── Expense candidates: ${expenses.length}`);

    for (const entry of expenses) {
      if (!entry.event_id) continue;
      if (await hasExistingJe(entry.event_id)) continue;
      const label = `Expense ${entry.period}-${entry.cycle} (${entry._id})`;
      if (!(await guardPeriod(entry.entity_id, entry.period, label))) continue;

      try {
        const coaMap = await getCoaMap();
        const lines = [];
        const desc = `EXP ${entry.period}-${entry.cycle}`;
        let creditOre = 0, creditAccess = 0, accessCoa = null;
        for (const line of (entry.lines || [])) {
          const amt = line.amount || 0;
          if (amt <= 0) continue;
          lines.push({ account_code: line.coa_code || coaMap.MISC_EXPENSE || '6900', account_name: line.expense_category || 'Miscellaneous Expense', debit: amt, credit: 0, description: line.establishment || desc });
          if (line.expense_type === 'ACCESS') { creditAccess += amt; if (!accessCoa) accessCoa = await resolveFundingCoa(line, coaMap.AP_TRADE || '2000'); }
          else { creditOre += amt; }
        }
        if (creditOre > 0) lines.push({ account_code: coaMap.AR_BDM || '1110', account_name: 'AR — BDM Advances', debit: 0, credit: creditOre, description: desc, is_contra: true });
        if (creditAccess > 0) {
          const coa = accessCoa || { coa_code: coaMap.AP_TRADE || '2000', coa_name: 'Accounts Payable — Trade' };
          const isContra = /^[156]/.test(String(coa.coa_code || ''));
          lines.push({ account_code: coa.coa_code, account_name: coa.coa_name, debit: 0, credit: creditAccess, description: desc, is_contra: isContra });
        }
        if (lines.length < 2) { console.log(`  [${label}] SKIP — no lines`); continue; }

        if (!APPLY) { console.log(`  [${label}] DRY-RUN would post ${lines.length} lines`); summary.expense_repaired += 1; continue; }
        await createAndPostJournal(entry.entity_id, {
          je_date: entry.posted_at || new Date(),
          period: entry.period,
          description: `Expenses: ${desc} (Phase 35 repost)`,
          source_module: 'EXPENSE',
          source_event_id: entry.event_id,
          source_doc_ref: `EXP-${entry.period}-${entry.cycle}`,
          lines,
          bir_flag: entry.bir_flag || 'BOTH',
          vat_flag: 'N/A',
          bdm_id: entry.bdm_id,
          created_by: entry.posted_by || entry.bdm_id,
        });
        summary.expense_repaired += 1;
        console.log(`  [${label}] REPOSTED`);
      } catch (err) {
        summary.failed.push({ type: 'EXPENSE', id: String(entry._id), error: err.message });
        console.error(`  [${label}] FAILED: ${err.message}`);
      }
    }
  }

  // ─── 4) PRF/CALF ───────────────────────────────────────────────
  if (!TYPE_FILTER || TYPE_FILTER === 'PRFCALF') {
    const docs = await PrfCalf.find({
      status: 'POSTED',
      posted_at: { $gte: SINCE },
      deletion_event_id: { $exists: false },
    }).lean();
    summary.prfcalf = docs.length;
    console.log(`\n── PRF/CALF candidates: ${docs.length}`);

    for (const doc of docs) {
      if (!doc.event_id) continue;
      if (await hasExistingJe(doc.event_id)) continue;
      const label = `${doc.doc_type} ${doc.prf_number || doc.calf_number || doc.period} (${doc._id})`;
      if (!(await guardPeriod(doc.entity_id, doc.period, label))) continue;

      try {
        const jeData = await journalFromPrfCalf(doc, doc.posted_by || doc.bdm_id);
        if (!jeData) { console.log(`  [${label}] SKIP — zero amount`); continue; }
        jeData.source_event_id = doc.event_id;
        jeData.description = `${jeData.description} (Phase 35 repost)`;
        if (!APPLY) { console.log(`  [${label}] DRY-RUN would post`); summary.prfcalf_repaired += 1; continue; }
        await createAndPostJournal(doc.entity_id, jeData);
        summary.prfcalf_repaired += 1;
        console.log(`  [${label}] REPOSTED`);
      } catch (err) {
        summary.failed.push({ type: 'PRFCALF', id: String(doc._id), error: err.message });
        console.error(`  [${label}] FAILED: ${err.message}`);
      }
    }
  }

  console.log('\n──── SUMMARY ────');
  console.log(`SMER      : ${summary.smer_repaired}/${summary.smer} repaired`);
  console.log(`CarLogbook: ${summary.logbook_repaired}/${summary.logbook} repaired`);
  console.log(`Expense   : ${summary.expense_repaired}/${summary.expense} repaired`);
  console.log(`PrfCalf   : ${summary.prfcalf_repaired}/${summary.prfcalf} repaired`);
  console.log(`Period-locked skips: ${summary.period_locked}`);
  console.log(`Failures  : ${summary.failed.length}`);
  if (summary.failed.length) {
    console.log('\nFailed docs:');
    for (const f of summary.failed) console.log(`  ${f.type} ${f.id}: ${f.error}`);
  }
  if (!APPLY) console.log('\n(Dry-run — no writes made. Add --apply to persist.)');

  await mongoose.disconnect();
  process.exit(summary.failed.length ? 1 : 0);
}

main().catch(async (err) => {
  console.error('Fatal:', err);
  try { await mongoose.disconnect(); } catch {}
  process.exit(1);
});

/**
 * Restore Stock from GRN Reversal — Inventory-Only
 *
 * Context: On 2026-04-21 02:47 UTC, Gregg (as president) reversed GRN
 * 69e1eec226e39698b6857ec6 via President Reversals Console → DELETE.
 * That generated 242 compensating ADJUSTMENT(qty_out) rows across 10
 * warehouses linked to TransactionEvent 69e6e53a8f323da1a8eba808.
 *
 * He wants the inventory back (clean slate for live day) but does NOT
 * want the journal entries restored (he deleted them manually — books
 * are intentionally starting from zero).
 *
 * This script posts 242 compensating ADJUSTMENT(qty_in) entries that
 * mirror the reversal's qty_out back as qty_in. Inventory returns to
 * the pre-reversal state. Nothing else is touched:
 *   - journal_entries: NOT touched (stay wiped)
 *   - GrnEntry.deletion_event_id: NOT cleared (audit preserves fact
 *     that the GRN was formally reversed; this restore is a separate
 *     inventory-state correction)
 *   - PurchaseOrder.qty_received: NOT touched
 *   - SupplierInvoice / AP: NOT touched
 *
 * Idempotent via override_reason tag UNDO_GRN_REVERSAL_2026-04-21.
 *
 * Usage (from backend/):
 *   node erp/scripts/restoreGrnReversalStock.js           # dry-run
 *   node erp/scripts/restoreGrnReversalStock.js --apply   # writes
 */
require('dotenv').config();
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const InventoryLedger = require('../models/InventoryLedger');
const Warehouse = require('../models/Warehouse');

const APPLY = process.argv.includes('--apply');
const REVERSAL_EVENT_ID = '69e6e53a8f323da1a8eba808';
const UNDO_TAG = 'UNDO_GRN_REVERSAL_2026-04-21';

async function run() {
  await connectDB();

  // Idempotency check
  const alreadyDone = await InventoryLedger.countDocuments({
    override_reason: { $regex: UNDO_TAG },
  });
  if (alreadyDone > 0) {
    console.log(`Already restored (${alreadyDone} entries tagged "${UNDO_TAG}"). Nothing to do.`);
    return await mongoose.disconnect();
  }

  // Find all ADJUSTMENT(qty_out) rows from the reversal
  const reversalRows = await InventoryLedger.find({
    event_id: new mongoose.Types.ObjectId(REVERSAL_EVENT_ID),
    transaction_type: 'ADJUSTMENT',
  }).lean();

  if (!reversalRows.length) {
    console.log(`No rows found for reversal event ${REVERSAL_EVENT_ID}. Aborting.`);
    return await mongoose.disconnect();
  }

  // Summary
  const warehouses = await Warehouse.find({}).lean();
  const whMap = new Map(warehouses.map(w => [w._id.toString(), w]));

  const perWh = new Map();
  let totalQtyOut = 0;
  for (const r of reversalRows) {
    const whCode = whMap.get(r.warehouse_id?.toString())?.warehouse_code || '?';
    perWh.set(whCode, (perWh.get(whCode) || 0) + (r.qty_out || 0));
    totalQtyOut += r.qty_out || 0;
  }

  console.log(`\nMode: ${APPLY ? 'APPLY (writes will occur)' : 'DRY-RUN (no writes)'}\n`);
  console.log(`Reversal event: ${REVERSAL_EVENT_ID}`);
  console.log(`Rows to compensate: ${reversalRows.length}`);
  console.log(`\nQty to restore per warehouse:`);
  for (const [wh, qty] of [...perWh.entries()].sort((a, b) => b[1] - a[1])) {
    console.log(`  ${wh.padEnd(12)} ${String(qty).padStart(8)}`);
  }
  console.log(`  ${'TOTAL'.padEnd(12)} ${String(totalQtyOut).padStart(8)}`);

  if (!APPLY) {
    console.log('\nDRY-RUN only. Re-run with --apply to write the compensating entries.');
    console.log('Note: journal entries will NOT be restored. Books stay clean.');
    return await mongoose.disconnect();
  }

  console.log('\nWriting compensating ADJUSTMENT(qty_in) entries...');
  let written = 0;
  for (const r of reversalRows) {
    await InventoryLedger.create({
      entity_id: r.entity_id,
      bdm_id: r.bdm_id,
      warehouse_id: r.warehouse_id,
      product_id: r.product_id,
      batch_lot_no: r.batch_lot_no,
      expiry_date: r.expiry_date,
      transaction_type: 'ADJUSTMENT',
      qty_in: r.qty_out,     // mirror qty_out back as qty_in
      qty_out: 0,
      recorded_by: r.recorded_by,
      override_reason: `${UNDO_TAG} — restore inventory from GRN reversal event ${REVERSAL_EVENT_ID}; journal entries intentionally NOT restored (user wiped books for clean slate)`,
    });
    written++;
    if (written % 50 === 0) console.log(`  ...${written}/${reversalRows.length}`);
  }
  console.log(`  wrote ${written}/${reversalRows.length} entries.`);

  console.log('\nDone. Verify with diagnoseStockVisibility.js — section 6 should show all 10 warehouses populated.');
  await mongoose.disconnect();
}

run().catch(err => { console.error(err); process.exit(1); });

/**
 * Restore ILO-MAIN Opening Stock — Remediation
 *
 * On 2026-04-21 02:47 UTC, two ADJUSTMENT entries zeroed out ILO-MAIN's
 * opening balance:
 *   - Viptriaxone 1g (batch ECFXM24107) — 5800 out
 *   - Viprazole 40mg (batch D260118)    — 5000 out
 *
 * This script posts two compensating ADJUSTMENT entries (qty_in) that
 * restore the balance. It looks up the ORIGINAL OPENING_BALANCE rows by
 * warehouse + product + batch, then mirrors their qty as qty_in on new
 * ADJUSTMENT rows. Idempotent: exits if a prior restore entry already
 * exists with the same override_reason tag.
 *
 * Usage (from backend/):
 *   node erp/scripts/restoreIloMainOpeningStock.js           # dry-run
 *   node erp/scripts/restoreIloMainOpeningStock.js --apply   # writes
 */
require('dotenv').config();
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const InventoryLedger = require('../models/InventoryLedger');
const Warehouse = require('../models/Warehouse');
const ProductMaster = require('../models/ProductMaster');

const APPLY = process.argv.includes('--apply');
const REASON_TAG = 'RESTORE_ILOMAIN_2026-04-21';

async function run() {
  await connectDB();

  const wh = await Warehouse.findOne({ warehouse_code: 'ILO-MAIN' }).lean();
  if (!wh) {
    console.log('ILO-MAIN warehouse not found. Aborting.');
    return await mongoose.disconnect();
  }

  // Idempotency check — have we already restored?
  const alreadyRestored = await InventoryLedger.countDocuments({
    warehouse_id: wh._id,
    transaction_type: 'ADJUSTMENT',
    override_reason: { $regex: REASON_TAG },
  });
  if (alreadyRestored > 0) {
    console.log(`Already restored (${alreadyRestored} entries tagged "${REASON_TAG}"). Nothing to do.`);
    return await mongoose.disconnect();
  }

  // Find the original OPENING_BALANCE entries
  const openings = await InventoryLedger.find({
    warehouse_id: wh._id,
    transaction_type: 'OPENING_BALANCE',
  }).lean();

  if (!openings.length) {
    console.log('No OPENING_BALANCE entries found on ILO-MAIN. Aborting.');
    return await mongoose.disconnect();
  }

  // For each opening, verify a matching ADJUSTMENT zeroed it out
  const plan = [];
  for (const op of openings) {
    const adj = await InventoryLedger.findOne({
      warehouse_id: wh._id,
      product_id: op.product_id,
      batch_lot_no: op.batch_lot_no,
      transaction_type: 'ADJUSTMENT',
      qty_out: op.qty_in,
    }).lean();

    if (!adj) {
      console.log(`  SKIP ${op.batch_lot_no}: no matching ADJUSTMENT zeroing-out row found — leaving alone.`);
      continue;
    }

    const product = await ProductMaster.findById(op.product_id).select('brand_name dosage_strength').lean();
    plan.push({
      product_id: op.product_id,
      product_label: `${product?.brand_name || '?'}${product?.dosage_strength ? ' ' + product.dosage_strength : ''}`,
      batch_lot_no: op.batch_lot_no,
      expiry_date: op.expiry_date,
      qty_to_restore: op.qty_in,
      entity_id: op.entity_id,
      bdm_id: op.bdm_id,
      recorded_by: op.recorded_by,
    });
  }

  console.log(`\nMode: ${APPLY ? 'APPLY (writes will occur)' : 'DRY-RUN (no writes)'}\n`);
  console.log('Plan:');
  console.log('------------------------------------------------------------');
  for (const p of plan) {
    console.log(`  + ${p.product_label.padEnd(28)} batch=${p.batch_lot_no.padEnd(14)} qty_in=${p.qty_to_restore}`);
  }
  console.log('------------------------------------------------------------');
  console.log(`Total entries to write: ${plan.length}`);
  console.log(`Total qty_in to restore: ${plan.reduce((s, p) => s + p.qty_to_restore, 0)}`);

  if (!APPLY) {
    console.log('\nDRY-RUN only. Re-run with --apply to write the entries.');
    return await mongoose.disconnect();
  }

  // APPLY
  console.log('\nWriting compensating ADJUSTMENT entries...');
  for (const p of plan) {
    await InventoryLedger.create({
      entity_id: p.entity_id,
      bdm_id: p.bdm_id,
      warehouse_id: wh._id,
      product_id: p.product_id,
      batch_lot_no: p.batch_lot_no,
      expiry_date: p.expiry_date,
      transaction_type: 'ADJUSTMENT',
      qty_in: p.qty_to_restore,
      qty_out: 0,
      recorded_by: p.recorded_by,
      override_reason: `${REASON_TAG} — restore stock zeroed by accidental adjustment on 2026-04-21 02:47 UTC`,
    });
    console.log(`  wrote ${p.product_label} / ${p.batch_lot_no} / qty_in=${p.qty_to_restore}`);
  }

  console.log('\nDone. Verify with diagnoseIloMainAdjustments.js — net balance should return to 10800.');
  await mongoose.disconnect();
}

