      entry_date: new Date('2026-04-02'),
      starting_km: 50000, ending_km: 50120, personal_km: 20,
      fuel_entries: [
        { station_name: 'Shell Iloilo', fuel_type: 'UNLEADED', liters: 10, price_per_liter: 58.19, payment_mode: 'CASH' }
      ],
      created_by: bId, status: 'DRAFT'
    });
