/**
 * Trace where a GRN's stock actually landed.
 *
 * Usage:
 *   node backend/erp/scripts/traceGrnStock.js GRN-ACC042326-002
 *
 * Prints:
 *   - The GRN doc (status, reviewed_by, bdm_id, event_id, line_items)
 *   - The linked UT (status, acknowledged_by)
 *   - The TransactionEvent this GRN emitted
 *   - Every InventoryLedger row tied to that event (who owns them NOW)
 *   - The named user of each bdm_id so you can see who got the stock
 */
require('dotenv').config();
const mongoose = require('mongoose');

async function main() {
  const arg = process.argv[2];
  if (!arg) {
    console.error('Usage: node traceGrnStock.js <GRN-number or GRN _id>');
    process.exit(1);
  }

  const MONGO = process.env.MONGO_URI;
  if (!MONGO) {
    console.error('MONGO_URI not set. Run from project root with .env loaded.');
    process.exit(1);
  }

  await mongoose.connect(MONGO);
  console.log(`\nConnected. Tracing GRN: ${arg}\n${'═'.repeat(70)}`);

  const GrnEntry = require('../models/GrnEntry');
  const Undertaking = require('../models/Undertaking');
  const InventoryLedger = require('../models/InventoryLedger');
  const TransactionEvent = require('../models/TransactionEvent');
  const User = require('../../models/User');

  const byRef = mongoose.Types.ObjectId.isValid(arg)
    ? { _id: new mongoose.Types.ObjectId(arg) }
    : { grn_number: arg };
  const grn = await GrnEntry.findOne(byRef).lean();
  if (!grn) {
    console.error(`GRN not found: ${arg}`);
    process.exit(2);
  }

  const nameOf = async (id) => {
    if (!id) return '(null)';
    const u = await User.findById(id).select('name email role').lean();
    return u ? `${u.name} <${u.email}> [${u.role}]` : `(unknown _id=${id})`;
  };

  console.log('\nGRN DOC');
  console.log('───────');
  console.log(`  _id:             ${grn._id}`);
  console.log(`  grn_number:      ${grn.grn_number}`);
  console.log(`  entity_id:       ${grn.entity_id}`);
  console.log(`  status:          ${grn.status}`);
  console.log(`  bdm_id:          ${grn.bdm_id}  →  ${await nameOf(grn.bdm_id)}`);
  console.log(`  reviewed_by:     ${grn.reviewed_by}  →  ${await nameOf(grn.reviewed_by)}`);
  console.log(`  reviewed_at:     ${grn.reviewed_at}`);
  console.log(`  created_by:      ${grn.created_by}  →  ${await nameOf(grn.created_by)}`);
  console.log(`  event_id:        ${grn.event_id}`);
  console.log(`  waybill:         ${grn.waybill_photo_url ? 'present' : 'MISSING'}`);
  console.log(`  line_items:      ${(grn.line_items || []).length} line(s)`);
  (grn.line_items || []).forEach((li, i) => {
    console.log(`    [${i}] product=${li.product_id} batch=${li.batch_lot_no} qty=${li.qty} qty_selling=${li.qty_selling_units ?? '(unset)'}`);
  });

  console.log('\nLINKED UNDERTAKING');
  console.log('──────────────────');
  const ut = await Undertaking.findOne({ linked_grn_id: grn._id }).lean();
  if (!ut) {
    console.log('  (no UT found)');
  } else {
    console.log(`  _id:             ${ut._id}`);
    console.log(`  undertaking_no:  ${ut.undertaking_number}`);
    console.log(`  status:          ${ut.status}`);
    console.log(`  bdm_id:          ${ut.bdm_id}  →  ${await nameOf(ut.bdm_id)}`);
    console.log(`  acknowledged_by: ${ut.acknowledged_by}  →  ${await nameOf(ut.acknowledged_by)}`);
    console.log(`  acknowledged_at: ${ut.acknowledged_at}`);
    if (grn.bdm_id && ut.bdm_id && String(grn.bdm_id) !== String(ut.bdm_id)) {
      console.log(`  *** MISMATCH: GRN.bdm_id ≠ UT.bdm_id — stock wrote under GRN.bdm_id ***`);
    }
  }

  console.log('\nTRANSACTION EVENT');
  console.log('─────────────────');
  if (!grn.event_id) {
    console.log('  (no event_id on GRN — approveGrnCore likely never ran, even though status may show APPROVED)');
  } else {
    const ev = await TransactionEvent.findById(grn.event_id).lean();
    if (!ev) {
      console.log(`  (event_id=${grn.event_id} not found — broken reference)`);
    } else {
      console.log(`  _id:             ${ev._id}`);
      console.log(`  event_type:      ${ev.event_type}`);
      console.log(`  bdm_id:          ${ev.bdm_id}  →  ${await nameOf(ev.bdm_id)}`);
      console.log(`  created_by:      ${ev.created_by}  →  ${await nameOf(ev.created_by)}`);
    }
  }

  console.log('\nINVENTORY LEDGER ROWS FOR THIS GRN');
  console.log('──────────────────────────────────');
  const rows = grn.event_id
    ? await InventoryLedger.find({ event_id: grn.event_id }).lean()
    : [];
  if (rows.length === 0) {
    console.log('  (no ledger rows found — stock did not post)');
  } else {
    for (const r of rows) {
      console.log(`  product=${r.product_id} batch=${r.batch_lot_no} qty_in=${r.qty_in}`);
      console.log(`    bdm_id=${r.bdm_id}  →  ${await nameOf(r.bdm_id)}`);
      console.log(`    warehouse_id=${r.warehouse_id || '(none)'}`);
    }
  }

  console.log(`\n${'═'.repeat(70)}`);
  console.log('Interpretation');
  console.log('──────────────');
  if (rows.length === 0 && grn.status === 'APPROVED') {
    console.log('  ⚠ GRN shows APPROVED but there are no ledger rows. approveGrnCore never wrote them.');
    console.log('    Most likely: gateApproval routed the approval to the Approval Hub (HTTP 202) and');
    console.log('    the status flip happened via a separate path that skipped the ledger write.');
  } else if (rows.length > 0) {
    const uniqueBdms = [...new Set(rows.map(r => String(r.bdm_id)))];
    if (uniqueBdms.length === 1) {
      console.log(`  Stock landed under bdm_id = ${uniqueBdms[0]}.`);
      console.log('  If that user name above is NOT "Judy Mae Patrocinio", her My Stock will be empty.');
      console.log('  Remedy: reverse this GRN, then re-capture with correct bdm_id.');
    }
  }

  await mongoose.disconnect();
}

main().catch(err => {
  console.error(err);
  process.exit(99);
});

/**
 * UNDO IloMain Opening Stock Restore
 *
 * Context: On 2026-04-21 ~05:57 UTC, restoreIloMainOpeningStock.js wrote
 * 2 compensating ADJUSTMENT(qty_in) entries to ILO-MAIN totalling 10800
 * qty. That restore was posted in error — the original 02:47 UTC
 * ADJUSTMENT(qty_out) entries that zeroed the stock were NOT accidental.
 * They were part of a legitimate GRN_REVERSAL / PRESIDENT_REVERSAL with
 * reason=DELETE, event_id=69e6e53a8f323da1a8eba808.
 *
 * This script posts 2 compensating ADJUSTMENT(qty_out) entries to undo
 * the restore. Preserves audit trail (both entries remain in ledger).
 *
 * Targets rows tagged: override_reason contains "RESTORE_ILOMAIN_2026-04-21"
 *
 * Usage (from backend/):
 *   node erp/scripts/undoIloMainRestore.js           # dry-run
 *   node erp/scripts/undoIloMainRestore.js --apply   # writes
 */
require('dotenv').config();
const mongoose = require('mongoose');
const connectDB = require('../../config/db');
const InventoryLedger = require('../models/InventoryLedger');
const ProductMaster = require('../models/ProductMaster');
const Warehouse = require('../models/Warehouse');

const APPLY = process.argv.includes('--apply');
const RESTORE_TAG = 'RESTORE_ILOMAIN_2026-04-21';
const UNDO_TAG = 'UNDO_RESTORE_ILOMAIN_2026-04-21';

async function run() {
  await connectDB();

  // Idempotency check
  const alreadyUndone = await InventoryLedger.countDocuments({
    override_reason: { $regex: UNDO_TAG },
  });
  if (alreadyUndone > 0) {
    console.log(`Already undone (${alreadyUndone} entries tagged "${UNDO_TAG}"). Nothing to do.`);
    return await mongoose.disconnect();
  }

  // Find the restore rows
  const restoreRows = await InventoryLedger.find({
    override_reason: { $regex: RESTORE_TAG },
  }).lean();

  if (!restoreRows.length) {
    console.log('No rows found tagged with RESTORE_ILOMAIN_2026-04-21. Nothing to undo.');
    return await mongoose.disconnect();
  }

  const pids = await ProductMaster.find({ _id: { $in: restoreRows.map(r => r.product_id) } }).select('brand_name dosage_strength').lean();
  const pMap = new Map(pids.map(p => [p._id.toString(), p]));

  console.log(`\nMode: ${APPLY ? 'APPLY (writes will occur)' : 'DRY-RUN (no writes)'}\n`);
  console.log('Found restore rows to undo:');
  console.log('--------------------------------------------------------------------------------');
  for (const r of restoreRows) {
    const p = pMap.get(r.product_id?.toString());
    const label = p ? `${p.brand_name}${p.dosage_strength ? ' ' + p.dosage_strength : ''}` : '(unknown)';
    console.log(`  ${label.padEnd(28)} batch=${(r.batch_lot_no || '?').padEnd(14)} qty_in=${r.qty_in} recorded_at=${r.recorded_at?.toISOString()}`);
  }
  console.log('--------------------------------------------------------------------------------');
  console.log(`Will post ${restoreRows.length} compensating ADJUSTMENT(qty_out) entries.`);
  console.log(`Total qty to remove: ${restoreRows.reduce((s, r) => s + (r.qty_in || 0), 0)}`);

  if (!APPLY) {
    console.log('\nDRY-RUN only. Re-run with --apply to write the undo entries.');
    return await mongoose.disconnect();
  }

  console.log('\nWriting compensating ADJUSTMENT(qty_out) entries...');
  for (const r of restoreRows) {
    await InventoryLedger.create({
      entity_id: r.entity_id,
      bdm_id: r.bdm_id,
      warehouse_id: r.warehouse_id,
      product_id: r.product_id,
      batch_lot_no: r.batch_lot_no,
      expiry_date: r.expiry_date,
      transaction_type: 'ADJUSTMENT',
      qty_in: 0,
      qty_out: r.qty_in,
      recorded_by: r.recorded_by,
      override_reason: `${UNDO_TAG} — undo restore posted in error; original 02:47 UTC adjustment was part of legitimate GRN_REVERSAL event 69e6e53a8f323da1a8eba808`,
    });
    const p = pMap.get(r.product_id?.toString());
    const label = p ? `${p.brand_name}${p.dosage_strength ? ' ' + p.dosage_strength : ''}` : '(unknown)';
    console.log(`  wrote undo: ${label} / ${r.batch_lot_no} / qty_out=${r.qty_in}`);
  }

  console.log('\nDone. Verify with diagnoseIloMainAdjustments.js — net balance should return to 0.');
  await mongoose.disconnect();
}

run().catch(err => { console.error(err); process.exit(1); });

/**
 * AP Payment Service — Phase 12.5
 *
 * Records payments against supplier invoices.
 * COA resolved at runtime via resolveFundingCoa() — no hardcoded COA codes.
 * Auto-posts JE: DR 2000 AP Trade, CR Cash/Bank (resolved).
 */
const SupplierInvoice = require('../models/SupplierInvoice');
const ApPayment = require('../models/ApPayment');
const { resolveFundingCoa, getCoaMap } = require('./autoJournal');
const { createAndPostJournal } = require('./journalEngine');

/**
 * Helper: format period from Date
 */
function dateToPeriod(d) {
  const dt = new Date(d);
  return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}`;
}

/**
 * Record a payment against a supplier invoice
 * @param {String} invoiceId
 * @param {Object} paymentData — { amount, payment_date, payment_mode, check_no, check_date, bank_account_id, funding_card_id, reference, notes }
 * @param {String} entityId
 * @param {String} userId
 * @returns {Object} ApPayment document with je_id
 */
async function recordApPayment(invoiceId, paymentData, entityId, userId) {
  const invoice = await SupplierInvoice.findById(invoiceId);
  if (!invoice) throw new Error('Supplier invoice not found');
  if (invoice.status !== 'POSTED') throw new Error('Can only pay POSTED invoices');
  if (invoice.payment_status === 'PAID') throw new Error('Invoice is already fully paid');

  const remaining = Math.round((invoice.total_amount - invoice.amount_paid) * 100) / 100;
  if (paymentData.amount > remaining) {
    throw new Error(`Payment amount (${paymentData.amount}) exceeds remaining balance (${remaining})`);
  }

  // Resolve Cash/Bank COA from payment method
  const { coa_code, coa_name } = await resolveFundingCoa(paymentData);

  // Create JE: DR 2000 AP Trade, CR Cash/Bank
  const jeData = {
    je_date: paymentData.payment_date || new Date(),
    period: dateToPeriod(paymentData.payment_date || new Date()),
    description: `AP Payment: ${invoice.vendor_name || ''} — ${invoice.invoice_ref || ''}`,
    source_module: 'AP',
    source_doc_ref: invoice.invoice_ref || String(invoice._id),
    lines: [
      {
        // DR AP_TRADE reduces a CREDIT-normal liability — contra.
        account_code: (await getCoaMap()).AP_TRADE || '2000',
        account_name: 'Accounts Payable — Trade',
        debit: paymentData.amount,
        credit: 0,
        description: `Payment on SI: ${invoice.invoice_ref || ''}`,
        is_contra: true
      },
      {
        // CR Cash/Bank reduces a DEBIT-normal asset — contra when funding is 1/5/6.
        account_code: coa_code,
        account_name: coa_name,
        debit: 0,
        credit: paymentData.amount,
        description: `Payment on SI: ${invoice.invoice_ref || ''}`,
        is_contra: /^[156]/.test(String(coa_code || ''))
      }
    ],
    bir_flag: 'BOTH',
    vat_flag: 'N/A',
    created_by: userId
  };

  const je = await createAndPostJournal(entityId, jeData);

  // Create payment record
  const payment = await ApPayment.create({
    entity_id: entityId,
    supplier_invoice_id: invoice._id,
    vendor_id: invoice.vendor_id,
    payment_date: paymentData.payment_date || new Date(),
    amount: paymentData.amount,
    payment_mode: paymentData.payment_mode,
    check_no: paymentData.check_no,
    check_date: paymentData.check_date,
    bank_account_id: paymentData.bank_account_id,
    funding_card_id: paymentData.funding_card_id,
    reference: paymentData.reference,
    je_id: je._id,
    notes: paymentData.notes,
    created_by: userId
  });

  // Update invoice
  invoice.amount_paid = Math.round((invoice.amount_paid + paymentData.amount) * 100) / 100;
  invoice.payment_status = invoice.amount_paid >= invoice.total_amount ? 'PAID' : 'PARTIAL';
  await invoice.save();

  return payment;
}

/**
 * Get payment history, optionally filtered by vendor
 */
async function getPaymentHistory(entityId, vendorId) {
  const filter = { entity_id: entityId };
  if (vendorId) filter.vendor_id = vendorId;

  return ApPayment.find(filter)
    .populate('supplier_invoice_id', 'invoice_ref invoice_date total_amount')
    .populate('vendor_id', 'vendor_name')
    .sort({ payment_date: -1 })
    .lean();
}

module.exports = { recordApPayment, getPaymentHistory };

/**
 * Approval Service — Phase 28 (Authority Matrix)
 *
 * Provides the business logic for multi-level approval workflows.
 * Only active when Settings.ENFORCE_AUTHORITY_MATRIX is true.
 *
 * Key design decisions:
 *   - Rules are entity-scoped and database-driven (no hardcoded thresholds)
 *   - Multi-level: level 1 must approve before level 2 is evaluated
 *   - Approver resolution is dynamic (by role, specific user, or reporting chain)
 *   - Email notifications sent via erpNotificationService (non-blocking)
 *   - All decisions recorded in ApprovalRequest.history (immutable audit trail)
 */

const { ROLES, ROLE_SETS } = require('../../constants/roles');
const Settings = require('../models/Settings');
const ApprovalRule = require('../models/ApprovalRule');
const ApprovalRequest = require('../models/ApprovalRequest');
const Lookup = require('../models/Lookup');
const User = require('../../models/User');
const PeopleMaster = require('../models/PeopleMaster');
const { notifyApprovalRequest, notifyApprovalDecision } = require('./erpNotificationService');
const { getParentEntityIds } = require('../utils/parentEntityResolver');

// Module key aliases — controllers historically used inconsistent keys.
// Normalize to the canonical lookup code so the gate finds the right MODULE_DEFAULT_ROLES entry.
const MODULE_KEY_ALIASES = {
  COLLECTIONS: 'COLLECTION', // legacy controller spelling
};

/**
 * Get the lookup-driven list of roles allowed to POST documents in a module.
 * Returns null if no entry exists or roles is null (open — anyone can post).
 *
 * Self-seeds the requested entry from SEED_DEFAULTS on miss (subscription-ready):
 * a fresh subsidiary doesn't need the admin to open the Approval Hub before the
 * gate works — the first submit lazily seeds the missing entry.
 *
 * @param {ObjectId} entityId
 * @param {string} moduleKey - e.g. 'SALES', 'COLLECTION', 'EXPENSES'
 * @returns {Promise<string[]|null>}
 */
const getModulePostingRoles = async (entityId, moduleKey) => {
  // Uppercase first so the alias map handles any casing the controller passes.
  const upper = (moduleKey || '').toUpperCase();
  const code = MODULE_KEY_ALIASES[upper] || upper;
  if (!code || !entityId) return null;
  let entry = await Lookup.findOne({
    entity_id: entityId,
    category: 'MODULE_DEFAULT_ROLES',
    code,
    is_active: true,
  }).lean();

  // Lazy auto-seed: if no entry yet for this entity+module, upsert from SEED_DEFAULTS.
  // Mirrors the pattern in getUniversalPending — keeps both paths in sync without
  // requiring admins to open the Approval Hub before the gate becomes effective.
  if (!entry) {
    try {
      const { SEED_DEFAULTS } = require('../controllers/lookupGenericController');
      const seeds = SEED_DEFAULTS?.MODULE_DEFAULT_ROLES || [];
      const seed = seeds.find(s => (s.code || '').toUpperCase() === code);
      if (seed) {
        await Lookup.updateOne(
          { entity_id: entityId, category: 'MODULE_DEFAULT_ROLES', code },
          {
            $setOnInsert: {
              label: seed.label,
              sort_order: 0,
              is_active: true,
              metadata: seed.metadata || {},
            },
          },
          { upsert: true }
        );
        entry = await Lookup.findOne({
          entity_id: entityId,
          category: 'MODULE_DEFAULT_ROLES',
          code,
          is_active: true,
        }).lean();
      }
    } catch (seedErr) {
      console.error(`MODULE_DEFAULT_ROLES lazy-seed failed for ${code}:`, seedErr.message);
    }
  }

  if (!entry) return null;
  const roles = entry.metadata?.roles;
  if (roles == null) return null; // null = open
  return Array.isArray(roles) && roles.length > 0 ? roles : null;
};

/**
 * Phase G6 — Get the lookup-driven rejection config for a module.
 * Returns { rejected_status, reason_field, resubmit_allowed, editable_statuses,
 * banner_tone, description } or null if the module has no config.
 *
 * Self-seeds from SEED_DEFAULTS on miss — mirrors getModulePostingRoles so a fresh
 * subsidiary gets a working banner on first render without requiring admin to open
 * Control Center first. Keeps G4 (posting roles) and G6 (rejection surface) in sync.
 *
 * Frontend <RejectionBanner> calls this via GET /api/erp/lookups/module-rejection-config/:code.
 *
 * @param {ObjectId} entityId
 * @param {string} moduleKey - canonical MODULE_DEFAULT_ROLES code (e.g. 'SALES', 'INCOME')
 * @returns {Promise<Object|null>}
 */
const getModuleRejectionConfig = async (entityId, moduleKey) => {
  const upper = (moduleKey || '').toUpperCase();
  const code = MODULE_KEY_ALIASES[upper] || upper;
  if (!code || !entityId) return null;
  let entry = await Lookup.findOne({
    entity_id: entityId,
    category: 'MODULE_REJECTION_CONFIG',
    code,
    is_active: true,
  }).lean();

  if (!entry) {
    try {
      const { SEED_DEFAULTS } = require('../controllers/lookupGenericController');
      const seeds = SEED_DEFAULTS?.MODULE_REJECTION_CONFIG || [];
      const seed = seeds.find(s => (s.code || '').toUpperCase() === code);
      if (seed) {
        await Lookup.updateOne(
          { entity_id: entityId, category: 'MODULE_REJECTION_CONFIG', code },
          {
            $setOnInsert: {
              label: seed.label,
              sort_order: 0,
              is_active: true,
              metadata: seed.metadata || {},
            },
          },
          { upsert: true }
        );
        entry = await Lookup.findOne({
          entity_id: entityId,
          category: 'MODULE_REJECTION_CONFIG',
          code,
          is_active: true,
        }).lean();
      }
    } catch (seedErr) {
      console.error(`MODULE_REJECTION_CONFIG lazy-seed failed for ${code}:`, seedErr.message);
    }
  }

  if (!entry) return null;
  return entry.metadata || null;
};

// In-memory cache for editable-statuses reads on the controller hot path.
// Keyed by `${entityId}:${moduleKey}`. TTL bounds staleness if a Lookup row is
// mutated outside the Control Center (e.g. direct DB edit); the invalidate hook
// in lookupGenericController gives instant propagation on UI-driven edits.
const editableStatusesCache = new Map();
const EDITABLE_STATUSES_TTL_MS = 60_000;
const EDITABLE_STATUSES_FALLBACK = Object.freeze(['DRAFT', 'ERROR']);

/**
 * Return the list of statuses in which a document of `moduleKey` is still
 * user-editable (draft-like, or rejected-and-awaiting-fix). Reads from the
 * per-entity MODULE_REJECTION_CONFIG.metadata.editable_statuses, with a
 * short-TTL cache so write-guard queries don't pay a DB round-trip per edit.
 *
 * Falls back to ['DRAFT','ERROR'] — the historical hardcoded value — when no
 * config exists or the lookup lookup returns malformed data. This keeps
 * controllers safe during rollout even if the seed hasn't reached an entity.
 *
 * @param {ObjectId|string} entityId
 * @param {string} moduleKey - canonical MODULE_REJECTION_CONFIG code
 * @returns {Promise<string[]>}
 */
const getEditableStatuses = async (entityId, moduleKey) => {
  const upper = (moduleKey || '').toUpperCase();
  const code = MODULE_KEY_ALIASES[upper] || upper;
  if (!code || !entityId) return EDITABLE_STATUSES_FALLBACK.slice();

  const cacheKey = `${entityId}:${code}`;
  const hit = editableStatusesCache.get(cacheKey);
  if (hit && hit.expiresAt > Date.now()) return hit.statuses;

  const cfg = await getModuleRejectionConfig(entityId, code);
  const raw = cfg?.editable_statuses;
  const statuses = Array.isArray(raw) && raw.length > 0 ? raw.slice() : EDITABLE_STATUSES_FALLBACK.slice();
  editableStatusesCache.set(cacheKey, { statuses, expiresAt: Date.now() + EDITABLE_STATUSES_TTL_MS });
  return statuses;
};

/**
 * Clear cached editable-statuses for a single (entityId, moduleKey) pair, or
 * clear the whole cache when either argument is omitted. Called by
 * lookupGenericController on MODULE_REJECTION_CONFIG mutations so Control
 * Center edits take effect immediately instead of after the TTL.
 */
const invalidateEditableStatuses = (entityId, moduleKey) => {
  if (entityId && moduleKey) {
    const upper = (moduleKey || '').toUpperCase();
    const code = MODULE_KEY_ALIASES[upper] || upper;
    editableStatusesCache.delete(`${entityId}:${code}`);
    return;
  }
  editableStatusesCache.clear();
};

/**
 * Check whether the authority matrix is enabled for this entity.
 * @returns {Promise<boolean>}
 */
const isApprovalEnabled = async () => {
  const settings = await Settings.getSettings();
  return !!settings.ENFORCE_AUTHORITY_MATRIX;
};

/**
 * Find matching approval rules for a document.
 * Returns rules sorted by level (ascending).
 *
 * @param {ObjectId} entityId
 * @param {string} module - e.g., 'PURCHASING'
 * @param {string} docType - e.g., 'PO'
 * @param {number} [amount] - document amount for threshold matching
 * @returns {Promise<Array>} sorted rules
 */
const findMatchingRules = async (entityId, module, docType, amount) => {
  const query = {
    entity_id: entityId,
    module,
    is_active: true,
    $or: [
      { doc_type: null },     // module-wide rules
      { doc_type: docType },  // doc-type-specific rules
    ],
  };

  const rules = await ApprovalRule.find(query).sort({ level: 1 }).lean();

  // Filter by amount threshold
  return rules.filter(rule => {
    if (rule.amount_threshold == null) return true; // no threshold = always applies
    return (amount || 0) >= rule.amount_threshold;
  });
};

/**
 * Resolve the list of users who can approve at a given rule level.
 *
 * @param {Object} rule - ApprovalRule document
 * @param {ObjectId} entityId
 * @param {ObjectId} requesterId - the user requesting approval
 * @returns {Promise<Array<{_id, email, name}>>}
 */
const resolveApprovers = async (rule, entityId, requesterId) => {
  switch (rule.approver_type) {
    case 'ROLE': {
      const parentEntityIds = await getParentEntityIds();
      return User.find({
        role: { $in: rule.approver_roles },
        isActive: true,
        email: { $exists: true, $ne: '' },
        $or: [
          { entity_id: entityId },
          { entity_ids: entityId },
          // Cross-entity escape: only presidents/CEOs of a PARENT entity —
          // subsidiary presidents are excluded so they see only their own
          // subsidiary's approvals (matched via entity_id above).
          { role: { $in: ROLE_SETS.PRESIDENT_ROLES }, entity_id: { $in: parentEntityIds } },
        ],
      }).select('_id email name role').lean();
    }

    case 'USER': {
      return User.find({
        _id: { $in: rule.approver_user_ids },
        isActive: true,
      }).select('_id email name role').lean();
    }

    case 'REPORTS_TO': {
      // Find the requester's manager from PeopleMaster
      const person = await PeopleMaster.findOne({
        user_id: requesterId,
        entity_id: entityId,
        is_active: true,
      }).select('reports_to').lean();

      if (!person?.reports_to) return [];

      // reports_to references another PeopleMaster; find their User account
      const manager = await PeopleMaster.findById(person.reports_to)
        .select('user_id')
        .lean();

      if (!manager?.user_id) return [];

      const managerUser = await User.findOne({
        _id: manager.user_id,
        isActive: true,
      }).select('_id email name role').lean();

      return managerUser ? [managerUser] : [];
    }

    default:
      return [];
  }
};

/**
 * Check if a document requires approval before posting.
 * If approval is not enabled or no rules match, returns { required: false }.
 * If approval is required, creates ApprovalRequest(s) and returns { required: true, requests }.
 *
 * @param {Object} opts
 * @param {ObjectId} opts.entityId
 * @param {string} opts.module - 'SALES', 'PURCHASING', etc.
 * @param {string} opts.docType - 'CSI', 'PO', etc.
 * @param {ObjectId} opts.docId - the document's _id
 * @param {string} [opts.docRef] - human-readable reference
 * @param {number} [opts.amount]
 * @param {string} [opts.description]
 * @param {ObjectId} opts.requesterId - the user trying to post
 * @returns {Promise<{required: boolean, requests?: Array, message?: string}>}
 */
const checkApprovalRequired = async (opts) => {
  // ── Layer 1: Default-Roles Gate (always enforced, lookup-driven, subscription-ready) ──
  // Governing principle: "Any person can CREATE, but authority POSTS."
  // Per-entity MODULE_DEFAULT_ROLES.metadata.roles defines who can post each module.
  // Subscribers configure via Control Center → Lookup Tables (no code change needed).
  // Setting metadata.roles = null on a module disables this gate (open-post).
  const requester = await User.findById(opts.requesterId).select('role name email').lean();
  const requesterRole = requester?.role;

  // President / CEO bypass (cross-entity superusers — they own the company)
  const isPresidentBypass = ROLE_SETS.PRESIDENT_ROLES.includes(requesterRole);

  // Phase G4.5a — proxy entry always routes through Approval Hub. When a
  // document was recorded on behalf of another BDM, the proxy (even an admin
  // or finance) does NOT auto-post — the owner (or their approver) must sign
  // off. Rationale: a clerk keying under someone else's name is four-eyes
  // territory, and the proxy's authority chain is not the owner's chain
  // (fixed properly in Phase G4.5b — owner-chain propagation). Until then,
  // this conservative guard keeps proxy entry safe for contractor clerks.
  const forceApproval = !!opts.forceApproval;

  if (forceApproval || !isPresidentBypass) {
    let allowedRoles = await getModulePostingRoles(opts.entityId, opts.module);
    // Phase G4.5a — if the module is open-post (metadata.roles = null) but the
    // caller asks for proxy approval, we still need SOME pool to sign off.
    // Fall back to admin/finance/president so the doc doesn't land in the hub
    // with zero eligible approvers.
    if (forceApproval && !allowedRoles) {
      allowedRoles = [ROLES.ADMIN, ROLES.FINANCE, ROLES.PRESIDENT];
    }
    const notAllowed = forceApproval || (allowedRoles && !allowedRoles.includes(requesterRole));
    if (notAllowed) {
      // Requester not authorized to post → hold for Approval Hub.
      // Check for existing pending/approved request first (idempotent re-submit).
      const existingDefault = await ApprovalRequest.findOne({
        doc_id: opts.docId,
        status: { $in: ['PENDING', 'APPROVED'] },
      }).lean();

      if (existingDefault?.status === 'APPROVED') return { required: false };
      if (existingDefault?.status === 'PENDING') {
        return {
          required: true,
          message: 'This document is pending approval in the Approval Hub',
          requests: [existingDefault],
        };
      }

      // Create synthetic request (no rule_id — this is the default-roles gate, not a matrix rule).
      // level: 0 distinguishes from matrix rules (which start at level 1).
      // Phase G4.5a — forceApproval means proxy entry. Tag as PROXY_ENTRY gate
      // so the Approval Hub can show an explicit "proxied" label; resolution of
      // approvers still uses the same allowed_roles list (admin/finance/president
      // by default) so someone authorized can sign off for the owner.
      const gateLabel = forceApproval ? 'PROXY_ENTRY' : 'DEFAULT_ROLES';
      const historyReason = forceApproval
        ? `Proxy entry — recorded on behalf of another BDM by ${requester?.name || requesterRole}; owner approval required.`
        : `Posting authority required (submitter role: ${requesterRole}, allowed: ${(allowedRoles || []).join(', ')})`;
      const request = await ApprovalRequest.create({
        entity_id: opts.entityId,
        rule_id: null,
        module: opts.module,
        doc_type: opts.docType,
        doc_id: opts.docId,
        doc_ref: opts.docRef,
        amount: opts.amount,
        description: opts.description,
        metadata: {
          ...(opts.metadata || {}),
          gate: gateLabel,
          allowed_roles: allowedRoles,
          ...(forceApproval ? { proxy_entry: true, proxied_by: opts.requesterId, owner_bdm_id: opts.ownerBdmId } : {}),
        },
        level: 0,
        requested_by: opts.requesterId,
        status: 'PENDING',
        history: [{
          status: 'PENDING',
          by: opts.requesterId,
          reason: historyReason,
        }],
      });

      // Resolve approvers: users with allowed roles in this entity, plus
      // parent-entity presidents/CEOs (true cross-entity superusers).
      // Subsidiary presidents are scoped to their own entity only — they
      // must NOT receive approval requests for unrelated entities.
      const parentEntityIds = await getParentEntityIds();
      const approvers = await User.find({
        role: { $in: allowedRoles },
        isActive: true,
        email: { $exists: true, $ne: '' },
        $or: [
          { entity_id: opts.entityId },
          { entity_ids: opts.entityId },
          { role: { $in: ROLE_SETS.PRESIDENT_ROLES }, entity_id: { $in: parentEntityIds } },
        ],
      }).select('_id email name role').lean();

      notifyApprovalRequest({
        entityId: opts.entityId,
        module: opts.module,
        docType: opts.docType,
        docRef: opts.docRef,
        requestedBy: opts.requesterName || requester?.name || 'User',
        amount: opts.amount,
        description: opts.description,
        approvers,
        approvalRequestId: request._id, // G9.B — thread linkage for inbox
      }).catch(err => console.error('Default-roles gate notification failed:', err.message));

      return {
        required: true,
        message: 'Posting authority required. Request submitted to Approval Hub.',
        requests: [request],
      };
    }
  }

  // ── Layer 2: Authority Matrix (existing escalation rules — only when enabled) ──
  // Even authorized posters may need additional approval for high-value transactions.
  const enabled = await isApprovalEnabled();
  if (!enabled) return { required: false };

  const rules = await findMatchingRules(opts.entityId, opts.module, opts.docType, opts.amount);
  if (!rules.length) return { required: false };

  // Check if there's already a pending/approved request for this doc at the first level
  const existing = await ApprovalRequest.findOne({
    doc_id: opts.docId,
    status: { $in: ['PENDING', 'APPROVED'] },
  }).lean();

  if (existing?.status === 'APPROVED') {
    // Already approved — allow posting
    return { required: false };
  }

  if (existing?.status === 'PENDING') {
    // Already pending — return the existing request
    return {
      required: true,
      message: 'This document is pending approval',
      requests: [existing],
    };
  }

  // Create approval request for level 1
  const firstRule = rules[0];
  const approvers = await resolveApprovers(firstRule, opts.entityId, opts.requesterId);

  const request = await ApprovalRequest.create({
    entity_id: opts.entityId,
    rule_id: firstRule._id,
    module: opts.module,
    doc_type: opts.docType,
    doc_id: opts.docId,
    doc_ref: opts.docRef,
    amount: opts.amount,
    description: opts.description,
    metadata: opts.metadata,  // module-specific structured data (e.g., entry_id, override_tier for PERDIEM_OVERRIDE)
    level: firstRule.level,
    requested_by: opts.requesterId,
    status: 'PENDING',
    history: [{ status: 'PENDING', by: opts.requesterId, reason: 'Approval required by authority matrix' }],
  });

  // Non-blocking: notify approvers
  notifyApprovalRequest({
    entityId: opts.entityId,
    module: opts.module,
    docType: opts.docType,
    docRef: opts.docRef,
    requestedBy: opts.requesterName || 'User',
    amount: opts.amount,
    description: opts.description,
    approvers,
    approvalRequestId: request._id, // G9.B — thread linkage for inbox
  }).catch(err => console.error('Approval request notification failed:', err.message));

  return {
    required: true,
    message: 'Approval required. Request has been submitted.',
    requests: [request],
  };
};

/**
 * Process an approval decision (approve or reject).
 *
 * @param {ObjectId} requestId - ApprovalRequest._id
 * @param {string} decision - 'APPROVED' or 'REJECTED'
 * @param {ObjectId} deciderId - User._id of the approver
 * @param {string} [reason] - optional reason
 * @returns {Promise<Object>} updated ApprovalRequest
 */
const processDecision = async (requestId, decision, deciderId, reason) => {
  const request = await ApprovalRequest.findById(requestId);
  if (!request) throw new Error('Approval request not found');
  if (request.status !== 'PENDING') throw new Error(`Request is already ${request.status}`);

  // Verify the decider is authorized
  const rule = await ApprovalRule.findById(request.rule_id).lean();
  if (rule) {
    const approvers = await resolveApprovers(rule, request.entity_id, request.requested_by);
    const isAuthorized = approvers.some(a => a._id.toString() === deciderId.toString());

    // Presidents can always approve
    const decider = await User.findById(deciderId).select('role').lean();
    if (!isAuthorized && decider?.role !== ROLES.PRESIDENT) {
      throw new Error('You are not authorized to approve this request');
    }
  }

  request.status = decision;
  request.decided_by = deciderId;
  request.decided_at = new Date();
  request.decision_reason = reason;
  request.history.push({
    status: decision,
    by: deciderId,
    reason: reason || `${decision} by approver`,
  });
  await request.save();

  // Notify the requester of the decision
  const deciderUser = await User.findById(deciderId).select('name email').lean();
  notifyApprovalDecision({
    entityId: request.entity_id,
    module: request.module,
    docType: request.doc_type,
    docRef: request.doc_ref,
    decision,
    decidedBy: deciderUser?.name || 'Approver',
    ownerId: request.requested_by,
    reason,
    approvalRequestId: request._id, // G9.B — thread continuity with original request
  }).catch(err => console.error('Approval decision notification failed:', err.message));

  // If approved, check if there's a next level
  if (decision === 'APPROVED' && rule) {
    const nextRule = await ApprovalRule.findOne({
      entity_id: request.entity_id,
      module: request.module,
      is_active: true,
      level: { $gt: request.level },
      $or: [
        { doc_type: null },
        { doc_type: request.doc_type },
      ],
    }).sort({ level: 1 }).lean();

    if (nextRule) {
      // Amount check for next level
      const meetsThreshold = nextRule.amount_threshold == null || (request.amount || 0) >= nextRule.amount_threshold;

      if (meetsThreshold) {
        const nextApprovers = await resolveApprovers(nextRule, request.entity_id, request.requested_by);

        const nextRequest = await ApprovalRequest.create({
          entity_id: request.entity_id,
          rule_id: nextRule._id,
          module: request.module,
          doc_type: request.doc_type,
          doc_id: request.doc_id,
          doc_ref: request.doc_ref,
          amount: request.amount,
          description: request.description,
          level: nextRule.level,
          requested_by: request.requested_by,
          status: 'PENDING',
          history: [{ status: 'PENDING', by: deciderId, reason: `Escalated from level ${request.level}` }],
        });

        notifyApprovalRequest({
          entityId: request.entity_id,
          module: request.module,
          docType: request.doc_type,
          docRef: request.doc_ref,
          requestedBy: 'System (escalated)',
          amount: request.amount,
          description: request.description,
          approvers: nextApprovers,
          approvalRequestId: nextRequest._id, // G9.B — thread linkage for escalated level
        }).catch(err => console.error('Next-level approval notification failed:', err.message));

        return { request, nextLevel: nextRequest };
      }
    }
  }

  return { request };
};

/**
 * Check if a document has been fully approved (all levels).
 * @param {ObjectId} docId
 * @returns {Promise<boolean>}
 */
const isFullyApproved = async (docId) => {
  const pending = await ApprovalRequest.countDocuments({
    doc_id: docId,
    status: 'PENDING',
  });
  if (pending > 0) return false;

  const approved = await ApprovalRequest.countDocuments({
    doc_id: docId,
    status: 'APPROVED',
  });
  return approved > 0;
};

/**
 * Get pending approval requests for a user (as approver).
 * @param {ObjectId} userId
 * @param {ObjectId} entityId
 * @returns {Promise<Array>}
 */
const getPendingForApprover = async (userId, entityId) => {
  const user = await User.findById(userId).select('role').lean();
  if (!user) return [];

  // Find all rules where this user could be an approver
  const roleRules = await ApprovalRule.find({
    entity_id: entityId,
    is_active: true,
    approver_type: 'ROLE',
    approver_roles: user.role,
  }).select('_id').lean();

  const userRules = await ApprovalRule.find({
    entity_id: entityId,
    is_active: true,
    approver_type: 'USER',
    approver_user_ids: userId,
  }).select('_id').lean();

  const ruleIds = [...roleRules, ...userRules].map(r => r._id);

  // Presidents see all pending requests
  const query = user.role === ROLES.PRESIDENT
    ? { entity_id: entityId, status: 'PENDING' }
    : { entity_id: entityId, status: 'PENDING', rule_id: { $in: ruleIds } };

  return ApprovalRequest.find(query)
    .populate('requested_by', 'name email')
    .sort({ createdAt: -1 })
    .lean();
};

/**
 * Convenience gate for controllers — checks approval and sends 202 if needed.
 * Returns true if the response was sent (caller should return early).
 *
 * Usage in any submit/post controller:
 *   const gated = await gateApproval({ entityId, module, docType, docId, ... }, res);
 *   if (gated) return;
 *   // ... proceed with normal posting
 *
 * @param {Object} opts - same as checkApprovalRequired
 * @param {import('express').Response} res
 * @returns {Promise<boolean>} true if 202 was sent (caller must return)
 */
const gateApproval = async (opts, res) => {
  const check = await checkApprovalRequired(opts);
  if (check.required) {
    res.status(202).json({
      success: true,
      message: check.message,
      approval_pending: true,
      requests: check.requests,
    });
    return true;
  }
  return false;
};

module.exports = {
  isApprovalEnabled,
  findMatchingRules,
  resolveApprovers,
  checkApprovalRequired,
  gateApproval,
  processDecision,
  isFullyApproved,
  getPendingForApprover,
  getModulePostingRoles,
  getModuleRejectionConfig,
  getEditableStatuses,
  invalidateEditableStatuses,
  MODULE_KEY_ALIASES,
};

/**
 * AR Engine — Accounts Receivable computed on-read
 *
 * AR = POSTED SalesLines minus POSTED Collections (settled amounts)
 * Never stored on SalesLine — always aggregated fresh from the ledger.
 */
const mongoose = require('mongoose');
const SalesLine = require('../models/SalesLine');
const Collection = require('../models/Collection');

/**
 * Get open (unpaid/partially-paid) CSIs for a hospital
 * Returns CSIs with balance_due > 0
 */
async function getOpenCsis(entityId, bdmId, hospitalId, customerId) {
  // Exclude sales routed to petty cash (CASH_RECEIPT/SERVICE_INVOICE with fund) — those bypass AR
  const match = { status: 'POSTED', deletion_event_id: { $exists: false }, petty_cash_fund_id: null };
  if (entityId) match.entity_id = new mongoose.Types.ObjectId(entityId);
  if (bdmId) match.bdm_id = new mongoose.Types.ObjectId(bdmId);
  if (hospitalId) match.hospital_id = new mongoose.Types.ObjectId(hospitalId);
  if (customerId) match.customer_id = new mongoose.Types.ObjectId(customerId);

  const pipeline = [
    { $match: match },
    {
      $lookup: {
        from: 'erp_collections',
        let: { slId: '$_id' },
        pipeline: [
          { $match: { status: 'POSTED', deletion_event_id: { $exists: false } } },
          { $unwind: '$settled_csis' },
          { $match: { $expr: { $eq: ['$settled_csis.sales_line_id', '$$slId'] } } },
          { $group: { _id: null, total_collected: { $sum: '$settled_csis.invoice_amount' } } }
        ],
        as: 'collections'
      }
    },
    {
      $addFields: {
        amount_collected: {
          $ifNull: [{ $arrayElemAt: ['$collections.total_collected', 0] }, 0]
        }
      }
    },
    {
      $addFields: {
        balance_due: { $subtract: ['$invoice_total', '$amount_collected'] },
        days_outstanding: {
          $dateDiff: { startDate: '$csi_date', endDate: '$$NOW', unit: 'day' }
        }
      }
    },
    { $match: { balance_due: { $gt: 0.01 } } },
    {
      $lookup: {
        from: 'erp_hospitals',
        localField: 'hospital_id',
        foreignField: '_id',
        as: 'hospital'
      }
    },
    { $unwind: { path: '$hospital', preserveNullAndEmptyArrays: true } },
    {
      $project: {
        _id: 1, doc_ref: 1, csi_date: 1, hospital_id: 1, bdm_id: 1, warehouse_id: 1,
        invoice_total: 1, total_net_of_vat: 1, source: 1,
        amount_collected: 1, balance_due: 1, days_outstanding: 1,
        hospital_name: '$hospital.hospital_name',
        line_items: 1,
        // Dunning readiness — Finance can only chase receivables that are
        // backed by a signed CSI. `dunning_ready=false` surfaces POSTED-but-
        // un-photographed rows so the BDM gets pinged for the proof before
        // collection follow-up starts.
        //
        // Guard: MongoDB's `$cond` treats an empty string as truthy, so we
        // check string length > 0 explicitly. The controller rejects empty
        // writes, but this is defense-in-depth against any legacy/manual row
        // where the field might be "".
        csi_received_photo_url: 1,
        csi_received_at: 1,
        dunning_ready: { $gt: [{ $strLenCP: { $ifNull: ['$csi_received_photo_url', ''] } }, 0] }
      }
    },
    { $sort: { csi_date: 1 } }
  ];

  return SalesLine.aggregate(pipeline);
}

/**
 * Get AR aging — bucket open CSIs by days outstanding
 */
async function getArAging(entityId, bdmId, hospitalId) {
  const openCsis = await getOpenCsis(entityId, bdmId, hospitalId);

  const buckets = { CURRENT: 0, OVERDUE_30: 0, OVERDUE_60: 0, OVERDUE_90: 0, OVERDUE_120: 0 };
  const hospitalMap = new Map();
  // Dunning-readiness tallies — Finance uses these to see how much of the AR
  // book is collectable today (signed CSI on file) vs blocked on BDM follow-up.
  let dunningReadyAr = 0;
  let dunningReadyCount = 0;
  let dunningMissingAr = 0;
  let dunningMissingCount = 0;

  for (const csi of openCsis) {
    const days = csi.days_outstanding || 0;
    let bucket;
    if (days <= 30) bucket = 'CURRENT';
    else if (days <= 60) bucket = 'OVERDUE_30';
    else if (days <= 90) bucket = 'OVERDUE_60';
    else if (days <= 120) bucket = 'OVERDUE_90';
    else bucket = 'OVERDUE_120';

    buckets[bucket] += csi.balance_due;

    // OPENING_AR rows do not require a received-photo (historical bucket; the
    // signed CSI is already on csi_photo_url at entry). Treat them as
    // dunning-ready regardless so they don't skew the missing-proof tally.
    const isReady = !!csi.dunning_ready || csi.source === 'OPENING_AR';
    if (isReady) {
      dunningReadyAr += csi.balance_due;
      dunningReadyCount += 1;
    } else {
      dunningMissingAr += csi.balance_due;
      dunningMissingCount += 1;
    }

    const hid = csi.hospital_id.toString();
    if (!hospitalMap.has(hid)) {
      hospitalMap.set(hid, {
        hospital_id: csi.hospital_id,
        hospital_name: csi.hospital_name || '—',
        CURRENT: 0, OVERDUE_30: 0, OVERDUE_60: 0, OVERDUE_90: 0, OVERDUE_120: 0,
        total_ar: 0, worst_days: 0,
        dunning_missing_count: 0, dunning_missing_ar: 0,
        csis: []
      });
    }
    const h = hospitalMap.get(hid);
    h[bucket] += csi.balance_due;
    h.total_ar += csi.balance_due;
    if (days > h.worst_days) h.worst_days = days;
    if (!isReady) {
      h.dunning_missing_count += 1;
      h.dunning_missing_ar += csi.balance_due;
    }
    h.csis.push({ ...csi, aging_bucket: bucket, dunning_ready: isReady });
  }

  const hospitals = [...hospitalMap.values()]
    .map(h => ({ ...h, dunning_missing_ar: Math.round(h.dunning_missing_ar * 100) / 100 }))
    .sort((a, b) => b.total_ar - a.total_ar);
  const totalAr = hospitals.reduce((sum, h) => sum + h.total_ar, 0);

  return {
    summary: {
      total_ar: Math.round(totalAr * 100) / 100,
      total_csis: openCsis.length,
      buckets: Object.fromEntries(Object.entries(buckets).map(([k, v]) => [k, Math.round(v * 100) / 100])),
      dunning_ready_ar: Math.round(dunningReadyAr * 100) / 100,
      dunning_ready_count: dunningReadyCount,
      dunning_missing_ar: Math.round(dunningMissingAr * 100) / 100,
      dunning_missing_count: dunningMissingCount
    },
    hospitals
  };
}

/**
 * Collection rate = total collections / total sales × 100%
 */
async function getCollectionRate(entityId, bdmId, dateFrom, dateTo) {
  // Exclude petty-cash-routed sales from collection rate (already "collected" at sale time)
  const salesMatch = { status: 'POSTED', deletion_event_id: { $exists: false }, petty_cash_fund_id: null };
  const collMatch = { status: 'POSTED', deletion_event_id: { $exists: false } };

  if (entityId) {
    salesMatch.entity_id = new mongoose.Types.ObjectId(entityId);
    collMatch.entity_id = new mongoose.Types.ObjectId(entityId);
  }
  if (bdmId) {
    salesMatch.bdm_id = new mongoose.Types.ObjectId(bdmId);
    collMatch.bdm_id = new mongoose.Types.ObjectId(bdmId);
  }
  if (dateFrom || dateTo) {
    const dateFilter = {};
    if (dateFrom) dateFilter.$gte = new Date(dateFrom);
    if (dateTo) dateFilter.$lte = new Date(dateTo);
    salesMatch.csi_date = dateFilter;
    collMatch.cr_date = dateFilter;
  }

  const [salesAgg] = await SalesLine.aggregate([
    { $match: salesMatch },
    { $group: { _id: null, total: { $sum: '$invoice_total' } } }
  ]);
  const [collAgg] = await Collection.aggregate([
    { $match: collMatch },
    { $group: { _id: null, total: { $sum: '$cr_amount' } } }
  ]);

  const totalSales = salesAgg?.total || 0;
  const totalCollections = collAgg?.total || 0;
  const rate = totalSales > 0 ? (totalCollections / totalSales) : 0;

  // Use configurable threshold from Settings (not hardcoded 70%)
  const Settings = require('../models/Settings');
  const settings = await Settings.getSettings();
  const thresholdPct = (settings?.COLLECTION_OK_THRESHOLD || 0.70) * 100;

  return {
    total_sales: Math.round(totalSales * 100) / 100,
    total_collections: Math.round(totalCollections * 100) / 100,
    collection_rate: Math.round(rate * 10000) / 100,
    threshold: thresholdPct,
    status: rate >= (thresholdPct / 100) ? 'GREEN' : 'RED'
  };
}

/**
 * Simple AR balance for a hospital (for credit limit check)
 */
async function getHospitalArBalance(hospitalId, entityId) {
  const openCsis = await getOpenCsis(entityId, null, hospitalId);
  return openCsis.reduce((sum, csi) => sum + (csi.balance_due || 0), 0);
}

/**
 * Generalized AR balance — supports hospital OR customer
 */
async function getArBalance(entityId, hospitalId, customerId) {
  const openCsis = await getOpenCsis(entityId, null, hospitalId, customerId);
  return openCsis.reduce((sum, csi) => sum + (csi.balance_due || 0), 0);
}

module.exports = { getOpenCsis, getArAging, getCollectionRate, getHospitalArBalance, getArBalance };

/**
 * Auto-Journal Service — generates JE data from source documents
 *
 * PRD v5 §11.3 — Each function returns a JE data object (not persisted).
 * The caller (monthEndClose or controller) creates+posts via journalEngine.
 *
 * Phase 22: All COA codes are read from Settings.COA_MAP (configurable).
 * Use getCoaMap() to load the mapping — cached per process lifetime until settings change.
 */

const BankAccount = require('../models/BankAccount');
const CreditCard = require('../models/CreditCard');
const PaymentMode = require('../models/PaymentMode');
const Settings = require('../models/Settings');

// ═══ COA Map Cache ═══
let _coaCache = null;
let _coaCacheTime = 0;
const COA_CACHE_TTL = 60_000; // 1 minute

async function getCoaMap() {
  const now = Date.now();
  if (_coaCache && now - _coaCacheTime < COA_CACHE_TTL) return _coaCache;
  const settings = await Settings.getSettings();
  _coaCache = settings.COA_MAP || {};
  _coaCacheTime = now;
  return _coaCache;
}

// Helper for COA name lookup (avoids stale names by using code as key)
const COA_NAMES = {
  AR_TRADE: 'Accounts Receivable — Trade',
  AR_BDM: 'AR — BDM Advances',
  IC_RECEIVABLE: 'Intercompany Receivable',
  CASH_ON_HAND: 'Cash on Hand',
  PETTY_CASH: 'Petty Cash Fund',
  INVENTORY: 'Inventory',
  INPUT_VAT: 'Input VAT',
  CWT_RECEIVABLE: 'CWT Receivable',
  ACCUM_DEPRECIATION: 'Accumulated Depreciation',
  AP_TRADE: 'Accounts Payable — Trade',
  IC_PAYABLE: 'Intercompany Payable',
  OUTPUT_VAT: 'Output VAT',
  LOANS_PAYABLE: 'Loans Payable',
  OWNER_CAPITAL: 'Owner Capital',
  OWNER_DRAWINGS: 'Owner Drawings',
  SALES_REVENUE: 'Sales Revenue — Vatable',
  SERVICE_REVENUE: 'Service Revenue',
  INTEREST_INCOME: 'Interest Income',
  COGS: 'Cost of Goods Sold',
  BDM_COMMISSION: 'BDM Commission',
  PARTNER_REBATE: 'Partner Rebate Expense',
  INCENTIVE_EXPENSE: 'Incentive Expense',
  INCENTIVE_ACCRUAL: 'Incentive Accrual Payable',
  PER_DIEM: 'Per Diem Expense',
  TRANSPORT: 'Transport Expense',
  SPECIAL_TRANSPORT: 'Special Transport Expense',
  OTHER_REIMBURSABLE: 'Other Reimbursable Expense',
  FUEL_GAS: 'Fuel & Gas Expense',
  INVENTORY_WRITEOFF: 'Inventory Write-Off',
  INVENTORY_ADJ_GAIN: 'Inventory Adjustment Gain',
  MISC_EXPENSE: 'Miscellaneous Expense',
  DEPRECIATION: 'Depreciation Expense',
  INTEREST_EXPENSE: 'Interest Expense',
  INTEREST_PAYABLE: 'Interest Payable',
  BANK_CHARGES: 'Bank Charges',
  // Payroll
  SALARIES_WAGES: 'Salaries & Wages',
  ALLOWANCES: 'Allowances',
  BONUS_13TH: 'Bonus & 13th Month',
  SSS_PAYABLE: 'SSS Payable',
  PHILHEALTH_PAYABLE: 'PhilHealth Payable',
  PAGIBIG_PAYABLE: 'Pag-IBIG Payable',
  WHT_PAYABLE: 'Withholding Tax Payable',
};

/** Clear cached COA_MAP — call after Settings update */
function clearCoaCache() { _coaCache = null; _coaCacheTime = 0; }

function c(coa, key) { return coa[key] || '9999'; }
function n(key) { return COA_NAMES[key] || key; }

// Phase 35 — first-digit heuristic used by auto-journal helpers to mark contra
// lines. Standard VIP COA ranges:
//   1xxx Asset         (normal DEBIT)  — a CR line reduces it
//   2xxx Liability     (normal CREDIT) — a DR line reduces it
//   3xxx Equity        (normal CREDIT) — a DR line reduces it
//     (contra-equity like OWNER_DRAWINGS coded 3xxx is DEBIT-normal; a CR line
//      reduces it, which is what Petty Cash replenishment does.)
//   4xxx Revenue       (normal CREDIT) — a DR line reverses it
//   5xxx COGS          (normal DEBIT)  — a CR line reverses it
//   6xxx Expense       (normal DEBIT)  — a CR line reverses it
//
// Caveat: contra-asset accounts (e.g., ACCUM_DEPRECIATION 1350 with CREDIT
// normal_balance) sit in 1xxx but credits to them are increases, not reductions.
// The validator's COA lookup is authoritative — the flag only means "skip the
// direction check for this line" — so over-marking is_contra on such lines is a
// no-op for the balance guard. Callers that know the COA is DEBIT-normal set the
// flag explicitly; callers with a dynamic funding_coa use these helpers.
function isDebitNormalByCode(code) {
  const d = String(code || '').charAt(0);
  return d === '1' || d === '5' || d === '6';
}
function isCreditNormalByCode(code) {
  const d = String(code || '').charAt(0);
  return d === '2' || d === '3' || d === '4';
}

/**
 * Helper: format period from Date
 */
function dateToPeriod(d) {
  const dt = new Date(d);
  return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}`;
}

/**
 * Resolve COA code from funding references.
 * Priority: funding_card_id → funding_account_id → bank_account_id → payment_mode lookup → fallback
 */
async function resolveFundingCoa(doc, fallback) {
  const coa = await getCoaMap();
  const fb = fallback || c(coa, 'CASH_ON_HAND');

  if (doc.funding_card_id) {
    const card = await CreditCard.findById(doc.funding_card_id).lean();
    if (card?.coa_code) return { coa_code: card.coa_code, coa_name: card.card_name };
  }

  const bankRef = doc.funding_account_id || doc.bank_account_id;
  if (bankRef) {
    const bank = await BankAccount.findById(bankRef).lean();
    if (bank?.coa_code) return { coa_code: bank.coa_code, coa_name: bank.bank_name };
  }

  if (doc.payment_mode) {
    const pm = await PaymentMode.findOne({ mode_code: doc.payment_mode }).lean()
      || await PaymentMode.findOne({ mode_type: doc.payment_mode }).lean();
    if (pm?.coa_code) return { coa_code: pm.coa_code, coa_name: pm.mode_label };
  }

  return { coa_code: fb, coa_name: fallback ? `Account ${fb}` : n('CASH_ON_HAND') };
}

/**
 * Journal from Sales Line
 * DR AR_TRADE (gross), CR SALES_REVENUE (net), CR OUTPUT_VAT (vat)
 */
async function journalFromSale(salesLine, entityId, userId) {
  const coa = await getCoaMap();
  const gross = salesLine.total_amount || salesLine.invoice_total || 0;
  const vat = salesLine.total_vat || 0;
  const net = gross - vat;

  // Skip journal for zero-amount sales (complimentary/samples)
  if (gross === 0) return null;

  // CSI sales carry the booklet# in `doc_ref`; SERVICE_INVOICE/CASH_RECEIPT use
  // auto-generated `invoice_number`. Without this priority the JE falls back to
  // the raw ObjectId for every CSI, which is what users see in the detail panel.
  const docRef = salesLine.doc_ref || salesLine.invoice_number || String(salesLine._id);
  const saleLabel = salesLine.sale_type === 'SERVICE_INVOICE' ? 'SI'
    : salesLine.sale_type === 'CASH_RECEIPT' ? 'CR' : 'CSI';

  // Direct cash routing: DR PETTY_CASH instead of DR AR_TRADE when fund is set
  const debitCode = salesLine.petty_cash_fund_id && salesLine.payment_mode === 'CASH'
    ? c(coa, 'PETTY_CASH') : c(coa, 'AR_TRADE');
  const debitName = salesLine.petty_cash_fund_id && salesLine.payment_mode === 'CASH'
    ? n('PETTY_CASH') : n('AR_TRADE');

  const lines = [
    { account_code: debitCode, account_name: debitName, debit: gross, credit: 0, description: `${saleLabel} ${docRef}` },
    { account_code: c(coa, 'SALES_REVENUE'), account_name: n('SALES_REVENUE'), debit: 0, credit: net, description: `${saleLabel} ${docRef}` },
  ];

  if (vat > 0) {
    lines.push({ account_code: c(coa, 'OUTPUT_VAT'), account_name: n('OUTPUT_VAT'), debit: 0, credit: vat, description: `VAT on ${saleLabel} ${docRef}` });
  }

  return {
    je_date: salesLine.csi_date || salesLine.created_at || new Date(),
    period: dateToPeriod(salesLine.csi_date || salesLine.created_at || new Date()),
    description: `${saleLabel} ${docRef} — ${gross.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`,
    source_module: 'SALES',
    source_event_id: salesLine.event_id || null,
    source_doc_ref: docRef,
    lines,
    bir_flag: 'BOTH',
    vat_flag: vat > 0 ? 'VATABLE' : 'EXEMPT',
    bdm_id: salesLine.bdm_id || null,
    created_by: userId
  };
}

/**
 * Journal from Collection
 * DR Cash/Bank (resolved), CR AR_TRADE
 */
async function journalFromCollection(collection, bankCoaCode, bankName, userId) {
  const coa = await getCoaMap();
  const amount = collection.cr_amount || 0;

  let coaCode, coaName;
  if (collection.petty_cash_fund_id) {
    coaCode = c(coa, 'PETTY_CASH');
    coaName = n('PETTY_CASH');
  } else {
    coaCode = bankCoaCode || c(coa, 'CASH_ON_HAND');
    coaName = bankName || n('CASH_ON_HAND');
  }

  return {
    je_date: collection.cr_date || collection.created_at || new Date(),
    period: dateToPeriod(collection.cr_date || collection.created_at || new Date()),
    description: `Collection: ${collection.cr_no || collection._id}`,
    source_module: 'COLLECTION',
    source_event_id: collection.event_id || null,
    source_doc_ref: collection.cr_no || String(collection._id),
    lines: [
      { account_code: coaCode, account_name: coaName, debit: amount, credit: 0, description: `Collection ${collection.cr_no || ''}` },
      { account_code: c(coa, 'AR_TRADE'), account_name: n('AR_TRADE'), debit: 0, credit: amount, description: `Collection ${collection.cr_no || ''}`, is_contra: true }
    ],
    bir_flag: 'BOTH',
    vat_flag: 'N/A',
    bdm_id: collection.bdm_id || null,
    created_by: userId
  };
}

/**
 * Journal from CWT
