async function draftNewEntry(ctx, args = {}) {
  const moduleKey = String(args.module || '').toUpperCase();
  const values = (args.values && typeof args.values === 'object') ? args.values : {};

  const ENTRY_ROUTES = {
    EXPENSES:   '/erp/expenses?new=1',
