/**
 * Cost Center Service — SAP CO Cost Centers (Phase 15.5)
 */
const mongoose = require('mongoose');
const CostCenter = require('../models/CostCenter');

/**
 * Create a cost center
 */
async function createCostCenter(entityId, data, userId) {
  const eId = new mongoose.Types.ObjectId(entityId);

  // Validate parent exists if specified
  if (data.parent_cost_center) {
    const parent = await CostCenter.findOne({
      _id: data.parent_cost_center,
      entity_id: eId
    });
    if (!parent) {
      throw Object.assign(new Error('Parent cost center not found'), { statusCode: 400 });
    }
  }

  const cc = await CostCenter.create({
    entity_id: eId,
    code: data.code,
    name: data.name,
    parent_cost_center: data.parent_cost_center || null,
    description: data.description || '',
    created_by: userId
  });

  return cc;
}

/**
 * Get all cost centers (flat list)
 */
async function getCostCenters(entityId, filters = {}) {
  const query = { entity_id: new mongoose.Types.ObjectId(entityId) };
  if (!filters.include_inactive) query.is_active = true;

  const centers = await CostCenter.find(query)
    .populate('parent_cost_center', 'code name')
    .sort({ code: 1 })
    .lean();

  return centers;
}

/**
 * Update a cost center
 */
async function updateCostCenter(costCenterId, updates, userId) {
  const allowedFields = ['name', 'parent_cost_center', 'description', 'is_active'];
  const updateData = {};
  for (const field of allowedFields) {
    if (updates[field] !== undefined) updateData[field] = updates[field];
  }

  const cc = await CostCenter.findByIdAndUpdate(costCenterId, updateData, { new: true }).lean();
  if (!cc) throw Object.assign(new Error('Cost center not found'), { statusCode: 404 });
  return cc;
}

/**
 * Get hierarchical tree structure
 */
async function getCostCenterTree(entityId) {
  const centers = await CostCenter.find({
    entity_id: new mongoose.Types.ObjectId(entityId),
    is_active: true
  }).sort({ code: 1 }).lean();

  // Build tree
  const map = new Map(centers.map(c => [c._id.toString(), { ...c, children: [] }]));
  const roots = [];

  for (const c of centers) {
    const node = map.get(c._id.toString());
    if (c.parent_cost_center) {
      const parent = map.get(c.parent_cost_center.toString());
      if (parent) {
        parent.children.push(node);
      } else {
        roots.push(node);
      }
    } else {
      roots.push(node);
    }
  }

  return roots;
}

module.exports = {
  createCostCenter,
  getCostCenters,
  updateCostCenter,
  getCostCenterTree
};

/**
 * creditRuleEngine — Phase SG-4 #22
 *
 * Pure assignment engine. Given a posted SalesLine, it produces N
 * SalesCredit rows describing who-earns-what credit. Designed to be a
 * single, self-contained call from the SalesLine post path:
 *
 *     await creditRuleEngine.assign(saleLine, { userId });
 *
 * The engine never throws back into the sales path — failures are logged
 * to ErpAuditLog with log_type 'CREDIT_RULE_ERROR' (best-effort, behaves
 * like the auto-journal pattern in salesController). A sale that posts
 * without credit rows will fall back to sale.bdm_id @ 100% on the next
 * run — see `assign()` "fallback rule" branch.
 *
 * No mutation of SalesLine. No mutation of incentive payouts (those are
 * computed from snapshots, not credits — SG-5 will migrate that read).
 *
 * Idempotency: assign() upserts by sale_line_id — running twice for the
 * same sale produces the same SalesCredit rows. Reversal rows (source =
 * 'reversal') are written by SalesLine reopen/storno path (TODO: wire in
 * a follow-up; today reopen leaves credit rows orphaned which is OK
 * because consumers ignore credits whose parent sale is no longer POSTED).
 *
 * Subscription posture: rules are entity-scoped; engine never reaches
 * across entities.
 */

const mongoose = require('mongoose');
const CreditRule = require('../models/CreditRule');
const SalesCredit = require('../models/SalesCredit');
const ProductMaster = require('../models/ProductMaster');
const Customer = require('../models/Customer');
const Hospital = require('../models/Hospital');
const ErpAuditLog = require('../models/ErpAuditLog');

function periodFromDate(d) {
  const dt = d ? new Date(d) : new Date();
  return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}`;
}

function fiscalYearFromDate(d) {
  // Mirrors GOAL_CONFIG.FISCAL_START_MONTH treatment elsewhere — assumes
  // calendar year. Subscribers with non-calendar fiscal years should
  // override this on a follow-up by reading GOAL_CONFIG.FISCAL_START_MONTH;
  // not in SG-4 scope.
  return d ? new Date(d).getFullYear() : new Date().getFullYear();
}

/**
 * Returns true when the rule's conditions match the given context.
 * Empty arrays / null bounds = "no constraint on this dimension".
 *
 * `ctx` shape:
 *   {
 *     entity_id, hospital_id, customer_id, territory_id,
 *     product_codes (Set<String>),
 *     customer_code (String|null),
 *     hospital_id (ObjectId),
 *     invoice_total, sale_type, csi_date,
 *   }
 */
function ruleMatches(rule, ctx) {
  // Entity scope is always enforced upstream in the .find() filter; defensive.
  if (String(rule.entity_id) !== String(ctx.entity_id)) return false;

  // Effective dating
  if (rule.effective_from && new Date(rule.effective_from) > ctx.csi_date) return false;
  if (rule.effective_to && new Date(rule.effective_to) < ctx.csi_date) return false;

  const c = rule.conditions || {};

  if (Array.isArray(c.territory_ids) && c.territory_ids.length > 0) {
    if (!ctx.territory_id) return false;
    if (!c.territory_ids.some(id => String(id) === String(ctx.territory_id))) return false;
  }

  if (Array.isArray(c.product_codes) && c.product_codes.length > 0) {
    if (!ctx.product_codes || ctx.product_codes.size === 0) return false;
    const ruleSet = new Set(c.product_codes.map(s => String(s).toUpperCase()));
    let any = false;
    for (const code of ctx.product_codes) {
      if (ruleSet.has(String(code).toUpperCase())) { any = true; break; }
    }
    if (!any) return false;
  }

  if (Array.isArray(c.customer_codes) && c.customer_codes.length > 0) {
    if (!ctx.customer_code) return false;
    const upper = String(ctx.customer_code).toUpperCase();
    if (!c.customer_codes.map(s => String(s).toUpperCase()).includes(upper)) return false;
  }

  if (Array.isArray(c.hospital_ids) && c.hospital_ids.length > 0) {
    if (!ctx.hospital_id) return false;
    if (!c.hospital_ids.some(id => String(id) === String(ctx.hospital_id))) return false;
  }

  if (Array.isArray(c.sale_types) && c.sale_types.length > 0) {
    if (!ctx.sale_type) return false;
    if (!c.sale_types.includes(ctx.sale_type)) return false;
  }

  if (c.min_amount != null && Number.isFinite(c.min_amount) && ctx.invoice_total < c.min_amount) return false;
  if (c.max_amount != null && Number.isFinite(c.max_amount) && ctx.invoice_total > c.max_amount) return false;

  return true;
}

/**
 * Build the matching context for a SalesLine. Loads the per-line product
 * codes + customer code in one batch (no N+1 queries).
 *
 * Returns null when the sale lacks the minimum data the engine needs
 * (entity_id + bdm_id + invoice_total) — caller skips assignment.
 */
async function buildContext(saleLine) {
  if (!saleLine || !saleLine.entity_id || !saleLine.bdm_id) return null;

  // Collect distinct product ids
  const productIds = (saleLine.line_items || [])
    .map(li => li.product_id)
    .filter(Boolean);

  let productCodes = new Set();
  if (productIds.length > 0) {
    const products = await ProductMaster.find({ _id: { $in: productIds } })
      .select('product_code')
      .lean();
    productCodes = new Set(products.map(p => p.product_code).filter(Boolean));
  }

  let customerCode = null;
  if (saleLine.customer_id) {
    const cust = await Customer.findById(saleLine.customer_id).select('customer_code').lean();
    customerCode = cust?.customer_code || null;
  }

  // Territory: derive from the sale's bdm_id's PeopleMaster.territory_id
  // (lightweight — we don't reload the whole person). Hospital may also
  // have a territory_id; we prefer the hospital's territory when present
  // since rule writers tend to target territory by deal location.
  let territoryId = null;
  if (saleLine.hospital_id) {
    const hosp = await Hospital.findById(saleLine.hospital_id).select('territory_id').lean();
    if (hosp?.territory_id) territoryId = hosp.territory_id;
  }

  return {
    entity_id: saleLine.entity_id,
    bdm_id: saleLine.bdm_id,
    hospital_id: saleLine.hospital_id || null,
    customer_id: saleLine.customer_id || null,
    customer_code: customerCode,
    territory_id: territoryId,
    product_codes: productCodes,
    invoice_total: Number(saleLine.invoice_total) || 0,
    sale_type: saleLine.sale_type || 'CSI',
    csi_date: saleLine.csi_date || saleLine.posted_at || new Date(),
  };
}

/**
 * Apply the engine to a single SalesLine, write SalesCredit rows.
 * Idempotent: existing 'rule' / 'fallback' rows for this sale are deleted
 * and re-created so the latest rule set wins.
 *
 * `manual` and `reversal` rows are NEVER deleted — those are admin/audit
 * artifacts that survive engine re-runs.
 *
 * Returns { assigned: [...rows], totalPct, fallbackUsed: bool }.
 */
async function assign(saleLine, opts = {}) {
  if (!saleLine) return { assigned: [], totalPct: 0, fallbackUsed: false };

  const userId = opts.userId || saleLine.posted_by || saleLine.bdm_id;

  let ctx;
  try {
    ctx = await buildContext(saleLine);
  } catch (err) {
    console.error('[creditRuleEngine] buildContext failed for sale', saleLine._id, err.message);
    return { assigned: [], totalPct: 0, fallbackUsed: false, error: err.message };
  }
  if (!ctx) return { assigned: [], totalPct: 0, fallbackUsed: false };

  // Load all candidate rules for this entity. plan_id null OR matching
  // sale's plan are kept; we don't know the active plan version per sale
  // in SG-4 scope (kept for SG-5 when snapshots migrate to read credits).
  const rules = await CreditRule.find({
    entity_id: ctx.entity_id,
    is_active: true,
    $or: [{ plan_id: null }, { plan_id: { $exists: false } }],
  }).sort({ priority: 1, createdAt: 1 }).lean();

  const matched = rules.filter(r => ruleMatches(r, ctx));

  // Build the assignment list. Stop assigning credits once we hit 100% to
  // protect against runaway over-allocation; but record overage on the
  // last allowed row's reason so admin sees why a stacked rule was capped.
  const rows = [];
  let totalPct = 0;
  for (const rule of matched) {
    const pct = Number(rule.credit_pct) || 0;
    if (pct <= 0) continue;
    const remaining = Math.max(100 - totalPct, 0);
    const applied = Math.min(pct, remaining);
    const reason = applied < pct
      ? `Rule "${rule.rule_name}" capped at ${applied}% (${pct - applied}% would exceed 100%)`
      : `Rule "${rule.rule_name}" matched (priority ${rule.priority})`;
    rows.push({
      entity_id: ctx.entity_id,
      sale_line_id: saleLine._id,
      credit_bdm_id: rule.credit_bdm_id,
      rule_id: rule._id,
      rule_name: rule.rule_name,
      credit_pct: applied,
      credited_amount: Math.round((ctx.invoice_total * applied / 100) * 100) / 100,
      credit_reason: reason,
      invoice_total: ctx.invoice_total,
      csi_date: ctx.csi_date,
      fiscal_year: fiscalYearFromDate(ctx.csi_date),
      period: periodFromDate(ctx.csi_date),
      source: 'rule',
      created_at: new Date(),
      created_by: userId,
    });
    totalPct += applied;
    if (totalPct >= 100) break;
  }

  // Fallback: residual goes to sale.bdm_id (preserves pre-SG-4 behavior).
  let fallbackUsed = false;
  if (totalPct < 100) {
    const fallbackPct = 100 - totalPct;
    rows.push({
      entity_id: ctx.entity_id,
      sale_line_id: saleLine._id,
      credit_bdm_id: ctx.bdm_id,
      rule_id: null,
      rule_name: '',
      credit_pct: fallbackPct,
      credited_amount: Math.round((ctx.invoice_total * fallbackPct / 100) * 100) / 100,
      credit_reason: matched.length === 0
        ? 'No CreditRule matched — defaulted to sale.bdm_id (legacy implicit credit).'
        : `Residual ${fallbackPct}% not covered by matched rules — credited to sale.bdm_id.`,
      invoice_total: ctx.invoice_total,
      csi_date: ctx.csi_date,
      fiscal_year: fiscalYearFromDate(ctx.csi_date),
      period: periodFromDate(ctx.csi_date),
      source: 'fallback',
      created_at: new Date(),
      created_by: userId,
    });
    totalPct = 100;
    fallbackUsed = true;
  }

  // Idempotent rewrite: drop existing rule/fallback rows for this sale,
  // insert the freshly-computed set. manual + reversal rows survive.
  const session = opts.session || null;
  try {
    await SalesCredit.deleteMany(
      { sale_line_id: saleLine._id, source: { $in: ['rule', 'fallback'] } },
      session ? { session } : {}
    );
    if (rows.length > 0) {
      // insertMany bypasses the immutable pre('save') guard which only fires
      // on document.save(). Use create() per-row so the guard runs and any
      // accidental insert-on-update is caught.
      const inserted = [];
      for (const r of rows) {
        const docArr = await SalesCredit.create([r], session ? { session } : {});
        inserted.push(docArr[0]);
      }
      return { assigned: inserted, totalPct, fallbackUsed };
    }
    return { assigned: [], totalPct, fallbackUsed };
  } catch (err) {
    console.error('[creditRuleEngine] assign failed for sale', saleLine._id, err.message);
    // Best-effort audit so the failure is visible without breaking the sale.
    try {
      await ErpAuditLog.logChange({
        entity_id: ctx.entity_id,
        log_type: 'STATUS_CHANGE',
        target_ref: saleLine._id.toString(),
        target_model: 'SalesCredit',
        field_changed: 'assignment',
        new_value: 'FAILED',
        changed_by: userId,
        note: `creditRuleEngine.assign() failed: ${err.message}`,
      });
    } catch { /* swallow — log is best-effort */ }
    return { assigned: [], totalPct: 0, fallbackUsed: false, error: err.message };
  }
}

/**
 * Convenience: list credits for a sale (for SalesLine detail view).
 */
async function listForSale(saleLineId) {
  if (!saleLineId) return [];
  return SalesCredit.find({ sale_line_id: saleLineId })
    .populate('credit_bdm_id', 'name email')
    .populate('rule_id', 'rule_name priority')
    .sort({ source: 1, credit_pct: -1 })
    .lean();
}

module.exports = {
  assign,
  listForSale,
  ruleMatches,
  buildContext,
};

/**
 * Cycle Report Service — GENERATED → REVIEWED → BDM_CONFIRMED → CREDITED (Phase 15.3)
 */
const mongoose = require('mongoose');
const CycleReport = require('../models/CycleReport');
const SalesLine = require('../models/SalesLine');
const Collection = require('../models/Collection');
const ExpenseEntry = require('../models/ExpenseEntry');
const SmerEntry = require('../models/SmerEntry');
const CarLogbookEntry = require('../models/CarLogbookEntry');

function periodToDates(period) {
  const [year, month] = period.split('-').map(Number);
  return { start: new Date(year, month - 1, 1), end: new Date(year, month, 1) };
}

/**
 * Generate a cycle report snapshot
 */
async function generateCycleReport(entityId, bdmId, period, cycle, userId) {
  const eId = new mongoose.Types.ObjectId(entityId);
  const bId = new mongoose.Types.ObjectId(bdmId);
  const { start, end } = periodToDates(period);
  const baseMatch = { entity_id: eId, bdm_id: bId, status: 'POSTED' };

  // Aggregate sales
  const salesAgg = await SalesLine.aggregate([
    { $match: { ...baseMatch, csi_date: { $gte: start, $lt: end } } },
    { $group: { _id: null, total: { $sum: '$invoice_total' }, count: { $sum: 1 } } }
  ]);
  const sales_total = salesAgg[0]?.total || 0;

  // Aggregate collections
  const collAgg = await Collection.aggregate([
    { $match: { ...baseMatch, cr_date: { $gte: start, $lt: end } } },
    {
      $group: {
        _id: null,
        total: { $sum: '$cr_amount' },
        commission: { $sum: '$total_commission' },
        count: { $sum: 1 }
      }
    }
  ]);
  const collections_total = collAgg[0]?.total || 0;
  const commission_total = collAgg[0]?.commission || 0;

  // Aggregate expenses across 3 sources
  const periodMatch = { ...baseMatch, period };
  const [smerAgg, gasAgg, expAgg] = await Promise.all([
    SmerEntry.aggregate([{ $match: periodMatch }, { $group: { _id: null, total: { $sum: '$total_reimbursable' } } }]),
    CarLogbookEntry.aggregate([{ $match: periodMatch }, { $group: { _id: null, total: { $sum: '$official_gas_amount' } } }]),
    ExpenseEntry.aggregate([{ $match: periodMatch }, { $group: { _id: null, total: { $sum: '$total_amount' } } }])
  ]);
  const expenses_total = (smerAgg[0]?.total || 0) + (gasAgg[0]?.total || 0) + (expAgg[0]?.total || 0);
  const net_income = Math.round((collections_total - expenses_total) * 100) / 100;

  // Build breakdowns
  const sales_breakdown = { total: sales_total, count: salesAgg[0]?.count || 0 };
  const collection_breakdown = { total: collections_total, commission: commission_total, count: collAgg[0]?.count || 0 };
  const expense_breakdown = {
    smer: smerAgg[0]?.total || 0,
    gas: gasAgg[0]?.total || 0,
    other_expenses: expAgg[0]?.total || 0,
    total: expenses_total
  };

  // Guard: don't overwrite reports past GENERATED status
  const existing = await CycleReport.findOne({ entity_id: eId, bdm_id: bId, period, cycle }).select('status').lean();
  if (existing && ['REVIEWED', 'BDM_CONFIRMED', 'CREDITED'].includes(existing.status)) {
    throw Object.assign(new Error(`Cannot regenerate report in ${existing.status} status. It must be reverted first.`), { statusCode: 400 });
  }

  // Create or update cycle report
  const report = await CycleReport.findOneAndUpdate(
    { entity_id: eId, bdm_id: bId, period, cycle },
    {
      sales_total: Math.round(sales_total * 100) / 100,
      collections_total: Math.round(collections_total * 100) / 100,
      expenses_total: Math.round(expenses_total * 100) / 100,
      commission_total: Math.round(commission_total * 100) / 100,
      net_income,
      sales_breakdown,
      expense_breakdown,
      collection_breakdown,
      status: 'GENERATED',
      generated_at: new Date(),
      generated_by: userId
    },
    { upsert: true, new: true, setDefaultsOnInsert: true }
  );

  return report;
}

/**
 * Review a cycle report (GENERATED -> REVIEWED)
 */
async function reviewCycleReport(reportId, userId, notes) {
  const report = await CycleReport.findById(reportId);
  if (!report) throw Object.assign(new Error('Cycle report not found'), { statusCode: 404 });
  if (report.status !== 'GENERATED') {
    throw Object.assign(new Error(`Cannot review report in ${report.status} status`), { statusCode: 400 });
  }

  report.status = 'REVIEWED';
  report.reviewed_at = new Date();
  report.reviewed_by = userId;
  report.review_notes = notes || '';
  await report.save();
  return report;
}

/**
 * BDM confirms cycle report (REVIEWED -> BDM_CONFIRMED)
 */
async function confirmCycleReport(reportId, userId, notes) {
  const report = await CycleReport.findById(reportId);
  if (!report) throw Object.assign(new Error('Cycle report not found'), { statusCode: 404 });
  if (report.status !== 'REVIEWED') {
    throw Object.assign(new Error(`Cannot confirm report in ${report.status} status`), { statusCode: 400 });
  }

  report.status = 'BDM_CONFIRMED';
  report.bdm_confirmed_at = new Date();
  report.bdm_confirmed_by = userId;
  report.bdm_notes = notes || '';
  await report.save();
  return report;
}

/**
 * Credit a cycle report (BDM_CONFIRMED -> CREDITED)
 */
async function creditCycleReport(reportId, userId, creditReference) {
  const report = await CycleReport.findById(reportId);
  if (!report) throw Object.assign(new Error('Cycle report not found'), { statusCode: 404 });
  if (report.status !== 'BDM_CONFIRMED') {
    throw Object.assign(new Error(`Cannot credit report in ${report.status} status`), { statusCode: 400 });
  }

  report.status = 'CREDITED';
  report.credited_at = new Date();
  report.credited_by = userId;
  report.credit_reference = creditReference || '';
  await report.save();
  return report;
}

/**
 * List cycle reports with filters
 */
async function getCycleReports(entityId, filters = {}) {
  const query = { entity_id: new mongoose.Types.ObjectId(entityId) };
  if (filters.bdm_id) query.bdm_id = new mongoose.Types.ObjectId(filters.bdm_id);
  if (filters.period) query.period = filters.period;
  if (filters.status) query.status = filters.status;

  const reports = await CycleReport.find(query)
    .sort({ period: -1, created_at: -1 })
    .lean();

  return reports;
}

module.exports = {
  generateCycleReport,
  reviewCycleReport,
  confirmCycleReport,
  creditCycleReport,
  getCycleReports
};

/**
 * Dashboard Service — CEO KPIs, Summary Cards, MTD & PNL-YTD
 *
 * PRD §13.5: BOSS-style dashboard with 4 summary cards, MTD metrics, and PNL-YTD.
 * Uses existing services (arEngine, fifoEngine, expenseSummary) for aggregation.
 */
const mongoose = require('mongoose');
const SalesLine = require('../models/SalesLine');
const Collection = require('../models/Collection');
const InventoryLedger = require('../models/InventoryLedger');
const ProductMaster = require('../models/ProductMaster');
const IncomeReport = require('../models/IncomeReport');
const SmerEntry = require('../models/SmerEntry');
const ExpenseEntry = require('../models/ExpenseEntry');
const CarLogbookEntry = require('../models/CarLogbookEntry');
const Hospital = require('../models/Hospital');
const Visit = require('../../models/Visit');

/**
 * Get current month start/end dates
 */
function currentMonthRange() {
  const now = new Date();
  const start = new Date(now.getFullYear(), now.getMonth(), 1);
  const end = new Date(now.getFullYear(), now.getMonth() + 1, 1);
  return { start, end };
}

/**
 * Phase 9.2: Compute engagements from CRM Visit data
 * visited = unique CRM visit days in range, target = tagged hospital count
 */
async function computeEngagements(bdmId, start, end) {
  if (!bdmId) return { visited: 0, target: 0, rate: 0 };

  try {
    const bdmObjectId = typeof bdmId === 'string'
      ? new mongoose.Types.ObjectId(bdmId)
      : bdmId;

    // Count completed CRM visits in date range
    const visitCount = await Visit.countDocuments({
      user: bdmObjectId,
      visitDate: { $gte: start, $lt: end },
      status: 'completed'
    }).catch(() => 0);

    // Count accessible hospitals for this BDM (warehouse-driven + legacy tagged_bdms)
    const { buildHospitalAccessFilter } = require('../utils/hospitalAccess');
    const accessFilter = await buildHospitalAccessFilter({ _id: bdmObjectId, role: 'staff' });
    const hospitalCount = await Hospital.countDocuments({
      status: 'ACTIVE',
      ...accessFilter
    }).catch(() => 0);

    const target = hospitalCount || 0;
    const rate = target > 0 ? Math.round((visitCount / target) * 100) / 100 : 0;

    return { visited: visitCount, target, rate };
  } catch {
    return { visited: 0, target: 0, rate: 0 };
  }
}

/**
 * Get current year start/end dates
 */
function currentYearRange() {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 1);
  const end = new Date(now.getFullYear() + 1, 0, 1);
  return { start, end };
}

/**
 * Summary cards: Total Sales, AR, Stock Value, Engagements
 * PRD §13.5 Section 2
 */
async function getSummary(entityId, bdmId, isAdmin) {
  const filter = {};
  if (entityId) filter.entity_id = new mongoose.Types.ObjectId(entityId);
  if (bdmId && !isAdmin) filter.bdm_id = new mongoose.Types.ObjectId(bdmId);

  // 1. Total Sales (all POSTED)
  const salesAgg = await SalesLine.aggregate([
    { $match: { ...filter, status: 'POSTED' } },
    { $group: { _id: null, total: { $sum: '$invoice_total' } } }
  ]);
  const totalSales = salesAgg[0]?.total || 0;

  // 2. Total Collections (all POSTED)
  const collAgg = await Collection.aggregate([
    { $match: { ...filter, status: 'POSTED' } },
    { $group: { _id: null, total: { $sum: '$cr_amount' } } }
  ]);
  const totalCollections = collAgg[0]?.total || 0;

  // 3. AR = Sales - Collections
  const accountsReceivable = Math.round((totalSales - totalCollections) * 100) / 100;

  // 4. Stock on Hand Value (sum of available_qty × purchase_price per product)
  const stockAgg = await InventoryLedger.aggregate([
    { $match: filter },
    {
      $group: {
        _id: { product_id: '$product_id', batch_lot_no: '$batch_lot_no' },
        total_in: { $sum: '$qty_in' },
        total_out: { $sum: '$qty_out' }
      }
    },
    { $addFields: { available: { $subtract: ['$total_in', '$total_out'] } } },
    { $match: { available: { $gt: 0 } } },
    {
      $group: {
        _id: '$_id.product_id',
        total_qty: { $sum: '$available' }
      }
    },
    {
      $lookup: {
        from: 'erp_product_master',
        localField: '_id',
        foreignField: '_id',
        as: 'product'
      }
    },
    { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } },
    {
      $group: {
        _id: null,
        value: { $sum: { $multiply: ['$total_qty', { $ifNull: ['$product.purchase_price', 0] }] } }
      }
    }
  ]);
  const stockOnHandValue = Math.round((stockAgg[0]?.value || 0) * 100) / 100;

  // 5. Engagements — Phase 9.2: real CRM Visit counts
  const { start: mStart, end: mEnd } = currentMonthRange();
  const engagements = await computeEngagements(bdmId, mStart, mEnd);

  return {
    total_sales: Math.round(totalSales * 100) / 100,
    total_collections: Math.round(totalCollections * 100) / 100,
    accounts_receivable: accountsReceivable,
    stock_on_hand_value: stockOnHandValue,
    engagements
  };
}

/**
 * Month-to-Date metrics
 * PRD §13.5 Section 3
 */
async function getMtd(entityId, bdmId, isAdmin) {
  const { start, end } = currentMonthRange();
  const filter = {};
  if (entityId) filter.entity_id = new mongoose.Types.ObjectId(entityId);
  if (bdmId && !isAdmin) filter.bdm_id = new mongoose.Types.ObjectId(bdmId);

  // Sales MTD
  const salesAgg = await SalesLine.aggregate([
    { $match: { ...filter, status: 'POSTED', csi_date: { $gte: start, $lt: end } } },
    { $group: { _id: null, total: { $sum: '$invoice_total' } } }
  ]);
  const salesMtd = salesAgg[0]?.total || 0;

  // Collections MTD
  const collAgg = await Collection.aggregate([
    { $match: { ...filter, status: 'POSTED', cr_date: { $gte: start, $lt: end } } },
    { $group: { _id: null, total: { $sum: '$cr_amount' } } }
  ]);
  const collectionsMtd = collAgg[0]?.total || 0;

  // Income MTD (from IncomeReport if exists)
  const now = new Date();
  const currentPeriod = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  const incomeFilter = { period: currentPeriod };
  if (entityId) incomeFilter.entity_id = new mongoose.Types.ObjectId(entityId);
  if (bdmId && !isAdmin) incomeFilter.bdm_id = new mongoose.Types.ObjectId(bdmId);

  const incomeAgg = await IncomeReport.aggregate([
    { $match: incomeFilter },
    { $group: { _id: null, total: { $sum: '$net_pay' } } }
  ]);
  const incomeMtd = incomeAgg[0]?.total || 0;

  // Engagements MTD — Phase 9.2: real CRM Visit counts
  const engagementsMtd = await computeEngagements(bdmId, start, end);

  // KPIs: DSO, Collection Rate, Gross Margin
  // DSO = (AR / Sales MTD) × days elapsed in month
  const daysElapsed = Math.max(1, new Date().getDate());
  const arBalance = Math.max(0, salesMtd - collectionsMtd);
  const dso = salesMtd > 0 ? Math.round((arBalance / salesMtd) * daysElapsed) : 0;

  // Collection Rate = Collections / Sales (%)
  const collectionRate = salesMtd > 0 ? Math.round((collectionsMtd / salesMtd) * 10000) / 100 : 0;

  // Gross Margin = (Sales Net of VAT - COGS) / Sales Net of VAT (%)
  const salesNetAgg = await SalesLine.aggregate([
    { $match: { ...filter, status: 'POSTED', csi_date: { $gte: start, $lt: end } } },
    { $group: { _id: null, netSales: { $sum: '$total_net_of_vat' } } }
  ]);
  const netSalesMtd = salesNetAgg[0]?.netSales || 0;

  // COGS from POSTED sales line items × purchase_price
  const cogsAgg = await SalesLine.aggregate([
    { $match: { ...filter, status: 'POSTED', csi_date: { $gte: start, $lt: end }, sale_type: { $ne: 'SERVICE_INVOICE' } } },
    { $unwind: '$line_items' },
    {
      $lookup: {
        from: 'erp_product_master',
        localField: 'line_items.product_id',
        foreignField: '_id',
        as: 'product'
      }
    },
    { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } },
    {
      $group: {
        _id: null,
        total_cogs: { $sum: { $multiply: ['$line_items.qty', { $ifNull: ['$product.purchase_price', 0] }] } }
      }
    }
  ]);
  const cogsMtd = cogsAgg[0]?.total_cogs || 0;
  const grossMargin = netSalesMtd > 0 ? Math.round(((netSalesMtd - cogsMtd) / netSalesMtd) * 10000) / 100 : 0;

  return {
    sales_mtd: Math.round(salesMtd * 100) / 100,
    collections_mtd: Math.round(collectionsMtd * 100) / 100,
    engagements_mtd: engagementsMtd,
    income_mtd: Math.round(incomeMtd * 100) / 100,
    dso,
    collection_rate: collectionRate,
    gross_margin: grossMargin
  };
}

/**
 * Year-to-Date PNL
 * PRD §13.5 Section 4, Tab 4
 */
async function getPnlYtd(entityId, bdmId, isAdmin) {
  const { start, end } = currentYearRange();
  const filter = {};
  if (entityId) filter.entity_id = new mongoose.Types.ObjectId(entityId);
  if (bdmId && !isAdmin) filter.bdm_id = new mongoose.Types.ObjectId(bdmId);

  // Total Sales YTD (net of VAT for P&L)
  const salesAgg = await SalesLine.aggregate([
    { $match: { ...filter, status: 'POSTED', csi_date: { $gte: start, $lt: end } } },
    { $group: { _id: null, total: { $sum: '$total_net_of_vat' } } }
  ]);
  const totalSalesYtd = salesAgg[0]?.total || 0;

  // Total Expenses YTD (SMER + Car Logbook + ORE/ACCESS)
  const now = new Date();
  const yearStr = String(now.getFullYear());
  const periodFilter = { ...filter };

  // SMER
  const smerAgg = await SmerEntry.aggregate([
    { $match: { ...periodFilter, status: 'POSTED', period: { $regex: `^${yearStr}` } } },
    { $group: { _id: null, total: { $sum: '$total_reimbursable' } } }
  ]);
  const smerTotal = smerAgg[0]?.total || 0;

  // Car Logbook (official gas)
  const carAgg = await CarLogbookEntry.aggregate([
    { $match: { ...periodFilter, status: 'POSTED', period: { $regex: `^${yearStr}` } } },
    { $group: { _id: null, total: { $sum: '$official_gas_amount' } } }
  ]);
  const carTotal = carAgg[0]?.total || 0;

  // ORE + ACCESS
  const expAgg = await ExpenseEntry.aggregate([
    { $match: { ...periodFilter, status: 'POSTED', period: { $regex: `^${yearStr}` } } },
    { $group: { _id: null, total: { $sum: '$total_amount' } } }
  ]);
  const expTotal = expAgg[0]?.total || 0;

  // Partner rebates from Collections YTD
  const rebateAgg = await Collection.aggregate([
    { $match: { ...filter, status: 'POSTED', cr_date: { $gte: start, $lt: end } } },
    { $group: { _id: null, total: { $sum: '$total_partner_rebates' } } }
  ]);
  const rebateTotal = rebateAgg[0]?.total || 0;

  const totalExpensesYtd = smerTotal + carTotal + expTotal + rebateTotal;
  const netPnlYtd = totalSalesYtd - totalExpensesYtd;

  return {
    total_sales_ytd: Math.round(totalSalesYtd * 100) / 100,
    total_expenses_ytd: Math.round(totalExpensesYtd * 100) / 100,
    net_pnl_ytd: Math.round(netPnlYtd * 100) / 100
  };
}

/**
 * Product stock levels for bottom tab "Product Master"
 */
async function getProductStockLevels(entityId, bdmId, isAdmin) {
  const filter = {};
  if (entityId) filter.entity_id = new mongoose.Types.ObjectId(entityId);
  if (bdmId && !isAdmin) filter.bdm_id = new mongoose.Types.ObjectId(bdmId);

  const result = await InventoryLedger.aggregate([
    { $match: filter },
    {
      $group: {
        _id: '$product_id',
        total_in: { $sum: '$qty_in' },
        total_out: { $sum: '$qty_out' }
      }
    },
    { $addFields: { available: { $subtract: ['$total_in', '$total_out'] } } },
    { $match: { available: { $gt: 0 } } },
    {
      $lookup: {
        from: 'erp_product_master',
        localField: '_id',
        foreignField: '_id',
        as: 'product'
      }
    },
    { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } },
    {
      $project: {
        product_id: '$_id',
        brand_name: '$product.brand_name',
        dosage_strength: '$product.dosage_strength',
        sold_per: '$product.sold_per',
        selling_price: '$product.selling_price',
        purchase_price: '$product.purchase_price',
        available_qty: '$available',
        stock_value: { $multiply: ['$available', { $ifNull: ['$product.purchase_price', 0] }] }
      }
    },
    { $sort: { brand_name: 1 } }
  ]);

  return result;
}

module.exports = {
  getSummary,
  getMtd,
  getPnlYtd,
  getProductStockLevels,
  currentMonthRange,
  currentYearRange
};

/**
 * Deduction Schedule Service — CRUD + business logic for recurring/non-recurring deductions
 *
 * Contractors create schedules (PENDING_APPROVAL). Finance approves → ACTIVE.
 * Active schedule installments auto-inject into payslips via incomeCalc.js
 * (BDM owner) or payslipCalc.js (employee owner, Phase G1.4).
 *
 * Owner is XOR: createSchedule takes either `bdm_id` (contractor) or `person_id`
 * (employee). Validator in DeductionSchedule pre-save enforces the invariant.
 */
const mongoose = require('mongoose');
const DeductionSchedule = require('../models/DeductionSchedule');
const ApprovalRequest = require('../models/ApprovalRequest');
const { generateDocNumber } = require('./docNumbering');

// Phase G4.2 — close any open PENDING ApprovalRequest for a schedule when the
// decision is reached via the direct route (POST /:id/approve|reject|withdraw).
// The Approval Hub path closes the request in universalApprovalController via
// the catch-all at lines 705-734; keeping the close logic here too means both
// paths behave identically so `Approval History` never diverges from the
// `DeductionSchedule` source of truth.
//
// Idempotent: $set only fires when status is still PENDING, so a second call
// (e.g. Hub approve → catch-all → direct route) is a no-op.
async function closeApprovalRequest(docId, decisionStatus, userId, reason) {
  if (!docId) return;
  try {
    await ApprovalRequest.updateMany(
      { doc_id: docId, module: 'DEDUCTION_SCHEDULE', status: 'PENDING' },
      {
        $set: {
          status: decisionStatus,
          decided_by: userId,
          decided_at: new Date(),
          decision_reason: reason || `${decisionStatus.toLowerCase()} via deduction schedule route`,
        },
        $push: {
          history: {
            status: decisionStatus,
            by: userId,
            reason: reason || `${decisionStatus.toLowerCase()} via deduction schedule route`,
          },
        },
      }
    );
  } catch (err) {
    // Non-fatal: schedule state is already persisted. Log and continue — a stuck
    // ApprovalRequest can be repaired with the migration script below.
    console.error(`DeductionSchedule closeApprovalRequest failed (doc_id=${docId}):`, err.message);
  }
}

/**
 * Create a new deduction schedule with pre-generated installments.
 *
 * Owner is XOR: pass `{ bdm_id }` for contractors (schedule installments feed
 * IncomeReport.deduction_lines) or `{ person_id }` for employees (feed
 * Payslip.deduction_lines). Legacy callers that pass a plain `bdmId` string
 * as the second argument continue to work (back-compat for the BDM path).
 *
 * @param {String} entityId
 * @param {String|Object} ownerOrBdmId — legacy BDM id string, or
 *   `{ bdm_id }` / `{ person_id }` for explicit owner selection.
 * @param {Object} data — deduction fields
 * @param {String} userId — acting user
 * @param {Boolean} isFinance — when true, schedule activates immediately (bypasses the gate)
 */
async function createSchedule(entityId, ownerOrBdmId, data, userId, isFinance = false) {
  const { deduction_type, deduction_label, description, total_amount, term_months, start_period, target_cycle } = data;

  if (!deduction_type || !deduction_label || !total_amount || !term_months || !start_period) {
    throw new Error('deduction_type, deduction_label, total_amount, term_months, and start_period are required');
  }
  if (total_amount <= 0) throw new Error('total_amount must be positive');
  if (term_months < 1) throw new Error('term_months must be at least 1');

  // Resolve owner — string is legacy BDM id, object selects explicitly.
  let bdmId = null;
  let personId = null;
  if (ownerOrBdmId && typeof ownerOrBdmId === 'object') {
    bdmId = ownerOrBdmId.bdm_id || null;
    personId = ownerOrBdmId.person_id || null;
  } else {
    bdmId = ownerOrBdmId || null;
  }
  if (!!bdmId === !!personId) {
    throw new Error('createSchedule requires exactly one owner: bdm_id (contractor) OR person_id (employee)');
  }

  // Doc numbering: BDM schedules use territory code (existing behaviour).
  // Employee schedules have no BDM/territory, so fall back to entity short_name
  // (Rule #19 — subscription-ready, no territory required).
  const schedule_code = await generateDocNumber({
    prefix: 'DS',
    bdmId: bdmId || undefined,
    entityId: bdmId ? undefined : entityId,
    date: new Date()
  });

  const schedule = await DeductionSchedule.create({
    entity_id: entityId,
    bdm_id: bdmId || undefined,
    person_id: personId || undefined,
    schedule_code,
    deduction_type,
    deduction_label,
    description: description || '',
    total_amount,
    term_months,
    start_period,
    target_cycle: target_cycle || 'C2',
    status: isFinance ? 'ACTIVE' : 'PENDING_APPROVAL',
    approved_by: isFinance ? userId : undefined,
    approved_at: isFinance ? new Date() : undefined,
    created_by: userId
  });

  return schedule;
}

/**
 * Approve a PENDING_APPROVAL schedule → ACTIVE
 */
async function approveSchedule(scheduleId, userId) {
  const schedule = await DeductionSchedule.findById(scheduleId);
  if (!schedule) throw new Error('Schedule not found');
  if (schedule.status !== 'PENDING_APPROVAL') {
    throw new Error(`Cannot approve schedule in ${schedule.status} status`);
  }

  schedule.status = 'ACTIVE';
  schedule.approved_by = userId;
  schedule.approved_at = new Date();
  await schedule.save();

  // Phase G4.2 — close the audit loop so Approval History mirrors the decision.
  await closeApprovalRequest(schedule._id, 'APPROVED', userId);

  return schedule;
}

/**
 * Reject a PENDING_APPROVAL schedule
 */
async function rejectSchedule(scheduleId, userId, reason) {
  const schedule = await DeductionSchedule.findById(scheduleId);
  if (!schedule) throw new Error('Schedule not found');
  if (schedule.status !== 'PENDING_APPROVAL') {
    throw new Error(`Cannot reject schedule in ${schedule.status} status`);
  }

  schedule.status = 'REJECTED';
  schedule.reject_reason = reason || '';
  await schedule.save();

  // Phase G4.2 — close the audit loop with the provided rejection reason so the
  // Approval History row carries the same `decision_reason` surfaced on the schedule.
  await closeApprovalRequest(schedule._id, 'REJECTED', userId, reason);

  return schedule;
}

/**
 * Cancel an ACTIVE schedule — marks all PENDING installments as CANCELLED
 */
async function cancelSchedule(scheduleId, userId, reason) {
  const schedule = await DeductionSchedule.findById(scheduleId);
  if (!schedule) throw new Error('Schedule not found');
  if (schedule.status !== 'ACTIVE') {
    throw new Error(`Cannot cancel schedule in ${schedule.status} status`);
  }

  for (const inst of schedule.installments) {
    if (inst.status === 'PENDING') {
      inst.status = 'CANCELLED';
      inst.note = reason || 'Schedule cancelled';
    }
  }

  schedule.status = 'CANCELLED';
  await schedule.save();
  return schedule;
}

/**
 * Early payoff — cancel remaining PENDING installments, create lump-sum for remaining balance
 */
async function earlyPayoff(scheduleId, payoffPeriod, userId) {
  const schedule = await DeductionSchedule.findById(scheduleId);
  if (!schedule) throw new Error('Schedule not found');
  if (schedule.status !== 'ACTIVE') {
    throw new Error(`Cannot early payoff schedule in ${schedule.status} status`);
  }

  const pendingInstallments = schedule.installments.filter(i => i.status === 'PENDING');
  if (pendingInstallments.length === 0) {
    throw new Error('No pending installments to pay off');
  }

  // Cancel all remaining PENDING installments
  const lumpSum = pendingInstallments.reduce((sum, i) => sum + i.amount, 0);
  for (const inst of pendingInstallments) {
    inst.status = 'CANCELLED';
    inst.note = `Replaced by early payoff in ${payoffPeriod}`;
  }

  // Add lump-sum installment
  const maxNo = Math.max(...schedule.installments.map(i => i.installment_no));
  schedule.installments.push({
    period: payoffPeriod,
    installment_no: maxNo + 1,
    amount: Math.round(lumpSum * 100) / 100,
    status: 'PENDING',
    note: `Early payoff (${pendingInstallments.length} installments consolidated)`
  });

  await schedule.save();
  return schedule;
}

/**
 * Finance adjusts a single installment amount
 */
async function adjustInstallment(scheduleId, installmentId, newAmount, userId, note) {
  const schedule = await DeductionSchedule.findById(scheduleId);
  if (!schedule) throw new Error('Schedule not found');

  const inst = schedule.installments.id(installmentId);
  if (!inst) throw new Error('Installment not found');
  if (!['PENDING', 'INJECTED'].includes(inst.status)) {
    throw new Error(`Cannot adjust installment in ${inst.status} status`);
  }

  inst.amount = Math.round(newAmount * 100) / 100;
  inst.note = note || `Adjusted by Finance to ₱${inst.amount}`;
  inst.verified_by = userId;
  inst.verified_at = new Date();

  await schedule.save();
  return schedule;
}

/**
 * Sync installment status from payslip verification back to schedule.
 * Called by incomeController when Finance verifies/rejects a SCHEDULE deduction line.
 *
 * Contractor path — updates `income_report_id` on the installment.
 */
async function syncInstallmentStatus(scheduleId, installmentId, newStatus, incomeReportId, deductionLineId) {
  const schedule = await DeductionSchedule.findById(scheduleId);
  if (!schedule) return;

  const inst = schedule.installments.id(installmentId);
  if (!inst) return;

  inst.status = newStatus;
  if (incomeReportId) inst.income_report_id = incomeReportId;
  if (deductionLineId) inst.deduction_line_id = deductionLineId;

  await schedule.save();
}

/**
 * Phase G1.4 — employee counterpart of syncInstallmentStatus. Called by
 * payrollController (Finance verify/reject of a SCHEDULE line on a Payslip)
 * and by payslipCalc (post-save to mark freshly injected installments as
 * INJECTED). Updates `payslip_id` on the installment instead of
 * `income_report_id` so the schedule carries a clean audit trail of which
 * payslip each installment landed in.
 */
async function syncInstallmentStatusForPayslip(scheduleId, installmentId, newStatus, payslipId, deductionLineId) {
  const schedule = await DeductionSchedule.findById(scheduleId);
  if (!schedule) return;

  const inst = schedule.installments.id(installmentId);
  if (!inst) return;

  inst.status = newStatus;
  if (payslipId) inst.payslip_id = payslipId;
  if (deductionLineId) inst.deduction_line_id = deductionLineId;

  await schedule.save();
}

/**
 * BDM withdraws a PENDING_APPROVAL schedule (self-service cancel before Finance acts)
 */
async function withdrawSchedule(scheduleId, bdmId, entityId) {
  const schedule = await DeductionSchedule.findOne({ _id: scheduleId, entity_id: entityId });
  if (!schedule) throw new Error('Schedule not found');
  // Phase G1.4 — route is contractor-only, so an employee-owner schedule (no
  // bdm_id) should never match. Guard defensively in case the route gate is
  // ever loosened: ownership check becomes "no bdm_id or wrong bdm_id → reject".
  if (!schedule.bdm_id || schedule.bdm_id.toString() !== bdmId.toString()) {
    throw new Error('You can only withdraw your own schedules');
  }
  if (schedule.status !== 'PENDING_APPROVAL') {
    throw new Error(`Cannot withdraw schedule in ${schedule.status} status`);
  }

  for (const inst of schedule.installments) {
    if (inst.status === 'PENDING') {
      inst.status = 'CANCELLED';
      inst.note = 'Withdrawn by BDM';
    }
  }

  schedule.status = 'CANCELLED';
  schedule.edit_history.push({
    action: 'WITHDRAWN',
    by: bdmId,
    at: new Date()
  });
  await schedule.save();

  // Phase G4.2 — BDM voluntarily pulled the request; close the ApprovalRequest as
  // CANCELLED so approvers no longer see it and the history row reflects the BDM's
  // action rather than an approver decision.
  await closeApprovalRequest(schedule._id, 'CANCELLED', bdmId, 'Withdrawn by BDM');

  return schedule;
}

/**
 * BDM edits a PENDING_APPROVAL schedule (modify before Finance reviews)
 */
async function editPendingSchedule(scheduleId, bdmId, entityId, updates) {
  const schedule = await DeductionSchedule.findOne({ _id: scheduleId, entity_id: entityId });
  if (!schedule) throw new Error('Schedule not found');
  // Phase G1.4 — same defensive null-check as withdrawSchedule. Employee
  // schedules (no bdm_id) cannot reach this path via the current contractor-
  // gated route, but the guard makes the service layer safe if the gate is
  // ever opened (e.g. for an employee self-service edit future story).
  if (!schedule.bdm_id || schedule.bdm_id.toString() !== bdmId.toString()) {
    throw new Error('You can only edit your own schedules');
  }
  if (schedule.status !== 'PENDING_APPROVAL') {
    throw new Error(`Cannot edit schedule in ${schedule.status} status`);
  }

  const { deduction_type, deduction_label, description, total_amount, term_months, start_period, target_cycle } = updates;

  // Snapshot old values for audit trail
  schedule.edit_history.push({
    action: 'EDITED',
    by: bdmId,
    at: new Date(),
    previous: {
      deduction_type: schedule.deduction_type,
      deduction_label: schedule.deduction_label,
      description: schedule.description,
      total_amount: schedule.total_amount,
      term_months: schedule.term_months,
      start_period: schedule.start_period,
      target_cycle: schedule.target_cycle
    }
  });

  // Apply updates
  if (deduction_type) schedule.deduction_type = deduction_type;
  if (deduction_label) schedule.deduction_label = deduction_label;
  if (description !== undefined) schedule.description = description;
  if (total_amount && total_amount > 0) schedule.total_amount = total_amount;
  if (term_months && term_months >= 1) schedule.term_months = term_months;
  if (start_period) schedule.start_period = start_period;
  if (target_cycle) schedule.target_cycle = target_cycle;

  // Regenerate installments (pre-save hook only runs on isNew)
  const { incrementPeriod } = require('../models/DeductionSchedule');
  const baseAmount = Math.floor(schedule.total_amount / schedule.term_months * 100) / 100;
  const lastAmount = Math.round((schedule.total_amount - baseAmount * (schedule.term_months - 1)) * 100) / 100;

  schedule.installment_amount = baseAmount;
  schedule.installments = [];
  for (let i = 0; i < schedule.term_months; i++) {
    schedule.installments.push({
      period: incrementPeriod(schedule.start_period, i),
      installment_no: i + 1,
      amount: i === schedule.term_months - 1 ? lastAmount : baseAmount,
      status: 'PENDING'
    });
  }
  schedule.remaining_balance = schedule.total_amount;

  await schedule.save();

  // Phase G4.2 — BDM edited total_amount / label / term, so the PENDING
  // ApprovalRequest's `amount` and `description` must be refreshed. Otherwise
  // the Approval Hub and the eventual Approval History row show stale values.
  try {
    await ApprovalRequest.updateMany(
      { doc_id: schedule._id, module: 'DEDUCTION_SCHEDULE', status: 'PENDING' },
      {
        $set: {
          amount: schedule.total_amount,
          doc_type: schedule.term_months === 1 ? 'ONE_TIME' : 'INSTALLMENT',
          description: `${schedule.deduction_label}${schedule.term_months > 1 ? ` · ₱${schedule.installment_amount}/mo × ${schedule.term_months}` : ''} · ${schedule.target_cycle}`,
        },
      }
    );
  } catch (err) {
    console.error(`DeductionSchedule editPending approvalRequest sync failed (doc_id=${schedule._id}):`, err.message);
  }

  return schedule;
}

module.exports = {
  createSchedule,
  approveSchedule,
  rejectSchedule,
  cancelSchedule,
  earlyPayoff,
  adjustInstallment,
  syncInstallmentStatus,
  // Phase G1.4 — employee-owner counterpart (Payslip-linked installments)
  syncInstallmentStatusForPayslip,
  withdrawSchedule,
  editPendingSchedule
};

/**
 * Dependent-Document Checker — Pre-flight blocker for SAP Storno reversals.
 *
 * Before reversing an upstream document (e.g., GRN, IC Transfer Receive,
 * Income Report), we must verify no downstream POSTED document depends on it.
 * Reversing an upstream doc whose stock/funds have already been consumed by a
 * downstream doc would orphan the downstream and corrupt the ledger.
 *
 * Each handler returns `{ has_deps, dependents: [{ type, ref, doc_id, message }] }`.
 * Caller (documentReversalService) blocks reversal when `has_deps` is true and
 * surfaces the dependents list to the user so they reverse downstream first.
 *
 * Subscription/scalability: register new doc types in CHECKERS map. Lookups can
 * be added without code changes because each checker queries Mongoose models —
 * no hardcoded business values are inspected here.
 */

const SalesLine = require('../models/SalesLine');
const InventoryLedger = require('../models/InventoryLedger');
const ConsignmentTracker = require('../models/ConsignmentTracker');
const InterCompanyTransfer = require('../models/InterCompanyTransfer');
const PrfCalf = require('../models/PrfCalf');
const ExpenseEntry = require('../models/ExpenseEntry');
const IncomeReport = require('../models/IncomeReport');
const Payslip = require('../models/Payslip');
const Collection = require('../models/Collection');
const PurchaseOrder = require('../models/PurchaseOrder');
// Phase 31R — AP payment blocker for Supplier Invoice reversal
const ApPayment = require('../models/ApPayment');
// Phase G4.3 — Sales Goal plan reversal guards
const IncentivePayout = require('../models/IncentivePayout');
const PettyCashTransaction = require('../models/PettyCashTransaction');
const SmerEntry = require('../models/SmerEntry');
const CarLogbookEntry = require('../models/CarLogbookEntry');
const CarLogbookCycle = require('../models/CarLogbookCycle');
const OfficeSupplyTransaction = require('../models/OfficeSupplyTransaction');

/**
 * GRN dependent check — block reversal if any batch from this GRN has been
 * consumed by a downstream POSTED SalesLine, IC Transfer, or expense ORE.
 *
 * The link is established through `InventoryLedger`: the GRN creates qty_in
 * entries with (batch_lot_no, product_id). Downstream consumers create qty_out
 * entries against the same batch. We look for qty_out entries whose `event_id`
 * resolves to a POSTED non-reversed downstream doc.
 */
async function checkGrnDependents({ doc, tenantFilter }) {
  const dependents = [];

  // Step 1 — collect (product_id, batch_lot_no) tuples this GRN brought in
  const batchKeys = (doc.line_items || []).map(li => ({
    product_id: li.product_id,
    batch_lot_no: li.batch_lot_no,
  }));
  if (!batchKeys.length) return { has_deps: false, dependents };

  // Step 2 — find all qty_out InventoryLedger entries against those batches in
  // the same entity. (Cross-entity batches don't share — IC Transfer creates
  // its own ledger entries on receive.)
  const ledgerOuts = await InventoryLedger.find({
    entity_id: doc.entity_id,
    qty_out: { $gt: 0 },
    $or: batchKeys,
  }).select('event_id batch_lot_no product_id qty_out').lean();
  if (!ledgerOuts.length) return { has_deps: false, dependents };

  // Step 3 — group by event_id; resolve each to a known posting doc and check
  // whether it's still POSTED (not reversed).
  const eventIds = [...new Set(ledgerOuts.map(l => String(l.event_id)).filter(Boolean))];
  if (!eventIds.length) return { has_deps: false, dependents };

  // Sales consumers
  const sales = await SalesLine.find({
    event_id: { $in: eventIds },
    deletion_event_id: { $exists: false },
    status: 'POSTED',
  }).select('_id doc_ref invoice_number sale_type').lean();
  for (const s of sales) {
    dependents.push({
      type: 'SALES_LINE',
      ref: s.doc_ref || s.invoice_number || String(s._id),
      doc_id: s._id,
      message: `Sales ${s.sale_type || 'CSI'} ${s.doc_ref || s.invoice_number} consumed batch from this GRN`,
    });
  }

  // IC Transfer consumers (source-side OUT events)
  const icts = await InterCompanyTransfer.find({
    source_event_id: { $in: eventIds },
    deletion_event_id: { $exists: false },
    status: { $in: ['SHIPPED', 'RECEIVED', 'POSTED'] },
  }).select('_id transfer_ref status').lean();
  for (const ic of icts) {
    dependents.push({
      type: 'IC_TRANSFER',
      ref: ic.transfer_ref,
      doc_id: ic._id,
      message: `IC Transfer ${ic.transfer_ref} (${ic.status}) shipped batch from this GRN`,
    });
  }

  return { has_deps: dependents.length > 0, dependents };
}

/**
 * IC Transfer dependent check — when reversing a TRANSFER_OUT/RECEIVE, block
 * if the TRANSFER_IN inventory at the target entity has been consumed.
 */
async function checkIcTransferDependents({ doc /* , tenantFilter */ }) {
  const dependents = [];
  if (!doc.target_event_id) return { has_deps: false, dependents }; // never received

  // Any qty_out against the target_event_id's lot inventory?
  // Resolve target inventory lots created by this IC.
  const targetLedger = await InventoryLedger.find({
    event_id: doc.target_event_id,
    qty_in: { $gt: 0 },
  }).select('product_id batch_lot_no').lean();
  if (!targetLedger.length) return { has_deps: false, dependents };

  const batchKeys = targetLedger.map(l => ({
    product_id: l.product_id,
    batch_lot_no: l.batch_lot_no,
  }));

  const consumers = await InventoryLedger.find({
    entity_id: doc.target_entity_id,
    qty_out: { $gt: 0 },
    $or: batchKeys,
  }).select('event_id').lean();
  if (!consumers.length) return { has_deps: false, dependents };

  const eventIds = [...new Set(consumers.map(c => String(c.event_id)).filter(Boolean))];
  const sales = await SalesLine.find({
    entity_id: doc.target_entity_id,
    event_id: { $in: eventIds },
    deletion_event_id: { $exists: false },
    status: 'POSTED',
  }).select('_id doc_ref invoice_number').lean();
  for (const s of sales) {
    dependents.push({
      type: 'SALES_LINE',
      ref: s.doc_ref || s.invoice_number,
      doc_id: s._id,
      message: `Target-entity Sales ${s.doc_ref || s.invoice_number} consumed batch transferred in by this ICT`,
    });
  }

  return { has_deps: dependents.length > 0, dependents };
}

/**
 * DR / Consignment dependent check — block if any conversion has been recorded
 * (i.e., the hospital consumed any of the consigned stock).
 */
async function checkConsignmentDependents({ doc /* , tenantFilter */ }) {
  const dependents = [];
  // The "doc" here is a ConsignmentTracker row.
  if ((doc.qty_consumed || 0) > 0 || (doc.conversions && doc.conversions.length)) {
    dependents.push({
      type: 'CONSIGNMENT_CONVERSION',
      ref: String(doc._id),
      doc_id: doc._id,
      message: `Consignment has ${doc.conversions?.length || 0} conversion(s) totalling ${doc.qty_consumed} units. Reverse the converting CSIs first.`,
    });
  }
  return { has_deps: dependents.length > 0, dependents };
}

/**
 * CALF dependent check — block if any linked ExpenseEntry is POSTED and uses
 * this CALF as funding (i.e., calf_required satisfied by this CALF).
 */
async function checkCalfDependents({ doc /* , tenantFilter */ }) {
  const dependents = [];
  // ExpenseEntry uses `calf_id` (1:M back-reference). PrfCalf.linked_expense_id
  // is the forward 1:1 reference (set when CALF was created from a single expense).
  const linked = await ExpenseEntry.find({
    entity_id: doc.entity_id,
    $or: [
      { calf_id: doc._id },
      ...(doc.linked_expense_id ? [{ _id: doc.linked_expense_id }] : []),
    ],
    status: 'POSTED',
  }).select('_id period status').lean();
  for (const e of linked) {
    dependents.push({
      type: 'EXPENSE',
      ref: String(e._id),
      doc_id: e._id,
      message: `Expense ${e._id} (${e.period || ''}) is POSTED and funded by this CALF — reverse the expense first.`,
    });
  }

  // Also block if an IncomeReport already deducted this CALF balance.
  const incomeRefs = await IncomeReport.find({
    entity_id: doc.entity_id,
    bdm_id: doc.bdm_id,
    'deduction_lines.auto_source': 'CALF',
    status: { $in: ['BDM_CONFIRMED', 'CREDITED'] },
    deletion_event_id: { $exists: false },
  }).select('_id period status').lean();
  for (const ir of incomeRefs) {
    dependents.push({
      type: 'INCOME_REPORT',
      ref: `${ir.period}/${ir.status}`,
      doc_id: ir._id,
      message: `IncomeReport ${ir.period} (${ir.status}) auto-deducted CASH_ADVANCE from this CALF — reverse the income first.`,
    });
  }

  return { has_deps: dependents.length > 0, dependents };
}

