      });
    });
  }

  if (wantedTypes.includes('IC_TRANSFER')) {
    const q = {
      ...notReversed,
      status: { $in: ['SHIPPED', 'RECEIVED', 'POSTED'] },
      ...(entityId ? { $or: [{ source_entity_id: entityId }, { target_entity_id: entityId }] } : {}),
