  }

  if (wantedTypes.includes('SUPPLIER_INVOICE')) {
    const q = { ...baseEntity, ...notReversed, status: 'POSTED' };
    if (dateFilter) q.invoice_date = dateFilter;
    const { rows, cnt } = await fetchAndCount(SupplierInvoice, q, '_id invoice_ref invoice_date entity_id status total_amount vendor_name', 'invoice_date');
    totalCount += cnt;
    rows.forEach(r => out.push({ doc_type: 'SUPPLIER_INVOICE', doc_id: r._id, doc_ref: r.invoice_ref, entity_id: r.entity_id, posted_at: r.invoice_date, status: r.status, label: REVERSAL_HANDLERS.SUPPLIER_INVOICE.label, sub: `${r.vendor_name || ''} ₱${r.total_amount || 0}`.trim() }));
  }

  if (wantedTypes.includes('CREDIT_NOTE')) {
    const q = { ...baseEntity, ...notReversed, status: 'POSTED' };
    if (dateFilter) q.posted_at = dateFilter;
    const { rows, cnt } = await fetchAndCount(CreditNote, q, '_id cn_number cn_date entity_id bdm_id posted_at status credit_total', 'posted_at');
    totalCount += cnt;
    rows.forEach(r => out.push({ doc_type: 'CREDIT_NOTE', doc_id: r._id, doc_ref: r.cn_number || String(r._id), entity_id: r.entity_id, bdm_id: r.bdm_id, posted_at: r.posted_at, status: r.status, label: REVERSAL_HANDLERS.CREDIT_NOTE.label, sub: `₱${r.credit_total || 0}` }));
  }

  if (wantedTypes.includes('IC_SETTLEMENT')) {
    // IC Settlement has creditor_entity_id, not entity_id. Scope by either side.
    const q = {
      ...notReversed,
      status: 'POSTED',
      ...(entityId ? { $or: [{ creditor_entity_id: entityId }, { debtor_entity_id: entityId }] } : {}),
    };
    if (dateFilter) q.posted_at = dateFilter;
    const { rows, cnt } = await fetchAndCount(IcSettlement, q, '_id cr_no cr_date creditor_entity_id debtor_entity_id posted_at status cr_amount', 'posted_at');
    totalCount += cnt;
    rows.forEach(r => out.push({ doc_type: 'IC_SETTLEMENT', doc_id: r._id, doc_ref: r.cr_no, entity_id: r.creditor_entity_id, posted_at: r.posted_at, status: r.status, label: REVERSAL_HANDLERS.IC_SETTLEMENT.label, sub: `₱${r.cr_amount || 0}` }));
  }

  // ─── Phase 31R-OS ───
  if (wantedTypes.includes('OFFICE_SUPPLY_ITEM')) {
    const q = { ...baseEntity, ...notReversed };
    if (dateFilter) q.createdAt = dateFilter;
    const { rows, cnt } = await fetchAndCount(OfficeSupply, q, '_id item_name item_code category entity_id createdAt qty_on_hand', 'createdAt');
    totalCount += cnt;
    rows.forEach(r => out.push({ doc_type: 'OFFICE_SUPPLY_ITEM', doc_id: r._id, doc_ref: r.item_code || r.item_name, entity_id: r.entity_id, posted_at: r.createdAt, status: 'ACTIVE', label: REVERSAL_HANDLERS.OFFICE_SUPPLY_ITEM.label, sub: `${r.category || ''} · qty ${r.qty_on_hand || 0}`.trim() }));
  }

  if (wantedTypes.includes('OFFICE_SUPPLY_TXN')) {
    const q = { ...baseEntity, ...notReversed, reversal_event_id: { $exists: false } };
    if (dateFilter) q.txn_date = dateFilter;
    const { rows, cnt } = await fetchAndCount(OfficeSupplyTransaction, q, '_id supply_id txn_type qty txn_date entity_id total_cost', 'txn_date');
    totalCount += cnt;
    rows.forEach(r => out.push({ doc_type: 'OFFICE_SUPPLY_TXN', doc_id: r._id, doc_ref: `${r.txn_type} ${r.qty}`, entity_id: r.entity_id, posted_at: r.txn_date, status: 'POSTED', label: REVERSAL_HANDLERS.OFFICE_SUPPLY_TXN.label, sub: r.total_cost ? `₱${r.total_cost}` : '' }));
  }

  out.sort((a, b) => new Date(b.posted_at || 0) - new Date(a.posted_at || 0));
  const start = (page - 1) * limit;
  return { data: out.slice(start, start + limit), total: totalCount, page, limit };
}

/**
 * Reversal history — reads ErpAuditLog where log_type='PRESIDENT_REVERSAL'.
 */
async function listReversalHistory({ entityId, doc_type, fromDate, toDate, page = 1, limit = 50 }) {
  const q = { log_type: 'PRESIDENT_REVERSAL' };
  if (entityId) q.entity_id = entityId;
  if (doc_type) q.target_model = doc_type;
  if (fromDate || toDate) {
    // ErpAuditLog uses `changed_at` (not `created_at`) — see models/ErpAuditLog.js
    q.changed_at = {};
    if (fromDate) q.changed_at.$gte = new Date(fromDate);
    if (toDate)   q.changed_at.$lte = new Date(toDate);
  }
  const skip = (page - 1) * limit;
  const [data, total] = await Promise.all([
    ErpAuditLog.find(q).populate('changed_by', 'name email role').sort({ changed_at: -1 }).skip(skip).limit(limit).lean(),
    ErpAuditLog.countDocuments(q),
  ]);
  return { data, total, page, limit };
}

/**
 * Preview the dependent-doc check for any registered doc type — so the UI can
 * show "this is blocked by X, Y, Z" before the user clicks Reverse.
 */
async function previewDependents({ doc_type, doc_id, tenantFilter }) {
  const handler = REVERSAL_HANDLERS[doc_type];
  if (!handler) { const err = new Error(`Unknown doc_type='${doc_type}'`); err.statusCode = 400; throw err; }
  const doc = await handler.load({ doc_id, tenantFilter });
  const { has_deps, dependents } = await checkHardBlockers({ doc_type, doc, tenantFilter });
  return {
    doc_type, doc_id, doc_ref: doc.doc_ref || doc.cr_no || doc.calf_number || doc.prf_number || doc.transfer_ref || String(doc._id),
    has_deps, dependents,
  };
}

/**
 * Factory: returns an Express handler for `POST /:id/president-reverse` that
 * delegates to `presidentReverse()` for a specific doc_type. Avoids copy-pasting
 * the same wrapper across every controller.
 *
 * Each controller does:
 *   const presidentReverseGrn = buildPresidentReverseHandler('GRN');
 *   module.exports = { ..., presidentReverseGrn };
 */
function buildPresidentReverseHandler(docType) {
  return async function presidentReverseHandler(req, res) {
    const { reason, confirm } = req.body || {};
    if (confirm !== 'DELETE') {
      return res.status(400).json({ success: false, message: 'Type DELETE in the confirmation field to proceed' });
    }
    if (!reason || !String(reason).trim()) {
      return res.status(400).json({ success: false, message: 'Reason is required' });
    }
    try {
      const result = await presidentReverse({
        doc_type: docType,
        doc_id: req.params.id,
        reason,
        user: req.user,
        tenantFilter: req.tenantFilter || {},
      });
      res.json({
        success: true,
        message: result.mode === 'HARD_DELETE'
          ? `Deleted ${result.doc_ref || result.doc_id} (no posting side effects)`
          : `Reversed ${result.doc_ref || result.doc_id} (${result.mode}) — original retained for audit`,
        data: result,
      });
    } catch (err) {
      return res.status(err.statusCode || 500).json({
        success: false,
        message: err.message,
        dependents: err.dependents || undefined,
      });
    }
  };
}

module.exports = {
  presidentReverse,
  listReversibleDocs,
  listReversalHistory,
  previewDependents,
  buildPresidentReverseHandler,
  REVERSAL_HANDLERS,
};

/**
 * ERP Notification Service
 *
 * Sends email notifications on document status changes (posted, reopened, approval).
 * All sends are non-blocking (fire-and-forget) — notification failure never breaks
 * business logic.
 *
 * Notification recipients are resolved dynamically from:
 *   - User model (role + entity_id + erp_access)
 *   - NotificationPreference model (user-level opt-in/out)
 *   - Settings.ENFORCE_AUTHORITY_MATRIX (controls whether approval notifications fire)
 *
 * No hardcoded recipient lists — all resolved from database at send time.
 */

const { ROLE_SETS } = require('../../constants/roles');
const User = require('../../models/User');
const Entity = require('../models/Entity');
const Settings = require('../models/Settings');
const Lookup = require('../models/Lookup');
const EmailLog = require('../../models/EmailLog');
const MessageInbox = require('../../models/MessageInbox');
const { sendEmail } = require('../../config/ses');
const { getParentEntityIds } = require('../utils/parentEntityResolver');
const {
  documentPostedTemplate,
  documentReopenedTemplate,
  approvalRequestTemplate,
  approvalDecisionTemplate,
  payrollPostedTemplate,
  // Phase SG-Q2 W3
  salesGoalPlanLifecycleTemplate,
  tierReachedTemplate,
  kpiVarianceAlertTemplate,
  // Phase SG-4 #23 ext
  compensationStatementReadyTemplate,
} = require('../../templates/erpEmails');

// ─── Helpers ────────────────────────────────────────────────────────

/**
 * Resolve entity name for email context.
 * Cached per request to avoid repeated DB calls.
 */
const entityNameCache = new Map();
const ENTITY_CACHE_TTL = 5 * 60 * 1000; // 5 minutes

const resolveEntityName = async (entityId) => {
  if (!entityId) return 'N/A';
  const key = entityId.toString();
  const cached = entityNameCache.get(key);
  if (cached && Date.now() < cached.expiry) return cached.name;

  try {
    const entity = await Entity.findById(entityId).select('name short_name').lean();
    const name = entity?.short_name || entity?.name || 'Unknown Entity';
    entityNameCache.set(key, { name, expiry: Date.now() + ENTITY_CACHE_TTL });
    return name;
  } catch {
    return 'Unknown Entity';
  }
};

/**
 * Find users who should receive notifications for a given entity and role filter.
 * Respects: isActive, entity scope, and email existence.
 *
 * @param {ObjectId} entityId
 * @param {Object} filter - additional query filters (e.g., { role: { $in: ['admin', 'finance'] } })
 * @returns {Promise<Array<{_id, email, name}>>}
 */
const findNotificationRecipients = async (entityId, filter = {}) => {
  try {
    const query = {
      isActive: true,
      email: { $exists: true, $ne: '' },
      ...filter,
    };

    // Multi-entity users: check entity_ids array; single-entity: check entity_id.
    // Cross-entity superusers = PARENT-entity presidents/CEOs only. Subsidiary
    // presidents (e.g. BLW's Angeline) receive their own entity's notifications
    // only, via the entity_id/entity_ids clauses above.
    if (entityId) {
      const parentEntityIds = await getParentEntityIds();
      query.$or = [
        { entity_id: entityId },
        { entity_ids: entityId },
        { role: { $in: ROLE_SETS.PRESIDENT_ROLES }, entity_id: { $in: parentEntityIds } },
      ];
    }

    // `phone` is included so multi-channel SMS dispatch can use it (Phase
    // SG-Q2 W3 follow-ups). Callers that don't need SMS simply ignore it.
    return await User.find(query).select('_id email name role phone').lean();
  } catch (err) {
    console.error('Failed to find notification recipients:', err.message);
    return [];
  }
};

/**
 * Find management users for a given entity (the typical "notify management" audience).
 * Reads NOTIFICATION_RECIPIENT_ROLES from Settings — configurable by admin.
 */
const findManagementRecipients = async (entityId) => {
  let roles;
  try {
    const settings = await Settings.getSettings();
    roles = settings.NOTIFICATION_RECIPIENT_ROLES;
  } catch {
    // fallback if settings unavailable
  }
  if (!roles || !roles.length) roles = ROLE_SETS.MANAGEMENT;

  return findNotificationRecipients(entityId, {
    role: { $in: roles },
  });
};

/**
 * Find the user who owns a document (by userId).
 */
const findDocumentOwner = async (userId) => {
  if (!userId) return null;
  try {
    return await User.findById(userId).select('_id email name role').lean();
  } catch {
    return null;
  }
};

/**
 * Log email send attempt (matches existing EmailLog schema).
 */
const logEmail = async (recipient, recipientUserId, emailType, subject, status, messageId, errorMessage) => {
  try {
    await EmailLog.create({
      recipient,
      recipientUserId,
      emailType,
      subject,
      status,
      sesMessageId: messageId,
      errorMessage,
    });
  } catch (err) {
    console.error('Failed to log ERP email:', err.message);
  }
};

/**
 * Send email to a list of recipients (non-blocking, catches all errors).
 */
const sendToRecipients = async (recipients, templateFn, templateData, emailType) => {
  for (const recipient of recipients) {
    try {
      const data = { ...templateData, recipientName: recipient.name || 'User' };
      const { subject, html, text } = templateFn(data);
      const { messageId } = await sendEmail({ to: recipient.email, subject, html, text });
      await logEmail(recipient.email, recipient._id, emailType, subject, 'sent', messageId);
    } catch (err) {
      console.error(`ERP notification failed for ${recipient.email}:`, err.message);
      const subject = `VIP ERP - ${emailType}`;
      await logEmail(recipient.email, recipient._id, emailType, subject, 'failed', null, err.message);
    }
  }
};

// ─── Public API ─────────────────────────────────────────────────────

/**
 * Notify management when a document is posted.
 * Non-blocking — call without await in controllers.
 *
 * @param {Object} opts
 * @param {ObjectId} opts.entityId
 * @param {string} opts.module - 'Sales', 'Collections', 'Expenses', 'Purchasing'
 * @param {string} opts.docType - 'CSI', 'CR', 'SMER', 'ORE/ACCESS', etc.
 * @param {string} opts.docRef - document reference
 * @param {string} opts.postedBy - name of poster
 * @param {number} [opts.amount] - total amount
 * @param {string} [opts.period] - YYYY-MM
 */
const notifyDocumentPosted = async (opts) => {
  try {
    const entityName = await resolveEntityName(opts.entityId);
    const recipients = await findManagementRecipients(opts.entityId);
    if (!recipients.length) return;

    // Phase G9.B — dispatchMultiChannel persists an in-app MessageInbox row
    // in addition to the email, so management sees POSTED events inside the
    // inbox Approvals folder (badge + acknowledge action). Email kill-switch
    // and per-user preferences are honoured by dispatchMultiChannel.
    await dispatchMultiChannel(recipients, {
      templateFn: documentPostedTemplate,
      templateData: {
        module: opts.module,
        docType: opts.docType,
        docRef: opts.docRef,
        postedBy: opts.postedBy,
        entityName,
        amount: opts.amount,
        period: opts.period,
      },
      emailType: 'ERP_DOCUMENT_POSTED',
      category: 'document_posted',
      entityId: opts.entityId,
      inAppCategory: 'document_posted',
      inAppFolder: 'APPROVALS',
      inAppPriority: 'normal',
      inAppRequiresAction: false,
      inAppActionType: 'acknowledge',
      inAppActionPayload: { module: opts.module, doc_type: opts.docType, doc_ref: opts.docRef, deep_link: `/erp/${String(opts.module || '').toLowerCase()}` },
    });
  } catch (err) {
    console.error('notifyDocumentPosted failed:', err.message);
  }
};

/**
 * Notify management when a document is reopened (reversal).
 */
