/**
 * Expense Anomaly Detection Service — Period-over-period and budget overrun detection
 * Phase 14.3
 */
const mongoose = require('mongoose');
const SmerEntry = require('../models/SmerEntry');
const CarLogbookEntry = require('../models/CarLogbookEntry');
const ExpenseEntry = require('../models/ExpenseEntry');
const Collection = require('../models/Collection');
const BudgetAllocation = require('../models/BudgetAllocation');
const PeopleMaster = require('../models/PeopleMaster');
const Settings = require('../models/Settings');

function periodToDates(period) {
  const [year, month] = period.split('-').map(Number);
  return { start: new Date(year, month - 1, 1), end: new Date(year, month, 1) };
}

function priorPeriod(period) {
  let [year, month] = period.split('-').map(Number);
  month -= 1;
  if (month < 1) { month = 12; year -= 1; }
  return `${year}-${String(month).padStart(2, '0')}`;
}

/**
 * Aggregate a component for a period, grouped by bdm_id
 */
async function aggregateComponent(entityId, period, component) {
  const eId = new mongoose.Types.ObjectId(entityId);
  const { start, end } = periodToDates(period);
  const baseMatch = { entity_id: eId, status: 'POSTED' };

  switch (component) {
    case 'SMER':
      return SmerEntry.aggregate([
        { $match: { ...baseMatch, period } },
        { $group: { _id: '$bdm_id', total: { $sum: '$total_reimbursable' } } }
      ]);
    case 'GAS_OFFICIAL':
      return CarLogbookEntry.aggregate([
        { $match: { ...baseMatch, period } },
        { $group: { _id: '$bdm_id', total: { $sum: '$official_gas_amount' } } }
      ]);
    case 'INSURANCE':
      return Collection.aggregate([
        { $match: { ...baseMatch, cr_date: { $gte: start, $lt: end } } },
        { $group: { _id: '$bdm_id', total: { $sum: '$total_partner_rebates' } } }
      ]);
    case 'ACCESS':
      return ExpenseEntry.aggregate([
        { $match: { ...baseMatch, period } },
        { $group: { _id: '$bdm_id', total: { $sum: '$total_access' } } }
      ]);
    case 'CORE_COMM':
      return Collection.aggregate([
        { $match: { ...baseMatch, cr_date: { $gte: start, $lt: end } } },
        { $group: { _id: '$bdm_id', total: { $sum: '$total_commission' } } }
      ]);
    default:
      return [];
  }
}

function toMap(aggResult) {
  return new Map(aggResult.map(r => [r._id.toString(), r.total || 0]));
}

/**
 * detectAnomalies — compare current vs prior period per person per component
 */
async function detectAnomalies(entityId, period) {
  const settings = await Settings.getSettings();
  const threshold = settings.EXPENSE_ANOMALY_THRESHOLD || 0.30;
  const prior = priorPeriod(period);

  const components = ['SMER', 'GAS_OFFICIAL', 'INSURANCE', 'ACCESS', 'CORE_COMM'];

  // Aggregate all components for both periods in parallel
  const [currentResults, priorResults] = await Promise.all([
    Promise.all(components.map(c => aggregateComponent(entityId, period, c))),
    Promise.all(components.map(c => aggregateComponent(entityId, prior, c)))
  ]);

  const currentMaps = components.map((_, i) => toMap(currentResults[i]));
  const priorMaps = components.map((_, i) => toMap(priorResults[i]));

  // Get all people for name lookup
  const eId = new mongoose.Types.ObjectId(entityId);
  const people = await PeopleMaster.find({ entity_id: eId, is_active: true })
    .select('user_id full_name').lean();
  const nameMap = new Map(people.map(p => [p.user_id?.toString(), p.full_name]));

  // Collect all bdm_ids across all components
  const allBdmIds = new Set();
  [...currentMaps, ...priorMaps].forEach(m => {
    for (const key of m.keys()) allBdmIds.add(key);
  });

  const anomalies = [];
  for (const bdmId of allBdmIds) {
    for (let ci = 0; ci < components.length; ci++) {
      const current_amount = currentMaps[ci].get(bdmId) || 0;
      const prior_amount = priorMaps[ci].get(bdmId) || 0;

      if (prior_amount === 0 && current_amount === 0) continue;

      const change_pct = prior_amount > 0
        ? Math.round(((current_amount - prior_amount) / prior_amount) * 10000) / 100
        : (current_amount > 0 ? 100 : 0);

      const flag = Math.abs(change_pct) > threshold * 100 ? 'ALERT' : 'NORMAL';

      anomalies.push({
        person_id: bdmId,
        person_name: nameMap.get(bdmId) || 'Unknown',
        component: components[ci],
        prior_amount: Math.round(prior_amount * 100) / 100,
        current_amount: Math.round(current_amount * 100) / 100,
        change_pct,
        flag
      });
    }
  }

  // Sort by absolute change % descending
  anomalies.sort((a, b) => Math.abs(b.change_pct) - Math.abs(a.change_pct));

  return { period, prior_period: prior, threshold: threshold * 100, anomalies };
}

/**
 * detectBudgetOverruns — compare actual vs budgeted per component
 */
async function detectBudgetOverruns(entityId, period) {
  const eId = new mongoose.Types.ObjectId(entityId);

  const allocations = await BudgetAllocation.find({
    entity_id: eId, period, status: 'APPROVED'
  }).lean();

  if (allocations.length === 0) return { period, overruns: [] };

  // Component code to aggregation source mapping
  const componentMap = {
    SMER: 'SMER', GAS: 'GAS_OFFICIAL', INSURANCE: 'INSURANCE',
    ACCESS: 'ACCESS', ORE: 'ORE', CORE_COMM: 'CORE_COMM'
  };

  // All transaction models key by User._id (bdm_id). BudgetAllocation.target_id
  // must also store User._id when target_type='BDM' for consistent lookups.
  const people = await PeopleMaster.find({ entity_id: eId })
    .select('user_id full_name').lean();
  const nameMap = new Map(people.map(p => [p.user_id?.toString(), p.full_name]));

  // Pre-aggregate all components
  const components = ['SMER', 'GAS_OFFICIAL', 'INSURANCE', 'ACCESS', 'CORE_COMM'];
  const aggResults = await Promise.all(components.map(c => aggregateComponent(entityId, period, c)));
  const aggMaps = {};
  components.forEach((c, i) => { aggMaps[c] = toMap(aggResults[i]); });

  // Also get ORE separately
  const oreResult = await ExpenseEntry.aggregate([
    { $match: { entity_id: eId, status: 'POSTED', period } },
    { $group: { _id: '$bdm_id', total: { $sum: '$total_ore' } } }
  ]);
  aggMaps['ORE'] = toMap(oreResult);

  const overruns = [];
  for (const alloc of allocations) {
    // target_id is User._id (same as bdm_id in transaction models)
    const userId = alloc.target_id?.toString();
    const personName = nameMap.get(userId) || alloc.target_name || 'Unknown';

    for (const comp of (alloc.components || [])) {
      const sourceKey = componentMap[comp.component_code] || comp.component_code;
      const aggMap = aggMaps[sourceKey];
      const actual = aggMap ? (aggMap.get(userId) || 0) : 0;
      const budgeted = comp.budgeted_amount || 0;
      const variance = Math.round((actual - budgeted) * 100) / 100;
      const variance_pct = budgeted > 0 ? Math.round((variance / budgeted) * 10000) / 100 : 0;

      overruns.push({
        person_id: alloc.target_id,
        person_name: personName,
        component: comp.component_code,
        budgeted_amount: budgeted,
        actual_amount: Math.round(actual * 100) / 100,
        variance,
        variance_pct,
        flag: actual > budgeted ? 'OVER_BUDGET' : 'WITHIN_BUDGET'
      });
    }
  }

  overruns.sort((a, b) => b.variance - a.variance);

  return { period, overruns };
}

module.exports = {
  detectAnomalies,
  detectBudgetOverruns
};

/**
 * FIFO Engine — First Expiry, First Out
 *
 * All functions are read-only (no DB writes). They return consumption PLANS.
 * The caller (salesController.submitSales) creates InventoryLedger entries.
 *
 * Phase 17: All functions accept optional opts.warehouseId.
 * When provided, queries filter by warehouse_id instead of (or alongside) bdm_id.
 * Backward-compatible: existing callers without opts keep working.
 */
const mongoose = require('mongoose');
const InventoryLedger = require('../models/InventoryLedger');
const { cleanBatchNo } = require('../utils/normalize');

/**
 * Build the $match filter for inventory queries.
 * Supports both legacy bdm_id filtering and new warehouse_id filtering.
 * @param {string} entityId
 * @param {string} bdmId
 * @param {Object} [opts] - { warehouseId }
 * @param {string} [productId]
 */
const buildStockMatch = (entityId, bdmId, opts, productId) => {
  const match = { entity_id: new mongoose.Types.ObjectId(entityId) };
  // Prefer warehouse_id if provided (Phase 17); fall back to bdm_id
  if (opts?.warehouseId) {
    match.warehouse_id = new mongoose.Types.ObjectId(opts.warehouseId);
  } else if (bdmId) {
    match.bdm_id = new mongoose.Types.ObjectId(bdmId);
  }
  if (productId) {
    match.product_id = new mongoose.Types.ObjectId(productId);
  }
  return match;
};

/**
 * Get all batches with available stock for a specific product,
 * sorted by expiry date ascending (oldest/nearest expiry first = FEFO).
 *
 * @param {ObjectId|string} entityId
 * @param {ObjectId|string} bdmId
 * @param {ObjectId|string} productId
 * @returns {Array<{ batch_lot_no, expiry_date, available_qty }>}
 */
const getAvailableBatches = async (entityId, bdmId, productId, opts) => {
  const pipeline = [
    { $match: buildStockMatch(entityId, bdmId, opts, productId) },
    {
      $group: {
        _id: { batch_lot_no: '$batch_lot_no', expiry_date: '$expiry_date', bdm_id: '$bdm_id' },
        total_in: { $sum: '$qty_in' },
        total_out: { $sum: '$qty_out' }
      }
    },
    {
      $addFields: {
        available_qty: { $subtract: ['$total_in', '$total_out'] }
      }
    },
    { $match: { available_qty: { $gt: 0 } } },
    // Filter out expired batches — pharmaceutical compliance (FEFO)
    { $match: { '_id.expiry_date': { $gt: new Date() } } },
    { $sort: { '_id.expiry_date': 1 } },
    {
      $project: {
        _id: 0,
        batch_lot_no: '$_id.batch_lot_no',
        expiry_date: '$_id.expiry_date',
        bdm_id: '$_id.bdm_id',
        available_qty: 1
      }
    }
  ];

  // Use session for transactional consistency if provided
  const agg = InventoryLedger.aggregate(pipeline);
  if (opts?.session) agg.session(opts.session);
  return agg;
};

/**
 * Create a FIFO consumption plan for the requested quantity.
 * Consumes from oldest expiry first. Does NOT write to DB.
 *
 * @param {ObjectId|string} entityId
 * @param {ObjectId|string} bdmId
 * @param {ObjectId|string} productId
 * @param {number} qty - Total quantity to consume
 * @returns {Array<{ batch_lot_no, expiry_date, qty_consumed, bdm_id }>}
 * @throws {Error} INSUFFICIENT_STOCK if total available < qty
 */
const consumeFIFO = async (entityId, bdmId, productId, qty, opts) => {
  const batches = await getAvailableBatches(entityId, bdmId, productId, opts);

  const totalAvailable = batches.reduce((sum, b) => sum + b.available_qty, 0);
  if (totalAvailable < qty) {
    const err = new Error('Insufficient stock');
    err.code = 'INSUFFICIENT_STOCK';
    err.available = totalAvailable;
    err.requested = qty;
    throw err;
  }

  const consumed = [];
  let remaining = qty;

  for (const batch of batches) {
    if (remaining <= 0) break;

    const take = Math.min(batch.available_qty, remaining);
    consumed.push({
      batch_lot_no: batch.batch_lot_no,
      expiry_date: batch.expiry_date,
      qty_consumed: take,
      bdm_id: batch.bdm_id
    });
    remaining -= take;
  }

  return consumed;
};

/**
 * Create a consumption plan for a specific batch (FIFO override).
 *
 * @param {ObjectId|string} entityId
 * @param {ObjectId|string} bdmId
 * @param {ObjectId|string} productId
 * @param {string} batchLotNo - Specific batch to consume from
 * @param {number} qty
 * @returns {{ batch_lot_no, expiry_date, qty_consumed }}
 * @throws {Error} INSUFFICIENT_STOCK if batch doesn't have enough
 */
const consumeSpecificBatch = async (entityId, bdmId, productId, batchLotNo, qty, opts) => {
  const normalized = cleanBatchNo(batchLotNo);

  const match = buildStockMatch(entityId, bdmId, opts, productId);
  match.batch_lot_no = normalized;

  const agg = InventoryLedger.aggregate([
    { $match: match },
    {
      $group: {
        _id: { batch_lot_no: '$batch_lot_no', expiry_date: '$expiry_date', bdm_id: '$bdm_id' },
        total_in: { $sum: '$qty_in' },
        total_out: { $sum: '$qty_out' }
      }
    },
    {
      $addFields: {
        available_qty: { $subtract: ['$total_in', '$total_out'] }
      }
    }
  ]);
  // Apply session for transactional consistency if provided
  if (opts?.session) agg.session(opts.session);
  const result = await agg;

  if (!result.length || result[0].available_qty < qty) {
    const err = new Error('Insufficient stock in specified batch');
    err.code = 'INSUFFICIENT_STOCK';
    err.available = result.length ? result[0].available_qty : 0;
    err.requested = qty;
    err.batch_lot_no = normalized;
    throw err;
  }

  return {
    batch_lot_no: result[0]._id.batch_lot_no,
    expiry_date: result[0]._id.expiry_date,
    qty_consumed: qty,
    bdm_id: result[0]._id.bdm_id
  };
};

/**
 * Get full stock-on-hand for a BDM across all products.
 * Used by My Stock page and product dropdown (only show in-stock products).
 *
 * @param {ObjectId|string} entityId
 * @param {ObjectId|string} bdmId
 * @returns {Array<{ product_id, batch_lot_no, expiry_date, available_qty }>}
 */
const getMyStock = async (entityId, bdmId, opts) => {
  const match = buildStockMatch(entityId, bdmId, opts);

  const result = await InventoryLedger.aggregate([
    { $match: match },
    {
      $group: {
        _id: {
          product_id: '$product_id',
          batch_lot_no: '$batch_lot_no',
          expiry_date: '$expiry_date',
          bdm_id: '$bdm_id'
        },
        total_in: { $sum: '$qty_in' },
        total_out: { $sum: '$qty_out' }
      }
    },
    {
      $addFields: {
        available_qty: { $subtract: ['$total_in', '$total_out'] }
      }
    },
    { $match: { available_qty: { $gt: 0 } } },
    { $sort: { '_id.product_id': 1, '_id.expiry_date': 1 } },
    {
      $project: {
        _id: 0,
        product_id: '$_id.product_id',
        batch_lot_no: '$_id.batch_lot_no',
        expiry_date: '$_id.expiry_date',
        bdm_id: '$_id.bdm_id',
        available_qty: 1
      }
    }
  ]);

  return result;
};

/**
 * Build an in-memory stock snapshot for validation.
 * Returns a Map: "productId|batchLotNo" → available_qty
 * Used by validateSales to deduct from snapshot per row.
 */
const buildStockSnapshot = async (entityId, bdmId, opts) => {
  const stock = await getMyStock(entityId, bdmId, opts);
  const snapshot = new Map();

  for (const item of stock) {
    const key = `${item.product_id}|${item.batch_lot_no}`;
    snapshot.set(key, (snapshot.get(key) || 0) + item.available_qty);
  }

  // Also build a product-level total for FIFO consumption checks
  const productTotals = new Map();
  for (const item of stock) {
    const pid = item.product_id.toString();
    productTotals.set(pid, (productTotals.get(pid) || 0) + item.available_qty);
  }

  return { snapshot, productTotals };
};

module.exports = {
  getAvailableBatches,
  consumeFIFO,
  consumeSpecificBatch,
  getMyStock,
  buildStockSnapshot
};

/**
 * incentivePlanService — Phase SG-4 #21 (plan versioning)
 *
 * One service for the whole versioning lifecycle:
 *   - ensureHeader(plan)      — lazy-create IncentivePlan header for a SalesGoalPlan
 *   - getActiveVersion(...)   — resolve "the active plan right now" by header / fy
 *   - listVersions(headerId)  — every SalesGoalPlan tied to one header, newest first
 *   - createNewVersion(...)   — copy current → new draft version, mark old superseded
 *   - syncHeaderOnActivation  — keep IncentivePlan.current_version_id + status fresh
 *   - syncHeaderOnLifecycleChange — mirror status onto the header on close/reopen
 *
 * Source of truth for "what version is active for (entity, fiscal_year)":
 *   IncentivePlan.current_version_id (already O(1) via the unique index on
 *   {entity_id, fiscal_year}). Earlier drafts also wrote a parallel
 *   ACTIVE_PLAN_VERSION Lookup row, which was deliberately removed — operational
 *   state doesn't belong in the Lookup table (admins shouldn't see / edit it,
 *   and the lookup-driven Foundation Health check would fight with auto-upserts).
 *
 * Backward compatibility (Rule #2 wiring + plan integrity guardrail F.1):
 *   - All existing SalesGoalPlan code continues to work unchanged. Versioning
 *     fields (incentive_plan_id, version_no, effective_*, supersedes_plan_id)
 *     are optional on the schema; ensureHeader backfills v1 on first touch.
 *   - getActivePlan() helpers across the codebase keep returning a SalesGoalPlan
 *     row — versioning is a *header* atop the existing rows, not a replacement.
 *   - KpiSnapshot.plan_id, IncentivePayout.plan_id stay tied to the version
 *     that was active at compute time. Versioning never re-points historical
 *     rows. Snapshot accuracy is preserved by definition.
 *
 * Subscription posture:
 *   - One IncentivePlan header row per (entity_id, fiscal_year). Lazy-seeded.
 *   - Adding a new subsidiary requires zero rows up-front; first plan create
 *     auto-creates the header.
 */

const mongoose = require('mongoose');
const IncentivePlan = require('../models/IncentivePlan');
const SalesGoalPlan = require('../models/SalesGoalPlan');

/**
 * Ensure an IncentivePlan header exists for the given SalesGoalPlan and that
 * the plan's `incentive_plan_id` + `version_no` fields are populated. Idempotent.
 *
 * Used in three places:
 *  1. createPlan controller — right after SalesGoalPlan.create()
 *  2. activatePlan controller — defensive (in case create predated SG-4)
 *  3. createNewVersion service — to find the parent header by plan id
 *
 * Returns { header, plan, didBackfill }.
 */
async function ensureHeader(plan, opts = {}) {
  if (!plan || !plan._id || !plan.entity_id || !plan.fiscal_year) {
    throw new Error('ensureHeader: plan must have _id, entity_id, fiscal_year');
  }
  const session = opts.session || null;

  // Already linked → fast path; just confirm header exists (in case row was deleted).
  if (plan.incentive_plan_id) {
    const existingHeader = await IncentivePlan.findById(plan.incentive_plan_id).session(session);
    if (existingHeader) {
      return { header: existingHeader, plan, didBackfill: false };
    }
    // Header missing — fall through to upsert path.
  }

  // Upsert by (entity_id, fiscal_year). Mirrors plan_name from current row.
  const filter = { entity_id: plan.entity_id, fiscal_year: plan.fiscal_year };
  let header = await IncentivePlan.findOne(filter).session(session);

  if (!header) {
    // Use `findOneAndUpdate` with upsert to handle two-process race safely.
    header = await IncentivePlan.findOneAndUpdate(
      filter,
      {
        $setOnInsert: {
          entity_id: plan.entity_id,
          fiscal_year: plan.fiscal_year,
          plan_name: plan.plan_name,
          description: '',
          current_version_no: plan.version_no || 1,
          current_version_id: plan._id,
          status: plan.status,
          created_by: plan.created_by || null,
        },
      },
      { upsert: true, new: true, setDefaultsOnInsert: true, session }
    );
  }

  // Backfill plan-side fields if missing
  let didBackfill = false;
  if (!plan.incentive_plan_id) {
    plan.incentive_plan_id = header._id;
    didBackfill = true;
  }
  if (!plan.version_no) {
    plan.version_no = 1;
    didBackfill = true;
  }
  if (didBackfill && opts.persist !== false) {
    await plan.save({ session });
  }

  return { header, plan, didBackfill };
}

/**
 * Resolve the SalesGoalPlan version that is currently active for an
 * (entity_id, fiscal_year). Falls back across:
 *   1. IncentivePlan.current_version_id (fast path)
 *   2. SalesGoalPlan.findOne({ entity_id, fiscal_year, status: 'ACTIVE' })
 *      sorted by version_no desc (back-compat for pre-SG-4 rows)
 *   3. null
 *
 * Used by snapshot triggers (kpiSnapshotAgent, manual computeSnapshots) so
 * accruals always land on the right version.
 */
async function getActiveVersion(entityId, fiscalYear, opts = {}) {
  if (!entityId || !fiscalYear) return null;
  const session = opts.session || null;

  const header = await IncentivePlan.findOne({
    entity_id: entityId,
    fiscal_year: fiscalYear,
  }).session(session).lean();

  if (header?.current_version_id) {
    const versioned = await SalesGoalPlan.findById(header.current_version_id).session(session).lean();
    if (versioned && versioned.status === 'ACTIVE') return versioned;
  }

  // Back-compat fallback (legacy rows with no header)
  return SalesGoalPlan.findOne({
    entity_id: entityId,
    fiscal_year: fiscalYear,
    status: 'ACTIVE',
  }).sort({ version_no: -1, createdAt: -1 }).session(session).lean();
}

/**
 * List every version of a logical plan (by header id) newest-first.
 */
async function listVersions(headerId) {
  if (!headerId) return [];
  return SalesGoalPlan.find({ incentive_plan_id: headerId })
    .sort({ version_no: -1, createdAt: -1 })
    .populate('supersedes_plan_id', 'version_no reference status')
    .populate('superseded_by_plan_id', 'version_no reference status')
    .lean();
}

/**
 * Create a new version (v(N+1)) of the logical plan owned by `basisPlanId`.
 *
 * Behavior:
 *   - Validates `basisPlan` exists and is the latest version (no orphaned forks).
 *   - Copies growth_drivers / incentive_programs / baseline_revenue / target_revenue
 *     from the basis. Caller-supplied overrides in `body` win.
 *   - Mints `version_no = basis.version_no + 1`, status = DRAFT, links via
 *     `supersedes_plan_id = basis._id`. Reference number is NOT inherited;
 *     a fresh one is minted on first activation (matches pre-SG-4 behavior).
 *   - effective_from defaults to `body.effective_from` or now.
 *   - The basis plan's `superseded_by_plan_id` + `effective_to` are NOT set
 *     here — they are set in `syncHeaderOnSupersede()` once the new version
 *     transitions to ACTIVE (so a draft v2 sitting in review doesn't break
 *     v1's effective span).
 *
 * Returns the newly-created SalesGoalPlan v(N+1).
 *
 * Thread-safe: wraps the read-validate-create in a transaction so two parallel
 * "Create New Version" clicks can't mint v3 + v3' simultaneously.
 */
async function createNewVersion({ basisPlanId, body = {}, userId, session: outerSession = null }) {
  const useExternalSession = !!outerSession;
  const session = outerSession || await mongoose.startSession();

  let newPlan = null;
  try {
    const work = async () => {
      const basis = await SalesGoalPlan.findById(basisPlanId).session(session);
      if (!basis) throw new Error('Basis plan not found');

      // Ensure the basis has a header (handles legacy rows)
      const { header } = await ensureHeader(basis, { session });

      // Reject if a newer version already exists (only the *latest* version
      // can be the basis for v(N+1)).
      const newer = await SalesGoalPlan.findOne({
        incentive_plan_id: header._id,
        version_no: { $gt: basis.version_no },
      }).select('_id version_no').session(session).lean();
      if (newer) {
        throw new Error(`Cannot create new version from v${basis.version_no} — v${newer.version_no} already exists`);
      }

      const nextVersionNo = (basis.version_no || 1) + 1;
      const effectiveFrom = body.effective_from ? new Date(body.effective_from) : new Date();

      newPlan = await SalesGoalPlan.create([{
        entity_id: basis.entity_id,
        fiscal_year: basis.fiscal_year,
        plan_name: body.plan_name || basis.plan_name,
        status: 'DRAFT',
        baseline_revenue: body.baseline_revenue ?? basis.baseline_revenue,
        target_revenue: body.target_revenue ?? basis.target_revenue,
        collection_target_pct: body.collection_target_pct ?? basis.collection_target_pct,
        growth_drivers: Array.isArray(body.growth_drivers) ? body.growth_drivers : (basis.growth_drivers || []),
        incentive_programs: Array.isArray(body.incentive_programs) ? body.incentive_programs : (basis.incentive_programs || []),
        // Versioning fields
        incentive_plan_id: header._id,
        version_no: nextVersionNo,
        effective_from: effectiveFrom,
        effective_to: null,
        supersedes_plan_id: basis._id,
        superseded_by_plan_id: null,
        // Audit / lifecycle
        created_by: userId,
        // reference: minted on first activation (do NOT inherit basis.reference)
      }], { session });

      newPlan = newPlan[0];
    };

    if (useExternalSession) await work();
    else await session.withTransaction(work);
  } finally {
    if (!useExternalSession) session.endSession();
  }

  return newPlan;
}

/**
 * Called from activatePlan(): once a plan transitions to ACTIVE, mark the
 * basis version (if any) as superseded and point the header to the new version.
 *
 * Idempotent — safe to call on a v1 with no basis.
 */
async function syncHeaderOnActivation(plan, opts = {}) {
  const session = opts.session || null;
  if (!plan || !plan._id) return;

  // Make sure header exists
  const { header } = await ensureHeader(plan, { session, persist: true });

  // If this version supersedes a prior one, close out the prior version's
  // effective_to and link superseded_by_plan_id.
  if (plan.supersedes_plan_id) {
    await SalesGoalPlan.updateOne(
      { _id: plan.supersedes_plan_id, superseded_by_plan_id: { $in: [null, undefined] } },
      {
        $set: {
          superseded_by_plan_id: plan._id,
          effective_to: plan.effective_from || new Date(),
        },
      },
      { session }
    );
  }

  // Update header to point at this newly-activated version. This is the
  // single source of truth for "what version is active for (entity_id,
  // fiscal_year)" — already O(1) via the unique index, so no parallel lookup
  // mirror is needed.
  await IncentivePlan.updateOne(
    { _id: header._id },
    {
      $set: {
        current_version_no: plan.version_no || 1,
        current_version_id: plan._id,
        status: 'ACTIVE',
        plan_name: plan.plan_name || header.plan_name,
      },
    },
    { session }
  );
}

/**
 * Called from closePlan / president-reverse: when the active version closes
 * or reverses, mirror that status onto the header.
 */
async function syncHeaderOnLifecycleChange(plan, opts = {}) {
  const session = opts.session || null;
  if (!plan?.incentive_plan_id) return;
  await IncentivePlan.updateOne(
    { _id: plan.incentive_plan_id, current_version_id: plan._id },
    { $set: { status: plan.status } },
    { session }
  );
}

module.exports = {
  ensureHeader,
  getActiveVersion,
  listVersions,
  createNewVersion,
  syncHeaderOnActivation,
  syncHeaderOnLifecycleChange,
};

/**
 * Income Calculation Service — BDM Payslip Generation + Projection
 *
 * PRD §10: BDM Income Computation (per cycle)
 * Earnings: SMER + CORE Commission + CALF Reimbursement + Bonus + Profit Sharing + Reimbursements
 * Deductions: Lookup-driven deduction_lines[] (BDM enters, Finance verifies)
 *   Auto-deductions: CALF excess (auto_source: 'CALF'), Personal Gas (auto_source: 'PERSONAL_GAS'),
 *                    Schedule installments (auto_source: 'SCHEDULE')
 * Net Pay = Total Earnings - Total Deductions
 *
 * Phase G1: CALF bidirectional settlement, personal gas auto-deduction, income projection
 */
const mongoose = require('mongoose');
const IncomeReport = require('../models/IncomeReport');
const PnlReport = require('../models/PnlReport');
const SmerEntry = require('../models/SmerEntry');
const Collection = require('../models/Collection');
const ExpenseEntry = require('../models/ExpenseEntry');
const PrfCalf = require('../models/PrfCalf');
const CarLogbookEntry = require('../models/CarLogbookEntry');
const DeductionSchedule = require('../models/DeductionSchedule');
const CompProfile = require('../models/CompProfile');
const PeopleMaster = require('../models/PeopleMaster');
const { syncInstallmentStatus } = require('./deductionScheduleService');

/**
 * Resolve the ACTIVE CompProfile for a BDM user in a given entity.
 * Mirrors loadBdmCompProfile in expenseController; inlined here to keep
 * the service module dependency graph flat (no controller imports).
 */
async function _resolveCompProfile(entityId, bdmUserId) {
  const person = await PeopleMaster.findOne({
    user_id: new mongoose.Types.ObjectId(bdmUserId),
    entity_id: new mongoose.Types.ObjectId(entityId)
  }).select('_id').lean();
  if (!person) return null;
  return CompProfile.findOne({
    person_id: person._id,
    entity_id: new mongoose.Types.ObjectId(entityId),
    status: 'ACTIVE'
  }).sort({ effective_date: -1 }).lean();
}

/**
 * Parse period to start/end dates
 */
function periodToDates(period) {
  const [year, month] = period.split('-').map(Number);
  return {
    start: new Date(year, month - 1, 1),
    end: new Date(year, month, 1)
  };
}

/**
 * Generate income report for a BDM's period + cycle.
 * Auto-computes earnings from source data; preserves manual fields and BDM deduction_lines from existing report.
 *
 * @param {String} entityId
 * @param {String} bdmId
 * @param {String} period - "2026-04"
 * @param {String} cycle - "C1" | "C2" | "MONTHLY"
 * @param {ObjectId} userId - who triggered generation
 * @returns {Object} IncomeReport document
 */
async function generateIncomeReport(entityId, bdmId, period, cycle, userId) {
  const { start, end } = periodToDates(period);
  const filter = {
    entity_id: new mongoose.Types.ObjectId(entityId),
    bdm_id: new mongoose.Types.ObjectId(bdmId)
  };

  // 1. SMER earnings — per diem + transport only.
  //    ORE retired 2026-04 (Phase G1 hardening): SMER-ORE is phantom and flows
  //    exclusively through ExpenseEntry.expense_type='ORE'. On pre-retirement
  //    docs with legacy total_ore > 0, we subtract it so we don't double-count
  //    when we add ExpenseEntry-ORE below. New SMERs always have total_ore=0.
  const smer = await SmerEntry.findOne({
    ...filter, period, cycle,
    status: { $in: ['POSTED', 'VALID', 'DRAFT'] }
  }).lean();
  const smerLegacyOre = smer?.total_ore || 0;
  const smerAmount = Math.round(((smer?.total_reimbursable || 0) - smerLegacyOre) * 100) / 100;

  // 1b. ORE always from ExpenseEntry (receipt-backed, CASH). ACCESS lines are
  //     NOT reimbursable — company already paid via credit card / GCash / bank.
  const oreAgg = await ExpenseEntry.aggregate([
    { $match: { ...filter, period, cycle, status: { $in: ['POSTED', 'VALID', 'DRAFT'] } } },
    { $unwind: '$lines' },
    { $match: { 'lines.expense_type': 'ORE' } },
    { $group: { _id: null, total: { $sum: '$lines.amount' } } }
  ]);
  const oreAmount = Math.round((oreAgg[0]?.total || 0) * 100) / 100;

  // 2. CORE commission from POSTED Collections
  const collAgg = await Collection.aggregate([
    {
      $match: {
        ...filter,
        status: 'POSTED',
        cr_date: { $gte: start, $lt: end }
      }
    },
    {
      $group: {
        _id: null,
        total_commission: { $sum: '$total_commission' }
      }
    }
  ]);
  const coreCommission = collAgg[0]?.total_commission || 0;

  // 3. Profit Sharing from PNL report
  const pnl = await PnlReport.findOne({ ...filter, period }).lean();
  const profitSharing = (pnl?.profit_sharing?.eligible && pnl?.profit_sharing?.bdm_share > 0)
    ? pnl.profit_sharing.bdm_share
    : 0;

  // 4. CALF settlement — bidirectional
  //    Positive balance (advance > liquidation) → deduction (BDM returns excess)
  //    Negative balance (liquidation > advance) → reimbursement in earnings (company pays BDM back)
  const calfAgg = await PrfCalf.aggregate([
    {
      $match: {
        ...filter,
        doc_type: 'CALF',
        period,
        status: { $in: ['POSTED', 'VALID'] }
      }
    },
    {
      $group: {
        _id: null,
        total_advance: { $sum: '$advance_amount' },
        total_liquidation: { $sum: '$liquidation_amount' }
      }
    }
  ]);
  const calfData = calfAgg[0] || { total_advance: 0, total_liquidation: 0 };
  const calfBalance = Math.round((calfData.total_advance - calfData.total_liquidation) * 100) / 100;
  const calfReimbursement = calfBalance < 0 ? Math.abs(calfBalance) : 0;
  const calfExcessDeduction = calfBalance > 0 ? calfBalance : 0;

  // 4b. Personal gas deduction from Car Logbook
  const gasAgg = await CarLogbookEntry.aggregate([
    {
      $match: {
        ...filter,
        period, cycle,
        status: { $in: ['POSTED', 'VALID'] }
      }
    },
    {
      $group: {
        _id: null,
        total_personal_gas: { $sum: '$personal_gas_amount' }
      }
    }
  ]);
  const personalGasDeduction = Math.round((gasAgg[0]?.total_personal_gas || 0) * 100) / 100;

  // 4c. Recurring deduction schedule installments (filter by target_cycle)
  const activeSchedules = await DeductionSchedule.find({
    entity_id: new mongoose.Types.ObjectId(entityId),
    bdm_id: new mongoose.Types.ObjectId(bdmId),
    status: 'ACTIVE',
    $or: [
      { target_cycle: cycle },
      { target_cycle: { $exists: false } } // legacy schedules without target_cycle
    ],
    installments: { $elemMatch: { period, status: 'PENDING' } }
  }).lean();

  const scheduleLines = [];
  for (const sched of activeSchedules) {
    const inst = sched.installments.find(i => i.period === period && i.status === 'PENDING');
    if (inst) {
      scheduleLines.push({
        deduction_type: sched.deduction_type,
        deduction_label: sched.deduction_label,
        amount: inst.amount,
        description: `${sched.description || sched.deduction_label} (${inst.installment_no}/${sched.term_months})`,
        entered_by: userId,
        entered_at: new Date(),
        status: 'PENDING',
        auto_source: 'SCHEDULE',
        schedule_ref: {
          schedule_id: sched._id,
          installment_id: inst._id
        }
      });
    }
  }

  // 5. Source references
  const collectionIds = await Collection.find({
    ...filter, status: 'POSTED',
    cr_date: { $gte: start, $lt: end }
  }).select('_id').lean();

  const expenseIds = await ExpenseEntry.find({
    ...filter, period, cycle,
    status: { $in: ['POSTED', 'VALID'] }
  }).select('_id').lean();

  // Build auto-deduction lines (rebuilt fresh each generation)
  const autoLines = [];
  if (calfExcessDeduction > 0) {
    autoLines.push({
      deduction_type: 'CASH_ADVANCE',
      deduction_label: 'CALF Settlement (Return Excess)',
      amount: calfExcessDeduction,
      description: `Advance \u20B1${calfData.total_advance.toLocaleString()} \u2212 Liquidated \u20B1${calfData.total_liquidation.toLocaleString()}`,
      entered_by: userId,
      entered_at: new Date(),
      status: 'VERIFIED',
      auto_source: 'CALF'
    });
  }
  // Personal Gas — always render a row for logbook-eligible BDMs (even at \u20B10)
  // so the BDM can always confirm the logbook was reviewed. Non-eligible (office
  // staff with no car logbook) are suppressed to avoid a meaningless \u20B10 row.
  const compProfile = await _resolveCompProfile(entityId, bdmId);
  if (compProfile?.logbook_eligible) {
    autoLines.push({
      deduction_type: 'PERSONAL_GAS',
      deduction_label: 'Personal Gas Usage',
      amount: personalGasDeduction,
      description: personalGasDeduction > 0
        ? 'Auto-computed from Car Logbook personal km \u00D7 fuel cost'
        : 'No personal km logged this cycle \u2014 logbook reviewed',
      entered_by: userId,
      entered_at: new Date(),
      status: 'VERIFIED',
      auto_source: 'PERSONAL_GAS'
    });
  }

  // Build income data
  const incomeData = {
    entity_id: entityId,
    bdm_id: bdmId,
    period,
    cycle,
    earnings: {
      smer: Math.round((smerAmount + oreAmount) * 100) / 100,
      core_commission: Math.round(coreCommission * 100) / 100,
      profit_sharing: Math.round(profitSharing * 100) / 100,
      calf_reimbursement: Math.round(calfReimbursement * 100) / 100
      // bonus and reimbursements: manual — preserved from existing
    },
    source_refs: {
      smer_id: smer?._id || null,
      collection_ids: collectionIds.map(c => c._id),
      expense_ids: expenseIds.map(e => e._id),
      pnl_report_id: pnl?._id || null
    },
    status: 'GENERATED',
    generated_at: new Date(),
    created_by: userId
  };

  // Upsert — preserve manual fields and BDM deduction_lines from existing doc
  const existing = await IncomeReport.findOne({
    entity_id: entityId, bdm_id: bdmId, period, cycle
  });

  if (existing) {
    // Preserve manual Finance entries
    incomeData.earnings.bonus = existing.earnings?.bonus || 0;
    incomeData.earnings.reimbursements = existing.earnings?.reimbursements || 0;
    incomeData.notes = existing.notes;

    // Preserve BDM-entered manual deduction lines only (strip all auto-source lines — they're rebuilt fresh)
    const manualLines = (existing.deduction_lines || []).filter(
      l => !l.auto_source
    );

    // Keep already-verified/posted schedule lines (don't re-inject)
    const existingScheduleLines = (existing.deduction_lines || []).filter(
      l => l.auto_source === 'SCHEDULE' && l.status !== 'PENDING'
    );

    // Only inject new schedule lines for installments not already present
    const newScheduleLines = scheduleLines.filter(sl =>
      !existingScheduleLines.some(el =>
        el.schedule_ref?.installment_id?.toString() === sl.schedule_ref.installment_id.toString()
      )
    );

    incomeData.deduction_lines = [...autoLines, ...existingScheduleLines, ...newScheduleLines, ...manualLines];

    // Legacy flat deductions for backward compat
    incomeData.deductions = {
      cash_advance: calfExcessDeduction,
      credit_card_payment: existing.deductions?.credit_card_payment || 0,
      credit_payment: existing.deductions?.credit_payment || 0,
      purchased_goods: existing.deductions?.purchased_goods || 0,
      other_deductions: existing.deductions?.other_deductions || 0,
      over_payment: existing.deductions?.over_payment || 0
    };

    Object.assign(existing, incomeData);
    await existing.save();

    // Mark newly injected schedule installments as INJECTED
    await _syncInjectedInstallments(existing);

    return existing;
  }

  // New report — create with auto lines
  incomeData.earnings.bonus = 0;
  incomeData.earnings.reimbursements = 0;

  incomeData.deduction_lines = [...autoLines, ...scheduleLines];

  // Legacy flat deductions
  incomeData.deductions = {
    cash_advance: calfExcessDeduction,
    credit_card_payment: 0,
    credit_payment: 0,
    purchased_goods: 0,
    other_deductions: 0,
    over_payment: 0
  };

  const report = await IncomeReport.create(incomeData);

  // Mark injected schedule installments as INJECTED
  await _syncInjectedInstallments(report);

  return report;
}

/**
 * After saving a report, sync SCHEDULE deduction lines -> mark installments as INJECTED.
 * Non-blocking — errors logged but don't fail the generate.
 */
async function _syncInjectedInstallments(report) {
  const schedLines = (report.deduction_lines || []).filter(
    l => l.auto_source === 'SCHEDULE' && l.schedule_ref?.schedule_id && l.status === 'PENDING'
  );
  for (const line of schedLines) {
    try {
      await syncInstallmentStatus(
        line.schedule_ref.schedule_id,
        line.schedule_ref.installment_id,
        'INJECTED',
        report._id,
        line._id
      );
    } catch (err) {
      console.error('Schedule injection sync (non-blocking):', err.message);
    }
  }
}

/**
 * Project income for a BDM's current cycle — read-only, no document creation.
 * Returns breakdown of what's earned so far with confidence/source indicators.
 *
 * @param {String} entityId
 * @param {String} bdmId
 * @param {String} period - "2026-04"
 * @param {String} cycle - "C1" | "C2" | "MONTHLY"
 * @returns {Object} Income projection with confidence levels
 */
async function projectIncome(entityId, bdmId, period, cycle) {
  const { start, end } = periodToDates(period);
  const filter = {
    entity_id: new mongoose.Types.ObjectId(entityId),
    bdm_id: new mongoose.Types.ObjectId(bdmId)
  };

  // 1. SMER — any active status (exclude DELETION_REQUESTED)
  const smer = await SmerEntry.findOne({
    ...filter, period, cycle,
    status: { $in: ['DRAFT', 'VALID', 'ERROR', 'POSTED'] }
  }).sort({ updatedAt: -1 }).lean();

  // 1b. ORE always from ExpenseEntry (Phase G1 hardening — SMER-ORE retired)
  const oreAggP = await ExpenseEntry.aggregate([
    { $match: { ...filter, period, cycle, status: { $in: ['POSTED', 'VALID', 'DRAFT'] } } },
    { $unwind: '$lines' },
    { $match: { 'lines.expense_type': 'ORE' } },
    { $group: { _id: null, total: { $sum: '$lines.amount' } } }
  ]);
  const expenseOreP = Math.round((oreAggP[0]?.total || 0) * 100) / 100;
  const smerLegacyOreP = smer?.total_ore || 0;

  // 2. Commission from Collections — split by status
  const collAgg = await Collection.aggregate([
    { $match: { ...filter, cr_date: { $gte: start, $lt: end } } },
    {
      $group: {
        _id: '$status',
        total_commission: { $sum: '$total_commission' },
        count: { $sum: 1 }
      }
    }
  ]);
  const postedComm = collAgg.find(r => r._id === 'POSTED') || { total_commission: 0, count: 0 };
  const draftComm = collAgg.find(r => r._id === 'DRAFT') || { total_commission: 0, count: 0 };
  const validComm = collAgg.find(r => r._id === 'VALID') || { total_commission: 0, count: 0 };

  // 3. Profit sharing
  const pnl = await PnlReport.findOne({ ...filter, period }).lean();
  const profitSharing = (pnl?.profit_sharing?.eligible && pnl?.profit_sharing?.bdm_share > 0)
    ? pnl.profit_sharing.bdm_share : 0;

  // 4. CALF settlement — bidirectional
  const calfAgg = await PrfCalf.aggregate([
    { $match: { ...filter, doc_type: 'CALF', period, status: { $in: ['POSTED', 'VALID', 'DRAFT'] } } },
    { $group: { _id: null, total_advance: { $sum: '$advance_amount' }, total_liquidation: { $sum: '$liquidation_amount' } } }
  ]);
  const calfData = calfAgg[0] || { total_advance: 0, total_liquidation: 0 };
  const calfBalance = Math.round((calfData.total_advance - calfData.total_liquidation) * 100) / 100;

  // 5. Personal gas from Car Logbook
  const gasAgg = await CarLogbookEntry.aggregate([
    { $match: { ...filter, period, cycle, status: { $in: ['POSTED', 'VALID', 'DRAFT'] } } },
    { $group: { _id: null, total_personal_gas: { $sum: '$personal_gas_amount' } } }
  ]);
  const personalGas = Math.round((gasAgg[0]?.total_personal_gas || 0) * 100) / 100;

  // 6. Pending deduction schedules
  const schedules = await DeductionSchedule.find({
    entity_id: new mongoose.Types.ObjectId(entityId),
    bdm_id: new mongoose.Types.ObjectId(bdmId),
    status: 'ACTIVE',
    installments: { $elemMatch: { period, status: { $in: ['PENDING', 'INJECTED'] } } }
  }).lean();
  let scheduleAmount = 0, scheduleCount = 0;
  for (const s of schedules) {
    const inst = s.installments.find(i => i.period === period && ['PENDING', 'INJECTED'].includes(i.status));
    if (inst) { scheduleAmount += inst.amount || 0; scheduleCount++; }
  }

  // 7. Existing income report (if already generated)
  const existing = await IncomeReport.findOne({ ...filter, period, cycle })
    .select('status total_earnings total_deductions net_pay earnings deduction_lines')
    .lean();

  // Count manual deduction lines
  const manualLines = existing
    ? (existing.deduction_lines || []).filter(l => !l.auto_source && l.status !== 'REJECTED')
    : [];
  const manualAmount = manualLines.reduce((sum, l) => sum + (l.amount || 0), 0);

  // Compute confidence helper
  const statusConfidence = (status) => {
    if (status === 'POSTED') return 'CONFIRMED';
    if (status === 'VALID' || status === 'DRAFT') return 'PROJECTED';
    return 'NONE';
  };

  // Earnings — strip legacy SMER-ORE (retired) to avoid double-count with ExpenseEntry-ORE
  const smerAmount = ((smer?.total_reimbursable || 0) - smerLegacyOreP) + expenseOreP;
  const totalCommission = postedComm.total_commission + draftComm.total_commission + validComm.total_commission;
  const calfReimb = calfBalance < 0 ? Math.abs(calfBalance) : 0;
  const projectedEarnings = Math.round((smerAmount + totalCommission + calfReimb +
    profitSharing + (existing?.earnings?.bonus || 0) + (existing?.earnings?.reimbursements || 0)) * 100) / 100;

  // Deductions
  const calfExcess = calfBalance > 0 ? calfBalance : 0;
  const totalDeductions = Math.round((calfExcess + personalGas + scheduleAmount + manualAmount) * 100) / 100;

  return {
    period,
    cycle,
    has_official_report: !!existing,
    official_status: existing?.status || null,

    projection: {
      smer: {
        amount: Math.round(smerAmount * 100) / 100,
        ore_included: expenseOreP,
        ore_from_expenses: expenseOreP,
        ore_legacy_smer: smerLegacyOreP, // pre-retirement audit only; 0 on new docs
        status: smer?.status || 'NONE',
        confidence: smer ? statusConfidence(smer.status) : 'NONE'
      },
      core_commission: {
        posted: Math.round(postedComm.total_commission * 100) / 100,
        pending: Math.round((draftComm.total_commission + validComm.total_commission) * 100) / 100,
        total: Math.round(totalCommission * 100) / 100,
        posted_count: postedComm.count,
        pending_count: draftComm.count + validComm.count,
        confidence: postedComm.count > 0 ? 'PARTIAL' : (totalCommission > 0 ? 'PROJECTED' : 'NONE')
      },
      calf_reimbursement: {
        amount: Math.round(calfReimb * 100) / 100,
        confidence: calfReimb > 0 ? 'PROJECTED' : 'NONE'
      },
      profit_sharing: {
        amount: Math.round(profitSharing * 100) / 100,
        confidence: profitSharing > 0 ? 'PROJECTED' : 'NONE'
      },
      bonus: {
        amount: existing?.earnings?.bonus || 0,
        confidence: existing ? 'CONFIRMED' : 'NONE'
      },
      reimbursements: {
        amount: existing?.earnings?.reimbursements || 0,
        confidence: existing ? 'CONFIRMED' : 'NONE'
      }
    },

    deductions: {
      calf_excess: {
        amount: Math.round(calfExcess * 100) / 100,
        confidence: calfExcess > 0 ? 'PROJECTED' : 'NONE'
      },
      personal_gas: {
        amount: personalGas,
        confidence: personalGas > 0 ? 'PROJECTED' : 'NONE'
      },
      schedule_installments: {
        amount: Math.round(scheduleAmount * 100) / 100,
        count: scheduleCount,
        confidence: scheduleCount > 0 ? 'CONFIRMED' : 'NONE'
      },
      manual_lines: {
        amount: Math.round(manualAmount * 100) / 100,
        count: manualLines.length
      }
    },

    calf_summary: {
      total_advance: calfData.total_advance,
      total_liquidated: calfData.total_liquidation,
      balance: calfBalance
    },

    totals: {
      projected_earnings: projectedEarnings,
      total_deductions: totalDeductions,
      projected_net: Math.round((projectedEarnings - totalDeductions) * 100) / 100
    },

    revolving_fund: {
      travel_advance: smer?.travel_advance || 0,
      total_reimbursable: smerAmount,
      balance_on_hand: smer?.balance_on_hand || 0
    }
  };
}

/**
 * Get an existing income report
 */
async function getIncomeReport(entityId, bdmId, period, cycle) {
  return IncomeReport.findOne({
    entity_id: new mongoose.Types.ObjectId(entityId),
    bdm_id: new mongoose.Types.ObjectId(bdmId),
    period,
