/**
 * integrationHooks — Phase SG-6 #32
 *
 * Lookup-driven event bus for Sales Goal lifecycle events. Other ERP modules
 * (payroll batch, accounting close, HR, future integrations) SUBSCRIBE to these
 * events; Sales Goal NEVER imports those modules. Drop-in subscribers: add
 * code in the consuming module, register a listener at startup, done.
 *
 * Design:
 *  - Event NAMES are governed by the `INTEGRATION_EVENTS` Lookup category so
 *    subscribers can SEE what's available from Control Center → Lookup Tables.
 *    An emit() with an unknown event code still fires (never drops a real
 *    event because the lookup was deleted), but logs a warning.
 *  - Listeners are registered in-process via `on(event, handler)`. Payloads
 *    are plain JSON-serializable objects — NO mongoose docs (keep listeners
 *    agnostic of Sales Goal models).
 *  - Emit is FIRE-AND-FORGET. Handler errors are caught per-handler and
 *    logged; one bad listener never blocks the emitting module. This is the
 *    same posture as our notification service — integration contracts must
 *    never crash the primary flow.
 *  - Every emit is also written to ErpAuditLog (log_type: STATUS_CHANGE,
 *    target_model: 'IntegrationEvent') so admins can reconstruct the signal
 *    stream even if a subscriber hadn't registered at the time.
 *
 * Why this exists: without an explicit event bus, payroll/HR/finance have to
 * poll IncentivePayout / SalesGoalPlan for changes — tight coupling, noisy,
 * latency-sensitive. With it, those modules drop in a listener and ship.
 *
 * Reuse: matches the non-blocking pattern in erpNotificationService (notifyX
 * returns a Promise that callers don't await) + the lookup-driven registry
 * pattern from AGENT_CONFIG.
 */

const mongoose = require('mongoose');
const Lookup = require('../models/Lookup');
const ErpAuditLog = require('../models/ErpAuditLog');

// In-process subscriber table. Map<eventCode, Array<handler>>.
// Handlers are functions `(payload) => Promise|void`. Per-event array.
const listeners = new Map();

// Cached set of registered event codes (from INTEGRATION_EVENTS lookup).
// Refreshed on-demand; emit() still runs when the cache is stale so a
// subscriber-created event never silently drops.
let registryCache = null;
let registryCacheAt = 0;
const REGISTRY_TTL_MS = 60 * 1000; // 1 min — matches other ERP caches

// Canonical event codes. Seeded via lookupGenericController SEED_DEFAULTS so
// subscribers see them in Control Center. Adding new codes: extend this list
// AND the seed; legacy subscribers keep working because emit() is permissive.
const INTEGRATION_EVENTS = {
  PLAN_ACTIVATED:     'plan.activated',
  PLAN_CLOSED:        'plan.closed',
  PLAN_REOPENED:      'plan.reopened',
  PLAN_VERSIONED:     'plan.versioned',
  PAYOUT_ACCRUED:     'payout.accrued',
  PAYOUT_APPROVED:    'payout.approved',
  PAYOUT_PAID:        'payout.paid',
  PAYOUT_REVERSED:    'payout.reversed',
  DISPUTE_FILED:      'dispute.filed',
  DISPUTE_RESOLVED:   'dispute.resolved',
  TARGET_REVISED:     'target.revised',
  PERSON_AUTO_ENROLLED:      'person.auto_enrolled',
  PERSON_LIFECYCLE_CLOSED:   'person.lifecycle_closed',
};

/**
 * Refresh the registry cache from Lookup.
 * Never throws — a DB hiccup leaves the prior cache in place.
 */
async function loadRegistry(force = false) {
  const now = Date.now();
  if (!force && registryCache && (now - registryCacheAt) < REGISTRY_TTL_MS) return registryCache;
  try {
    const rows = await Lookup.find({
      category: 'INTEGRATION_EVENTS',
      is_active: true,
    }).select('code label metadata').lean();
    registryCache = new Map(rows.map(r => [String(r.code), r]));
    registryCacheAt = now;
    return registryCache;
  } catch (err) {
    console.warn('[integrationHooks] registry cache refresh failed:', err.message);
    return registryCache || new Map();
  }
}

/**
 * Register a listener for an event. Returns an `unsubscribe()` function.
 * Handlers must accept a single `payload` arg; return value is ignored.
 */
function on(eventCode, handler) {
  if (typeof handler !== 'function') {
    throw new Error(`[integrationHooks.on] handler for ${eventCode} must be a function`);
  }
  const code = String(eventCode);
  if (!listeners.has(code)) listeners.set(code, []);
  listeners.get(code).push(handler);
  return () => {
    const list = listeners.get(code) || [];
    const idx = list.indexOf(handler);
    if (idx >= 0) list.splice(idx, 1);
  };
}

/**
 * Emit an event to every registered listener. Non-blocking at the caller —
 * listeners run on the next microtask so emit() returns immediately.
 *
 * payload structure (contract — do NOT embed mongoose docs):
 *   {
 *     event: 'plan.activated',
 *     entity_id: ObjectId | string,
 *     actor_id?: ObjectId | string,
 *     ref?: string,       // e.g. plan.reference, payout._id
 *     data?: object,      // event-specific fields (flat, JSON-safe)
 *     at: ISO timestamp
 *   }
 *
 * ErpAuditLog best-effort: an audit-log failure never breaks emit.
 */
function emit(eventCode, payload = {}) {
  const code = String(eventCode);
  const fullPayload = {
    ...payload,
    event: code,
    at: payload.at || new Date().toISOString(),
  };

  // Audit trail (best-effort) — gives admins a replayable signal stream even
  // if no listener was registered at the time of emission.
  (async () => {
    try {
      if (!payload.entity_id) return;
      await ErpAuditLog.create({
        entity_id: payload.entity_id,
        log_type: 'STATUS_CHANGE',
        target_ref: String(payload.ref || code),
        target_model: 'IntegrationEvent',
        field_changed: 'event',
        old_value: null,
        new_value: code,
        changed_by: payload.actor_id || new mongoose.Types.ObjectId('000000000000000000000000'),
        note: `integration event ${code}: ${safeStringify(payload.data)}`,
      });
    } catch (err) {
      console.warn(`[integrationHooks] audit write skipped for ${code}:`, err.message);
    }
  })();

  // Warn if the event isn't in the registry (subscriber observability) but
  // ALWAYS dispatch — losing a real emit because the lookup row was deleted
  // would be far worse than a stderr line.
  loadRegistry().then((registry) => {
    if (!registry.has(code)) {
      console.warn(`[integrationHooks] emit: ${code} not registered in INTEGRATION_EVENTS lookup (listeners still fire)`);
    }
  }).catch(() => { /* swallow — logged inside loadRegistry */ });

  const handlers = listeners.get(code) || [];
  for (const handler of handlers) {
    // Defer to next microtask so emit() returns synchronously.
    Promise.resolve().then(async () => {
      try {
        await handler(fullPayload);
      } catch (err) {
        console.error(`[integrationHooks] listener for ${code} threw:`, err.message);
      }
    });
  }
}

/**
 * Inspection helper for admin UIs / the future SOX matrix. Returns:
 *   [{ code, label, description, listener_count, enabled }]
 */
async function describeRegistry() {
  const registry = await loadRegistry(true);
  const rows = [];
  for (const [code, entry] of registry.entries()) {
    rows.push({
      code,
      label: entry?.label || code,
      description: entry?.metadata?.description || '',
      listener_count: (listeners.get(code) || []).length,
      enabled: entry?.is_active !== false,
    });
  }
  // Include any built-in code that's missing from the lookup (legacy seeds).
  for (const code of Object.values(INTEGRATION_EVENTS)) {
    if (!registry.has(code)) {
      rows.push({
        code,
        label: code,
        description: '(not yet seeded in INTEGRATION_EVENTS lookup — run seedAllLookups or edit in Control Center)',
        listener_count: (listeners.get(code) || []).length,
        enabled: true,
      });
    }
  }
  rows.sort((a, b) => a.code.localeCompare(b.code));
  return rows;
}

/**
 * Test-only — flush all listeners. Never call from production paths.
 */
function _resetForTests() {
  listeners.clear();
  registryCache = null;
  registryCacheAt = 0;
}

function safeStringify(obj) {
  try { return JSON.stringify(obj).slice(0, 500); }
  catch { return '<unstringifiable>'; }
}

module.exports = {
  INTEGRATION_EVENTS,
  on,
  emit,
  describeRegistry,
  _resetForTests,
};

/**
 * Inter-Company Transfer Service — Dual-Ledger Inventory Movements
 *
 * Handles the SHIPPED and RECEIVED lifecycle steps for inter-company transfers.
 * Source entity stock decreases at SHIPPED (TRANSFER_OUT).
 * Target entity stock increases at RECEIVED (TRANSFER_IN).
 *
 * Also handles product catalog sync: if the target entity doesn't have
 * a ProductMaster record for a transferred product, one is auto-created.
 */
const mongoose = require('mongoose');
const InterCompanyTransfer = require('../models/InterCompanyTransfer');
const InventoryLedger = require('../models/InventoryLedger');
const TransactionEvent = require('../models/TransactionEvent');
const ProductMaster = require('../models/ProductMaster');
const { ROLES } = require('../../constants/roles');
const { journalFromInterCompany } = require('./autoJournal');
const { createAndPostJournal } = require('./journalEngine');
const ErpAuditLog = require('../models/ErpAuditLog');
const User = require('../../models/User');
const { consumeFIFO, consumeSpecificBatch } = require('./fifoEngine');

/**
 * Ship a transfer — APPROVED → SHIPPED
 * Deducts stock from source entity via FIFO engine, creates TRANSFER_OUT ledger entries.
 */
const shipTransfer = async (transferId, shippedBy) => {
  const transfer = await InterCompanyTransfer.findById(transferId);
  if (!transfer) throw new Error('Transfer not found');
  if (transfer.status !== 'APPROVED') {
    throw new Error(`Cannot ship transfer in ${transfer.status} status. Must be APPROVED.`);
  }

  // Use explicit source_bdm_id (warehouse keeper), fallback to first BDM in entity
  let sourceBdmId = transfer.source_bdm_id;
  if (!sourceBdmId) {
    const sourceBdm = await User.findOne({
      entity_id: transfer.source_entity_id,
      role: ROLES.CONTRACTOR,
      isActive: true
    }).select('_id').lean();
    sourceBdmId = sourceBdm ? sourceBdm._id : shippedBy;
  }

  const session = await mongoose.startSession();
  try {
    let sourceEvent;
    await session.withTransaction(async () => {
      const ledgerEntries = [];

      // Phase 17: pass warehouse context to FIFO engine
      const sourceWarehouseId = transfer.source_warehouse_id;
      const fifoOpts = sourceWarehouseId ? { warehouseId: sourceWarehouseId.toString() } : undefined;

      for (const item of transfer.line_items) {
        // Consume stock from source entity/warehouse
        let consumptionPlan;
        if (item.batch_lot_no) {
          const plan = await consumeSpecificBatch(
            transfer.source_entity_id, sourceBdmId,
            item.product_id, item.batch_lot_no, item.qty, fifoOpts
          );
          consumptionPlan = [plan];
        } else {
          consumptionPlan = await consumeFIFO(
            transfer.source_entity_id, sourceBdmId,
            item.product_id, item.qty, fifoOpts
          );
        }

        // Create TRANSFER_OUT ledger entries
        for (const consumed of consumptionPlan) {
          ledgerEntries.push({
            entity_id: transfer.source_entity_id,
            bdm_id: sourceBdmId,
            warehouse_id: sourceWarehouseId || undefined,
            product_id: item.product_id,
            batch_lot_no: consumed.batch_lot_no,
            expiry_date: consumed.expiry_date,
            transaction_type: 'TRANSFER_OUT',
            qty_in: 0,
            qty_out: consumed.qty_consumed,
            recorded_by: shippedBy
          });

          // Store batch info on the line item for receiving
          if (!item.batch_lot_no) {
            item.batch_lot_no = consumed.batch_lot_no;
            item.expiry_date = consumed.expiry_date;
          }
        }
      }

      // Create TransactionEvent for source
      const [event] = await TransactionEvent.create([{
        entity_id: transfer.source_entity_id,
        bdm_id: sourceBdmId,
        event_type: 'IC_SHIPMENT',
        event_date: new Date(),
        document_ref: transfer.transfer_ref,
        payload: {
          transfer_id: transfer._id,
          target_entity_id: transfer.target_entity_id,
          line_items: transfer.line_items
        },
        created_by: shippedBy
      }], { session });

      sourceEvent = event;

      // Create all ledger entries with event_id
      for (const entry of ledgerEntries) {
        entry.event_id = event._id;
        await InventoryLedger.create([entry], { session });
      }

      // Update transfer status
      transfer.status = 'SHIPPED';
      transfer.shipped_by = shippedBy;
      transfer.shipped_at = new Date();
      transfer.source_event_id = event._id;
      await transfer.save({ session });
    });

    await ErpAuditLog.logChange({
      entity_id: transfer.source_entity_id,
      bdm_id: sourceBdmId,
      log_type: 'STATUS_CHANGE',
      target_ref: transfer._id.toString(),
      target_model: 'InterCompanyTransfer',
      field_changed: 'status',
      old_value: 'APPROVED',
      new_value: 'SHIPPED',
      changed_by: shippedBy,
      note: `IC Transfer ${transfer.transfer_ref} shipped: ${transfer.line_items.length} item(s)`
    });

    return transfer;
  } finally {
    await session.endSession();
  }
};

/**
 * Receive a transfer — SHIPPED → RECEIVED
 * Creates TRANSFER_IN ledger entries in target entity.
 * Auto-creates ProductMaster in target entity if not exists (Phase 4B.6).
 */
const receiveTransfer = async (transferId, receivedBy) => {
  const transfer = await InterCompanyTransfer.findById(transferId);
  if (!transfer) throw new Error('Transfer not found');
  if (transfer.status !== 'SHIPPED') {
    throw new Error(`Cannot receive transfer in ${transfer.status} status. Must be SHIPPED.`);
  }

  // Use explicit target_bdm_id, fallback to first BDM in target entity
  let targetBdmId = transfer.target_bdm_id;
  if (!targetBdmId) {
    const targetBdm = await User.findOne({
      entity_id: transfer.target_entity_id,
      role: ROLES.CONTRACTOR,
      isActive: true
    }).select('_id').lean();
    targetBdmId = targetBdm ? targetBdm._id : receivedBy;
  }

  const session = await mongoose.startSession();
  try {
    let targetEvent;
    await session.withTransaction(async () => {
      const ledgerEntries = [];

      // Phase 17: target warehouse context
      const targetWarehouseId = transfer.target_warehouse_id;

      for (const item of transfer.line_items) {
        // Phase 4B.6 — Auto-create product in target entity if not exists
        await syncProductToTargetEntity(
          item.product_id, transfer.source_entity_id,
          transfer.target_entity_id, item.transfer_price, receivedBy
        );

        // Resolve the product_id in target entity
        const sourceProduct = await ProductMaster.findById(item.product_id).lean();
        let targetProduct = await ProductMaster.findOne({
          entity_id: transfer.target_entity_id,
          item_key: sourceProduct?.item_key || item.item_key
        }).lean();

        const targetProductId = targetProduct ? targetProduct._id : item.product_id;

        // Create TRANSFER_IN ledger entry
        ledgerEntries.push({
          entity_id: transfer.target_entity_id,
          bdm_id: targetBdmId,
          warehouse_id: targetWarehouseId || undefined,
          product_id: targetProductId,
          batch_lot_no: item.batch_lot_no || 'TRANSFER',
          expiry_date: item.expiry_date || new Date(Date.now() + 365 * 24 * 60 * 60 * 1000),
          transaction_type: 'TRANSFER_IN',
          qty_in: item.qty,
          qty_out: 0,
          recorded_by: receivedBy
        });
      }

      // Create TransactionEvent for target
      const [event] = await TransactionEvent.create([{
        entity_id: transfer.target_entity_id,
        bdm_id: targetBdmId,
        event_type: 'IC_RECEIPT',
        event_date: new Date(),
        document_ref: transfer.transfer_ref,
        payload: {
          transfer_id: transfer._id,
          source_entity_id: transfer.source_entity_id,
          line_items: transfer.line_items
        },
        created_by: receivedBy
      }], { session });

      targetEvent = event;

      // Create all ledger entries
      for (const entry of ledgerEntries) {
        entry.event_id = event._id;
        await InventoryLedger.create([entry], { session });
      }

      // Update transfer status
      transfer.status = 'RECEIVED';
      transfer.received_by = receivedBy;
      transfer.received_at = new Date();
      transfer.target_event_id = event._id;
      await transfer.save({ session });
    });

    await ErpAuditLog.logChange({
      entity_id: transfer.target_entity_id,
      bdm_id: targetBdmId,
      log_type: 'STATUS_CHANGE',
      target_ref: transfer._id.toString(),
      target_model: 'InterCompanyTransfer',
      field_changed: 'status',
      old_value: 'SHIPPED',
      new_value: 'RECEIVED',
      changed_by: receivedBy,
      note: `IC Transfer ${transfer.transfer_ref} received: ${transfer.line_items.length} item(s)`
    });

    return transfer;
  } finally {
    await session.endSession();
  }
};

/**
 * Post a transfer — RECEIVED → POSTED (final, immutable)
 */
const postTransfer = async (transferId, postedBy) => {
  const transfer = await InterCompanyTransfer.findById(transferId);
  if (!transfer) throw new Error('Transfer not found');
  if (transfer.status !== 'RECEIVED') {
    throw new Error(`Cannot post transfer in ${transfer.status} status. Must be RECEIVED.`);
  }

  // Period lock check
  const { checkPeriodOpen, dateToPeriod } = require('../utils/periodLock');
  const period = dateToPeriod(transfer.received_at || new Date());
  await checkPeriodOpen(transfer.source_entity_id, period);

  transfer.status = 'POSTED';
  transfer.posted_by = postedBy;
  transfer.posted_at = new Date();
  await transfer.save();

  // Generate AR/AP TransactionEvents — MG owes VIP for the transferred stock
  const sourceBdmId = transfer.source_bdm_id || postedBy;
  const targetBdmId = transfer.target_bdm_id || postedBy;

  // AR: source entity (VIP) is owed money by target entity (MG)
  await TransactionEvent.create({
    entity_id: transfer.source_entity_id,
    bdm_id: sourceBdmId,
    event_type: 'IC_AR',
    event_date: new Date(),
    document_ref: transfer.transfer_ref,
    payload: {
      transfer_id: transfer._id,
      amount: transfer.total_amount,
      debtor_entity_id: transfer.target_entity_id,
      line_items: transfer.line_items
    },
    created_by: postedBy
  });

  // AP: target entity (MG) owes money to source entity (VIP)
  await TransactionEvent.create({
    entity_id: transfer.target_entity_id,
    bdm_id: targetBdmId,
    event_type: 'IC_AP',
    event_date: new Date(),
    document_ref: transfer.transfer_ref,
    payload: {
      transfer_id: transfer._id,
      amount: transfer.total_amount,
      creditor_entity_id: transfer.source_entity_id,
      line_items: transfer.line_items
    },
    created_by: postedBy
  });

  // Journal entries for IC AR/AP
  const amount = transfer.total_amount || 0;
  if (amount > 0) {
    try {
      // Sender JE: DR 1150 IC Receivable, CR 1200 Inventory
      const senderJe = await journalFromInterCompany(transfer, 'SENDER', amount, postedBy);
      if (senderJe) await createAndPostJournal(transfer.source_entity_id, senderJe);

      // Receiver JE: DR 1200 Inventory, CR 2050 IC Payable
      const receiverJe = await journalFromInterCompany(transfer, 'RECEIVER', amount, postedBy);
      if (receiverJe) await createAndPostJournal(transfer.target_entity_id, receiverJe);
    } catch (jeErr) {
      console.error('[AUTO_JOURNAL_FAILURE] ICTransfer', transfer.transfer_ref, jeErr.message);
    }
  }

  await ErpAuditLog.logChange({
    entity_id: transfer.source_entity_id,
    log_type: 'STATUS_CHANGE',
    target_ref: transfer._id.toString(),
    target_model: 'InterCompanyTransfer',
    field_changed: 'status',
    old_value: 'RECEIVED',
    new_value: 'POSTED',
    changed_by: postedBy,
    note: `IC Transfer ${transfer.transfer_ref} posted (final) — AR/AP + JEs created for ₱${transfer.total_amount}`
  });

  return transfer;
};

/**
 * Cancel a transfer — DRAFT/APPROVED → CANCELLED
 * If SHIPPED: reverse by creating ADJUSTMENT entries to restore source stock.
 */
const cancelTransfer = async (transferId, cancelledBy, reason) => {
  const transfer = await InterCompanyTransfer.findById(transferId);
  if (!transfer) throw new Error('Transfer not found');

  if (['POSTED', 'CANCELLED'].includes(transfer.status)) {
    throw new Error(`Cannot cancel transfer in ${transfer.status} status`);
  }

  const oldStatus = transfer.status;

  // If SHIPPED, reverse the TRANSFER_OUT entries
  if (transfer.status === 'SHIPPED') {
    const sourceBdm = await User.findOne({
      entity_id: transfer.source_entity_id,
      role: ROLES.CONTRACTOR,
      isActive: true
    }).select('_id').lean();
    const sourceBdmId = sourceBdm ? sourceBdm._id : cancelledBy;

    for (const item of transfer.line_items) {
      await InventoryLedger.create({
        entity_id: transfer.source_entity_id,
        bdm_id: sourceBdmId,
        warehouse_id: transfer.source_warehouse_id || undefined,
        product_id: item.product_id,
        batch_lot_no: item.batch_lot_no || 'REVERSAL',
        expiry_date: item.expiry_date || new Date(),
        transaction_type: 'ADJUSTMENT',
        qty_in: item.qty,
        qty_out: 0,
        recorded_by: cancelledBy
      });
    }
  }

  // If RECEIVED, also reverse the TRANSFER_IN entries in target
  if (transfer.status === 'RECEIVED') {
    const targetBdm = await User.findOne({
      entity_id: transfer.target_entity_id,
      role: ROLES.CONTRACTOR,
      isActive: true
    }).select('_id').lean();
    const targetBdmId = targetBdm ? targetBdm._id : cancelledBy;

    for (const item of transfer.line_items) {
      // Reverse target TRANSFER_IN
      await InventoryLedger.create({
        entity_id: transfer.target_entity_id,
        bdm_id: targetBdmId,
        warehouse_id: transfer.target_warehouse_id || undefined,
        product_id: item.product_id,
        batch_lot_no: item.batch_lot_no || 'REVERSAL',
        expiry_date: item.expiry_date || new Date(),
        transaction_type: 'ADJUSTMENT',
        qty_in: 0,
        qty_out: item.qty,
        recorded_by: cancelledBy
      });
    }

    // Also reverse source TRANSFER_OUT
    const sourceBdm = await User.findOne({
      entity_id: transfer.source_entity_id,
      role: ROLES.CONTRACTOR,
      isActive: true
    }).select('_id').lean();
    const sourceBdmId = sourceBdm ? sourceBdm._id : cancelledBy;

    for (const item of transfer.line_items) {
      await InventoryLedger.create({
        entity_id: transfer.source_entity_id,
        bdm_id: sourceBdmId,
        warehouse_id: transfer.source_warehouse_id || undefined,
        product_id: item.product_id,
        batch_lot_no: item.batch_lot_no || 'REVERSAL',
        expiry_date: item.expiry_date || new Date(),
        transaction_type: 'ADJUSTMENT',
        qty_in: item.qty,
        qty_out: 0,
        recorded_by: cancelledBy
      });
    }
  }

  transfer.status = 'CANCELLED';
  transfer.cancelled_by = cancelledBy;
  transfer.cancelled_at = new Date();
  transfer.cancel_reason = reason || '';
  await transfer.save();

  await ErpAuditLog.logChange({
    entity_id: transfer.source_entity_id,
    log_type: 'STATUS_CHANGE',
    target_ref: transfer._id.toString(),
    target_model: 'InterCompanyTransfer',
    field_changed: 'status',
    old_value: oldStatus,
    new_value: 'CANCELLED',
    changed_by: cancelledBy,
    note: `IC Transfer ${transfer.transfer_ref} cancelled: ${reason || 'No reason'}`
  });

  return transfer;
};

/**
 * Phase 4B.6 — Sync product to target entity on transfer receive.
 * If target entity doesn't have a ProductMaster record for this product, auto-create one.
 */
async function syncProductToTargetEntity(sourceProductId, sourceEntityId, targetEntityId, transferPrice, userId) {
  const sourceProduct = await ProductMaster.findById(sourceProductId).lean();
  if (!sourceProduct) return;

  // Check if product already exists in target entity
  const existing = await ProductMaster.findOne({
    entity_id: targetEntityId,
    item_key: sourceProduct.item_key
  }).lean();

  if (existing) {
    // Flag price discrepancy if transfer_price != purchase_price
    if (transferPrice && existing.purchase_price !== transferPrice) {
      await ErpAuditLog.logChange({
        entity_id: targetEntityId,
        log_type: 'PRICE_CHANGE',
        target_ref: existing._id.toString(),
        target_model: 'ProductMaster',
        field_changed: 'purchase_price_discrepancy',
        old_value: existing.purchase_price,
        new_value: transferPrice,
        changed_by: userId,
        note: `Transfer price (${transferPrice}) differs from target purchase_price (${existing.purchase_price})`
      });
    }
    return;
  }

  // Auto-create in target entity
  await ProductMaster.create({
    entity_id: targetEntityId,
    item_key: sourceProduct.item_key,
    brand_name: sourceProduct.brand_name,
    generic_name: sourceProduct.generic_name,
    dosage_strength: sourceProduct.dosage_strength,
    sold_per: sourceProduct.sold_per,
    unit_code: sourceProduct.unit_code,
    vat_status: sourceProduct.vat_status,
    category: sourceProduct.category,
    purchase_price: transferPrice || sourceProduct.selling_price,
    selling_price: transferPrice || sourceProduct.selling_price,
    added_by: userId
  });

  await ErpAuditLog.logChange({
    entity_id: targetEntityId,
    log_type: 'ITEM_CHANGE',
    target_model: 'ProductMaster',
    field_changed: 'auto_created',
    new_value: sourceProduct.item_key,
    changed_by: userId,
    note: `Product auto-created from IC transfer: ${sourceProduct.brand_name} (${sourceProduct.item_key})`
  });
}

module.exports = {
  shipTransfer,
  receiveTransfer,
  postTransfer,
  cancelTransfer,
  syncProductToTargetEntity
};

/**
 * Journal Entry Engine — core double-entry posting service
 *
 * PRD v5 §11.3 — Create, post, reverse journal entries.
 * Uses DocSequence for auto-incrementing JE numbers per entity per year.
 * Reversal uses SAP Storno pattern (new opposite JE, original stays POSTED).
 */
const mongoose = require('mongoose');
const JournalEntry = require('../models/JournalEntry');
const VatLedger = require('../models/VatLedger');
const CwtLedger = require('../models/CwtLedger');
const { generateJeNumber } = require('./docNumbering');

/**
 * Create a journal entry in DRAFT status with auto-assigned JE number
 * @param {String} entityId
 * @param {Object} data — { je_date, period, description, source_module, lines[], bir_flag, vat_flag, bdm_id, source_event_id, source_doc_ref, created_by }
 * @returns {Object} created JournalEntry document
 */
async function createJournal(entityId, data) {
  const jeNumber = await generateJeNumber({ entityId, date: data.je_date });

  const je = await JournalEntry.create({
    entity_id: entityId,
    bdm_id: data.bdm_id || null,
    je_number: jeNumber,
    je_date: data.je_date,
    period: data.period,
    description: data.description,
    source_module: data.source_module,
    source_event_id: data.source_event_id || null,
    source_doc_ref: data.source_doc_ref || null,
    lines: data.lines,
    bir_flag: data.bir_flag || 'BOTH',
    vat_flag: data.vat_flag || 'N/A',
    status: 'DRAFT',
    created_by: data.created_by
  });

  return je;
}

/**
 * Post a DRAFT journal entry — validates DR=CR balance
 * @param {String} jeId — JournalEntry _id
 * @param {String} userId — who is posting
 * @param {String} entityId — entity scope (prevents cross-entity posting)
 * @returns {Object} posted JournalEntry
 */
async function postJournal(jeId, userId, entityId) {
  const query = { _id: jeId };
  if (entityId) query.entity_id = entityId;

  const je = await JournalEntry.findOne(query);
  if (!je) throw new Error('Journal entry not found');
  if (je.status !== 'DRAFT') throw new Error(`Cannot post JE in status: ${je.status}`);

  je.status = 'POSTED';
  je.posted_by = userId;
  je.posted_at = new Date();
  await je.save(); // pre-save validates DR=CR balance

  return je;
}

/**
 * Create and immediately post a journal entry (convenience for auto-journals)
 * @param {String} entityId
 * @param {Object} data — same as createJournal
 * @param {Object} [options] — { session } for transaction support
 * @returns {Object} posted JournalEntry
 */
async function createAndPostJournal(entityId, data, options = {}) {
  // Phase SG-Q2 W3 — thread `session` into JE# allocation so the entire
  // accrual flow (sequence bump + JE create + payout upsert) commits together.
  const jeNumber = await generateJeNumber({ entityId, date: data.je_date, session: options.session });

  const doc = {
    entity_id: entityId,
    bdm_id: data.bdm_id || null,
    je_number: jeNumber,
    je_date: data.je_date,
    period: data.period,
    description: data.description,
    source_module: data.source_module,
    source_event_id: data.source_event_id || null,
    source_doc_ref: data.source_doc_ref || null,
    lines: data.lines,
    bir_flag: data.bir_flag || 'BOTH',
    vat_flag: data.vat_flag || 'N/A',
    status: 'POSTED',
    is_reversal: data.is_reversal || false,
    // Omit corrects_je_id when absent so the unique+sparse index (JournalEntry.js)
    // excludes the doc. Writing `null` would still be indexed → E11000 on 2nd insert.
    ...(data.corrects_je_id ? { corrects_je_id: data.corrects_je_id } : {}),
    posted_by: data.created_by,
    posted_at: new Date(),
    created_by: data.created_by
  };

  const createOpts = options.session ? { session: options.session } : {};
  const [je] = await JournalEntry.create([doc], createOpts);

  return je;
}

/**
 * Reverse a POSTED journal entry (SAP Storno pattern)
 * Creates a NEW JE with all amounts flipped. Original stays POSTED.
 * Uses MongoDB transaction for atomicity.
 * @param {String} jeId — original JE _id
 * @param {String} reason — reversal reason
 * @param {String} userId — who is reversing
 * @param {String} entityId — entity scope (prevents cross-entity reversal)
 * @returns {Object} reversal JournalEntry
 */
async function reverseJournal(jeId, reason, userId, entityId) {
  const session = await mongoose.startSession();
  session.startTransaction();

  try {
    const query = { _id: jeId };
    if (entityId) query.entity_id = entityId;

    const original = await JournalEntry.findOne(query).session(session);
    if (!original) throw new Error('Journal entry not found');
    if (original.status !== 'POSTED') throw new Error('Only POSTED entries can be reversed');

    // Check not already reversed
    const existing = await JournalEntry.findOne({ corrects_je_id: original._id }).session(session);
    if (existing) throw new Error(`JE already reversed by ${existing.je_number}`);

    // Flip debit/credit on each line
    const reversedLines = original.lines.map(line => ({
      account_code: line.account_code,
      account_name: line.account_name,
      debit: line.credit,
      credit: line.debit,
      description: line.description ? `Reversal: ${line.description}` : 'Reversal',
      bdm_id: line.bdm_id,
      cost_center: line.cost_center
    }));

    // Derive period from reversal date (not original)
    const now = new Date();
    const reversalPeriod = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;

    const reversal = await createAndPostJournal(original.entity_id, {
      je_date: now,
      period: reversalPeriod,
      description: `Reversal of ${original.je_number}: ${reason || ''}`.trim(),
      source_module: original.source_module,
      source_event_id: original.source_event_id,
      lines: reversedLines,
      bir_flag: original.bir_flag,
      vat_flag: original.vat_flag,
      created_by: userId,
      is_reversal: true,
      corrects_je_id: original._id
    }, { session });

    // Clean up VAT/CWT ledger entries linked to the original source event
    if (original.source_event_id) {
      await VatLedger.deleteMany({ source_event_id: original.source_event_id }).session(session);
      await CwtLedger.deleteMany({ entity_id: original.entity_id, cr_no: original.source_doc_ref }).session(session);
    }

    await session.commitTransaction();
    return reversal;
  } catch (err) {
    await session.abortTransaction();
    throw err;
  } finally {
    session.endSession();
  }
}

/**
 * List journal entries for a period with optional filters
 * @param {String} entityId
 * @param {Object} filters — { period, source_module, status, page, limit }
 * @returns {Object} { data, total, page, limit }
 */
async function getJournalsByPeriod(entityId, filters = {}) {
  const query = { entity_id: entityId };
  if (filters.period) query.period = filters.period;
  if (filters.source_module) query.source_module = filters.source_module;
  if (filters.status) query.status = filters.status;
  if (filters.bdm_id) query.bdm_id = filters.bdm_id;

  const page = parseInt(filters.page) || 1;
  const limit = parseInt(filters.limit) || 50;
  const skip = (page - 1) * limit;

  // Chronological sort: je_date first, then created_at as tiebreaker. String
  // je_number sort would be lexical (MMDDYY doesn't sort across years) so we
  // cannot rely on it for ordering — numbering is for identification, not order.
  const [data, total] = await Promise.all([
    JournalEntry.find(query)
      .sort({ je_date: -1, created_at: -1 })
      .skip(skip)
      .limit(limit)
      .lean(),
    JournalEntry.countDocuments(query)
  ]);

  return { data, total, page, limit };
}

/**
 * General Ledger — all POSTED JE lines for a specific account
 * @param {String} entityId
 * @param {String} accountCode
 * @param {Object} dateRange — { from, to } (YYYY-MM-DD)
 * @returns {Array} ledger entries with running balance
 */
async function getGeneralLedger(entityId, accountCode, dateRange = {}) {
  const match = {
    entity_id: entityId,
    status: 'POSTED',
    'lines.account_code': accountCode
  };
  if (dateRange.from) match.je_date = { $gte: new Date(dateRange.from) };
  if (dateRange.to) {
    match.je_date = match.je_date || {};
    match.je_date.$lte = new Date(dateRange.to);
  }

  const entries = await JournalEntry.find(match)
    .sort({ je_date: 1, created_at: 1 })
    .lean();

  // Extract relevant lines and compute running balance
  let runningBalance = 0;
  const ledger = [];

  for (const je of entries) {
    for (const line of je.lines) {
      if (line.account_code === accountCode) {
        runningBalance += (line.debit || 0) - (line.credit || 0);
        ledger.push({
          je_id: je._id,
          je_number: je.je_number,
          je_date: je.je_date,
          period: je.period,
          description: line.description || je.description,
          source_module: je.source_module,
          debit: line.debit || 0,
          credit: line.credit || 0,
          running_balance: runningBalance
        });
      }
    }
  }

  return ledger;
}

module.exports = {
  createJournal,
  postJournal,
  createAndPostJournal,
  reverseJournal,
  getJournalsByPeriod,
  getGeneralLedger
};

/**
 * Payslip Calculation Service — Employee / Consultant / Director
 *
 * Phase G1.3 — transparency parity with contractor IncomeReport:
 *   Deductions render as a deduction_lines[] array (label + amount + kind
 *   badge + expandable source). Flat deductions.* fields are DERIVED from the
 *   lines so the JE consumer (autoJournal.journalFromPayroll) keeps working
 *   without changes. Personal Gas auto-emits for employees whose CompProfile
 *   has logbook_eligible=true.
 *
 * Phase G1.4 — DeductionSchedule parity with contractor IncomeReport:
 *   Finance-created schedules with `person_id` populated auto-inject one
 *   installment per matching period+cycle as an auto_source='SCHEDULE' line
 *   (status=PENDING). Installments are marked INJECTED post-save and carry
 *   `schedule_ref` so PayslipView can badge the row INSTALLMENT N/M and
 *   expand the timeline. Finance can verify/correct/reject the line just
 *   like a BDM schedule on IncomeReport.
 *
 * Statutory (auto_source = SSS / PHILHEALTH / PAGIBIG / WITHHOLDING_TAX):
 *   Rebuilt every compute from the lookup-driven rate tables. Not user-
 *   editable. Single VERIFIED line per source.
 *
 * Personal Gas (auto_source = PERSONAL_GAS):
 *   Only emitted when CompProfile.logbook_eligible=true. Always rendered (even
 *   at ₱0) so Finance can confirm the logbook was reviewed this cycle.
 *
 * Manual (auto_source = null):
 *   Cash Advance, Loan Payments, Other Deductions are preserved from the
 *   existing payslip's flat fields on re-compute. Finance can also add per-line
 *   deductions via POST /payroll/:id/deduction-line (Phase G1.4 Finance UI) —
 *   manual lines with auto_source=null and deduction_type from
 *   EMPLOYEE_DEDUCTION_TYPE.
 */
const mongoose = require('mongoose');
const PeopleMaster = require('../models/PeopleMaster');
const CompProfile = require('../models/CompProfile');
const Payslip = require('../models/Payslip');
const CarLogbookEntry = require('../models/CarLogbookEntry');
const DeductionSchedule = require('../models/DeductionSchedule');
const { syncInstallmentStatusForPayslip } = require('./deductionScheduleService');
const { computeSSS } = require('./sssCalc');
const { computePhilHealth } = require('./philhealthCalc');
const { computePagIBIG } = require('./pagibigCalc');
const { computeWithholdingTax } = require('./withholdingTaxCalc');
const { computeDeMinimis } = require('./deMinimisCalc');

// ────────────────────────────────────────────────────────────────────────────
// Deduction-line builders
// ────────────────────────────────────────────────────────────────────────────

/**
 * Build the auto-generated deduction_lines[] from statutory amounts + Personal
 * Gas (when eligible). Called every compute; replaces the previous auto-lines
 * on re-compute (preserving only the manual non-auto_source lines).
 *
 * Lines are VERIFIED by default — these are system-computed, not user-entered.
 * Finance can still override via the existing flat-field path until G1.4 adds
 * per-line verify/correct UI.
 */
function buildAutoDeductionLines({ stat, personalGas, emitPersonalGas, userId }) {
  const now = new Date();
  const lines = [];

  const push = (auto_source, deduction_label, amount, description) => {
    lines.push({
      deduction_type: auto_source,
      deduction_label,
      amount: Math.round((amount || 0) * 100) / 100,
      description: description || '',
      entered_by: userId,
      entered_at: now,
      status: 'VERIFIED',
      auto_source,
    });
  };

  // Statutory — only emit rows with > 0 amounts. Zero-amount statutory lines
  // would clutter the payslip without adding information (unlike Personal Gas,
  // where a ₱0 row proves the logbook was reviewed).
  if ((stat.sss || 0) > 0) push('SSS', 'SSS (Employee Share)', stat.sss, 'Social Security System contribution');
  if ((stat.philhealth || 0) > 0) push('PHILHEALTH', 'PhilHealth (Employee Share)', stat.philhealth, 'PhilHealth premium');
  if ((stat.pagibig || 0) > 0) push('PAGIBIG', 'Pag-IBIG (Employee Share)', stat.pagibig, 'HDMF contribution');
  if ((stat.withholding_tax || 0) > 0) push('WITHHOLDING_TAX', 'Withholding Tax', stat.withholding_tax, 'BIR withholding tax on compensation');

  // Personal Gas — always render for logbook-eligible employees (even at ₱0)
  // so Finance can see the logbook was reviewed this cycle. Suppress entirely
  // for non-eligible employees (office staff without a car) to avoid a
  // meaningless ₱0 row.
  if (emitPersonalGas) {
    lines.push({
      deduction_type: 'PERSONAL_GAS',
      deduction_label: 'Personal Gas Usage',
      amount: Math.round((personalGas || 0) * 100) / 100,
      description: (personalGas || 0) > 0
        ? 'Auto-computed from Car Logbook personal km \u00D7 fuel cost'
        : 'No personal km logged this cycle \u2014 logbook reviewed',
      entered_by: userId,
      entered_at: now,
      status: 'VERIFIED',
      auto_source: 'PERSONAL_GAS',
    });
  }

  return lines;
}

/**
 * Rebuild manual (non-statutory, non-auto) lines from the existing payslip's
 * flat fields. Called when we need to reflect Finance-entered flat-field
 * values in the transparent lines array. Lines keep auto_source=null and are
 * VERIFIED (they came in via a Finance path, not a self-service path).
 *
 * Today the Cash Advance / Loan Payments / Other Deductions flows still set
 * the flat fields directly (no line-level UI yet). This helper ensures the
 * array stays consistent with the flat fields regardless of entry path.
 */
function buildManualLinesFromFlat({ flat, userId }) {
  const now = new Date();
  const lines = [];
  const entries = [
    ['CASH_ADVANCE', 'Cash Advance', flat.cash_advance],
    ['LOAN', 'Loan Payment', flat.loan_payments],
    ['OTHER', 'Other Deduction', flat.other_deductions],
  ];
  for (const [code, label, amount] of entries) {
    if ((amount || 0) > 0) {
      lines.push({
        deduction_type: code,
        deduction_label: label,
        amount: Math.round(amount * 100) / 100,
        description: '',
        entered_by: userId,
        entered_at: now,
        status: 'VERIFIED',
        auto_source: null,
      });
    }
  }
  return lines;
}

/**
 * Derive the flat deductions.* fields from deduction_lines. Keeps the JE
 * consumer (autoJournal.journalFromPayroll) working unchanged — it reads
 * the flat fields, we keep them in sync with the array.
 */
function deriveFlatFromLines(lines) {
  const flat = {
    sss_employee: 0,
    philhealth_employee: 0,
    pagibig_employee: 0,
    withholding_tax: 0,
    cash_advance: 0,
    loan_payments: 0,
    other_deductions: 0,
  };
  for (const l of (lines || [])) {
    if (l.status === 'REJECTED') continue;
    switch (l.auto_source) {
      case 'SSS': flat.sss_employee += l.amount || 0; break;
      case 'PHILHEALTH': flat.philhealth_employee += l.amount || 0; break;
      case 'PAGIBIG': flat.pagibig_employee += l.amount || 0; break;
      case 'WITHHOLDING_TAX': flat.withholding_tax += l.amount || 0; break;
      case 'PERSONAL_GAS': flat.other_deductions += l.amount || 0; break;
      // Phase G1.4 — schedule installments fall into the bucket their
      // deduction_type identifies (LOAN → loan_payments, CASH_ADVANCE →
      // cash_advance, everything else → other_deductions). Matches the
      // JE treatment on autoJournal.journalFromPayroll where loan payments
      // credit a different COA than generic other-deductions.
      case 'SCHEDULE': {
        if (l.deduction_type === 'CASH_ADVANCE') flat.cash_advance += l.amount || 0;
        else if (l.deduction_type === 'LOAN') flat.loan_payments += l.amount || 0;
        else flat.other_deductions += l.amount || 0;
        break;
      }
      // Manual lines go to their canonical bucket by deduction_type, not by
      // auto_source (auto_source is null for manual).
      default: {
        if (l.deduction_type === 'CASH_ADVANCE') flat.cash_advance += l.amount || 0;
        else if (l.deduction_type === 'LOAN') flat.loan_payments += l.amount || 0;
        else flat.other_deductions += l.amount || 0;
      }
    }
  }
  for (const k of Object.keys(flat)) flat[k] = Math.round(flat[k] * 100) / 100;
  return flat;
}

/**
 * Phase G1.4 — Load active employee DeductionSchedules and build auto-inject
 * lines for the current period + cycle. Mirrors the BDM path in
 * incomeCalc.generateIncomeReport (lines ~162-193) so the two stay in lockstep.
 *
 * Only PENDING installments of ACTIVE schedules owned by this person are
 * injected. target_cycle filtering matches the caller's cycle; legacy
 * schedules without target_cycle are treated as "all cycles" (same permissive
 * default used on the BDM side for migration safety).
 */
async function buildScheduleLinesForPerson({ entityId, personId, period, cycle, userId }) {
  if (!personId) return [];
  const activeSchedules = await DeductionSchedule.find({
    entity_id: new mongoose.Types.ObjectId(entityId),
    person_id: new mongoose.Types.ObjectId(personId),
    status: 'ACTIVE',
    $or: [
      { target_cycle: cycle },
      { target_cycle: { $exists: false } }
    ],
    installments: { $elemMatch: { period, status: 'PENDING' } }
  }).lean();

  const lines = [];
  for (const sched of activeSchedules) {
    const inst = sched.installments.find(i => i.period === period && i.status === 'PENDING');
    if (inst) {
      lines.push({
        deduction_type: sched.deduction_type,
        deduction_label: sched.deduction_label,
        amount: inst.amount,
        description: `${sched.description || sched.deduction_label} (${inst.installment_no}/${sched.term_months})`,
        entered_by: userId,
        entered_at: new Date(),
        status: 'PENDING',
        auto_source: 'SCHEDULE',
        schedule_ref: {
          schedule_id: sched._id,
          installment_id: inst._id
        }
      });
    }
  }
  return lines;
}

/**
 * Phase G1.4 — after saving a payslip, mark any newly injected SCHEDULE-sourced
 * lines' installments as INJECTED on the DeductionSchedule. Non-blocking — we
 * log and move on so a transient schedule-save failure doesn't revert the
 * payslip (the payslip is the source of truth for the employee's paycheck).
 */
async function _syncInjectedInstallmentsForPayslip(payslip) {
  const schedLines = (payslip.deduction_lines || []).filter(
    l => l.auto_source === 'SCHEDULE' && l.schedule_ref?.schedule_id && l.status === 'PENDING'
  );
  for (const line of schedLines) {
    try {
      await syncInstallmentStatusForPayslip(
        line.schedule_ref.schedule_id,
        line.schedule_ref.installment_id,
        'INJECTED',
        payslip._id,
        line._id
      );
    } catch (err) {
      console.error('Payslip schedule injection sync (non-blocking):', err.message);
    }
  }
}

/**
 * Personal-gas aggregation for employees — mirrors incomeCalc's CarLogbook
 * query. Keyed on entity + person (via PeopleMaster.user_id) + period + cycle.
 *
 * Employees typically won't have a Car Logbook today, so the aggregation
 * returns 0. The gate is CompProfile.logbook_eligible; if that flag is true
 * and the person_id's linked user has car logbook entries, they aggregate.
 */
async function aggregatePersonalGas(entityId, userId, period, cycle) {
  if (!userId) return 0;
  const match = {
    entity_id: new mongoose.Types.ObjectId(entityId),
    bdm_id: new mongoose.Types.ObjectId(userId),
    period,
    status: { $in: ['POSTED', 'VALID'] },
  };
  if (cycle && cycle !== 'MONTHLY') match.cycle = cycle;
  const agg = await CarLogbookEntry.aggregate([
    { $match: match },
    { $group: { _id: null, total: { $sum: '$personal_gas_amount' } } },
  ]);
  return Math.round((agg[0]?.total || 0) * 100) / 100;
}

// ────────────────────────────────────────────────────────────────────────────
// Generate / compute
// ────────────────────────────────────────────────────────────────────────────

/**
 * Generate a payslip for a fixed-salary employee.
 * Computes earnings from comp profile, government deductions, and net pay.
 */
async function generateEmployeePayslip(entityId, personId, period, cycle, userId) {
  const person = await PeopleMaster.findById(personId).lean();
  if (!person) throw new Error('Person not found');

  const comp = await CompProfile.getActiveProfile(personId);
  if (!comp) throw new Error(`No active compensation profile for ${person.full_name}`);

  // Prorate for semi-monthly cycles
  const divisor = cycle === 'MONTHLY' ? 1 : 2;

  const earnings = {
    basic_salary: Math.round((comp.basic_salary / divisor) * 100) / 100,
    rice_allowance: Math.round((comp.rice_allowance / divisor) * 100) / 100,
    clothing_allowance: Math.round((comp.clothing_allowance / divisor) * 100) / 100,
    medical_allowance: Math.round((comp.medical_allowance / divisor) * 100) / 100,
    laundry_allowance: Math.round((comp.laundry_allowance / divisor) * 100) / 100,
    transport_allowance: Math.round((comp.transport_allowance / divisor) * 100) / 100,
  };

  // Government deductions (monthly basis, split for semi-monthly)
  const monthlySalary = comp.monthly_gross || comp.basic_salary || 0;
  const sss = await computeSSS(monthlySalary);
  const ph = await computePhilHealth(monthlySalary);
  const pag = await computePagIBIG(monthlySalary);

  // De minimis: compute taxable excess from allowances
  const deMi = await computeDeMinimis(comp);

  // Taxable income: gross - SSS - PhilHealth - PagIBIG - de minimis exempt
  const monthlyTaxable = monthlySalary - sss.employee_share - ph.employee_share - pag.employee_share - deMi.exempt_total + deMi.taxable_excess;
  const annualTaxable = monthlyTaxable * 12;
  const tax = await computeWithholdingTax(annualTaxable);

  const stat = {
    sss: Math.round((sss.employee_share / divisor) * 100) / 100,
    philhealth: Math.round((ph.employee_share / divisor) * 100) / 100,
    pagibig: Math.round((pag.employee_share / divisor) * 100) / 100,
    withholding_tax: Math.round((tax.monthly_tax / divisor) * 100) / 100,
  };

  // Personal gas gate — only aggregate & emit for logbook-eligible employees.
  // Zero-amount row still renders so Finance can confirm the logbook was
  // reviewed. Rule #3: logbook_eligible is a per-person CompProfile flag.
  const emitPersonalGas = !!comp.logbook_eligible;
  const personalGas = emitPersonalGas
    ? await aggregatePersonalGas(entityId, person.user_id, period, cycle)
    : 0;

  const employer_contributions = {
    sss_employer: Math.round((sss.employer_share / divisor) * 100) / 100,
    philhealth_employer: Math.round((ph.employer_share / divisor) * 100) / 100,
    pagibig_employer: Math.round((pag.employer_share / divisor) * 100) / 100,
    ec_employer: Math.round((sss.ec / divisor) * 100) / 100,
  };

  // Snapshot rates for audit
  const gov_rates_snapshot = {
    sss: { employee: sss.employee_share, employer: sss.employer_share, ec: sss.ec },
    philhealth: { employee: ph.employee_share, employer: ph.employer_share },
    pagibig: { employee: pag.employee_share, employer: pag.employer_share },
    tax: { annual_taxable: annualTaxable, annual_tax: tax.annual_tax, monthly_tax: tax.monthly_tax },
    de_minimis: { exempt: deMi.exempt_total, taxable_excess: deMi.taxable_excess },
  };

  // Upsert: preserve manual fields (bonus, reimbursements, cash_advance, loan_payments, other)
  const existing = await Payslip.findOne({ entity_id: entityId, person_id: personId, period, cycle });

  // Preserved manual earnings from existing payslip
  const preservedManual = existing ? {
    bonus: existing.earnings?.bonus || 0,
    reimbursements: existing.earnings?.reimbursements || 0,
    other_earnings: existing.earnings?.other_earnings || 0,
    overtime: existing.earnings?.overtime || 0,
    holiday_pay: existing.earnings?.holiday_pay || 0,
    night_diff: existing.earnings?.night_diff || 0,
    flat_cash_advance: existing.deductions?.cash_advance || 0,
    flat_loan_payments: existing.deductions?.loan_payments || 0,
    flat_other_deductions: existing.deductions?.other_deductions || 0,
  } : {
    bonus: 0, reimbursements: 0, other_earnings: 0,
    overtime: 0, holiday_pay: 0, night_diff: 0,
    flat_cash_advance: 0, flat_loan_payments: 0, flat_other_deductions: 0,
  };

  // Assemble final earnings with preserved manual bits
  earnings.bonus = preservedManual.bonus;
  earnings.reimbursements = preservedManual.reimbursements;
  earnings.other_earnings = preservedManual.other_earnings;
  earnings.overtime = preservedManual.overtime;
  earnings.holiday_pay = preservedManual.holiday_pay;
  earnings.night_diff = preservedManual.night_diff;

  // Build deduction_lines — auto lines rebuilt fresh, manual lines reconstructed
  // from the preserved flat fields. Preserving any already-present user-entered
  // lines (Phase G1.4 per-line Finance UI) is a superset operation: keep
  // non-auto lines whose deduction_type isn't CASH_ADVANCE/LOAN/OTHER (those
  // are the flat-field path).
  const autoLines = buildAutoDeductionLines({
    stat, personalGas, emitPersonalGas, userId,
  });
  const manualLines = buildManualLinesFromFlat({
    flat: {
      cash_advance: preservedManual.flat_cash_advance,
      loan_payments: preservedManual.flat_loan_payments,
      other_deductions: preservedManual.flat_other_deductions,
    },
    userId,
  });
  const preservedFreeformLines = (existing?.deduction_lines || []).filter(l =>
    !l.auto_source &&
    !['CASH_ADVANCE', 'LOAN', 'OTHER'].includes(l.deduction_type)
  );

  // Phase G1.4 — DeductionSchedule injection. Pull active schedules for this
  // person + cycle and emit one PENDING line per matching installment. On
  // re-compute, already-verified/posted schedule lines are preserved (never
  // re-injected); only PENDING-status installments that aren't yet on the
  // payslip generate new lines. Mirrors incomeCalc.generateIncomeReport's
  // preservation logic so the two flows behave identically.
  const scheduleLines = await buildScheduleLinesForPerson({
    entityId, personId, period, cycle, userId,
  });
  const preservedScheduleLines = (existing?.deduction_lines || []).filter(
    l => l.auto_source === 'SCHEDULE' && l.status !== 'PENDING'
  );
  const newScheduleLines = scheduleLines.filter(sl =>
    !preservedScheduleLines.some(el =>
      el.schedule_ref?.installment_id?.toString() === sl.schedule_ref.installment_id.toString()
    )
  );
  const deduction_lines = [
    ...autoLines,
    ...preservedScheduleLines,
    ...newScheduleLines,
    ...manualLines,
    ...preservedFreeformLines,
  ];

  // Derive flat fields from the final lines (keeps JE consumer in sync)
  const deductions = deriveFlatFromLines(deduction_lines);

  if (existing) {
    existing.earnings = earnings;
    existing.deduction_lines = deduction_lines;
    existing.deductions = deductions;
    existing.employer_contributions = employer_contributions;
    existing.person_type = person.person_type;
    existing.comp_profile_snapshot = comp;
    existing.gov_rates_snapshot = gov_rates_snapshot;
    existing.status = 'COMPUTED';
    existing.computed_at = new Date();
    existing.markModified('earnings');
    existing.markModified('deduction_lines');
    existing.markModified('deductions');
    existing.markModified('employer_contributions');
    existing.markModified('comp_profile_snapshot');
    existing.markModified('gov_rates_snapshot');
    await existing.save();
    // Phase G1.4 — mark freshly injected schedule installments as INJECTED
    await _syncInjectedInstallmentsForPayslip(existing);
    return existing;
  }

  const payslip = await Payslip.create({
    entity_id: entityId,
    person_id: personId,
    person_type: person.person_type,
    period,
    cycle,
    earnings,
    deduction_lines,
    deductions,
    employer_contributions,
    comp_profile_snapshot: comp,
    gov_rates_snapshot: gov_rates_snapshot,
    status: 'COMPUTED',
    computed_at: new Date(),
    created_by: userId,
  });

  // Phase G1.4 — mark freshly injected schedule installments as INJECTED
  await _syncInjectedInstallmentsForPayslip(payslip);

  return payslip;
}

/**
 * Generate a BDM payslip — commission-based.
 * BDMs typically get per diem + fuel + commission; government deductions
 * may apply depending on employment type.
 */
async function generateBdmPayslip(entityId, personId, period, cycle, userId) {
  // BDM payslips use the same structure but earnings come from per diem/commission
  // For now, use the same generator with comp profile fields
  return generateEmployeePayslip(entityId, personId, period, cycle, userId);
}

/**
 * Generate a professional / consultation fee payslip.
 *
 * salary_type=PROFESSIONAL_FEE carries a flat `consultation_fee_amount` paid at
 * `consultation_fee_frequency` (ONE_TIME / MONTHLY / SEMI_MONTHLY). No statutory
 * contributions (SSS / PhilHealth / Pag-IBIG / withholding tax on comp), no
 * allowances, no Personal Gas. EWT/other deductions can be added manually via
 * Finance per-line UI if the consultant is BIR-subject.
 *
 * Amount reconciliation between fee frequency and payroll run cycle:
 *   - ONE_TIME × any cycle       → full fee once; refuse if a prior slip exists
 *     for this person in a different (period, cycle) pair.
 *   - MONTHLY  × MONTHLY         → full fee per slip.
 *   - MONTHLY  × SEMI_MONTHLY    → 50/50 split (half per slip).
 *   - SEMI_MONTHLY × MONTHLY     → both halves summed (2 × fee per slip).
 *   - SEMI_MONTHLY × SEMI_MONTHLY → full fee per slip.
 */
async function generateProfessionalFeePayslip(entityId, personId, period, cycle, userId) {
  const person = await PeopleMaster.findById(personId).lean();
  if (!person) throw new Error('Person not found');

  const comp = await CompProfile.getActiveProfile(personId);
  if (!comp) throw new Error(`No active compensation profile for ${person.full_name}`);
  if (comp.salary_type !== 'PROFESSIONAL_FEE') {
    throw new Error(`generateProfessionalFeePayslip requires salary_type=PROFESSIONAL_FEE (got ${comp.salary_type})`);
  }

  const fee = Number(comp.consultation_fee_amount) || 0;
  const freq = comp.consultation_fee_frequency || 'MONTHLY';

  // One-time fee: refuse if this person already has a payslip in a DIFFERENT
  // period/cycle pair. Re-computing the same slip is fine (idempotent).
  if (freq === 'ONE_TIME') {
    const otherSlip = await Payslip.findOne({
      entity_id: entityId,
      person_id: personId,
      $or: [{ period: { $ne: period } }, { cycle: { $ne: cycle } }],
      deletion_event_id: { $exists: false },
    }).select('period cycle').lean();
    if (otherSlip) {
      throw new Error(`One-time professional fee already paid on ${otherSlip.period} (${otherSlip.cycle}). Switch consultation_fee_frequency to MONTHLY or SEMI_MONTHLY for recurring fees.`);
    }
  }

  let feeForThisSlip = 0;
  if (freq === 'ONE_TIME') feeForThisSlip = fee;
  else if (freq === 'MONTHLY' && cycle === 'MONTHLY') feeForThisSlip = fee;
  else if (freq === 'MONTHLY' && cycle === 'SEMI_MONTHLY') feeForThisSlip = fee / 2;
  else if (freq === 'SEMI_MONTHLY' && cycle === 'MONTHLY') feeForThisSlip = fee * 2;
  else if (freq === 'SEMI_MONTHLY' && cycle === 'SEMI_MONTHLY') feeForThisSlip = fee;
  else throw new Error(`Unknown consultation_fee_frequency '${freq}' for ${person.full_name}`);

  feeForThisSlip = Math.round(feeForThisSlip * 100) / 100;

  const earnings = {
    basic_salary: feeForThisSlip,
    rice_allowance: 0,
    clothing_allowance: 0,
    medical_allowance: 0,
    laundry_allowance: 0,
    transport_allowance: 0,
  };

  const existing = await Payslip.findOne({ entity_id: entityId, person_id: personId, period, cycle });

  // Preserve manual earnings (bonus, reimbursements) + manual deduction lines
  // (Finance may have added EWT or other per-line deductions via Phase G1.4 UI).
  const preservedManual = existing ? {
    bonus: existing.earnings?.bonus || 0,
    reimbursements: existing.earnings?.reimbursements || 0,
    other_earnings: existing.earnings?.other_earnings || 0,
    overtime: existing.earnings?.overtime || 0,
    holiday_pay: existing.earnings?.holiday_pay || 0,
    night_diff: existing.earnings?.night_diff || 0,
    flat_cash_advance: existing.deductions?.cash_advance || 0,
    flat_loan_payments: existing.deductions?.loan_payments || 0,
    flat_other_deductions: existing.deductions?.other_deductions || 0,
  } : {
    bonus: 0, reimbursements: 0, other_earnings: 0,
    overtime: 0, holiday_pay: 0, night_diff: 0,
    flat_cash_advance: 0, flat_loan_payments: 0, flat_other_deductions: 0,
  };

  earnings.bonus = preservedManual.bonus;
  earnings.reimbursements = preservedManual.reimbursements;
  earnings.other_earnings = preservedManual.other_earnings;
  earnings.overtime = preservedManual.overtime;
  earnings.holiday_pay = preservedManual.holiday_pay;
  earnings.night_diff = preservedManual.night_diff;

  // No statutory lines. Reconstruct only the manual-flat lines + preserve any
  // freeform Finance-entered lines (e.g. EWT).
  const manualLines = buildManualLinesFromFlat({
    flat: {
      cash_advance: preservedManual.flat_cash_advance,
      loan_payments: preservedManual.flat_loan_payments,
      other_deductions: preservedManual.flat_other_deductions,
    },
    userId,
  });
  const preservedFreeformLines = (existing?.deduction_lines || []).filter(l =>
    !l.auto_source &&
    !['CASH_ADVANCE', 'LOAN', 'OTHER'].includes(l.deduction_type)
  );

  const deduction_lines = [...manualLines, ...preservedFreeformLines];
  const deductions = deriveFlatFromLines(deduction_lines);

  const employer_contributions = {
    sss_employer: 0, philhealth_employer: 0, pagibig_employer: 0, ec_employer: 0,
  };

  if (existing) {
    existing.earnings = earnings;
    existing.deduction_lines = deduction_lines;
    existing.deductions = deductions;
    existing.employer_contributions = employer_contributions;
    existing.person_type = person.person_type;
    existing.comp_profile_snapshot = comp;
    existing.status = 'COMPUTED';
    existing.computed_at = new Date();
    existing.markModified('earnings');
    existing.markModified('deduction_lines');
    existing.markModified('deductions');
    existing.markModified('employer_contributions');
    existing.markModified('comp_profile_snapshot');
    await existing.save();
    return existing;
  }

  return Payslip.create({
    entity_id: entityId,
    person_id: personId,
    person_type: person.person_type,
    period,
    cycle,
    earnings,
    deduction_lines,
    deductions,
    employer_contributions,
    comp_profile_snapshot: comp,
    status: 'COMPUTED',
    computed_at: new Date(),
    created_by: userId,
  });
}

/**
 * Compute 13th month pay for a person for a given year.
 * Formula: (total basic salary earned in year) / 12
 * Tax-exempt up to ₱90,000.
 */
async function computeThirteenthMonth(entityId, personId, year, userId) {
  const payslips = await Payslip.find({
    entity_id: entityId,
    person_id: personId,
    period: { $regex: `^${year}-` },
    status: { $in: ['COMPUTED', 'REVIEWED', 'APPROVED', 'POSTED'] },
  }).lean();

  let totalBasic = 0;
  for (const ps of payslips) {
    totalBasic += ps.earnings?.basic_salary || 0;
  }

  const thirteenthMonth = Math.round((totalBasic / 12) * 100) / 100;
  const period = `${year}-12`;

  // Upsert a special payslip for December
  const existing = await Payslip.findOne({
    entity_id: entityId,
    person_id: personId,
    period,
    cycle: 'MONTHLY',
  });

  if (existing) {
    existing.earnings.thirteenth_month = thirteenthMonth;
    existing.markModified('earnings');
    await existing.save();
    return existing;
  }

  const person = await PeopleMaster.findById(personId).lean();
  return Payslip.create({
    entity_id: entityId,
    person_id: personId,
    person_type: person?.person_type || 'EMPLOYEE',
    period,
    cycle: 'MONTHLY',
    earnings: { thirteenth_month: thirteenthMonth },
    status: 'COMPUTED',
    computed_at: new Date(),
    created_by: userId,
  });
}

// ────────────────────────────────────────────────────────────────────────────
// Transparent breakdown — mirrors getIncomeBreakdown from incomeCalc.js
// ────────────────────────────────────────────────────────────────────────────

/**
 * Lazy backfill: if a historical POSTED payslip has no deduction_lines but
 * carries flat deductions.*, reconstruct the lines in-memory (no DB write).
 * Lets PayslipView.jsx render the new transparent layout for pre-G1.3 docs.
 *
 * Safe to call on every read — returns an array either way. Never mutates
 * the input doc.
 */
function backfillDeductionLines(payslip) {
  if (payslip?.deduction_lines?.length) return payslip.deduction_lines;
  const d = payslip?.deductions || {};
  const lines = [];
  const now = payslip?.computed_at || payslip?.createdAt || new Date();
  const push = (code, label, amount, auto_source) => {
    if ((amount || 0) > 0) {
      lines.push({
        _id: new mongoose.Types.ObjectId(), // synthetic — for React key only
        deduction_type: code,
        deduction_label: label,
        amount: Math.round(amount * 100) / 100,
        description: '(historical — reconstructed for display)',
        entered_at: now,
        status: 'VERIFIED',
        auto_source: auto_source || null,
      });
    }
  };
  push('SSS', 'SSS (Employee Share)', d.sss_employee, 'SSS');
  push('PHILHEALTH', 'PhilHealth (Employee Share)', d.philhealth_employee, 'PHILHEALTH');
  push('PAGIBIG', 'Pag-IBIG (Employee Share)', d.pagibig_employee, 'PAGIBIG');
  push('WITHHOLDING_TAX', 'Withholding Tax', d.withholding_tax, 'WITHHOLDING_TAX');
  push('CASH_ADVANCE', 'Cash Advance', d.cash_advance, null);
  push('LOAN', 'Loan Payment', d.loan_payments, null);
  push('OTHER', 'Other Deduction', d.other_deductions, null);
  return lines;
}

/**
 * Get detailed breakdown for a payslip — fetches Car Logbook entries for the
 * Personal Gas expandable section. Returns null fields for sources that don't
 * apply to this payslip (e.g. no logbook for office staff).
 *
 * Shape mirrors IncomeReport.getIncomeBreakdown so PayslipView.jsx can render
 * with the same components as Income.jsx / MyIncome.jsx.
 */
async function getPayslipBreakdown(payslip) {
  const personId = payslip.person_id?._id || payslip.person_id;
  const entityId = payslip.entity_id?._id || payslip.entity_id;
  const { period, cycle } = payslip;

  const person = await PeopleMaster.findById(personId).select('user_id full_name').lean();
  const userId = person?.user_id;

  // Personal Gas — only resolve if there's a line with auto_source='PERSONAL_GAS'
  const lines = payslip.deduction_lines?.length
    ? payslip.deduction_lines
    : backfillDeductionLines(payslip);
  const hasPersonalGasLine = lines.some(l => l.auto_source === 'PERSONAL_GAS');

  let personalGasBreakdown = null;
  if (hasPersonalGasLine && userId) {
    const match = {
      entity_id: new mongoose.Types.ObjectId(entityId),
      bdm_id: new mongoose.Types.ObjectId(userId),
      period,
      status: { $in: ['POSTED', 'VALID'] },
    };
    if (cycle && cycle !== 'MONTHLY') match.cycle = cycle;
    const logbookEntries = await CarLogbookEntry.find(match).sort({ entry_date: 1 }).lean();

    const summary = {
      total_km: 0, total_personal_km: 0, total_official_km: 0,
      total_fuel_liters: 0, total_fuel_cost: 0, total_personal_gas: 0,
    };
    const entries = logbookEntries.map(e => {
      summary.total_km += e.total_km || 0;
      summary.total_personal_km += e.personal_km || 0;
      summary.total_official_km += e.official_km || 0;
      const entryFuelLiters = (e.fuel_entries || []).reduce((s, f) => s + (f.liters || 0), 0);
      const entryFuelCost = (e.fuel_entries || []).reduce((s, f) => s + (f.total_amount || 0), 0);
      summary.total_fuel_liters += entryFuelLiters;
      summary.total_fuel_cost += entryFuelCost;
      summary.total_personal_gas += e.personal_gas_amount || 0;
      return {
        _id: e._id,
        entry_date: e.entry_date,
        starting_km: e.starting_km,
        ending_km: e.ending_km,
        total_km: e.total_km || 0,
        personal_km: e.personal_km || 0,
        official_km: e.official_km || 0,
        personal_gas_amount: e.personal_gas_amount || 0,
        total_fuel_amount: entryFuelCost,
        fuel_entries: (e.fuel_entries || []).map(f => ({
          station_name: f.station_name,
          liters: f.liters || 0,
          price_per_liter: f.price_per_liter || 0,
          total_amount: f.total_amount || 0,
          payment_mode: f.payment_mode,
        })),
      };
    });
    summary.total_personal_gas = Math.round(summary.total_personal_gas * 100) / 100;
    summary.total_fuel_cost = Math.round(summary.total_fuel_cost * 100) / 100;
    summary.avg_price_per_liter = summary.total_fuel_liters > 0
      ? Math.round((summary.total_fuel_cost / summary.total_fuel_liters) * 100) / 100
      : 0;

    const lineAmount = lines.find(l => l.auto_source === 'PERSONAL_GAS')?.amount || summary.total_personal_gas;
    personalGasBreakdown = {
      total_deduction: lineAmount,
      entry_count: entries.length,
      entries,
      summary,
    };
  }

  // Phase G1.4 — hydrate DeductionSchedule details for every SCHEDULE-sourced
  // line so PayslipView.jsx can render the installment timeline (what's paid,
  // what's pending, remaining balance). Mirrors getIncomeBreakdown's schedules
  // block so both view surfaces use the same shape.
  const scheduleIds = [...new Set(
    lines
      .filter(l => l.auto_source === 'SCHEDULE' && l.schedule_ref?.schedule_id)
      .map(l => l.schedule_ref.schedule_id.toString())
  )];
  const schedulesByKey = {};
  if (scheduleIds.length > 0) {
    const scheds = await DeductionSchedule.find({
      _id: { $in: scheduleIds.map(id => new mongoose.Types.ObjectId(id)) }
    }).lean();
    for (const s of scheds) {
      schedulesByKey[s._id.toString()] = {
        _id: s._id,
        schedule_code: s.schedule_code,
        deduction_type: s.deduction_type,
        deduction_label: s.deduction_label,
        description: s.description,
        total_amount: s.total_amount || 0,
        installment_amount: s.installment_amount || 0,
        term_months: s.term_months || 1,
        start_period: s.start_period,
        target_cycle: s.target_cycle,
        status: s.status,
        remaining_balance: s.remaining_balance || 0,
        installments: (s.installments || []).map(i => ({
          _id: i._id,
          period: i.period,
          installment_no: i.installment_no,
          amount: i.amount,
          status: i.status,
          payslip_id: i.payslip_id || null,
          income_report_id: i.income_report_id || null,
        })),
      };
    }
  }

  return {
    payslip_id: payslip._id,
    period,
    cycle,
    person_name: person?.full_name || 'N/A',
    personal_gas: personalGasBreakdown,
    schedules: schedulesByKey,
  };
}

// Valid workflow transitions
const VALID_TRANSITIONS = {
  review: { from: ['COMPUTED'], to: 'REVIEWED' },
  approve: { from: ['REVIEWED'], to: 'APPROVED' },
  post: { from: ['APPROVED'], to: 'POSTED' },
};

async function transitionPayslipStatus(payslipId, action, userId) {
  const transition = VALID_TRANSITIONS[action];
  if (!transition) throw new Error(`Invalid action: ${action}`);

  const payslip = await Payslip.findById(payslipId);
  if (!payslip) throw new Error('Payslip not found');
  if (!transition.from.includes(payslip.status)) {
    throw new Error(`Cannot ${action} payslip in ${payslip.status} status`);
  }

  payslip.status = transition.to;
  if (action === 'review') { payslip.reviewed_by = userId; payslip.reviewed_at = new Date(); }
  if (action === 'approve') { payslip.approved_by = userId; payslip.approved_at = new Date(); }
  if (action === 'post') { payslip.posted_by = userId; payslip.posted_at = new Date(); }

  await payslip.save();
  return payslip;
}

