/**
 * SMER ↔ CRM Bridge — Pulls MD visit counts from CRM visit logs
 *
 * CRM Visit model tracks every BDM visit to a Doctor (VIP Client / MD):
 *   Visit.user     = BDM who visited
 *   Visit.doctor   = MD/VIP Client visited
 *   Visit.visitDate = date of visit
 *   Visit.status   = 'completed'
 *
 * This bridge counts completed visits per day per BDM to auto-populate
 * the SMER md_count field, which drives per diem tier calculation:
 *   ≥ 8 MDs → FULL (100% per diem)
 *   ≥ 3 MDs → HALF (50% per diem)
 *   < 3 MDs → ZERO (0% per diem)
 *
 * Benefits over manual entry:
 * - Exact count from system (BDM can't miscount)
 * - Audit trail (each count traceable to actual visit records with GPS + photos)
 * - Auto-populated when generating SMER daily entries
 */

const Visit = require('../../models/Visit');
const Doctor = require('../../models/Doctor');
const CarLogbookEntry = require('../models/CarLogbookEntry');

// Manila (UTC+8) — all day boundaries are anchored to Manila calendar days so a
// 1am-Manila visit (which lands at 5pm UTC the previous day) does not drop out
// of the query window when the server runs in UTC. Matches the inline +08:00
// convention used across Visit.js and the aggregation $dateToString below.
const MANILA_TZ = '+08:00';

function toManilaDateKey(date) {
  const d = date instanceof Date ? date : new Date(date);
  return new Date(d.getTime() + 8 * 60 * 60 * 1000).toISOString().slice(0, 10);
}

function manilaDayStart(dateKey) {
  return new Date(`${dateKey}T00:00:00${MANILA_TZ}`);
}

function manilaDayEnd(dateKey) {
  return new Date(`${dateKey}T23:59:59.999${MANILA_TZ}`);
}

/**
 * Get MD visit count for a BDM on a specific date
 * @param {String} bdmUserId - CRM User._id of the BDM
 * @param {Date|String} date - The date to count visits for (Manila calendar day)
 * @returns {Promise<Number>} Count of DISTINCT MDs visited that day (per-person)
 */
async function getDailyMdCount(bdmUserId, date) {
  const dateKey = typeof date === 'string' && /^\d{4}-\d{2}-\d{2}/.test(date)
    ? date.slice(0, 10)
    : toManilaDateKey(date);

  const distinct = await Visit.distinct('doctor', {
    user: bdmUserId,
    visitDate: { $gte: manilaDayStart(dateKey), $lte: manilaDayEnd(dateKey) },
    status: 'completed'
  });
  return distinct.length;
}

/**
 * Get MD visit counts for a BDM across a date range (for SMER generation)
 * Returns a map of date string → visit count
 *
 * Phase G1.5 (Apr 2026):
 * - Optional `skipFlagged` flag — when true, visits with non-empty photoFlags
 *   (duplicate_photo, date_mismatch, etc.) are excluded from the count. Flagged
 *   visits stay in CRM (audit trail preserved); only per-diem credit drops.
 * - `locations` now uses structured `locality, province` from Doctor (per Rule #3 +
 *   user preference for "Iloilo City, Iloilo" style notes). Falls back to raw
 *   clinicOfficeAddress when a legacy doctor has no locality/province yet (post
 *   backfill, all doctors should have these fields).
 *
 * @param {String} bdmUserId
 * @param {Date|String} startDate
 * @param {Date|String} endDate
 * @param {Object} [opts]
 * @param {Boolean} [opts.skipFlagged=false] - Skip visits with photoFlags (per-diem integrity)
 * @returns {Promise<Object>} { "2026-04-01": { md_count, unique_doctors, locations }, ... }
 */
async function getDailyMdCounts(bdmUserId, startDate, endDate, opts = {}) {
  const { skipFlagged = false, source = 'visit' } = opts;

  // Phase G1.6 — dispatch by eligibility source. 'visit' = pharma CRM Visit model
  // (default); 'logbook' = CarLogbook (non-pharma worked-day credit); 'manual'/'none'
  // return empty so expenseController falls back to md_count=0 for every day.
  if (source === 'logbook') return getDailyLogbookCounts(bdmUserId, startDate, endDate);
  if (source === 'manual' || source === 'none') return {};

  // Accept Date objects or YYYY-MM-DD strings; normalize to Manila calendar keys.
  const startKey = typeof startDate === 'string' && /^\d{4}-\d{2}-\d{2}/.test(startDate)
    ? startDate.slice(0, 10)
    : toManilaDateKey(startDate);
  const endKey = typeof endDate === 'string' && /^\d{4}-\d{2}-\d{2}/.test(endDate)
    ? endDate.slice(0, 10)
    : toManilaDateKey(endDate);

  const baseMatch = {
    user: typeof bdmUserId === 'string'
      ? require('mongoose').Types.ObjectId.createFromHexString(bdmUserId)
      : bdmUserId,
    visitDate: { $gte: manilaDayStart(startKey), $lte: manilaDayEnd(endKey) },
    status: 'completed'
  };

  // Phase G1.5 follow-up — match ALL completed visits (no flag pre-filter) and
  // split into flagged vs unflagged inside $group. This lets us return both the
  // counted md_count AND the flagged_excluded count for UI transparency
  // ("X flagged not counted today"). The previous $match-time pre-filter hid
  // flagged drops and made the bridge silently disagree with CRM list view.
  const pipeline = [
    { $match: baseMatch },
    {
      // Group by Manila calendar day (YYYY-MM-DD), de-dup doctors per day.
      // doctors_unflagged uses $cond → null for flagged rows; null is filtered
      // in JS below. Non-flagged visits either omit photoFlags (sparse) or have
      // [] — $size with $ifNull normalizes both shapes.
      $group: {
        _id: {
          $dateToString: { format: '%Y-%m-%d', date: '$visitDate', timezone: MANILA_TZ }
        },
        doctors_all: { $addToSet: '$doctor' },
        doctors_unflagged: {
          $addToSet: {
            $cond: [
              { $eq: [{ $size: { $ifNull: ['$photoFlags', []] } }, 0] },
              '$doctor',
              null
            ]
          }
        }
      }
    },
    {
      $sort: { _id: 1 }
    }
  ];

  const results = await Visit.aggregate(pipeline);

  // Collect all unique doctor IDs across all days to batch-fetch addresses.
  // Use the union of both sets so locations resolve regardless of skipFlagged.
  const allDoctorIds = new Set();
  for (const r of results) {
    for (const docId of r.doctors_all) allDoctorIds.add(docId.toString());
  }
  const doctorMap = new Map();
  if (allDoctorIds.size > 0) {
    const doctors = await Doctor.find({ _id: { $in: [...allDoctorIds] } })
      .select('firstName lastName clinicOfficeAddress locality province').lean();
    for (const d of doctors) doctorMap.set(d._id.toString(), d);
  }

  const counts = {};
  for (const r of results) {
    const unflagged = (r.doctors_unflagged || []).filter(d => d !== null);
    const flaggedCount = r.doctors_all.length - unflagged.length;
    // When skipFlagged is on, md_count + locations come from unflagged set only;
    // otherwise everything counts (and flagged_excluded is reported as 0 since
    // nothing was actually excluded).
    const countedDoctors = skipFlagged ? unflagged : r.doctors_all;

    // Phase G1.5 — build location summary from structured locality+province.
    // Format: "Iloilo City, Iloilo" or "Digos City, Davao del Sur".
    // Fallback to clinicOfficeAddress for pre-backfill legacy doctors.
    const locationLabels = countedDoctors
      .map(id => {
        const d = doctorMap.get(id.toString());
        if (!d) return null;
        if (d.locality && d.province) return `${d.locality}, ${d.province}`;
        if (d.locality) return d.locality;
        if (d.clinicOfficeAddress) return d.clinicOfficeAddress;
        return null;
      })
      .filter(Boolean);
    const uniqueLocations = [...new Set(locationLabels)];

    // md_count is "per-person" — count DISTINCT MDs visited that day, not raw
    // visit rows. The weekly-unique index makes these equal today, but naming
    // them identically removes ambiguity if that constraint ever loosens.
    const uniqueMdCount = countedDoctors.length;
    counts[r._id] = {
      md_count: uniqueMdCount,
      unique_doctors: uniqueMdCount,
      flagged_excluded: skipFlagged ? flaggedCount : 0,
      locations: uniqueLocations.join('; ')
    };
  }
  return counts;
}

/**
 * Phase G1.6 — Logbook-sourced daily credits for non-pharma subscribers.
 *
 * Semantics: 1 POSTED CarLogbookEntry per day with official_km > 0 = 1 worked-day credit.
 * md_count returns the binary 0/1 "did the BDM work?" signal. Admin configures
 * PERDIEM_RATES.{role}.metadata.full_tier_threshold=1 (or similar) so any worked
 * day triggers full per-diem. Locations come from the CarLogbookEntry.destination
 * field (falls back to notes when destination is blank).
 *
 * Why POSTED-only: DRAFT/VALID/ERROR entries are in-progress and not audited.
 * Paying per-diem on an un-posted entry risks double-payment on reopen/edit.
 *
 * @param {String} bdmUserId
 * @param {Date|String} startDate
 * @param {Date|String} endDate
 * @returns {Promise<Object>} Same shape as getDailyMdCounts:
 *   { "2026-04-01": { md_count, unique_doctors, locations }, ... }
 */
async function getDailyLogbookCounts(bdmUserId, startDate, endDate) {
  const startKey = typeof startDate === 'string' && /^\d{4}-\d{2}-\d{2}/.test(startDate)
    ? startDate.slice(0, 10)
    : toManilaDateKey(startDate);
  const endKey = typeof endDate === 'string' && /^\d{4}-\d{2}-\d{2}/.test(endDate)
    ? endDate.slice(0, 10)
    : toManilaDateKey(endDate);

  const mongooseLib = require('mongoose');
  const entries = await CarLogbookEntry.find({
    bdm_id: typeof bdmUserId === 'string'
      ? mongooseLib.Types.ObjectId.createFromHexString(bdmUserId)
      : bdmUserId,
    entry_date: { $gte: manilaDayStart(startKey), $lte: manilaDayEnd(endKey) },
    status: 'POSTED',
    official_km: { $gt: 0 }
  })
    .select('entry_date official_km destination notes')
    .sort({ entry_date: 1 })
    .lean();

  const counts = {};
  for (const e of entries) {
    const dateKey = toManilaDateKey(e.entry_date);
    // If a BDM has multiple POSTED entries on one day (shouldn't happen — cycle
    // wrapper prevents duplicates — but defensive), treat as single worked day.
    if (counts[dateKey]) continue;

    const label = (e.destination && e.destination.trim()) || (e.notes && e.notes.trim()) || '';
    counts[dateKey] = {
      md_count: 1,           // Binary: worked = 1. Threshold config determines tier.
      unique_doctors: 1,     // Kept for response-shape parity with visit source.
      flagged_excluded: 0,   // Logbook source has no photo-flag concept.
      locations: label
    };
  }
  return counts;
}

/**
 * Get detailed drill-down for a BDM on a specific date (for SMER drill-down).
 * Phase G1.6 — dispatches by source. Visit source returns actual doctor rows;
 * logbook source returns a synthetic 1-row summary from the CarLogbookEntry.
 * @param {String} bdmUserId
 * @param {Date|String} date
 * @param {Object} [opts]
 * @param {String} [opts.source='visit'] - 'visit' | 'logbook' | 'manual' | 'none'
 * @returns {Promise<Array>} Visits (or logbook-adapted rows) for the day.
 */
async function getDailyVisitDetails(bdmUserId, date, opts = {}) {
  const { source = 'visit' } = opts;
  const dateKey = typeof date === 'string' && /^\d{4}-\d{2}-\d{2}/.test(date)
    ? date.slice(0, 10)
    : toManilaDateKey(date);

  if (source === 'logbook') {
    const entries = await CarLogbookEntry.find({
      bdm_id: bdmUserId,
      entry_date: { $gte: manilaDayStart(dateKey), $lte: manilaDayEnd(dateKey) },
      status: 'POSTED',
      official_km: { $gt: 0 }
    })
      .select('entry_date official_km destination notes period cycle')
      .lean();

    // Adapt to the same shape the frontend consumes, so the drill-down UI renders
    // destination+km instead of doctor name without a separate template.
    return entries.map(e => ({
      doctor: {
        firstName: 'Logbook',
        lastName: 'Entry',
        specialization: `${e.official_km} km — ${e.cycle || ''}`,
        clinicOfficeAddress: e.destination || e.notes || '',
      },
      visitDate: e.entry_date,
      visitType: 'LOGBOOK',
      engagementTypes: [],
      weekLabel: e.cycle
    }));
  }

  if (source === 'manual' || source === 'none') return [];

  return Visit.find({
    user: bdmUserId,
    visitDate: { $gte: manilaDayStart(dateKey), $lte: manilaDayEnd(dateKey) },
    status: 'completed'
  })
    .populate('doctor', 'firstName lastName specialization clinicOfficeAddress locality province')
    .select('doctor visitDate visitType engagementTypes weekLabel')
    .sort({ visitDate: 1 })
    .lean();
}

module.exports = {
  getDailyMdCount,
  getDailyMdCounts,
  getDailyLogbookCounts,
  getDailyVisitDetails
};

/**
 * Stock Seed Service — Phase 17
 *
 * Reusable logic for importing opening stock balances from parsed CSV rows
 * into InventoryLedger as OPENING_BALANCE entries.
 *
 * Used by:
 *   - importStockOnHand.js (CLI script)
 *   - inventoryController.seedStockOnHand (API endpoint)
 */
const InventoryLedger = require('../models/InventoryLedger');
const ProductMaster = require('../models/ProductMaster');
const Warehouse = require('../models/Warehouse');
const User = require('../../models/User');
const { cleanName } = require('../utils/nameClean');

/**
 * Build BDM name → warehouse code mapping from the database.
 * Resolves manager_id to User.name for each warehouse.
 */
async function buildBdmToWarehouseMap() {
  const warehouses = await Warehouse.find({ is_active: true }).lean();
  const managerIds = warehouses.filter(w => w.manager_id).map(w => w.manager_id);
  const users = await User.find({ _id: { $in: managerIds } }).select('_id name').lean();
  const userMap = new Map(users.map(u => [u._id.toString(), u.name]));

  const mapping = {};
  for (const wh of warehouses) {
    if (wh.manager_id) {
      const name = userMap.get(wh.manager_id.toString());
      if (name) mapping[name] = wh.warehouse_code;
    }
  }
  return mapping;
}

function parseDate(dateStr) {
  if (!dateStr || dateStr === '0' || dateStr.includes('00/00')) return null;
  const cleaned = dateStr.replace(/;/g, '');
  const parsed = new Date(cleaned);
  if (isNaN(parsed.getTime())) return null;
  if (parsed.getFullYear() < 2020) return null;
  return parsed;
}

/**
 * Seed stock from parsed CSV rows.
 * @param {Array<Object>} rows — parsed CSV rows (each row is a key-value object)
 * @param {Object} options
 * @param {boolean} options.hasWarehouseCode — whether rows have WarehouseCode column
 * @returns {Object} { imported, skipped, errors, productUpdated, perWarehouse, unmatchedItems }
 */
async function seedStockFromRows(rows, options = {}) {
  const { hasWarehouseCode = false } = options;

  // Resolve all warehouses from DB
  const warehouses = await Warehouse.find({}).lean();
  const whByCode = new Map(warehouses.map(w => [w.warehouse_code, w]));

  // Build BDM→warehouse fallback from DB (no hardcoding)
  const bdmToWarehouse = await buildBdmToWarehouseMap();

  // Stats
  let imported = 0, skipped = 0, productUpdated = 0, errorCount = 0;
  const perWarehouse = {};
  const unmatchedItems = [];

  for (let i = 0; i < rows.length; i++) {
    const row = rows[i];
    const stockQty = parseInt(row.StockOnHand) || 0;

    // Skip zero-stock inactive items
    if (stockQty <= 0 && String(row.IsActive || '').toUpperCase() === 'FALSE') {
      skipped++;
      continue;
    }

    // Resolve warehouse (coerce to string — XLSX may parse as number)
    const whCode = hasWarehouseCode
      ? String(row.WarehouseCode || row['Warehouse Code'] || '').toUpperCase().trim()
      : bdmToWarehouse[String(row.BDM || '').trim()];

    if (!whCode) {
      unmatchedItems.push({ row: i + 2, brand: row.BrandName, dosage: row.DosageStrength, reason: `No warehouse mapping for BDM "${row.BDM}"` });
      errorCount++;
      continue;
    }

    const warehouse = whByCode.get(whCode);
    if (!warehouse) {
      unmatchedItems.push({ row: i + 2, brand: row.BrandName, dosage: row.DosageStrength, reason: `Warehouse "${whCode}" not found` });
      errorCount++;
      continue;
    }

    const entityId = warehouse.entity_id;
    const managerId = warehouse.manager_id;

    const batchLotNo = row.BatchLotNo || 'OPENING';
    const expiryDate = parseDate(row.ExpiryDate);

    // Match against ProductMaster — DO NOT auto-create
    const itemKey = String(row.ItemKey || `${row.BrandName}|${row.DosageStrength}`).trim();
    const csvBrandClean = cleanName(String(row.BrandName ?? ''));
    const csvDosage = String(row.DosageStrength ?? '').trim();

    // Strategy 1: exact item_key
    let product = await ProductMaster.findOne({ entity_id: entityId, item_key: itemKey }).lean();

    // Strategy 2: brand_name_clean + dosage within entity
    if (!product && csvBrandClean) {
      product = await ProductMaster.findOne({
        entity_id: entityId,
        brand_name_clean: csvBrandClean,
        dosage_strength: csvDosage || { $in: [null, ''] },
      }).lean();
    }

    // Strategy 3: cross-entity
    if (!product && csvBrandClean) {
      product = await ProductMaster.findOne({
        brand_name_clean: csvBrandClean,
        dosage_strength: csvDosage || { $in: [null, ''] },
      }).lean();
    }

    if (!product) {
      unmatchedItems.push({ row: i + 2, brand: row.BrandName, dosage: row.DosageStrength, reason: 'No product match' });
      errorCount++;
      continue;
    }

    // Update prices if currently zero
    const updates = {};
    if (!product.purchase_price && parseFloat(row.PurchasePrice)) updates.purchase_price = parseFloat(row.PurchasePrice);
    if (!product.selling_price && parseFloat(row.SellingPrice)) updates.selling_price = parseFloat(row.SellingPrice);
    if (!product.reorder_min_qty && parseInt(row.MinimalStock)) updates.reorder_min_qty = parseInt(row.MinimalStock);
    if (Object.keys(updates).length) {
      await ProductMaster.updateOne({ _id: product._id }, { $set: updates });
      productUpdated++;
    }

    // Skip zero-stock
    if (stockQty <= 0) {
      skipped++;
      continue;
    }

    // Dedup check
    const existingLedger = await InventoryLedger.findOne({
      entity_id: entityId,
      warehouse_id: warehouse._id,
      product_id: product._id,
      batch_lot_no: batchLotNo,
      transaction_type: 'OPENING_BALANCE',
    }).lean();
    if (existingLedger) {
      skipped++;
      continue;
    }

    // Create OPENING_BALANCE
    await InventoryLedger.create({
      entity_id: entityId,
      bdm_id: managerId,
      warehouse_id: warehouse._id,
      product_id: product._id,
      batch_lot_no: batchLotNo,
      expiry_date: expiryDate || new Date('2030-12-31'),
      transaction_type: 'OPENING_BALANCE',
      qty_in: stockQty,
      qty_out: 0,
      recorded_by: managerId,
    });

    imported++;
    perWarehouse[whCode] = (perWarehouse[whCode] || 0) + 1;
  }

  return { imported, skipped, errors: errorCount, productUpdated, perWarehouse, unmatchedItems };
}

module.exports = { seedStockFromRows, buildBdmToWarehouseMap, parseDate };

/**
 * Three-Way Match Service — Phase 12.3
 *
 * Compares PO line → GRN line → Supplier Invoice line.
 * Match by product_id or item_key; check qty and price within tolerance.
 * Updates invoice match_status and per-line flags.
 */
const SupplierInvoice = require('../models/SupplierInvoice');
const PurchaseOrder = require('../models/PurchaseOrder');
const GrnEntry = require('../models/GrnEntry');

/**
 * Run 3-way matching on a supplier invoice
 * @param {String} invoiceId
 * @param {Number} tolerancePct — price tolerance percentage (default 2%)
 * @returns {Object} { matched_lines[], discrepancy_lines[], unmatched_lines[], overall_status }
 */
async function matchInvoice(invoiceId, tolerancePct = 0.02) {
  const invoice = await SupplierInvoice.findById(invoiceId);
  if (!invoice) throw new Error('Supplier invoice not found');

  // Load PO and GRN if linked; auto-discover PO from GRN when invoice has grn_id but no po_id
  let po = invoice.po_id ? await PurchaseOrder.findById(invoice.po_id).lean() : null;
  const grn = invoice.grn_id ? await GrnEntry.findById(invoice.grn_id).lean() : null;
  if (!po && grn?.po_id) {
    po = await PurchaseOrder.findById(grn.po_id).lean();
  }

  // Build lookup maps — support duplicate product_id by summing qty and averaging price
  const poLineMap = new Map();
  if (po) {
    for (const line of po.line_items) {
      const key = line.product_id ? line.product_id.toString() : line.item_key;
      if (!key) continue;
      const existing = poLineMap.get(key);
      if (existing) {
        existing.qty_ordered += line.qty_ordered;
        // Weighted average unit price
        existing.unit_price = (existing.unit_price * (existing.qty_ordered - line.qty_ordered) + line.unit_price * line.qty_ordered) / existing.qty_ordered;
      } else {
        poLineMap.set(key, { qty_ordered: line.qty_ordered, unit_price: line.unit_price });
      }
    }
  }

  const grnLineMap = new Map();
  if (grn) {
    for (const line of grn.line_items) {
      const key = line.product_id ? line.product_id.toString() : null;
      if (!key) continue;
      const existing = grnLineMap.get(key) || { qty: 0 };
      existing.qty += line.qty;
      grnLineMap.set(key, existing);
    }
  }

  const matched_lines = [];
  const discrepancy_lines = [];
  const unmatched_lines = [];

  for (let i = 0; i < invoice.line_items.length; i++) {
    const invLine = invoice.line_items[i];
    const productKey = invLine.product_id ? invLine.product_id.toString() : null;
    const itemKey = invLine.item_key;

    // Try matching by product_id first, then by item_key
    const poLine = (productKey && poLineMap.get(productKey)) || (itemKey && poLineMap.get(itemKey)) || null;
    const grnLine = productKey ? grnLineMap.get(productKey) : null;

    let poMatch = false;
    let grnMatch = false;
    const discrepancies = [];

    // PO matching
    if (poLine) {
      // Qty check
      if (invLine.qty_invoiced === poLine.qty_ordered) {
        poMatch = true;
      } else {
        discrepancies.push(`PO qty: ordered=${poLine.qty_ordered}, invoiced=${invLine.qty_invoiced}`);
      }
      // Price check (within tolerance)
      if (poLine.unit_price > 0) {
        const priceDiff = Math.abs(invLine.unit_price - poLine.unit_price) / poLine.unit_price;
        if (priceDiff > tolerancePct) {
          poMatch = false;
          discrepancies.push(`Price: PO=${poLine.unit_price}, Invoice=${invLine.unit_price} (diff ${(priceDiff * 100).toFixed(1)}%)`);
        }
      }
    }

    // GRN matching
    if (grnLine) {
      if (invLine.qty_invoiced === grnLine.qty) {
        grnMatch = true;
      } else {
        discrepancies.push(`GRN qty: received=${grnLine.qty}, invoiced=${invLine.qty_invoiced}`);
      }
    }

    // Update per-line flags
    invoice.line_items[i].po_line_matched = poMatch;
    invoice.line_items[i].grn_line_matched = grnMatch;

    const lineResult = {
      index: i,
      product_id: invLine.product_id,
      item_key: invLine.item_key,
      qty_invoiced: invLine.qty_invoiced,
      unit_price: invLine.unit_price,
      po_matched: poMatch,
      grn_matched: grnMatch,
      discrepancies
    };

    if (poMatch && grnMatch) {
      matched_lines.push(lineResult);
    } else if (discrepancies.length > 0) {
      discrepancy_lines.push(lineResult);
    } else {
      unmatched_lines.push(lineResult);
    }
  }

  // Update PO qty_invoiced for matched AND discrepancy lines (ISSUE 8: track invoiced qty regardless of match quality)
  if (po) {
    const poDoc = await PurchaseOrder.findById(invoice.po_id);
    if (poDoc) {
      const invoicedLines = [...matched_lines, ...discrepancy_lines];
      for (const il of invoicedLines) {
        const key = il.product_id ? il.product_id.toString() : null;
        const poLine = poDoc.line_items.find(l =>
          (key && l.product_id?.toString() === key) || (il.item_key && l.item_key === il.item_key)
        );
        if (poLine) {
          poLine.qty_invoiced = Math.max(poLine.qty_invoiced || 0, il.qty_invoiced);
        }
      }
      await poDoc.save();
    }
  }

  // Determine overall status
  let overall_status;
  if (discrepancy_lines.length > 0) {
    overall_status = 'DISCREPANCY';
  } else if (unmatched_lines.length > 0 && matched_lines.length > 0) {
    overall_status = 'PARTIAL_MATCH';
  } else if (matched_lines.length === invoice.line_items.length) {
    overall_status = 'FULL_MATCH';
  } else if (unmatched_lines.length === invoice.line_items.length) {
    overall_status = 'UNMATCHED';
  } else {
    overall_status = 'PARTIAL_MATCH';
  }

  invoice.match_status = overall_status;
  await invoice.save();

  return { matched_lines, discrepancy_lines, unmatched_lines, overall_status };
}

module.exports = { matchInvoice };

/**
 * Undertaking Service — Phase 32R (Apr 20, 2026)
 *
 * The Undertaking is a read-only acknowledgement wrapper auto-created
 * alongside every GRN. Mirrors CALF→Expense direction: GRN is the
 * capture surface (batch, expiry, qty, waybill — validated in createGrn),
 * Undertaking is the approval wrapper BDM submits and approver acknowledges.
 *
 * Module exports:
 *   - autoUndertakingForGrn: copy GRN → DRAFT Undertaking (atomic with GRN create)
 *   - getGrnSetting:         per-entity numeric GRN_SETTINGS lookup (MIN_EXPIRY_DAYS,
 *                            VARIANCE_TOLERANCE_PCT, WAYBILL_REQUIRED). Legacy
 *                            UNDERTAKING_SETTINGS lookup is consulted as fallback
 *                            so Phase 32 deploys that never rename continue to work.
 *   - computeLineVariance:   pure helper — flags QTY_UNDER/QTY_OVER/NEAR_EXPIRY
 *                            from expected/received/expiry using lookup thresholds.
 *
 * Gone from Phase 32 (see project_phase_32_undertaking_apr2026.md):
 *   - syncUndertakingToGrn — the Undertaking no longer overwrites GRN; GRN is the
 *     source of truth so there is nothing to sync back.
 *   - validateUndertaking / validateUndertakingLine — validation now runs in
 *     inventoryController.createGrn (capture time), not at UT submit.
 */
const Undertaking = require('../models/Undertaking');
const GrnEntry = require('../models/GrnEntry');
const Lookup = require('../models/Lookup');

const DEFAULT_MIN_EXPIRY_DAYS = 30;
const DEFAULT_VARIANCE_TOLERANCE_PCT = 10;

/**
 * Read a numeric setting from the GRN_SETTINGS lookup category (with
 * UNDERTAKING_SETTINGS as a compat fallback for deploys that haven't run the
 * rename migration yet).
 *
 * Per-entity configurable; falls back to the passed default on miss.
 * Subscription-ready: subscribers tune their own thresholds in Control Center.
 */
async function getGrnSetting(entityId, code, fallback) {
  if (!entityId) return fallback;
  const categories = ['GRN_SETTINGS', 'UNDERTAKING_SETTINGS']; // legacy fallback
  try {
    const entry = await Lookup.findOne({
      entity_id: entityId,
      category: { $in: categories },
      code,
      is_active: true
    }).lean();
    const value = entry?.metadata?.value;
    if (value === undefined || value === null) return fallback;
    const num = Number(value);
    return Number.isFinite(num) ? num : fallback;
  } catch (err) {
    console.error(`[undertakingService] getGrnSetting failed for ${code}:`, err.message);
    return fallback;
  }
}

/**
 * Auto-create a DRAFT Undertaking alongside a newly-created GRN.
 * Called from inventoryController.createGrn within a MongoDB session
 * so both docs roll back together (global rule #20).
 *
 * Phase 32R: the Undertaking is a pure mirror of GRN capture data.
 * Batch/lot, expiry, received qty, and waybill already live on the GRN —
 * the Undertaking mirrors line fields so the Approval Hub can render
 * a self-contained card without joining, but the GRN is the source.
 *
 * @param {Object} grn - the just-created GrnEntry document
 * @param {Object} [opts]
 * @param {mongoose.ClientSession} [opts.session]
 * @returns {Promise<Object>} the created Undertaking
 */
async function autoUndertakingForGrn(grn, { session } = {}) {
  if (!grn) throw new Error('autoUndertakingForGrn: grn is required');
  if (!grn._id) throw new Error('autoUndertakingForGrn: grn must be persisted first');

  const varianceTolerancePct = await getGrnSetting(
    grn.entity_id, 'VARIANCE_TOLERANCE_PCT', DEFAULT_VARIANCE_TOLERANCE_PCT
  );

  const lineItems = (grn.line_items || []).map(li => {
    const expected = Number(li.expected_qty != null ? li.expected_qty : li.qty) || 0;
    const received = Number(li.qty) || 0;
    const variance_flag = computeLineVariance({
      expected_qty: expected,
      received_qty: received,
      expiry_date: li.expiry_date,
      variance_tolerance_pct: varianceTolerancePct
    });
    return {
      product_id: li.product_id,
      item_key: li.item_key,
      po_line_index: li.po_line_index,
      expected_qty: expected,
      received_qty: received,
      batch_lot_no: li.batch_lot_no || '',
      expiry_date: li.expiry_date || null,
      purchase_uom: li.purchase_uom,
      selling_uom: li.selling_uom,
      conversion_factor: li.conversion_factor || 1,
      qty_selling_units: received * (li.conversion_factor || 1),
      scan_confirmed: !!li.scan_confirmed,
      variance_flag
    };
  });

  const undertakingData = {
    entity_id: grn.entity_id,
    bdm_id: grn.bdm_id,
    warehouse_id: grn.warehouse_id,
    linked_grn_id: grn._id,
    receipt_date: grn.grn_date,
    waybill_photo_url: grn.waybill_photo_url || null,
    line_items: lineItems,
    status: 'DRAFT', // BDM reviews + submits from UT page
    created_by: grn.created_by || grn.bdm_id,
    // Phase G4.5b — mirror proxy flag so the UT inherits ownership metadata.
    // Without this, a proxied GRN would surface a "Proxied" pill on the GRN
    // list but the UT in the owner BDM's queue would look self-created.
    ...(grn.recorded_on_behalf_of ? { recorded_on_behalf_of: grn.recorded_on_behalf_of } : {})
  };

  // Mongoose .create() accepts session via array form
  const [undertaking] = await Undertaking.create([undertakingData], { session });

  // Back-link on GRN
  await GrnEntry.updateOne(
    { _id: grn._id },
    { $set: { undertaking_id: undertaking._id } },
    { session }
  );

  return undertaking;
}

/**
 * Pure helper — flag QTY_UNDER / QTY_OVER / NEAR_EXPIRY given a line's
 * expected/received/expiry and a variance tolerance percentage. Consumed by
 * autoUndertakingForGrn (at UT create) and can be reused by other surfaces
 * (Approval Hub recomputes on render for live badges).
 */
function computeLineVariance({ expected_qty, received_qty, expiry_date, variance_tolerance_pct } = {}) {
  // Expiry near-floor: < 90 days — advisory, already blocked-at-create by MIN_EXPIRY_DAYS.
  if (expiry_date) {
    const exp = new Date(expiry_date);
    if (!isNaN(exp.getTime())) {
      const ninetyDays = 90 * 24 * 60 * 60 * 1000;
      if ((exp - new Date()) < ninetyDays) return 'NEAR_EXPIRY';
    }
  }
  const exp = Number(expected_qty) || 0;
  const rec = Number(received_qty) || 0;
  const tol = Number(variance_tolerance_pct) || DEFAULT_VARIANCE_TOLERANCE_PCT;
  if (exp > 0 && rec > 0) {
    const diffPct = Math.abs(rec - exp) / exp * 100;
    if (diffPct > tol) return rec < exp ? 'QTY_UNDER' : 'QTY_OVER';
  }
  return null;
}

module.exports = {
  autoUndertakingForGrn,
  computeLineVariance,
  getGrnSetting,
  // Back-compat alias — callers that imported `getUndertakingSetting` still resolve.
  getUndertakingSetting: getGrnSetting,
  DEFAULT_MIN_EXPIRY_DAYS,
  DEFAULT_VARIANCE_TOLERANCE_PCT
};

