/**
 * Check if user has the approval sub-permission for a module.
 * Follows the existing erpSubAccessCheck convention:
 *   - President/CEO → always pass
 *   - FULL access with no sub_permissions defined → all granted
 *   - sub_permissions exist → check specific key
 *
 * @param {object} user - req.user with erp_access
 * @param {string} subKey - one of the approve_* keys
 * @returns {boolean}
 */
function hasApprovalSub(user, subKey) {
  if (!subKey) return true; // null sub_key = open (e.g., APPROVAL_REQUEST — filtered per-item)
  const { role, erp_access } = user;
  if ([ROLES.PRESIDENT, ROLES.CEO].includes(role)) return true;

  const subs = erp_access?.sub_permissions?.approvals;
  const truthyCount = subs ? Object.values(subs).filter(Boolean).length : 0;
  // FULL with no subs defined = all granted (matches erpSubAccessCheck convention)
  if (!subs || truthyCount === 0) {
    return (erp_access?.modules?.approvals === 'FULL');
  }
  return !!subs[subKey];
}

/**
 * Check if a user is authorized for a module.
 * 1. President/CEO → always authorized
 * 2. If ApprovalRules exist for this module → check if user matches any rule
 * 3. If no rules → fall back to lookup-driven MODULE_DEFAULT_ROLES (Rule #3 compliant)
 * 4. Phase 34: sub-permission check — user must also have the module's approval sub-permission
 *
 * @param {ObjectId} entityId
 * @param {object}   user - full req.user object (with _id, role, erp_access)
 * @param {object}   moduleEntry - entry from MODULE_QUERIES
 * @param {Map}      defaultRolesMap - pre-fetched MODULE_DEFAULT_ROLES lookup entries keyed by code
 */
async function isAuthorizedForModule(entityId, user, moduleEntry, defaultRolesMap) {
  const userId = user._id;
  const userRole = user.role;

  // President always sees everything
  if ([ROLES.PRESIDENT, ROLES.CEO].includes(userRole)) return true;

  // Phase 34: sub-permission gate — check before role/rule checks
  const subKey = moduleEntry.sub_key || MODULE_TO_SUB_KEY[moduleEntry.module];
  if (!hasApprovalSub(user, subKey)) return false;

  // Check ApprovalRules for delegation
  const rules = await ApprovalRule.find({
    entity_id: entityId,
    module: moduleEntry.module,
    is_active: true
  }).lean();

  if (rules.length > 0) {
    for (const rule of rules) {
      if (rule.approver_type === 'ROLE' && (rule.approver_roles || []).includes(userRole)) {
        return true;
      }
      if (rule.approver_type === 'USER' && (rule.approver_user_ids || []).some(id => id.toString() === userId.toString())) {
        return true;
      }
      // REPORTS_TO checked per-item (skip at module level)
    }
    return false;
  }

  // No ApprovalRules → fall back to lookup-driven MODULE_DEFAULT_ROLES
  const defaultEntry = defaultRolesMap.get(moduleEntry.module);
  if (!defaultEntry || !defaultEntry.metadata?.roles) return true; // null/missing = open
  return defaultEntry.metadata.roles.includes(userRole);
}

/**
 * Get all pending items across all modules for a user.
 * President/CEO: queries across ALL entities (cross-entity view).
 * Other roles: queries only their working entity.
 * Returns normalized array sorted by submitted_at descending.
 *
 * Phase 34: accepts full user object (was: userId, userRole) for sub-permission checks.
 * @param {ObjectId} entityId
 * @param {object}   user - full req.user object (with _id, role, erp_access)
 * @param {ObjectId[]} entityIds - user's entity_ids for cross-entity support
 */
async function getUniversalPending(entityId, user, entityIds) {
  const userRole = user.role;
  const isPresidentLike = [ROLES.PRESIDENT, ROLES.CEO].includes(userRole);

  // Determine which entities to query
  let entitiesToQuery;
  if (isPresidentLike) {
    // President sees all entities — query without entity filter
    const Entity = getModel('Entity');
    if (Entity) {
      const allEntities = await Entity.find({ status: { $ne: 'INACTIVE' } }).select('_id').lean();
      entitiesToQuery = allEntities.map(e => e._id);
    } else {
      entitiesToQuery = entityIds || [entityId];
    }
  } else if (entityIds && entityIds.length > 1) {
    // Multi-entity user — query all their entities
    entitiesToQuery = entityIds;
  } else {
    entitiesToQuery = [entityId];
  }

  // Fetch lookup-driven default roles in one query (Rule #3: no hardcoded business values)
  // Auto-seeds on first access if empty — mirrors getByCategory() pattern in lookupGenericController
  let defaultRoles = await Lookup.find({
    entity_id: entityId,
    category: 'MODULE_DEFAULT_ROLES',
    is_active: true
  }).lean();

  if (entityId) {
    // Auto-seed: merge missing defaults ($setOnInsert never overwrites existing entries)
    try {
      const { SEED_DEFAULTS } = require('../controllers/lookupGenericController');
      const seeds = SEED_DEFAULTS.MODULE_DEFAULT_ROLES;
      if (seeds && seeds.length > 0) {
        const ops = seeds.map((item, i) => ({
          updateOne: {
            filter: { entity_id: entityId, category: 'MODULE_DEFAULT_ROLES', code: item.code.toUpperCase() },
            update: { $setOnInsert: { label: item.label, sort_order: i * 10, is_active: true, metadata: item.metadata || {} } },
            upsert: true
          }
        }));
        await Lookup.bulkWrite(ops);
        if (defaultRoles.length === 0 || seeds.length > defaultRoles.length) {
          defaultRoles = await Lookup.find({ entity_id: entityId, category: 'MODULE_DEFAULT_ROLES', is_active: true }).lean();
        }
      }
    } catch (seedErr) {
      console.error('MODULE_DEFAULT_ROLES auto-seed failed:', seedErr.message);
    }
  }

  const defaultRolesMap = new Map(defaultRoles.map(r => [r.code, r]));

  // Filter to modules this user is authorized for
  const authorizedModules = [];
  for (const mod of MODULE_QUERIES) {
    const auth = await isAuthorizedForModule(entityId, user, mod, defaultRolesMap);
    if (auth) authorizedModules.push(mod);
  }

  // Query all authorized modules across all entities in parallel
  const results = await Promise.all(
    authorizedModules.flatMap(mod =>
      entitiesToQuery.map(async (eid) => {
        try {
          return await mod.query(eid);
        } catch (err) {
          console.error(`Universal approval query error [${mod.module}/${eid}]:`, err.message);
          return [];
        }
      })
    )
  );

  // Flatten + dedup by composite id (strict dupes from module re-entry across entities)
  const seen = new Set();
  const flat = results.flat().filter(item => {
    if (seen.has(item.id)) return false;
    seen.add(item.id);
    return true;
  });

  // ── Phase G4.1 — doc_id dedup across surfaces ──
  //
  // The APPROVAL_REQUEST query now returns ALL pending requests (previously it
  // excluded level-0 default-roles-gate items). That can duplicate any request
  // whose underlying doc is ALSO returned by a module-native query — e.g. a
  // CAR_LOGBOOK held by gateApproval appears both as
  //   id: 'CAR_LOGBOOK:<entryId>'       (raw, action_key: POST)
  //   id: 'APPROVAL_REQUEST:<reqId>'    (mirror, action_key: APPROVE)
  // Both items share the same `doc_id`. We prefer the raw module item because
  // its action handler runs the actual post (which resolves the request via
  // the Phase G4 close-loop). Orphan ApprovalRequests (no module-native
  // sibling) survive this pass and surface with their hydrated details so the
  // approver can still expand and act on them from the Hub.
  const byDocId = new Map();
  for (const item of flat) {
    const key = item.doc_id ? String(item.doc_id) : null;
    if (!key) continue;
    if (!byDocId.has(key)) byDocId.set(key, []);
    byDocId.get(key).push(item);
  }

  const dropIds = new Set();
  for (const group of byDocId.values()) {
    if (group.length < 2) continue;
    const hasRaw = group.some(g => !String(g.id).startsWith('APPROVAL_REQUEST:'));
    if (!hasRaw) continue;
    for (const g of group) {
      if (String(g.id).startsWith('APPROVAL_REQUEST:')) dropIds.add(g.id);
    }
  }

  // ── Phase G4.1 — per-item sub-permission filter for APPROVAL_REQUEST items ──
  //
  // APPROVAL_REQUEST is registered with `sub_key: null` (open at the module
  // level — any Hub user passes isAuthorizedForModule). Pre-Phase G4.1 the
  // query only returned level-1+ items, so the "bypass" was tiny. Now that we
  // surface ALL pending requests (incl. level-0 default-roles-gate), we must
  // derive each item's real sub_key from its `module` field and filter out
  // items the caller isn't entitled to approve. President/CEO always pass.
  const filteredByPerm = flat.filter(item => {
    if (!String(item.id).startsWith('APPROVAL_REQUEST:')) return true;
    const itemModule = item.module || 'APPROVAL_REQUEST';
    const itemSubKey = MODULE_TO_SUB_KEY[itemModule];
    return hasApprovalSub(user, itemSubKey);
  });

  const allItems = filteredByPerm.filter(i => !dropIds.has(i.id))
    .sort((a, b) => new Date(b.submitted_at) - new Date(a.submitted_at));

  // ── Enrich line_items: product names + available stock ──
  // 1. Collect all product_id values and warehouse/bdm context from items with line_items
  const productIdSet = new Set();
  const stockQueries = []; // { warehouseId, bdmId, productId } tuples for stock lookup
  for (const item of allItems) {
    const details = item.details || {};
    const whId = details._warehouse_id;
    const bdmId = details._bdm_id;
    for (const li of (details.line_items || [])) {
      if (li.product_id && mongoose.Types.ObjectId.isValid(li.product_id)) {
        const pid = li.product_id.toString();
        productIdSet.add(pid);
        if (whId || bdmId) {
          stockQueries.push({ warehouseId: whId?.toString(), bdmId: bdmId?.toString(), productId: pid });
        }
      }
    }
  }

  // 2. Bulk-fetch product names
  const productMap = new Map();
  if (productIdSet.size > 0) {
    const ProductMaster = getModel('ProductMaster');
    if (ProductMaster) {
      const productIds = [...productIdSet].map(id => new mongoose.Types.ObjectId(id));
      const products = await ProductMaster.find({ _id: { $in: productIds } })
        .select('brand_name dosage_strength item_key')
        .lean();
      for (const p of products) productMap.set(p._id.toString(), p);
    }
  }

  // 3. Bulk-fetch available stock per warehouse (or bdm) + product
  // Build unique warehouse/bdm keys and aggregate all at once
  const stockMap = new Map(); // "warehouseId|productId" or "bdm:bdmId|productId" → available_qty
  if (stockQueries.length > 0) {
    // De-duplicate queries
    const uniqueKeys = new Set();
    const matchConditions = [];
    for (const sq of stockQueries) {
      const key = sq.warehouseId
        ? `wh:${sq.warehouseId}|${sq.productId}`
        : `bdm:${sq.bdmId}|${sq.productId}`;
      if (!uniqueKeys.has(key)) {
        uniqueKeys.add(key);
        const m = { product_id: new mongoose.Types.ObjectId(sq.productId) };
        if (sq.warehouseId) m.warehouse_id = new mongoose.Types.ObjectId(sq.warehouseId);
        else if (sq.bdmId) m.bdm_id = new mongoose.Types.ObjectId(sq.bdmId);
        matchConditions.push(m);
      }
    }
    try {
      // Run two separate aggregations: one for warehouse-based, one for bdm-based
      // This avoids cross-grouping (warehouse entries also have bdm_id, which would split groups)
      const whConditions = matchConditions.filter(m => m.warehouse_id);
      const bdmConditions = matchConditions.filter(m => m.bdm_id && !m.warehouse_id);

      const [whResults, bdmResults] = await Promise.all([
        whConditions.length > 0
          ? InventoryLedger.aggregate([
              { $match: { $or: whConditions } },
              { $group: { _id: { warehouse_id: '$warehouse_id', product_id: '$product_id' }, total_in: { $sum: '$qty_in' }, total_out: { $sum: '$qty_out' } } },
              { $addFields: { available: { $subtract: ['$total_in', '$total_out'] } } }
            ])
          : [],
        bdmConditions.length > 0
          ? InventoryLedger.aggregate([
              { $match: { $or: bdmConditions } },
              { $group: { _id: { bdm_id: '$bdm_id', product_id: '$product_id' }, total_in: { $sum: '$qty_in' }, total_out: { $sum: '$qty_out' } } },
              { $addFields: { available: { $subtract: ['$total_in', '$total_out'] } } }
            ])
          : []
      ]);

      for (const s of whResults) {
        stockMap.set(`wh:${s._id.warehouse_id}|${s._id.product_id}`, s.available);
      }
      for (const s of bdmResults) {
        stockMap.set(`bdm:${s._id.bdm_id}|${s._id.product_id}`, s.available);
      }
    } catch (err) {
      console.error('Approval stock enrichment failed:', err.message);
    }
  }

  // 4. Apply enrichments to line items
  for (const item of allItems) {
    const details = item.details || {};
    const whId = details._warehouse_id?.toString();
    const bdmId = details._bdm_id?.toString();
    for (const li of (details.line_items || [])) {
      if (li.product_id) {
        const pid = li.product_id.toString();
        // Product name
        const prod = productMap.get(pid);
        if (prod) {
          li.product_name = `${prod.brand_name} ${prod.dosage_strength || ''}`.trim();
        } else {
          li.product_name = li.item_key || String(li.product_id);
        }
        // Available stock
        const stockKey = whId ? `wh:${whId}|${pid}` : bdmId ? `bdm:${bdmId}|${pid}` : null;
        if (stockKey) {
          li.available_stock = stockMap.get(stockKey) || 0;
        }
      }
    }
    // Clean up internal fields (don't send to frontend)
    delete details._warehouse_id;
    delete details._bdm_id;
  }

  // ── Sign S3 photo URLs so the browser can load them ──
  const signUrl = async (url) => {
    if (!url) return url;
    try {
      const key = extractKeyFromUrl(url);
      return await getSignedDownloadUrl(key, 3600);
    } catch (err) {
      console.error('Approval signUrl failed:', url, err.message);
      return url;
    }
  };
  const signUrls = (urls) => Promise.all((urls || []).map(u => signUrl(u)));

  await Promise.all(allItems.map(async (item) => {
    const d = item.details || {};
    switch (item.module) {
      case 'SALES':
        [d.csi_photo_url, d.csi_received_photo_url] = await Promise.all([
          signUrl(d.csi_photo_url),
          signUrl(d.csi_received_photo_url),
        ]);
        break;
      case 'COLLECTION':
        [d.deposit_slip_url, d.cr_photo_url, d.cwt_certificate_url] = await Promise.all([
          signUrl(d.deposit_slip_url), signUrl(d.cr_photo_url), signUrl(d.cwt_certificate_url)
        ]);
        d.csi_photo_urls = await signUrls(d.csi_photo_urls);
        break;
      case 'EXPENSES':
        await Promise.all((d.lines || []).map(async (l) => {
          l.or_photo_url = await signUrl(l.or_photo_url);
        }));
        break;
      case 'CAR_LOGBOOK':
        await Promise.all([
          ...(d.fuel_receipts || []).map(async (fr) => {
            [fr.receipt_url, fr.starting_km_photo_url, fr.ending_km_photo_url] = await Promise.all([
              signUrl(fr.receipt_url), signUrl(fr.starting_km_photo_url), signUrl(fr.ending_km_photo_url)
            ]);
          }),
          (async () => {
            [d.starting_km_photo_url, d.ending_km_photo_url] = await Promise.all([
              signUrl(d.starting_km_photo_url), signUrl(d.ending_km_photo_url)
            ]);
          })(),
        ]);
        break;
      case 'INVENTORY':
        [d.waybill_photo_url, d.undertaking_photo_url] = await Promise.all([
          signUrl(d.waybill_photo_url), signUrl(d.undertaking_photo_url)
        ]);
        break;
      case 'UNDERTAKING':
        // Phase 32 — waybill + legacy undertaking photo are stored on the linked
        // GRN and mirrored onto the Undertaking details payload by
        // buildUndertakingDetails. Sign both so the Hub can render the waybill
        // thumbnail + click-to-enlarge modal.
        [d.waybill_photo_url, d.undertaking_photo_url] = await Promise.all([
          signUrl(d.waybill_photo_url), signUrl(d.undertaking_photo_url)
        ]);
        break;
      case 'PRF_CALF':
        d.photo_urls = await signUrls(d.photo_urls);
        break;
      case 'CREDIT_NOTE':
        d.photo_urls = await signUrls(d.photo_urls);
        break;
      // Phase 31 — gap modules
      case 'IC_TRANSFER':
        if (d.kind === 'IC_SETTLEMENT') {
          [d.deposit_slip_url, d.cr_photo_url] = await Promise.all([
            signUrl(d.deposit_slip_url), signUrl(d.cr_photo_url)
          ]);
        }
        break;
      case 'PETTY_CASH':
        d.or_photo_url = await signUrl(d.or_photo_url);
        break;
    }
  }));

  return allItems;
}

module.exports = {
  getUniversalPending,
  MODULE_QUERIES,
  MODULE_TO_SUB_KEY,
  hasApprovalSub,
};

/**
 * VAT Service — VAT Ledger management and 2550Q computation
 *
 * PRD v5 §11.5 — Finance tags entries INCLUDE/EXCLUDE/DEFER.
 * 2550Q = Sum(Output VAT INCLUDE) - Sum(Input VAT INCLUDE) = Net VAT Payable.
 */
const VatLedger = require('../models/VatLedger');

/**
 * Create a VAT ledger entry (auto-created when collection/supplier invoice posted)
 */
async function createVatEntry(data) {
  return VatLedger.create({
    entity_id: data.entity_id,
    period: data.period,
    vat_type: data.vat_type,
    source_module: data.source_module,
    source_doc_ref: data.source_doc_ref,
    source_event_id: data.source_event_id,
    hospital_or_vendor: data.hospital_or_vendor,
    tin: data.tin,
    gross_amount: data.gross_amount || 0,
    vat_amount: data.vat_amount || 0,
    finance_tag: 'PENDING'
  });
}

/**
 * Finance tags a VAT entry (INCLUDE/EXCLUDE/DEFER)
 */
async function tagVatEntry(entryId, tag, userId) {
  const entry = await VatLedger.findById(entryId);
  if (!entry) throw new Error('VAT entry not found');

  entry.finance_tag = tag;
  entry.tagged_by = userId;
  entry.tagged_at = new Date();
  await entry.save();
  return entry;
}

/**
 * Get VAT ledger for a period with optional finance_tag filter
 */
async function getVatLedger(entityId, period, financeTag) {
  const filter = { entity_id: entityId };
  if (period) filter.period = period;
  if (financeTag) filter.finance_tag = financeTag;

  return VatLedger.find(filter).sort({ created_at: -1 }).lean();
}

/**
 * Compute VAT Return 2550Q
 * Output VAT (INCLUDE) - Input VAT (INCLUDE) = Net VAT Payable
 */
async function computeVatReturn2550Q(entityId, quarter, year) {
  // Map quarter to period months
  const quarterMonths = {
    Q1: ['01', '02', '03'],
    Q2: ['04', '05', '06'],
    Q3: ['07', '08', '09'],
    Q4: ['10', '11', '12']
  };
  const months = quarterMonths[quarter];
  if (!months) throw new Error('Invalid quarter');

  const periods = months.map(m => `${year}-${m}`);

  const pipeline = [
    { $match: { entity_id: entityId, period: { $in: periods }, finance_tag: 'INCLUDE' } },
    {
      $group: {
        _id: '$vat_type',
        total_gross: { $sum: '$gross_amount' },
        total_vat: { $sum: '$vat_amount' },
        count: { $sum: 1 }
      }
    }
  ];

  const results = await VatLedger.aggregate(pipeline);

  const output = results.find(r => r._id === 'OUTPUT') || { total_gross: 0, total_vat: 0, count: 0 };
  const input = results.find(r => r._id === 'INPUT') || { total_gross: 0, total_vat: 0, count: 0 };

  return {
    quarter,
    year,
    periods,
    output_vat: { gross: output.total_gross, vat: output.total_vat, count: output.count },
    input_vat: { gross: input.total_gross, vat: input.total_vat, count: input.count },
    net_vat_payable: output.total_vat - input.total_vat
  };
}

module.exports = {
  createVatEntry,
  tagVatEntry,
  getVatLedger,
  computeVatReturn2550Q
};

/**
 * Vendor Auto-Learner — Phase H5 (Tier 1 #2 from the OCR confidence playbook)
 *
 * When Claude's fallback classifies an OR / GAS_RECEIPT with a supplier_name the
 * expense classifier didn't recognise, the OCR pipeline has effectively paid for
 * training data that it throws away. This service closes the loop:
 *
 *   • If a similar VendorMaster entry already exists (entity-scoped), append the
 *     new OCR text variation to its `vendor_aliases` — so next scan hits ALIAS_MATCH.
 *   • Otherwise, create a new VendorMaster entry flagged `auto_learned_from_ocr: true`,
 *     `learning_status: 'UNREVIEWED'`. Next scan hits EXACT_VENDOR without calling Claude.
 *
 * Guardrails (all conditions must pass, else action = 'SKIPPED'):
 *   1. ai_result.supplier_name is present and ≥ MIN_NAME_LEN characters
 *   2. not purely numeric / not a generic word ("RECEIPT", "OR", "INVOICE", …)
 *   3. ai_result.confidence is HIGH or MEDIUM (never learn from LOW)
 *   4. ai_result.coa_code is present — a vendor without a COA is noise
 *   5. entity_id must be non-null (subscription-ready — no cross-tenant leak)
 *
 * Non-destructive: never overwrites an existing vendor's default_coa_code
 * (admin-set values win), only appends unique aliases. Admin can still reject
 * auto-learned entries via PATCH /vendor-learnings/:id (sets is_active = false).
 */
const VendorMaster = require('../models/VendorMaster');
const Lookup = require('../models/Lookup');

// ── Guardrail fallbacks (used when the Lookup table has no entries for a given
//    entity — fresh install before `ensureSeed` runs, or if admin deleted
//    every row). Keeps the learner safe even with an empty DB. Admin-facing
//    tuning lives in Control Center → Lookup Tables → VENDOR_AUTO_LEARN_*. ──
const FALLBACK_THRESHOLDS = {
  MIN_NAME_LEN: 3,
  MAX_NAME_LEN: 120,
  MAX_RAW_SNIPPET: 300,
};
const FALLBACK_BLOCKLIST = new Set([
  'RECEIPT', 'OFFICIAL RECEIPT', 'OR', 'INVOICE', 'UNKNOWN', 'N/A', 'NA',
  'SUPPLIER', 'VENDOR', 'ESTABLISHMENT', 'STORE', 'SHOP', 'CUSTOMER',
  'CASH', 'SALES', 'CASHIER', 'THANK YOU', 'THANK', 'NONE', 'NULL',
  'GAS STATION', 'STATION', 'PUMP',
]);

// ── Per-entity guardrail cache — mirrors expenseClassifier.getKeywordRules pattern.
//    Invalidation is wired into lookupGenericController.js (create/update/delete/seed). ──
const _guardrailCache = new Map(); // entityKey → { value, expiry }
const GUARDRAIL_CACHE_TTL_MS = 5 * 60 * 1000;
const _entityKey = (entityId) => entityId ? String(entityId) : '__GLOBAL__';

async function getGuardrails(entityId) {
  const key = _entityKey(entityId);
  const now = Date.now();
  const hit = _guardrailCache.get(key);
  if (hit && now < hit.expiry) return hit.value;

  // Lookups require entity_id — without it, fall back immediately.
  let thresholds = [];
  let blocklist = [];
  if (entityId) {
    try {
      [thresholds, blocklist] = await Promise.all([
        Lookup.find({ entity_id: entityId, category: 'VENDOR_AUTO_LEARN_THRESHOLDS', is_active: true }).lean(),
        Lookup.find({ entity_id: entityId, category: 'VENDOR_AUTO_LEARN_BLOCKLIST',  is_active: true }).lean(),
      ]);
    } catch (_) {
      // swallow — fallbacks below keep the learner safe
    }
  }

  const tMap = Object.fromEntries((thresholds || []).map(t => [t.code, t.metadata?.value]));
  const value = {
    MIN_NAME_LEN:    Number.isFinite(tMap.MIN_NAME_LEN)    ? tMap.MIN_NAME_LEN    : FALLBACK_THRESHOLDS.MIN_NAME_LEN,
    MAX_NAME_LEN:    Number.isFinite(tMap.MAX_NAME_LEN)    ? tMap.MAX_NAME_LEN    : FALLBACK_THRESHOLDS.MAX_NAME_LEN,
    MAX_RAW_SNIPPET: Number.isFinite(tMap.MAX_RAW_SNIPPET) ? tMap.MAX_RAW_SNIPPET : FALLBACK_THRESHOLDS.MAX_RAW_SNIPPET,
    BLOCKLIST: (blocklist && blocklist.length)
      ? new Set(blocklist.map(b => String(b.metadata?.blocked_value || b.code).toUpperCase().trim()))
      : FALLBACK_BLOCKLIST,
  };
  _guardrailCache.set(key, { value, expiry: now + GUARDRAIL_CACHE_TTL_MS });
  return value;
}

function invalidateGuardrailCache(entityId) {
  if (entityId) _guardrailCache.delete(_entityKey(entityId));
  else _guardrailCache.clear();
}

function isValidCandidateName(name, guardrails) {
  if (!name || typeof name !== 'string') return false;
  const trimmed = name.trim();
  if (trimmed.length < guardrails.MIN_NAME_LEN || trimmed.length > guardrails.MAX_NAME_LEN) return false;
  if (/^\d+$/.test(trimmed)) return false; // purely numeric
  if (guardrails.BLOCKLIST.has(trimmed.toUpperCase())) return false;
  return true;
}

function normaliseForCompare(s) {
  return (s || '').toString().toUpperCase().replace(/\s+/g, ' ').trim();
}

function escapeRegex(str) {
  return String(str || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/**
 * Learn from a Claude win on an OR/GAS_RECEIPT.
 *
 * @param {Object} params
 * @param {Object} params.aiResult         — Output of classifyWithClaude (must have supplier_name, coa_code, confidence)
 * @param {Object} params.extractedFields  — Original regex-parser output (used for raw OCR text variation)
 * @param {string} params.rawOcrText       — Full OCR text (truncated for learning_meta.source_raw_snippet)
 * @param {string} params.docType          — OR | GAS_RECEIPT
 * @param {ObjectId} params.entityId       — Required — prevents cross-tenant learning
 * @param {ObjectId} [params.userId]       — For audit (created_by / updated_by)
 *
 * @returns {Promise<{ action: 'CREATED'|'ALIAS_ADDED'|'SKIPPED', vendor_id: ObjectId|null, reason: string }>}
 */
async function learnFromAiResult({ aiResult, extractedFields = {}, rawOcrText = '', docType, entityId, userId }) {
  // Guardrail 0: entity required
  if (!entityId) {
    return { action: 'SKIPPED', vendor_id: null, reason: 'NO_ENTITY' };
  }

  // Load per-entity guardrails (lookup-driven; cached 5 min; falls back to defaults)
  const guardrails = await getGuardrails(entityId);

  const supplierName = aiResult?.supplier_name || aiResult?.station_name || null;

  // Guardrail 1 + 2: candidate name quality
  if (!isValidCandidateName(supplierName, guardrails)) {
    return { action: 'SKIPPED', vendor_id: null, reason: 'INVALID_NAME' };
  }

  // Guardrail 3: only learn from HIGH/MEDIUM Claude confidence
  const confidence = aiResult?.confidence;
  if (confidence !== 'HIGH' && confidence !== 'MEDIUM') {
    return { action: 'SKIPPED', vendor_id: null, reason: 'LOW_CONFIDENCE' };
  }

  // Guardrail 4: must have a COA to be worth learning
  if (!aiResult?.coa_code) {
    return { action: 'SKIPPED', vendor_id: null, reason: 'NO_COA' };
  }

  const cleanName = supplierName.trim();
  const cleanNameUpper = normaliseForCompare(cleanName);

  // The raw OCR text variation that produced this learning — preferred alias to add.
  // Prefer the regex-extracted supplier_name (actual receipt text) over Claude's cleaned version.
  const rawOcrVariation = normaliseForCompare(
    extractedFields.supplier_name?.value
    || extractedFields.establishment?.value
    || extractedFields.station_name?.value
    || extractedFields.station?.value
    || cleanName
  );

  // ── Step A: Look for existing vendor (exact name, alias match, or Claude-name alias) ──
  // Using a single compound query to minimise round-trips.
  const existing = await VendorMaster.findOne({
    entity_id: entityId,
    is_active: true,
    $or: [
      { vendor_name: { $regex: `^${escapeRegex(cleanName)}$`, $options: 'i' } },
      { vendor_aliases: { $in: [cleanNameUpper, rawOcrVariation] } },
    ],
  });

  if (existing) {
    // Append any missing alias variations (both the Claude-cleaned name and the raw OCR text).
    const existingAliases = new Set((existing.vendor_aliases || []).map(a => normaliseForCompare(a)));
    const newAliases = [];
    if (!existingAliases.has(cleanNameUpper)) newAliases.push(cleanNameUpper);
    if (rawOcrVariation && rawOcrVariation !== cleanNameUpper && !existingAliases.has(rawOcrVariation)) {
      newAliases.push(rawOcrVariation);
    }

    if (newAliases.length === 0) {
      return { action: 'SKIPPED', vendor_id: existing._id, reason: 'ALIAS_EXISTS' };
    }

    try {
      const update = {
        $addToSet: { vendor_aliases: { $each: newAliases } },
        $set: {
          updated_by: userId || existing.updated_by || null,
        },
      };
      // Only bump the learn_count + timestamp when the vendor was itself auto-learned —
      // preserve learning_meta on manually-created admin vendors untouched.
      if (existing.auto_learned_from_ocr) {
        update.$inc = { 'learning_meta.learn_count': 1 };
        update.$set['learning_meta.source_raw_snippet'] = (rawOcrText || '').slice(0, guardrails.MAX_RAW_SNIPPET);
        update.$set.learned_at = new Date();
      }
      await VendorMaster.updateOne({ _id: existing._id }, update);
      return { action: 'ALIAS_ADDED', vendor_id: existing._id, reason: 'ALIAS_APPENDED' };
    } catch (err) {
      return { action: 'SKIPPED', vendor_id: existing._id, reason: `ALIAS_UPDATE_FAILED: ${err.message}` };
    }
  }

  // ── Step B: Create a new auto-learned VendorMaster entry ──
  try {
    // Build alias set (unique, uppercased) — always include the Claude-cleaned name
    // plus the raw OCR variation if different. This maximises ALIAS_MATCH hit rate
    // for subsequent scans where OCR returns either form.
    const aliases = [cleanNameUpper];
    if (rawOcrVariation && rawOcrVariation !== cleanNameUpper) aliases.push(rawOcrVariation);

    const created = await VendorMaster.create({
      entity_id: entityId,
      vendor_name: cleanName,
      vendor_aliases: aliases,
      default_coa_code: aiResult.coa_code,
      default_expense_category: aiResult.expense_category || aiResult.coa_name || null,
      is_active: true,
      auto_learned_from_ocr: true,
      learning_source: 'CLAUDE_AI',
      learned_at: new Date(),
      learning_status: 'UNREVIEWED',
      learning_meta: {
        source_doc_type: docType || null,
        source_ocr_text: rawOcrVariation || cleanName,
        source_raw_snippet: (rawOcrText || '').slice(0, guardrails.MAX_RAW_SNIPPET),
        ai_confidence: confidence,
        suggested_coa_code: aiResult.coa_code,
        suggested_category: aiResult.expense_category || null,
        learn_count: 1,
      },
      created_by: userId || null,
      updated_by: userId || null,
    });
    return { action: 'CREATED', vendor_id: created._id, reason: 'NEW_VENDOR' };
  } catch (err) {
    // Possible duplicate-race under concurrent OCR calls — treat as skipped, not an error.
    if (err?.code === 11000) {
      return { action: 'SKIPPED', vendor_id: null, reason: 'DUPLICATE_RACE' };
    }
    return { action: 'SKIPPED', vendor_id: null, reason: `CREATE_FAILED: ${err.message}` };
  }
}

module.exports = {
  learnFromAiResult,
  getGuardrails,
  invalidateGuardrailCache,
  // exported for unit tests / admin diagnostics
  _internal: { isValidCandidateName, normaliseForCompare, FALLBACK_BLOCKLIST, FALLBACK_THRESHOLDS },
};

/**
 * Hospital Access Utility — Warehouse-Driven
 *
 * Shared filter logic for hospital queries across controllers.
 * BDMs see hospitals via warehouse_ids (linked to their assigned warehouses).
 * Admin-like roles see all hospitals.
 *
 * Usage:
 *   const { buildHospitalAccessFilter } = require('../utils/hospitalAccess');
 *   const accessFilter = await buildHospitalAccessFilter(req.user);
 *   const hospitals = await Hospital.find({ ...baseFilter, ...accessFilter });
 */
const Warehouse = require('../models/Warehouse');
const { isAdminLike } = require('../../constants/roles');

/**
 * Build the MongoDB filter conditions for hospital access based on user role.
 * @param {Object} user - req.user (must have _id and role)
 * @returns {Object} MongoDB filter to merge into Hospital.find() query
 */
async function buildHospitalAccessFilter(user) {
  if (!user || isAdminLike(user.role)) return {}; // no filter for admin-like roles

  // Find warehouses this BDM is assigned to (manager or assigned_user)
  const myWarehouses = await Warehouse.find({
    is_active: true,
    $or: [{ manager_id: user._id }, { assigned_users: user._id }]
  }).select('_id').lean();
  const myWhIds = myWarehouses.map(w => w._id);

  if (myWhIds.length > 0) {
    // Warehouse-driven: show only hospitals linked to BDM's warehouse(s)
    return { warehouse_ids: { $in: myWhIds } };
  }

  // No warehouse assignment — BDM sees nothing until assigned to a warehouse
  return { _id: null };
}

/**
 * Get the list of hospital IDs accessible to a user.
 * Useful for KPI/dashboard queries that need a count or ID list.
 * @param {Object} user - req.user
 * @returns {Array<ObjectId>} hospital IDs
 */
async function getAccessibleHospitalIds(user) {
  const Hospital = require('../models/Hospital');
  const filter = { status: 'ACTIVE', ...(await buildHospitalAccessFilter(user)) };
  const hospitals = await Hospital.find(filter).select('_id').lean();
  return hospitals.map(h => h._id);
}

module.exports = { buildHospitalAccessFilter, getAccessibleHospitalIds };

/**
 * User.entity_ids rebuild helper — Phase FRA-A (April 22, 2026).
 *
 * Rebuilds `User.entity_ids` as:
 *     union(entity_ids_static, activeFraEntityIds)
 *
 * `entity_ids_static`    = admin-direct assignments (BDM Management,
 *                          userController.updateUser). Baseline.
 * `activeFraEntityIds`   = `entity_id` from every active+ACTIVE
 *                          FunctionalRoleAssignment whose `person_id`
 *                          links to a PeopleMaster with `user_id = userId`.
 *
 * Called by:
 *   - functionalRoleController (create / update / deactivate / bulkCreate)
 *   - userController.updateUser (when admin writes entity_ids)
 *   - backfillEntityIdsFromFra.js (migration + drift report)
 *
 * Rule #9 mitigation: `entity_ids` is a thin duplication of
 * (entity_ids_static + FRA rows). We accept the duplication because:
 *   - `tenantFilter` hot path reads `entity_ids` on every authenticated
 *     ERP request — inlining FRA queries there would cost ~1ms × 1000s
 *     of requests/day.
 *   - Duplication is guarded by this single rebuild primitive plus
 *     `checkFraEntityIdsSync` in the health check. No other code path
 *     writes both stores.
 *
 * Rule #19 (cross-entity isolation) alignment: adding an entity to
 * `entity_ids` still requires an explicit X-Entity-Id header to be used
 * — `tenantFilter` validates the header against the allowed set. No
 * silent cross-entity writes.
 *
 * Rule #21 (no silent self-fallback) alignment: `resolveOwnerForWrite`
 * behavior unchanged; still throws 403 on cross-entity target.
 */

const User = require('../../models/User');
const PeopleMaster = require('../models/PeopleMaster');
const FunctionalRoleAssignment = require('../models/FunctionalRoleAssignment');

/**
 * Low-level rebuild for a specific User._id.
 *
 * Returns { userId, entity_ids, added, removed, static, fra } OR null if
 * the user does not exist.
 *
 * Writes only if the effective entity_ids changed (no redundant saves).
 */
async function rebuildUserEntityIdsForUser(userId) {
  if (!userId) return null;

  const user = await User.findById(userId).select('entity_ids entity_ids_static name');
  if (!user) return null;

  // Find every PeopleMaster record linked to this user. In most orgs this
  // is 1:1, but the schema allows 1:N (same user across multiple entities
  // as distinct PeopleMasters). Union all their FRA rows.
  const people = await PeopleMaster.find({ user_id: userId }).select('_id').lean();
  const personIds = people.map((p) => p._id);

  let fraEntityIds = [];
  if (personIds.length) {
    const activeFras = await FunctionalRoleAssignment.find({
      person_id: { $in: personIds },
      is_active: true,
      status: 'ACTIVE',
    })
      .select('entity_id')
      .lean();
    fraEntityIds = activeFras
      .map((f) => f.entity_id)
      .filter(Boolean);
  }

  const staticIds = user.entity_ids_static || [];

  // Dedup union preserving ObjectId type (string-keyed Set for uniqueness).
  const seen = new Set();
  const merged = [];
  for (const id of [...staticIds, ...fraEntityIds]) {
    const k = String(id);
    if (!seen.has(k)) {
      seen.add(k);
      merged.push(id);
    }
  }

  const prevKeys = new Set((user.entity_ids || []).map((id) => String(id)));
  const nextKeys = new Set(merged.map((id) => String(id)));

  const added = [...nextKeys].filter((k) => !prevKeys.has(k));
  const removed = [...prevKeys].filter((k) => !nextKeys.has(k));

  if (added.length || removed.length) {
    user.entity_ids = merged;
    await user.save();
  }

  return {
    userId: String(userId),
    userName: user.name || '',
    entity_ids: merged.map(String),
    static: staticIds.map(String),
    fra: fraEntityIds.map(String),
    added,
    removed,
  };
}

/**
 * Rebuild for the User linked to a given PeopleMaster._id.
 * No-op if the person has no linked user_id (e.g., directors not in the
 * auth system) — returns null silently.
 */
async function rebuildUserEntityIdsFromPerson(personId) {
  if (!personId) return null;
  const person = await PeopleMaster.findById(personId).select('user_id').lean();
  if (!person || !person.user_id) return null;
  return rebuildUserEntityIdsForUser(person.user_id);
}

/**
 * Best-effort wrapper — logs and swallows so an FRA mutation's primary
 * persistence is never blocked by a rebuild hiccup. Drift is surfaced by
 * the health check's live DB drift report.
 */
async function safeRebuildFromPerson(personId, context = '') {
  try {
    return await rebuildUserEntityIdsFromPerson(personId);
  } catch (err) {
    // eslint-disable-next-line no-console
    console.error(`[FRA] rebuild failed (${context}):`, err && err.message ? err.message : err);
    return null;
  }
}

module.exports = {
  rebuildUserEntityIdsForUser,
  rebuildUserEntityIdsFromPerson,
  safeRebuildFromPerson,
};

